class Strategy_ALTRUISTIC_96(BaseStrategy):
    """
    Altruistic Common Pool Resource Strategy.
    
    Always plays Cooperate (C) in every round, regardless of history or opponent behavior.
    This strategy minimizes personal consumption (C = S/(2n) vs D = S/n), preserves stock
    for collective benefit, and maximizes sustainable yield through logistic regeneration.
    Works consistently across first round, last round, and all intermediate rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_97(BaseStrategy):
    """
    Altruistic Common Pool Resource Strategy that protects the shared resource
    through sustained cooperation, defecting only when genuinely necessary for
    resource preservation or when facing severe exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        stock_ratio = current_stock / self.game_description.capacity
        n = self.game_description.n_players
        cooperators_last_round = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents > 0:
            defection_rate = 1.0 - cooperators_last_round / n_opponents
        else:
            defection_rate = 0.0
        current_round = history.round_number
        rounds_remaining = self.game_description.n_rounds - current_round
        if stock_ratio < 0.15:
            if rounds_remaining <= 2:
                return Action.D
            else:
                return Action.C
        elif stock_ratio < 0.3:
            if defection_rate > 0.6:
                return Action.D
            else:
                return Action.C
        elif stock_ratio < 0.5:
            if defection_rate > 0.7:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_ALTRUISTIC_98(BaseStrategy):
    """
    Adaptive Altruistic Cooperation Strategy for Common Pool Resource Game.
    
    Cooperates to sustain collective resource health, adjusting only when stock 
    depletion becomes critical or free-riding becomes severe. Prioritizes collective 
    resource maintenance over individual exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_defection_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        coop_rate = cooperators_last_round / (n - 1) if n > 1 else 1.0
        s_coop = current_stock / 2.0
        if capacity > 0:
            growth = 2.0 * s_coop * (1.0 - s_coop / capacity)
        else:
            growth = 0.0
        s_next_if_all_c = min(s_coop + growth, capacity)
        if current_stock < 0.05 * capacity:
            self.consecutive_defection_rounds = 0
            return Action.C
        if round_num == n_rounds - 1:
            self.consecutive_defection_rounds = 0
            return Action.C
        if coop_rate == 0.0:
            self.consecutive_defection_rounds += 1
            if self.consecutive_defection_rounds >= 2:
                return Action.D
            else:
                return Action.C
        else:
            self.consecutive_defection_rounds = 0
        if coop_rate >= 0.5 and s_next_if_all_c > 0.4 * capacity:
            return Action.C
        if current_stock < 0.2 * capacity and coop_rate < 0.3:
            return Action.D
        if current_stock > 0.5 * capacity and coop_rate >= 0.3:
            return Action.C
        return Action.C

class Strategy_ALTRUISTIC_99(BaseStrategy):
    """
    Altruistic Stewardship Strategy - Always cooperates to preserve the common pool.
    
    This strategy prioritizes collective resource preservation over personal gain,
    cooperating in all stock conditions and regardless of opponent behavior.
    All decision branches converge on cooperation to maximize shared sustainability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        critical_threshold = 2 * self.n_players
        recovery_threshold = self.capacity / 2
        if current_stock <= critical_threshold:
            stock_state = 'critical'
        elif current_stock < recovery_threshold:
            stock_state = 'recovering'
        elif current_stock < self.capacity:
            stock_state = 'healthy'
        else:
            stock_state = 'full'
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        if current_stock == 0:
            return Action.C
        n_opponents = self.n_players - 1
        if n_opponents > 0:
            cooperators_last_round = history.opponent_cooperators[-1]
            cooperation_rate = cooperators_last_round / n_opponents
        else:
            cooperation_rate = 1.0
        if cooperation_rate >= 0.5:
            return Action.C
        if stock_state == 'critical':
            return Action.C
        elif stock_state == 'recovering':
            return Action.C
        elif stock_state == 'healthy':
            return Action.C
        else:
            return Action.C
        return Action.C

class Strategy_ALTRUISTIC_100(BaseStrategy):
    """
    Adaptive Altruistic Stewardship Strategy for Common Pool Resource Game.
    
    Cooperates by default, defecting only under resource crisis conditions.
    Prioritizes collective sustainability while remaining responsive to low cooperation rates
    only when stock is critically depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.consecutive_all_defect_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        is_last_round = current_round == self.n_rounds - 1
        n_opponents = self.n_players - 1
        if n_opponents == 0:
            coop_rate = 0.0
        else:
            observed_cooperators = history.opponent_cooperators[-1]
            coop_rate = observed_cooperators / n_opponents
        if observed_cooperators == 0:
            self.consecutive_all_defect_rounds += 1
        else:
            self.consecutive_all_defect_rounds = 0
        if current_stock > 0.5 * self.capacity:
            return Action.C
        if current_stock > 0.3 * self.capacity:
            return Action.C
        if current_stock <= 0.1 * self.capacity:
            return Action.D
        if coop_rate >= 0.5:
            return Action.C
        if is_last_round and coop_rate < 0.5:
            return Action.D
        if self.consecutive_all_defect_rounds >= 2 and current_stock <= 0.2 * self.capacity:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_101(BaseStrategy):
    """
    Adaptive Reciprocal Cooperation with Resource Stewardship.
    
    Cooperates by default unless conditions indicate defection is strategically necessary.
    Evaluates resource health, opponent behavior, and temporal position to decide cooperation.
    Prioritizes collective welfare by maintaining cooperation when resource is stable,
    resisting exploitation in final rounds, and only defecting when resource health is
    genuinely threatened or widespread defection indicates cooperative equilibrium failure.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        if current_stock == 0:
            return Action.D
        health = current_stock / self.game_description.capacity
        cooperators_last_round = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        if n_opponents > 0:
            defection_rate_last_round = (n_opponents - cooperators_last_round) / n_opponents
        else:
            defection_rate_last_round = 0.0
        if health >= 0.55:
            return Action.C
        elif health < 0.2:
            return Action.D
        elif health < 0.35 and defection_rate_last_round > 0.6:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_102(BaseStrategy):
    """
    Adaptive Altruist Strategy: Cooperates by default, adapting based on stock health
    and reciprocal behavior from opponents. Prioritizes long-term sustainability of the
    commons while remaining responsive to critical depletion and reciprocal effort.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        capacity = self.game_description.capacity
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number == n_rounds - 1:
            if current_stock > 0:
                return Action.C
            else:
                return Action.D
        threshold_high = 2 * capacity / 3
        threshold_low = capacity / 3
        if current_stock >= threshold_high:
            return Action.C
        elif current_stock >= threshold_low:
            cooperators_last_round = history.opponent_cooperators[-1]
            reciprocity_threshold = n_players / 3
            if cooperators_last_round > reciprocity_threshold:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_ALTRUISTIC_103(BaseStrategy):
    """
    Altruistic Common Pool Resource Strategy that prioritizes collective sustainability
    over individual payoff maximization. Cooperates by default and only shifts toward
    defection when aggregate stock depletion threatens sustainability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock <= 0:
            return Action.D
        capacity = self.game_description.capacity
        stock_health = current_stock / capacity if capacity > 0 else 0.0
        cooperators_observed = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        coop_ratio = cooperators_observed / n_opponents if n_opponents > 0 else 0.0
        current_round = history.round_number
        is_final_round = current_round == self.game_description.n_rounds - 1
        if is_final_round:
            if stock_health >= 0.25:
                return Action.C
            else:
                return Action.D
        if stock_health >= 0.4:
            return Action.C
        elif stock_health >= 0.15:
            if coop_ratio >= 0.4:
                return Action.C
            else:
                prob_cooperate = 0.3 + 0.4 * coop_ratio
                if random.random() < prob_cooperate:
                    return Action.C
                else:
                    return Action.D
        elif coop_ratio >= 0.6:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_104(BaseStrategy):
    """
    Cooperative Resource Stewardship Strategy: Default cooperation with selective 
    defection only when resource is healthy AND widespread systematic exploitation 
    is detected. Prioritizes resource preservation over short-term extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        is_last_round = current_round == self.n_rounds - 1
        health_ratio = current_stock / self.capacity if self.capacity > 0 else 0
        n_opponents = self.n_players - 1
        recent_cooperators = history.opponent_cooperators[-1]
        recent_coop_rate = recent_cooperators / n_opponents if n_opponents > 0 else 0
        total_opponent_decisions = current_round * n_opponents
        total_cooperations = float(np.sum(history.opponent_cooperators))
        overall_coop_rate = total_cooperations / total_opponent_decisions if total_opponent_decisions > 0 else 0
        if is_last_round:
            if overall_coop_rate < 0.1:
                return Action.D
            else:
                return Action.C
        if health_ratio <= 0.35:
            return Action.C
        elif health_ratio <= 0.55:
            return Action.C
        elif recent_coop_rate == 0 and overall_coop_rate < 0.2:
            return Action.D
        elif recent_coop_rate < 0.15:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_105(BaseStrategy):
    """
    Altruistic Cooperation with Sustainability Safeguard.
    Maximizes resource preservation and collective welfare by cooperating by default,
    while adapting only when resource collapse is imminent and others are not reciprocating.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == n_rounds - 1:
            return Action.C
        if history.round_number == 0:
            return Action.C
        stock_ratio = current_stock / capacity if capacity > 0 else 0
        if stock_ratio >= 0.3:
            return Action.C
        n_opponents = n_players - 1
        others_cooperated_last_round = history.opponent_cooperators[-1]
        if n_opponents > 0:
            cooperation_rate = others_cooperated_last_round / n_opponents
        else:
            cooperation_rate = 0.0
        if cooperation_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_106(BaseStrategy):
    """
    Adaptive Sustainability Cooperation Strategy for Common Pool Resource Game.
    
    Uses threshold-based cooperation decisions that adjust with remaining rounds,
    combined with adaptive responses to opponent cooperation patterns.
    Cooperates unconditionally in the first and last rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.previous_stock = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.n_rounds - 1:
            return Action.C
        s_min = self.capacity / (4.0 * self.n_players)
        rounds_left = self.n_rounds - current_round
        threshold = s_min * (1.0 + rounds_left / float(self.n_rounds))
        c_prev = history.opponent_cooperators[-1]
        stock_was_increasing = current_stock >= self.previous_stock
        n_opponents = self.n_players - 1
        cooperation_rate = c_prev / float(n_opponents) if n_opponents > 0 else 0.0
        if cooperation_rate > 0.6 and stock_was_increasing:
            self.previous_stock = current_stock
            return Action.C
        if cooperation_rate < 0.3 and (not stock_was_increasing):
            self.previous_stock = current_stock
            return Action.C
        if c_prev == 0 and current_stock <= s_min:
            self.previous_stock = current_stock
            return Action.D
        self.previous_stock = current_stock
        if current_stock >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_107(BaseStrategy):
    """
    Altruistic Commons Preservation Strategy for Common Pool Resource Games.
    
    Cooperates as default action, defecting only when stock health is critical
    and insufficient cooperation exists to sustain the commons. Prioritizes
    resource preservation over personal gain and avoids final-round exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        health = current_stock / self.capacity if self.capacity > 0 else 0.0
        opponents_cooperated = history.opponent_cooperators[-1]
        my_previous_action_was_coop = history.my_actions[-1]
        total_cooperators = opponents_cooperated + (1 if my_previous_action_was_coop else 0)
        coop_ratio = total_cooperators / self.n_players
        if health >= 0.5:
            return Action.C
        elif health >= 0.25:
            if coop_ratio >= 0.5:
                return Action.C
            else:
                return Action.D
        elif coop_ratio >= 0.67:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_108(BaseStrategy):
    """
    Cooperative Sustainability Strategy: Prioritizes resource sustainability 
    and collective welfare by cooperating unconditionally in all rounds, 
    accepting lower personal payoff to sustain long-term resource health.
    
    Decision logic: Always cooperate regardless of stock level, round number,
    or opponent actions. This maintains credible commitment to sustainability
    over short-term exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        capacity = self.game_description.capacity
        if capacity <= 0:
            return Action.C
        health_ratio = current_stock / capacity
        if health_ratio >= 0.6:
            return Action.C
        elif health_ratio > 0.2:
            return Action.C
        else:
            return Action.C

class Strategy_ALTRUISTIC_109(BaseStrategy):
    """
    Altruistic Stock Stewardship Strategy.
    
    Cooperate if stock > capacity/2.5 (40% threshold), otherwise defect.
    Special case: if stock ≤ 1.0 (collapsed), always defect.
    
    This strategy sacrifices individual payoff for resource preservation,
    adapting to opponent behavior through stock observation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = game_description.capacity / 2.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= 1.0:
            return Action.D
        if current_stock > self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_110(BaseStrategy):
    """
    Altruistic Stock Preservation Strategy - cooperates to preserve the common pool resource
    when stock is sufficiently healthy, defects when preservation is futile.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < 2:
            return Action.D
        remaining_rounds = self.game_description.n_rounds - history.round_number
        k = math.ceil(remaining_rounds / 4)
        threshold = self.game_description.capacity / (2 + k)
        if current_stock > threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_111(BaseStrategy):
    """
    Altruistic Cooperative Stewardship Strategy.
    
    Maintains cooperation to preserve the common pool resource for collective benefit.
    Defects only when stock falls below capacity/3 (critical depletion threshold).
    Unconditionally cooperates in the final round to demonstrate intrinsic commitment
    to cooperation rather than exploiting others.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        capacity = self.game_description.capacity
        threshold = capacity / 3
        if current_stock >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_112(BaseStrategy):
    """
    Altruistic Adaptive Cooperation Strategy for Common Pool Resource Game.
    
    Cooperates when stock is healthy (≥ capacity/2), and adapts based on 
    opponent cooperation when stock is depleted. Only defects if fewer than 
    half of opponents cooperated in the previous round and it's not the first round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        if current_stock < 0.1:
            return Action.C
        if current_stock >= capacity / 2:
            return Action.C
        if history.round_number == 0:
            return Action.C
        opponents_cooperated_last = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents <= 0:
            return Action.C
        cooperation_rate = opponents_cooperated_last / n_opponents
        if cooperation_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_113(BaseStrategy):
    """
    Adaptive Altruistic Steward - prioritizes preservation of the common pool resource
    through consistent cooperation while adapting to resource depletion and defection.
    
    Phases:
    1. Round 0: Always cooperate to establish willingness
    2. Rounds 1 to r-2: Stock-dependent reciprocal cooperation (usually always C)
    3. Round r-1: Defect only if stock is critically low AND insufficient reciprocation
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        coop_count = history.opponent_cooperators[-1]
        if round_num == r - 1:
            if n == 2:
                opponent_cooperated = coop_count > 0
                if not opponent_cooperated and current_stock < 0.5 * capacity:
                    return Action.D
                else:
                    return Action.C
            elif current_stock < 0.5 * capacity and coop_count < n / 3:
                return Action.D
            else:
                return Action.C
        if current_stock >= 0.6 * capacity:
            return Action.C
        elif current_stock >= 0.3 * capacity:
            return Action.C
        else:
            return Action.C

class Strategy_ALTRUISTIC_114(BaseStrategy):
    """
    Altruistic Preservation Strategy: Always cooperate to preserve the common pool resource,
    maximizing long-term sustainability for all players regardless of others' behavior.
    
    This strategy unconditionally cooperates in every round, accepting lower per-round
    consumption to signal commitment to collective resource preservation. It never retaliates
    against defectors, instead maintaining discipline to enable recovery even when others exploit.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_115(BaseStrategy):
    """
    Altruistic Stock Restoration Strategy for Common Pool Resource Game.
    
    Cooperates by default when stock is healthy, with adaptive monitoring
    and recovery assistance. Defects only in critical depletion or when
    trust is broken and stock is moderately depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        opponents_cooperated_last = history.opponent_cooperators[-1]
        self_cooperated_last = history.my_actions[-1]
        total_cooperators_last = opponents_cooperated_last + (1 if self_cooperated_last else 0)
        if current_stock <= self.capacity * 0.2:
            return Action.D
        if round_num == self.n_rounds - 1:
            if current_stock > self.capacity * 0.3:
                return Action.C
            else:
                return Action.D
        if current_stock < self.capacity * 0.3 and total_cooperators_last >= int(math.ceil(0.75 * self.n_players)):
            return Action.C
        threshold_high = self.capacity * 0.4
        threshold_low = self.capacity * 0.2
        half_players = self.n_players / 2.0
        if current_stock > threshold_high:
            return Action.C
        if current_stock > threshold_low:
            if total_cooperators_last >= half_players:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_ALTRUISTIC_116(BaseStrategy):
    """
    Altruistic Adaptive Strategy for Common Pool Resource Game.
    
    Cooperates by default, defecting only under constrained circumstances
    where continuing to cooperate would be futile. Prioritizes stock 
    preservation over individual extraction, with special handling for
    first/last rounds and critical stock depletion scenarios.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.n_rounds - 1:
            return Action.C
        n_opponents = self.n_players - 1
        if n_opponents <= 0:
            return Action.C
        cooperating_opponents = int(history.opponent_cooperators[-1])
        cooperation_rate = cooperating_opponents / n_opponents
        healthy_threshold = self.capacity * 0.5
        critical_threshold = self.capacity * 0.2
        minimal_threshold = self.capacity * 0.08
        if current_stock > healthy_threshold:
            return Action.C
        if current_stock <= critical_threshold:
            if cooperation_rate < 0.4:
                if current_stock > minimal_threshold:
                    return Action.C if random.random() < 0.6 else Action.D
                return Action.C
            return Action.C
        if cooperation_rate >= 0.5:
            return Action.C
        elif cooperation_rate >= 0.3:
            return Action.C if random.random() < 0.7 else Action.D
        else:
            return Action.C if random.random() < 0.45 else Action.D

class Strategy_ALTRUISTIC_117(BaseStrategy):
    """
    Altruistic Cooperative Preservation Strategy.
    
    Consistently plays Cooperate (C) across all rounds to preserve the commons,
    prioritizing collective resource preservation over individual consumption gain.
    Maintains altruistic commitment even when opponents defect, recognizing that
    shared cooperation is necessary to prevent tragedy of the commons.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.C

class Strategy_ALTRUISTIC_118(BaseStrategy):
    """
    Altruistic Stock Preservation Strategy - Prioritizes collective pool health and long-term sustainability.
    Cooperates unconditionally in first and last rounds, uses adaptive cooperation in middle rounds
    based on stock health and observed cooperation patterns.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        rounds_left = self.n_rounds - current_round
        if rounds_left == 0:
            return Action.C
        if self.capacity <= 0:
            return Action.C
        stock_ratio = current_stock / self.capacity
        if current_stock <= 0:
            return Action.C
        if stock_ratio >= 0.95:
            return Action.C
        if stock_ratio >= 0.5:
            return Action.C
        if stock_ratio >= 0.3:
            n_opponents = self.n_players - 1
            if n_opponents > 0:
                observed_coop_rate = history.opponent_cooperators[-1] / n_opponents
            else:
                observed_coop_rate = 1.0
            cooperation_threshold = 0.35 - 0.1 * stock_ratio
            if observed_coop_rate >= cooperation_threshold:
                return Action.C
            else:
                return Action.D
        if stock_ratio >= 0.15:
            coop_prob = 0.85
            if rounds_left <= 2:
                coop_prob = min(coop_prob + 0.1, 1.0)
            return Action.C if random.random() < coop_prob else Action.D
        coop_prob = 0.95
        if rounds_left <= 2:
            coop_prob = min(coop_prob + 0.1, 1.0)
        return Action.C if random.random() < coop_prob else Action.D

class Strategy_ALTRUISTIC_119(BaseStrategy):
    """
    Altruistic Common Pool Resource Strategy that prioritizes collective welfare
    and resource sustainability. Cooperates in all non-final rounds unconditionally,
    then adapts in the final round based on remaining stock levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            threshold = self.game_description.capacity * 0.25
            if current_stock >= threshold:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_ALTRUISTIC_120(BaseStrategy):
    """
    Adaptive Altruistic Pool Conservation Strategy
    
    Cooperates by default to maintain resource health, but defects if the resource
    is in scarcity and others show insufficient reciprocity. Exhibits true altruism
    in final round and accepts resource collapse by continuing cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.sustainable_threshold = game_description.capacity * 0.65
        self.critical_threshold = game_description.capacity * 0.15
        self.cooperation_threshold = 0.5
        self.n_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        if current_round == n_rounds - 1:
            return Action.C
        if current_stock < self.critical_threshold:
            return Action.C
        if current_stock < self.sustainable_threshold:
            if current_round == 0:
                return Action.C
            total_cooperators = int(np.sum(history.opponent_cooperators[:current_round]))
            total_actions_observed = current_round * self.n_opponents
            if total_actions_observed == 0:
                observed_cooperation = 1.0
            else:
                observed_cooperation = total_cooperators / total_actions_observed
            if observed_cooperation >= self.cooperation_threshold:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_ALTRUISTIC_121(BaseStrategy):
    """
    Altruistic Common Pool Resource Strategy - maintains sustainability by cooperating 
    when the resource is healthy and defecting only when facing tragedy conditions.
    
    Decision rule: Cooperate if stock is healthy OR a sufficient majority of opponents
    cooperate, with thresholds that tighten as stock declines. First round always cooperates
    to signal commitment. Last round cooperates only if resource remains viable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.n_rounds - 1:
            if current_stock > 2 * self.n_players:
                return Action.C
            else:
                return Action.D
        healthy_threshold = 0.75 * self.capacity
        moderate_threshold = 0.5 * self.capacity
        stressed_threshold = 0.25 * self.capacity
        observed_cooperators = history.opponent_cooperators[-1]
        majority_threshold = math.ceil((self.n_players - 1) / 2)
        if current_stock >= healthy_threshold:
            return Action.C
        elif current_stock >= moderate_threshold:
            if observed_cooperators >= majority_threshold:
                return Action.C
            else:
                return Action.D
        elif current_stock >= stressed_threshold:
            if observed_cooperators == self.n_players - 1:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_ALTRUISTIC_122(BaseStrategy):
    """
    Adaptive Cooperative Stock Maintenance Strategy
    
    Prioritizes resource sustainability through stock-level-responsive cooperation.
    Maintains cooperative baseline in healthy stock conditions and adapts based on
    depletion levels while respecting collective outcome optimization.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        round_t = history.round_number
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        threshold_60 = 0.6 * capacity
        threshold_35 = 0.35 * capacity
        threshold_10 = 0.1 * capacity
        if current_stock <= 0:
            return Action.C
        elif current_stock >= threshold_60:
            return Action.C
        elif current_stock >= threshold_35:
            return Action.C
        elif current_stock >= threshold_10:
            remaining_rounds = n_rounds - round_t
            if remaining_rounds <= 1:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_ALTRUISTIC_123(BaseStrategy):
    """
    Stock-Responsive Altruistic Strategy for Common Pool Resource Game.
    
    Cooperates when stock is healthy (≥ 60% capacity), switches to conditional cooperation
    when stock is moderate (30-60% capacity), and defects when stock is critically low (<30% capacity).
    Always cooperates in round 0 and final round. Includes extreme defection response.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.C
        num_cooperators_last_round = history.opponent_cooperators[-1]
        num_defectors_last_round = n - 1 - num_cooperators_last_round
        threshold_high = 0.6 * capacity
        threshold_low = 0.3 * capacity
        threshold_extreme = 0.5 * capacity
        if current_stock >= threshold_high:
            return Action.C
        elif current_stock >= threshold_low:
            if num_defectors_last_round <= n / 3:
                return Action.C
            else:
                return Action.D
        elif num_defectors_last_round >= 0.8 * n and current_stock < threshold_extreme:
            return Action.D
        else:
            return Action.D

class Strategy_ALTRUISTIC_124(BaseStrategy):
    """
    Altruistic Commons-Preservation Strategy: Protects the common resource through
    persistent cooperation, defecting only when the resource is secure and opponents
    show systematic free-riding. Prioritizes resource sustainability over personal gain.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        total_opponent_actions = current_round * (n - 1)
        total_opponent_cooperations = int(np.sum(history.opponent_cooperators[:current_round]))
        if total_opponent_actions == 0:
            opp_coop_rate = 0.5
        else:
            opp_coop_rate = total_opponent_cooperations / total_opponent_actions
        if current_round == r - 1:
            if current_stock > 2 * n or current_stock > 0:
                return Action.C
        if current_stock <= capacity / 3:
            return Action.C
        elif current_stock <= 3 * capacity / 4:
            return Action.C
        elif opp_coop_rate >= 0.5:
            return Action.C
        elif opp_coop_rate >= 0.25:
            return Action.C if random.random() < 0.75 else Action.D
        else:
            return Action.C if random.random() < 0.6 else Action.D

class Strategy_ALTRUISTIC_125(BaseStrategy):
    """
    Altruistic Common Pool Resource Strategy.
    
    Cooperates by default when the resource stock is healthy (≥35% capacity).
    Also cooperates when stock is stressed but a majority of opponents cooperated last round.
    Only defects when stock is critically low AND opponents are predominantly defecting.
    Always cooperates in round 1 and final round as a commitment to collective welfare.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        if current_stock <= 0:
            return Action.D
        stock_health = current_stock / self.game_description.capacity
        n_opponents = self.game_description.n_players - 1
        if n_opponents > 0:
            observed_coop_rate = history.opponent_cooperators[-1] / n_opponents
        else:
            observed_coop_rate = 0.0
        if stock_health >= 0.35:
            return Action.C
        if observed_coop_rate >= 0.5:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_126(BaseStrategy):
    """
    Altruistic Commons Stewardship Strategy for the Common Pool Resource Game.
    
    Prioritizes resource sustainability over personal payoff extraction through:
    - Unconditional cooperation in rounds 1 and r
    - Resource-centric decision-making in intermediate rounds
    - Reciprocity without punishment
    - Hope preservation through moderate cooperation even under low opponent reciprocity
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        stock_ratio = current_stock / self.game_description.capacity
        n_opponents = self.game_description.n_players - 1
        if n_opponents <= 0:
            cooperation_rate = 0.0
        else:
            cooperation_rate = float(history.opponent_cooperators[-1]) / float(n_opponents)
        if stock_ratio < 0.35:
            return Action.C
        elif stock_ratio < 0.55:
            return Action.C
        elif stock_ratio < 0.8:
            if cooperation_rate >= 0.35:
                return Action.C
            else:
                return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_127(BaseStrategy):
    """
    Adaptive Reciprocal Cooperator strategy for Common Pool Resource Game.
    
    Prioritizes collective sustainability by adapting behavior based on:
    - Resource health (stock/capacity ratio)
    - Observed opponent cooperation rate
    
    Cooperates when resources are healthy, uses weighted reciprocity under stress,
    and only defects in final round when resources are critically depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if current_stock == 0:
            return Action.C
        h_t = current_stock / capacity if capacity > 0 else 0.0
        opponents_cooperated = history.opponent_cooperators[-1]
        n_opponents = n - 1
        coop_t = opponents_cooperated / n_opponents if n_opponents > 0 else 0.0
        if h_t >= 0.5:
            return Action.C
        elif h_t > 0.25:
            if coop_t >= 0.5:
                return Action.C
            else:
                return Action.C if random.random() < coop_t else Action.D
        elif round_num == n_rounds - 1:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_128(BaseStrategy):
    """
    Sustainability-Prioritizing Reciprocal Cooperation strategy for Common Pool Resource Game.
    
    Emphasizes resource sustainability while maintaining conditional reciprocity.
    Cooperates by default, with defection only under resource stress and evidence of widespread defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.n_rounds - 1:
            return Action.C
        n_opponents = self.n - 1
        if n_opponents == 0:
            return Action.C
        if current_round >= 2:
            if history.opponent_cooperators[-1] == n_opponents and history.opponent_cooperators[-2] == n_opponents:
                return Action.C
        if current_stock < self.capacity / 8:
            opponent_defection_count = n_opponents - history.opponent_cooperators[-1]
            opponent_defection_rate = opponent_defection_count / n_opponents
            if opponent_defection_rate > 0.75:
                return Action.D
        threshold_trigger = min(0.4, 1 - 1 / self.n)
        recent_cooperation_rate = history.opponent_cooperators[-1] / n_opponents
        cooperation_threshold = n_opponents / self.n * threshold_trigger
        if current_stock > self.capacity / 2:
            return Action.C
        if current_stock < self.capacity / 4:
            if history.opponent_cooperators[-1] >= n_opponents * 0.5:
                return Action.C
            else:
                return Action.D
        if recent_cooperation_rate > cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_33(BaseStrategy):
    """
    Benevolent Adaptive Strategy for Common Pool Resource Game.
    
    Cooperates by default while stock supports sustainable collective consumption.
    Defects only when stock is depleted (≤ 1.3 × capacity/2) and majority of 
    opponents are defecting, or in the final round when stock is critically low.
    Prioritizes reaching and maintaining the all-C equilibrium.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if current_stock < 2 * n and round_num < r - 1:
            return Action.C
        if round_num == r - 1:
            if current_stock > capacity / 2:
                return Action.C
            else:
                return Action.D
        threshold = 1.3 * capacity / 2
        if current_stock <= threshold:
            opponents_cooperators = history.opponent_cooperators[-1]
            opponents_defectors = n - 1 - opponents_cooperators
            if opponents_defectors > n / 2:
                return Action.D
        return Action.C

class Strategy_BENEVOLENT_34(BaseStrategy):
    """
    Benevolent Adaptive Commons Strategy with phase-dependent cooperation
    and stock health monitoring. Initiates and sustains cooperation to maximize
    collective welfare, only defecting when stock depletion makes cooperation
    mathematically futile, while avoiding final-round exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.C
        health = current_stock / capacity if capacity > 0 else 0.0
        num_cooperators = int(history.opponent_cooperators[-1])
        coop_rate = num_cooperators / (n - 1) if n - 1 > 0 else 0.0
        if current_stock < capacity / 5:
            return Action.D
        elif health >= 0.6 and coop_rate >= 0.3:
            return Action.C
        elif health >= 0.4 and coop_rate >= 0.5:
            return Action.C
        elif health >= 0.25 and coop_rate >= 0.7:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_35(BaseStrategy):
    """
    Stock-Aware Benevolent Strategy for Common Pool Resource Game.
    
    Cooperates based on stock health and observed cooperation patterns.
    Prioritizes collective resource preservation while maintaining reciprocal trust.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        rounds_remaining = r - current_round
        observed_cooperators = int(history.opponent_cooperators[-1])
        if current_stock <= 2 * n:
            return Action.C
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        if current_round == r - 1:
            if stock_ratio >= 0.6 and observed_cooperators >= 0.5 * n:
                return Action.C
            if stock_ratio < 0.2 and observed_cooperators > 0:
                return Action.C
            if current_stock == 0:
                return Action.D
        if stock_ratio < 0.4:
            return Action.C
        if stock_ratio >= 0.6 and observed_cooperators >= 0.5 * n - 1:
            return Action.C
        if 0.4 <= stock_ratio < 0.6 and observed_cooperators >= 0.3 * n:
            return Action.C
        if rounds_remaining <= 2 and observed_cooperators >= 0.2 * n and (current_stock > 0):
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_36(BaseStrategy):
    """
    Benevolent Adaptive Cooperation Strategy - Unconditionally cooperates
    to prioritize collective resource health and signal trustworthiness,
    regardless of others' behavior or resource state.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        n_opponents = n_players - 1
        opponent_cooperators_prev = history.opponent_cooperators[-1]
        cooperation_rate = opponent_cooperators_prev / n_opponents if n_opponents > 0 else 0.0
        rounds_remaining = n_rounds - current_round
        if stock_ratio < 0.2:
            return Action.C
        if stock_ratio >= 0.6:
            return Action.C
        if 0.2 <= stock_ratio < 0.6:
            if cooperation_rate >= 0.7:
                return Action.C
            if cooperation_rate >= 0.4:
                return Action.C
            if rounds_remaining >= 2:
                return Action.C
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_37(BaseStrategy):
    """
    Benevolent Common Pool Resource Strategy.
    
    Cooperates to sustain the resource, defecting only when the resource is
    critically depleted or when defection from others makes cooperation futile.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        if history.round_number == r - 1:
            if current_stock > 0.25 * capacity:
                return Action.C
            else:
                return Action.D
        k_prev = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents <= 0:
            return Action.C
        coop_rate = k_prev / n_opponents
        if current_stock >= 0.75 * capacity:
            return Action.C
        elif current_stock >= 0.4 * capacity:
            if coop_rate >= 0.5:
                return Action.C
            elif random.random() < 0.6:
                return Action.C
            else:
                return Action.D
        elif coop_rate >= 0.4:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_38(BaseStrategy):
    """
    Benevolent Adaptive Common Pool Resource Strategy.
    
    Cooperates unconditionally in round 1 and the final round.
    In middle rounds, adapts based on current stock level and opponent cooperation rates:
    - High stock (>capacity/2): Cooperate
    - Medium stock (capacity/4 to capacity/2): Reciprocate based on opponent cooperation rate
    - Low stock (≤capacity/4): Defect to preserve remaining stock
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number == r - 1:
            return Action.C
        if current_stock > capacity / 2:
            return Action.C
        elif capacity / 4 < current_stock <= capacity / 2:
            n_opponents = n - 1
            if n_opponents > 0:
                prev_cooperators = history.opponent_cooperators[-1]
                cooperation_rate = prev_cooperators / n_opponents
                if cooperation_rate >= 0.5:
                    return Action.C
                else:
                    return Action.D
            else:
                return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_39(BaseStrategy):
    """
    Adaptive Mutual Cooperation with Resource Stewardship strategy.
    Pursues Pareto-optimal all-cooperate sustainability by reciprocating cooperation levels
    while maintaining benevolent intent even in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number == n_rounds - 1:
            return Action.C
        k_c = history.opponent_cooperators[-1]
        cooperation_rate = k_c / (n - 1) if n - 1 > 0 else 0.0
        if current_stock <= 2 * n:
            return Action.D
        if cooperation_rate >= 0.75:
            return Action.C
        if 0.6 <= cooperation_rate < 0.75 and current_stock >= 0.6 * capacity:
            return Action.C
        if current_stock >= 0.75 * capacity:
            return Action.C
        if cooperation_rate >= 0.5 and current_stock >= 0.5 * capacity:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_40(BaseStrategy):
    """
    Benevolent Adaptive Sustainability Strategy for Common Pool Resource Game.
    
    Prioritizes resource sustainability while maintaining cooperative intent.
    Defects only when stock health is critical or cooperation has broken down.
    Initiates cooperation unconditionally and responds adaptively to opponent behavior
    and current stock levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        opponents_cooperated = history.opponent_cooperators[-1]
        cooperation_rate = opponents_cooperated / (n - 1)
        stock_health = current_stock / capacity
        if stock_health < 0.35:
            return Action.D
        if stock_health >= 0.65 and cooperation_rate >= 0.5:
            return Action.C
        if stock_health >= 0.5 and cooperation_rate >= (n - 2) / (n - 1):
            return Action.C
        if stock_health >= 0.35 and cooperation_rate >= 0.6:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_41(BaseStrategy):
    """
    Benevolent Adaptive Common Pool Resource Strategy.
    
    Cooperates unconditionally in round 1, then adapts based on stock levels
    and cooperators' behavior with emphasis on resource preservation over exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        stock = current_stock
        cooperators_count = history.opponent_cooperators[-1]
        if stock <= capacity / 3:
            return Action.D
        if stock >= 2 * capacity / 3:
            return Action.C
        if cooperators_count >= 0.75 * (n - 1):
            return Action.C
        if cooperators_count <= 0.25 * (n - 1) and stock < capacity / 2:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_42(BaseStrategy):
    """
    Benevolent Threshold Stewardship: Cooperates to maintain resource sustainability,
    defects only when the resource reaches critical depletion levels (< 20% of capacity).
    Always cooperates in first and last rounds to establish and maintain benevolent intent.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.high_threshold = 0.7 * game_description.capacity
        self.critical_threshold = 0.2 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        if current_stock >= self.critical_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_43(BaseStrategy):
    """
    Benevolent Cooperative Strategy with Adaptive Safeguards.
    
    Defaults to cooperation across all rounds, but strategically defects only when
    the stock is severely depleted (below capacity/4) AND opponents show widespread
    defection (cooperation rate < 30%), or when stock is critically low (below capacity/2)
    with minimal cooperation (< 15%). Maintains consistent benevolence without exploiting
    the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        if n_opponents > 0:
            cooperation_rate = history.opponent_cooperators[-1] / n_opponents
        else:
            cooperation_rate = 0.0
        capacity = self.game_description.capacity
        if current_stock < capacity / 4:
            if cooperation_rate < 0.3:
                return Action.D
            else:
                return Action.C
        elif current_stock < capacity / 2:
            if cooperation_rate < 0.15:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_BENEVOLENT_44(BaseStrategy):
    """
    Benevolent Adaptive Pool Strategy for Common Pool Resource Game.
    
    Leads with cooperation and stock stewardship. Gradually adjusts based on
    aggregate defection rates with time-aware thresholds that become more
    forgiving as the game nears its end. Maintains high cooperation standards
    when stock is critically depleted or in final rounds with low exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        rounds_left = r - current_round
        cooperators_last_round = history.opponent_cooperators[-1]
        defectors_last_round = n - 1 - cooperators_last_round
        defection_rate = defectors_last_round / n if n > 0 else 0.0
        if stock_ratio < 0.3:
            return Action.C
        if rounds_left <= 2 and defection_rate <= 0.65:
            return Action.C
        if rounds_left > 4:
            threshold = 0.5
        elif rounds_left > 2:
            threshold = 0.55
        else:
            threshold = 0.65
        if stock_ratio >= 0.3 and defection_rate > threshold:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_45(BaseStrategy):
    """
    Benevolent Adaptive Cooperation Strategy for Common Pool Resource Game.
    
    Prioritizes resource sustainability through strong cooperative commitment,
    with a single mild defection signal as a soft correction when resource is healthy
    and opponents are defecting.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.defection_signal_used = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number == r - 1:
            return Action.C
        if current_stock < capacity / 3:
            return Action.C
        opponents_cooperated = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents > 0:
            cooperation_rate = opponents_cooperated / n_opponents
        else:
            cooperation_rate = 0.0
        if cooperation_rate >= 0.5:
            return Action.C
        if not self.defection_signal_used and current_stock > 2 * capacity / 3:
            self.defection_signal_used = True
            return Action.D
        self.defection_signal_used = False
        return Action.C

class Strategy_BENEVOLENT_46(BaseStrategy):
    """
    Benevolent Cooperative Stewardship Strategy for Common Pool Resource Game.
    Cooperates by default, with conditional defection based on stock depletion
    and opponent cooperation rates. Always cooperates in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.n_players = game_description.n_players
        self.high_threshold = self.capacity / 2
        self.low_threshold = self.capacity / 3

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number == self.n_rounds - 1:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        n_opponents = self.n_players - 1
        cooperation_rate = cooperators_last_round / n_opponents if n_opponents > 0 else 0
        if current_stock > self.high_threshold:
            return Action.C
        elif current_stock > self.low_threshold:
            if cooperation_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        elif cooperation_rate > 2.0 / 3.0:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_47(BaseStrategy):
    """
    Benevolent Adaptive Stock Sustainability Strategy
    
    Prioritizes collective resource sustainability over personal extraction.
    Cooperates by default, defects only when resource faces collapse and
    defection rate is already high as a deterrent signal.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.safe_threshold = self.capacity * 0.6
        self.caution_threshold = self.capacity * 0.3

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        is_final_round = round_number == self.n_rounds - 1
        last_round_cooperators = history.opponent_cooperators[-1]
        n_opponents = self.n_players - 1
        if n_opponents > 0:
            cooperation_rate = last_round_cooperators / n_opponents
        else:
            cooperation_rate = 0.0
        if current_stock >= self.safe_threshold:
            return Action.C
        elif current_stock >= self.caution_threshold:
            if cooperation_rate < 0.25:
                return Action.D
            else:
                return Action.C
        elif is_final_round:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_48(BaseStrategy):
    """
    Adaptive Benevolent Preservation Strategy for Common Pool Resource Game.
    
    Cooperates by default, defecting only when resource depletion becomes acute
    or when insufficient opponents are reciprocating cooperation. Heavily weights
    resource sustainability over individual consumption gains through adaptive
    thresholds based on stock level and observed cooperation rate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock <= 0:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        if n_opponents <= 0:
            cooperation_rate = 0.0
        else:
            cooperation_rate = cooperators_last_round / n_opponents
        capacity = self.game_description.capacity
        if current_stock > 0.75 * capacity:
            return Action.C
        elif current_stock > 0.4 * capacity:
            if cooperation_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        elif current_stock > 0.1 * capacity:
            if cooperation_rate >= 0.75:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_BENEVOLENT_49(BaseStrategy):
    """
    Benevolent Adaptive Pool Conservation Strategy
    
    Prioritizes collective resource sustainability while adapting to opponent behavior.
    Cooperates by default when stock is healthy and opponents are mostly cooperative.
    Defects only when resource is depleted or exploitation is detected.
    Maintains consistent benevolent behavior even in final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        capacity = self.game_description.capacity
        n_opponents = self.game_description.n_players - 1
        cooperators_prev = history.opponent_cooperators[-1]
        defection_rate_prev = (n_opponents - cooperators_prev) / n_opponents if n_opponents > 0 else 0.0
        if current_stock >= 3 * capacity / 4:
            return Action.C
        if current_stock < capacity / 4:
            return Action.D
        if defection_rate_prev > 0.6:
            return Action.D
        if current_stock >= capacity / 2 and defection_rate_prev <= 0.4:
            return Action.C
        if current_stock >= capacity / 3 and defection_rate_prev <= 0.5:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_50(BaseStrategy):
    """
    Benevolent Adaptive Strategy for Common Pool Resource Game.
    
    Cooperates unconditionally in the first and final rounds.
    In middle rounds, monitors stock health and adapts based on opponent cooperation:
    - Cooperates if stock falls below 50% of capacity (prioritizing pool recovery)
    - Cooperates if majority of opponents cooperated (maintaining coordination)
    - Defects otherwise (protecting against systematic exploitation)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num == r - 1:
            return Action.C
        S = current_stock
        C_prev = history.opponent_cooperators[-1]
        majority_threshold = math.ceil((n - 1) / 2)
        if S <= 0.5 * capacity:
            return Action.C
        if C_prev >= majority_threshold:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_51(BaseStrategy):
    """
    Benevolent Adaptive Conservation Strategy: A phase-based resource management approach
    that adapts decisions based on stock levels, opponent cooperation, and remaining rounds.
    Prioritizes collective resource sustainability while defecting only under genuine scarcity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        stock_ratio = current_stock / capacity if capacity > 0 else 0
        rounds_remaining = r - current_round
        if current_round == 0:
            return Action.C
        opponents_cooperated = int(history.opponent_cooperators[-1])
        if stock_ratio < 0.25 and rounds_remaining >= 2:
            return Action.C
        if current_round == r - 1:
            if stock_ratio > 0.4:
                return Action.C
            elif opponents_cooperated > n / 2:
                return Action.C
            else:
                return Action.D
        if stock_ratio >= 0.5:
            return Action.C
        elif 0.3 <= stock_ratio < 0.5:
            if opponents_cooperated >= n / 2:
                return Action.C
            elif rounds_remaining >= 3:
                return Action.C
            else:
                return Action.D
        elif rounds_remaining == 1:
            return Action.D
        elif opponents_cooperated >= 3 * n / 4:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_52(BaseStrategy):
    """
    Sustainable Cooperation with Adaptive Defense strategy.
    
    Prioritizes collective sustainability over personal gain. Cooperates by default
    and only defects when cooperative effort is insufficient and the resource is
    genuinely threatened. Maintains cooperation as a signal that sustainability
    is possible, reducing cycles of mutual defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.previous_stock = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.previous_stock = current_stock
            return Action.C
        current_round = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        cooperators_last_round = history.opponent_cooperators[-1]
        coop_rate = cooperators_last_round / (n - 1) if n - 1 > 0 else 0.0
        is_stock_declining = current_stock < self.previous_stock
        self.previous_stock = current_stock
        if current_round == r - 1:
            if coop_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        if coop_rate >= 0.5:
            return Action.C
        if current_stock > 0.5 * capacity:
            return Action.C
        if is_stock_declining:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_53(BaseStrategy):
    """
    Benevolent Conditional Cooperator with Stock Sustainability.
    
    Prioritizes stock recovery and sustainable cooperation over exploitation.
    Never defects; always cooperates with varying levels of conditional reciprocity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.C
        coop_count = history.opponent_cooperators[-1]
        cooperation_rate = coop_count / (n - 1) if n > 1 else 0.0
        rounds_remaining = n_rounds - current_round
        if current_stock < capacity / 2:
            return Action.C
        if cooperation_rate > 0.5:
            return Action.C
        if cooperation_rate >= 1.0 / 3.0 and rounds_remaining > 2:
            return Action.C
        if current_stock >= capacity / 2 and cooperation_rate < 1.0 / 3.0 and (rounds_remaining == 2):
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_54(BaseStrategy):
    """
    Benevolent Conditional Cooperator with Resource Monitoring.
    
    Initiates cooperation and monitors both resource health and opponent behavior.
    Cooperates when stock is healthy and opponents cooperate, but defects defensively
    when resources are depleted or opponents persistently defect.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.previous_stock = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            self.previous_stock = current_stock
            return Action.C
        coop_count_last_round = history.opponent_cooperators[-1]
        n_opponents = n - 1
        coop_rate_last = coop_count_last_round / n_opponents if n_opponents > 0 else 0.0
        if current_round == r - 1:
            result = Action.C if current_stock > 0.1 * capacity else Action.D
            self.previous_stock = current_stock
            return result
        if coop_count_last_round == n_opponents:
            self.previous_stock = current_stock
            return Action.C
        stock_increased = current_stock > self.previous_stock
        if stock_increased and coop_rate_last >= 0.5:
            self.previous_stock = current_stock
            return Action.C
        if current_stock < 0.1 * capacity:
            self.previous_stock = current_stock
            return Action.D
        if current_round >= 3:
            recent_coop_rates = [history.opponent_cooperators[current_round - i] / n_opponents for i in range(1, 4) if current_round - i >= 0]
            if len(recent_coop_rates) >= 3 and all((rate < 0.25 for rate in recent_coop_rates)):
                self.previous_stock = current_stock
                return Action.D
        stock_healthy = current_stock >= 0.35 * capacity
        cooperation_threshold_met = coop_rate_last >= 0.4
        result = Action.C if stock_healthy and cooperation_threshold_met else Action.D
        self.previous_stock = current_stock
        return result

class Strategy_BENEVOLENT_55(BaseStrategy):
    """
    Benevolent Conditional Cooperation with Stock Monitoring.
    
    Cooperates by default, but conditionally defects based on:
    - Observed cooperation rate from opponents
    - Stock health ratio relative to capacity
    - System stress indicators
    
    Presumes cooperative intent and grants multiple chances before punishment,
    prioritizing system sustainability over individual extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        n_opponents = n_players - 1
        if n_opponents > 0:
            coop_rate = history.opponent_cooperators[-1] / n_opponents
        else:
            coop_rate = 0.0
        if capacity > 0:
            stock_ratio = current_stock / capacity
        else:
            stock_ratio = 0.0
        if stock_ratio < 0.1:
            return Action.D
        if coop_rate < 0.3 and stock_ratio < 0.35:
            return Action.D
        if stock_ratio >= 0.4:
            return Action.C
        if stock_ratio < 0.2:
            return Action.D
        if coop_rate >= 0.5 and stock_ratio >= 0.25:
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_56(BaseStrategy):
    """
    Benevolent Adaptive Cooperation Strategy for Common Pool Resource Game.
    
    Sustainability-weighted conditional cooperation that:
    - Leads with cooperation in round 1
    - Maintains cooperation early if stock is healthy (≥35% capacity)
    - Requires evidence of cooperation later (opponent rate ≥50%)
    - Defects unconditionally if stock collapses (<20% capacity)
    - Shows final-round benevolence unless stock is critically low (<50%)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.round_threshold = math.ceil(game_description.n_rounds / 2)
        self.stock_coop_threshold = 0.35 * game_description.capacity
        self.stock_critical_threshold = 0.2 * game_description.capacity
        self.stock_final_round_threshold = 0.5 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock < self.stock_critical_threshold:
            return Action.D
        if history.round_number == 0:
            return Action.C
        current_round_index = history.round_number
        final_round_index = self.game_description.n_rounds - 1
        if current_round_index == final_round_index:
            if current_stock < self.stock_final_round_threshold:
                return Action.D
            else:
                return Action.C
        if current_round_index < self.round_threshold:
            return Action.C if current_stock >= self.stock_coop_threshold else Action.D
        if current_stock >= self.stock_coop_threshold:
            n_opponents = self.game_description.n_players - 1
            if n_opponents > 0:
                opponent_cooperators_last_round = history.opponent_cooperators[-1]
                cooperation_rate = opponent_cooperators_last_round / n_opponents
                if cooperation_rate >= 0.5:
                    return Action.C
        return Action.D

class Strategy_BENEVOLENT_57(BaseStrategy):
    """
    Adaptive Benevolent Pool Management: Cooperate when stock is healthy,
    reciprocate cooperation when stock is moderate, defect when stock is critical.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        capacity = self.game_description.capacity
        n_opponents = self.game_description.n_players - 1
        if current_stock >= capacity / 2:
            return Action.C
        if current_stock >= capacity / 3:
            cooperation_rate = history.opponent_cooperators[-1] / n_opponents
            if cooperation_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_BENEVOLENT_58(BaseStrategy):
    """
    Benevolent Adaptive Stewardship Strategy for Common Pool Resource Game.
    
    This strategy prioritizes collective survival and stock restoration while maintaining
    reciprocal trust with cooperating opponents. Defection only occurs as a last resort
    when stock is clearly sustainable and opponents show no prospect of cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        stock_health_ratio = current_stock / self.game_description.capacity
        n_opponents = self.game_description.n_players - 1
        if n_opponents == 0:
            return Action.C
        opponent_cooperation_rate = history.opponent_cooperators[-1] / n_opponents
        if history.round_number == self.game_description.n_rounds - 1:
            if stock_health_ratio < 0.5:
                return Action.C
            elif stock_health_ratio >= 0.8 and opponent_cooperation_rate < 0.1:
                return Action.D
            else:
                return Action.C
        if stock_health_ratio < 0.4:
            return Action.C
        elif stock_health_ratio < 0.6:
            return Action.C
        elif opponent_cooperation_rate >= 0.5:
            return Action.C
        elif opponent_cooperation_rate >= 0.2:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_59(BaseStrategy):
    """
    Benevolent Adaptive Threshold Strategy (BAT)
    
    A cooperative strategy that prioritizes resource preservation through adaptive 
    thresholds based on observed cooperation rates and stock health.
    Starts unconditionally cooperative and maintains cooperation unless evidence shows
    it's futile or the resource is critically depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        stock_health = current_stock / capacity if capacity > 0 else 0.0
        rounds_left = r - current_round
        cooperators_prev = history.opponent_cooperators[-1]
        coop_rate = cooperators_prev / (n - 1) if n > 1 else 0.0
        if current_round == r - 1:
            if stock_health >= 0.8:
                return Action.C
        if coop_rate >= 0.5:
            return Action.C
        if stock_health >= 0.75:
            return Action.C
        if stock_health >= 0.5 and rounds_left >= 2:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_60(BaseStrategy):
    """
    Benevolent Stock-Aware Conditional Strategy.
    
    Cooperates by default while stock is healthy, tolerating moderate opponent defection.
    Prioritizes resource survival over personal gain by cooperating even at critical stock
    levels if opponents show restraint. Gradually increases defection as stock deteriorates
    or opponents defect more, without pre-emptive exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock <= 1e-09:
            return Action.D
        n_opponents = self.n_players - 1
        if n_opponents <= 0:
            return Action.C
        opponent_cooperators = history.opponent_cooperators[-1]
        opponent_defection_rate = 1.0 - opponent_cooperators / n_opponents
        critical_threshold = 0.2 * self.capacity
        healthy_threshold = 0.6 * self.capacity
        if current_stock < critical_threshold:
            stock_condition = 'critical'
        elif current_stock >= healthy_threshold:
            stock_condition = 'healthy'
        else:
            stock_condition = 'declining'
        if stock_condition == 'critical':
            if opponent_defection_rate <= 0.15:
                return Action.C
            else:
                return Action.D
        elif stock_condition == 'healthy':
            if opponent_defection_rate <= 0.4:
                return Action.C
            else:
                return Action.D
        elif opponent_defection_rate <= 0.25:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_61(BaseStrategy):
    """
    Benevolent Adaptive Pool Strategy that prioritizes resource stewardship 
    while maintaining graduated cooperative response to opponent behavior.
    Exhibits benevolence through proactive cooperation, resource stewardship,
    graduated response, and collective-first framing.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.stock_health_critical = game_description.capacity / 4
        self.stock_health_stable = game_description.capacity / 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            if current_stock > self.stock_health_stable:
                return Action.C
            else:
                return Action.D
        if current_stock <= 0:
            return Action.D
        n_opponents = n - 1
        if n_opponents <= 0:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        defectors_last_round = n_opponents - cooperators_last_round
        if defectors_last_round == n_opponents:
            return Action.D
        cooperation_rate = cooperators_last_round / n_opponents
        if cooperation_rate > 0.75:
            return Action.C
        if current_stock <= self.stock_health_critical:
            return Action.D
        if current_stock < self.stock_health_stable and cooperation_rate < 0.5:
            return Action.D
        if cooperation_rate < 0.33:
            return Action.D
        if current_stock >= self.stock_health_stable:
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_62(BaseStrategy):
    """
    Benevolent Adaptive Cooperation with Resource Stewardship.
    Cooperates by default, responding to observed cooperation rates while maintaining 
    awareness of stock health. Defects only when cooperation is demonstrably futile 
    or immediate extraction is necessary for survival.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        if history.round_number == 0:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        observed_cooperation_rate = cooperators_last_round / (n - 1) if n > 1 else 0.0
        is_final_round = history.round_number == n_rounds - 1
        if is_final_round:
            if observed_cooperation_rate >= 0.4 and current_stock >= capacity / 3:
                return Action.C
            elif observed_cooperation_rate >= 0.6:
                return Action.C
            else:
                return Action.D
        elif current_stock < capacity / 4:
            if observed_cooperation_rate >= 0.65:
                return Action.C
            else:
                return Action.D
        elif observed_cooperation_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_63(BaseStrategy):
    """
    Benevolent Adaptive Cooperation Strategy for Common Pool Resource Game.
    
    Cooperates when stock is healthy (> 40% capacity) and maintains benevolent
    commitment in first and last rounds. In depleted conditions, switches to
    conditional cooperation based on observed opponent behavior, requiring at
    least 50% opponent cooperation to continue cooperating. Defects only when
    the pool is threatened and partners have largely abandoned cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        if history.round_number == n_rounds - 1:
            return Action.C
        stock_threshold = 0.4 * capacity
        if current_stock > stock_threshold:
            return Action.C
        else:
            opponent_cooperators_last_round = history.opponent_cooperators[-1]
            n_opponents = n - 1
            if n_opponents > 0:
                opponent_cooperation_rate = opponent_cooperators_last_round / n_opponents
            else:
                opponent_cooperation_rate = 1.0
            if opponent_cooperation_rate >= 0.5:
                return Action.C
            else:
                return Action.D

class Strategy_BENEVOLENT_64(BaseStrategy):
    """
    Benevolent Adaptive Cooperation Strategy
    
    Cooperates by default, defecting only when resource depletion reaches critical
    levels, with focus on preserving the commons rather than maximizing personal extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.universal_defection_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.C
        if current_stock < 0.1:
            self.universal_defection_rounds = 0
            return Action.C
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        rounds_left = r - current_round
        last_round_cooperators = history.opponent_cooperators[-1]
        cooperation_rate = last_round_cooperators / (n - 1) if n > 1 else 0.0
        if stock_ratio >= 0.5:
            self.universal_defection_rounds = 0
            return Action.C
        elif stock_ratio >= 0.3 and cooperation_rate >= 0.4:
            self.universal_defection_rounds = 0
            return Action.C
        elif stock_ratio < 0.3 and rounds_left >= 2:
            if cooperation_rate == 0.0:
                self.universal_defection_rounds += 1
                if self.universal_defection_rounds <= 2:
                    return Action.C
                else:
                    return Action.D
            else:
                self.universal_defection_rounds = 0
                return Action.D
        else:
            self.universal_defection_rounds = 0
            return Action.C

class Strategy_BENEVOLENT_65(BaseStrategy):
    """
    Adaptive Benevolent Threshold Strategy for Common Pool Resource Game.
    Prioritizes resource sustainability while adapting to peer defection pressure.
    Cooperates when resources are healthy, conditionally cooperates under moderate stress
    based on peer behavior, and maintains strict cooperation in depleted states or final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        if current_stock == 0:
            return Action.C
        health = current_stock / self.game_description.capacity
        num_opponents = self.game_description.n_players - 1
        num_cooperators_last_round = history.opponent_cooperators[-1]
        num_defectors_last_round = num_opponents - num_cooperators_last_round
        defection_rate = num_defectors_last_round / num_opponents if num_opponents > 0 else 0.0
        if health >= 0.6:
            return Action.C
        elif 0.3 <= health < 0.6:
            if defection_rate <= 0.35:
                return Action.C
            else:
                return Action.D
        elif defection_rate <= 0.2:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_66(BaseStrategy):
    """
    Benevolent Common Pool Resource Strategy that prioritizes sustainability
    and reciprocal cooperation while resisting exploitation temptation.
    
    - Round 0: Always cooperate to establish precedent
    - Intermediate rounds: Always cooperate to maintain sustainability
    - Final round: Defect only if stock is healthy AND cooperation is minimal
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        c_prev = history.opponent_cooperators[-1]
        coop_rate = c_prev / n if n > 0 else 0.0
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        if history.round_number == n_rounds - 1:
            if stock_ratio >= 0.4 and coop_rate < 0.33:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_BENEVOLENT_67(BaseStrategy):
    """
    Cooperative Stewardship with Adaptive Thresholds.
    
    Cooperates in round 1, then adaptively cooperates or defects based on:
    - Observed opponent cooperation rate (reciprocity)
    - Current stock safety margin (resource sustainability)
    - Stock criticality thresholds
    
    In the final round, defects unless cooperation was strong and stock is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n_opponents = self.n_players - 1
        observed_cooperators_last_round = history.opponent_cooperators[-1]
        observed_coop_rate = observed_cooperators_last_round / n_opponents if n_opponents > 0 else 0.0
        stock_safety_margin = current_stock / self.capacity if self.capacity > 0 else 0.0
        is_stock_healthy = stock_safety_margin > 0.3
        is_stock_critical = stock_safety_margin < 0.15
        is_final_round = history.round_number == self.n_rounds - 1
        if is_final_round:
            if observed_coop_rate >= 0.5 and current_stock > self.capacity / 3:
                return Action.C
            else:
                return Action.D
        if is_stock_critical:
            return Action.D
        elif observed_coop_rate >= 0.5 and is_stock_healthy:
            return Action.C
        elif observed_coop_rate >= 0.5 and (not is_stock_healthy):
            return Action.D
        elif observed_coop_rate >= 0.33:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_68(BaseStrategy):
    """
    Adaptive Resource-Conscious Cooperation strategy that reciprocates based on 
    opponent cooperation rates and resource health while prioritizing stock sustainability.
    Opens with cooperation and uses a two-principle decision rule: reciprocal cooperation 
    under resource health, and resource protection as secondary priority.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        c_prev = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents <= 0 or capacity <= 0:
            return Action.C
        cooperation_rate = c_prev / n_opponents
        stock_health_ratio = current_stock / capacity
        if cooperation_rate >= 0.5 and stock_health_ratio >= 0.33:
            return Action.C
        elif stock_health_ratio > 0.5:
            return Action.C
        elif cooperation_rate < 0.25 and stock_health_ratio < 0.33:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_69(BaseStrategy):
    """
    Benevolent Adaptive Cooperation Strategy for Common Pool Resource Game.
    
    Prioritizes maintaining sustainable stock levels while defaulting to cooperation.
    Uses opponent behavior to adjust strategy only when stock faces critical depletion.
    Cooperates unconditionally in first and last rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num == n_rounds - 1:
            return Action.C
        opponents_cooperated = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents > 0:
            cooperation_rate = opponents_cooperated / n_opponents
        else:
            cooperation_rate = 0.0
        if current_stock < 2 * n:
            if cooperation_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        if cooperation_rate < 0.25:
            if current_stock > capacity / 2:
                return Action.C
            elif random.random() < 0.3:
                return Action.D
            else:
                return Action.C
        if cooperation_rate < 0.5:
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_70(BaseStrategy):
    """
    Benevolent Pool Steward Strategy for Common Pool Resource Game.
    
    Cooperates by default to maximize collective welfare and pool sustainability.
    Defects only when facing systemic exploitation or imminent pool collapse.
    Graduated response: defection triggered by clear evidence, not preemptively.
    No endgame exploitation: maintains cooperation principle in final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        n_opponents = n_players - 1
        cooperators_prev = history.opponent_cooperators[-1]
        defectors_prev = n_opponents - cooperators_prev
        defection_rate = defectors_prev / n_opponents if n_opponents > 0 else 0.0
        pool_health = current_stock / capacity if capacity > 0 else 0.0
        if defection_rate >= 0.75:
            return Action.D
        if pool_health < 0.25:
            return Action.D
        if defection_rate >= 0.4 and pool_health < 0.5:
            return Action.D
        if defection_rate >= 0.15 and pool_health < 0.35:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_71(BaseStrategy):
    """
    Benevolent Adaptive Steward Strategy for Common Pool Resource Game.
    
    Embodies benevolence through unconditional cooperation, treating the common
    pool as a shared trust and prioritizing long-term collective welfare over
    short-term individual gain. This strategy defaults to Cooperate (C) in almost
    all conditions, rejecting exploitation and maintaining stewardship of the
    resource for intergenerational equity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.sustainability_threshold = game_description.capacity * 0.55
        self.emergency_threshold = 2 * game_description.n_players
        self.collapse_threshold = game_description.capacity * 0.1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.C
        if current_stock < self.collapse_threshold:
            return Action.C
        if current_stock >= self.sustainability_threshold:
            return Action.C
        if current_stock < self.emergency_threshold:
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_72(BaseStrategy):
    """
    Benevolent Adaptive Conservation Strategy for Common Pool Resource games.
    
    Cooperates when stock is healthy and opponent defection is restrained.
    Transitions to defection under critical depletion or high opponent defection.
    Adjusts thresholds for the final round and maintains forgiveness for recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < 0.3 * self.capacity:
            return Action.D
        n_opponents = self.n_players - 1
        opponent_cooperators_last_round = history.opponent_cooperators[-1]
        opponent_defectors_last_round = n_opponents - opponent_cooperators_last_round
        opponent_defection_rate = opponent_defectors_last_round / n_opponents if n_opponents > 0 else 0.0
        if history.round_number == self.n_rounds - 1:
            if current_stock >= 0.6 * self.capacity and opponent_defection_rate <= 0.3:
                return Action.C
            else:
                return Action.D
        if current_stock >= 0.4 * self.capacity and opponent_defection_rate <= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_73(BaseStrategy):
    """
    Benevolent Stock-Preserving Strategy: Cooperate to preserve the common pool resource,
    defecting only in the final round under critical depletion (stock <= capacity/4).
    Prioritizes collective sustainability and resource recovery over individual maximization.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if current_stock == 0:
            return Action.C
        if current_stock > capacity / 2:
            return Action.C
        if round_number < n_rounds - 1:
            return Action.C
        elif current_stock <= capacity / 4:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_74(BaseStrategy):
    """
    Cooperative Guardian with Stock-Aware Adaptation.
    
    A benevolent strategy that prioritizes pool health in mid-game while adapting
    to opponent behavior. Cooperates on first round, uses stock-health-dependent
    thresholds for opponent cooperation rates in mid-game, and makes final-round
    decisions based on pool viability and observed cooperation levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.n_opponents = self.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock == 0:
            return Action.D
        stock_health = current_stock / self.capacity if self.capacity > 0 else 0
        last_round_cooperators = history.opponent_cooperators[-1]
        opponent_coop_rate = last_round_cooperators / self.n_opponents if self.n_opponents > 0 else 0
        current_round = history.round_number
        is_final_round = current_round == self.n_rounds - 1
        if last_round_cooperators == 0 and stock_health > 0.5:
            return Action.D
        if last_round_cooperators == 1 and stock_health < 0.35:
            return Action.C
        if is_final_round:
            if stock_health >= 0.4 and opponent_coop_rate >= 0.3:
                return Action.C
            else:
                return Action.D
        if stock_health < 0.25:
            if opponent_coop_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        elif stock_health < 0.45:
            if opponent_coop_rate >= 0.4:
                return Action.C
            else:
                return Action.D
        elif opponent_coop_rate >= 0.35:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_75(BaseStrategy):
    """
    Benevolent Sustainable Cooperation Strategy
    
    Maximizes long-term collective resource sustainability through unconditional 
    cooperation. The strategy prioritizes preserving the common pool, demonstrates 
    commitment to recovery, and remains forgiving of opponent defections.
    
    Core principle: Cooperate unconditionally to maintain sustainable resource levels
    and signal willingness to support collective recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.stock_health_threshold = 0.6 * game_description.capacity
        self.resilience_threshold = 0.3 * game_description.capacity
        self.reciprocation_bar = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        rounds_remaining = n_rounds - history.round_number
        if rounds_remaining == n_rounds:
            return Action.C
        if rounds_remaining == n_rounds - 1:
            return Action.C
        if current_stock > self.stock_health_threshold:
            return Action.C
        if current_stock > self.resilience_threshold:
            return Action.C
        if current_stock <= self.resilience_threshold:
            return Action.C
        if rounds_remaining == 1:
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_76(BaseStrategy):
    """
    Benevolent Adaptive Resource Conservation Strategy for Common Pool Resource Game.
    
    Prioritizes stock sustainability through cooperative play, with defensive defection
    only when opponents show weak cooperation or stock is critically depleted. Uses
    adaptive decision tree based on stock health and opponent cooperation rates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        stock_ratio = current_stock / capacity if capacity > 0 else 0
        n_opponents = n - 1
        opponent_cooperation_count = history.opponent_cooperators[-1]
        opponent_cooperation_rate = opponent_cooperation_count / n_opponents if n_opponents > 0 else 0
        rounds_remaining = r - current_round
        if rounds_remaining == 1:
            if stock_ratio >= 0.3:
                return Action.C
            else:
                return Action.D
        if stock_ratio > 0.65:
            return Action.C
        if stock_ratio > 0.45 and opponent_cooperation_rate > 0.4:
            return Action.C
        if stock_ratio < 0.15:
            if opponent_cooperation_rate > 0.75:
                return Action.C
            else:
                return Action.D
        if opponent_cooperation_rate > 0.65:
            return Action.C
        if opponent_cooperation_rate < 0.25:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_77(BaseStrategy):
    """
    Benevolent Adaptive Conservation Strategy for Common Pool Resource Game.
    
    Cooperates by default unless specific conditions trigger defection:
    - Stock endangered: always cooperate for recovery
    - Last round with uncooperative opponents: defect to extract final value
    - Persistent defection with vulnerable stock: defect for self-protection
    Otherwise: cooperate to maintain sustainable equilibrium.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        total_opponent_coop_rounds = int(np.sum(history.opponent_cooperators[:history.round_number]))
        total_opponent_opportunities = history.round_number * (n - 1)
        if total_opponent_opportunities == 0:
            opponent_coop_rate = 0.0
        else:
            opponent_coop_rate = total_opponent_coop_rounds / total_opponent_opportunities
        rounds_remaining = n_rounds - history.round_number
        if current_stock < 1.5 * n:
            return Action.C
        if rounds_remaining <= 1 and opponent_coop_rate < 0.4:
            return Action.D
        if opponent_coop_rate < 0.25 and current_stock < 0.8 * capacity:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_78(BaseStrategy):
    """
    Benevolent Adaptive Sustainability Strategy for Common Pool Resource Game.
    
    This strategy prioritizes resource sustainability while embodying benevolence through
    cooperation, patience, forgiveness, and reciprocal trust-building. It adapts decisions
    based on current stock levels and observed cooperation rates of other players.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.CRITICAL_THRESHOLD = 0.2
        self.HEALTHY_THRESHOLD = 0.6
        self.COOPERATION_RECIPROCITY_THRESHOLD = 0.4

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        stock_ratio = current_stock / self.game_description.capacity
        current_round_1indexed = history.round_number + 1
        rounds_left = self.game_description.n_rounds - current_round_1indexed
        num_opponents = self.game_description.n_players - 1
        if num_opponents > 0:
            observed_cooperation_rate = history.opponent_cooperators[-1] / num_opponents
        else:
            observed_cooperation_rate = 0.5
        if stock_ratio < self.CRITICAL_THRESHOLD:
            if observed_cooperation_rate > 0.6:
                return Action.C
            else:
                return Action.D
        elif stock_ratio < self.HEALTHY_THRESHOLD:
            return Action.C
        else:
            return Action.C

class Strategy_BENEVOLENT_79(BaseStrategy):
    """
    Benevolent Adaptive Pool Strategy: Prioritizes cooperation and collective welfare
    while conditionally punishing defection when cooperation rate is low.
    
    Decision rule:
    - Round 1: COOPERATE (benevolent opening)
    - Subsequent rounds: Adapt based on stock level, cooperation rate, and rounds remaining
    - Stock depleted: COOPERATE (signal hope for recovery)
    - Last round: DEFECT unconditionally
    - Second-to-last: DEFECT unless stock very high (≥0.75×capacity) and cooperation near-universal
    - Otherwise: COOPERATE if opponent cooperation rate ≥50%, else DEFECT
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        rounds_remaining = n_rounds - history.round_number
        n_opponents = n_players - 1
        cooperation_rate = history.opponent_cooperators[-1] / n_opponents if n_opponents > 0 else 0.0
        if current_stock == 0:
            return Action.C
        if rounds_remaining <= 1:
            return Action.D
        if rounds_remaining == 2:
            if current_stock >= 0.75 * capacity and cooperation_rate >= 0.9:
                return Action.C
            else:
                return Action.D
        if current_stock <= capacity / 3:
            if cooperation_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        elif current_stock <= capacity / 2:
            if cooperation_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        elif cooperation_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_80(BaseStrategy):
    """Benevolent Adaptive Strategy: Conditional Cooperation with Resource Stewardship
    
    Implements conditional cooperation based on opponent cooperation rates and resource health.
    Sustains the common pool through restraint when resources are depleted and reciprocation
    when cooperation is prevalent.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        stock_health = current_stock / self.game_description.capacity
        n_opponents = self.game_description.n_players - 1
        if n_opponents == 0:
            cooperation_rate = 0.0
        else:
            cooperation_rate = history.opponent_cooperators[-1] / n_opponents
        if stock_health < 0.3:
            return Action.D
        if cooperation_rate >= 0.5:
            return Action.C
        if cooperation_rate < 0.3:
            return Action.D
        if stock_health >= 0.7:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_81(BaseStrategy):
    """
    Benevolent Sustainability Strategy: Cooperates to maintain the resource for 
    long-term collective benefit. Defects only when resource depletion is imminent 
    or past recovery, prioritizing resource stability over short-term individual gain.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.critical_threshold = 0.15 * game_description.capacity
        self.sustainability_threshold = 0.35 * game_description.capacity
        self.healthy_threshold = 0.6 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock < self.critical_threshold:
            return Action.D
        elif current_stock < self.sustainability_threshold:
            n_opponents = self.game_description.n_players - 1
            if n_opponents > 0:
                c_opp = history.opponent_cooperators[-1]
                cooperation_proportion = c_opp / n_opponents
                if cooperation_proportion >= 0.5:
                    return Action.C
                else:
                    return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_BENEVOLENT_82(BaseStrategy):
    """
    Benevolent Adaptive Cooperation Strategy for Common Pool Resource Game.
    Cooperates initially, adapts based on stock levels and opponent cooperation rates,
    prioritizes sustainable outcomes and collective welfare.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_low_coop_rounds = 0
        self.last_defection_was_signal = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        n_opponents = n - 1
        if n_opponents > 0:
            opponent_coop_rate = history.opponent_cooperators[-1] / n_opponents
        else:
            opponent_coop_rate = 0.0
        if opponent_coop_rate <= 0.1:
            self.consecutive_low_coop_rounds += 1
            if self.consecutive_low_coop_rounds >= 2:
                return Action.D
        else:
            self.consecutive_low_coop_rounds = 0
        if current_stock < capacity / 3:
            self.consecutive_low_coop_rounds = 0
            self.last_defection_was_signal = False
            return Action.C
        if opponent_coop_rate > 0.5:
            self.consecutive_low_coop_rounds = 0
            self.last_defection_was_signal = False
            return Action.C
        threshold = 1.0 / (2 * n) if n > 0 else 0.0
        if current_stock >= capacity / 2 and opponent_coop_rate > threshold:
            self.consecutive_low_coop_rounds = 0
            self.last_defection_was_signal = False
            return Action.C
        if round_num == r - 1 and current_stock > capacity / 4:
            self.consecutive_low_coop_rounds = 0
            self.last_defection_was_signal = False
            return Action.C
        if current_stock < capacity / 4 and opponent_coop_rate < 0.3:
            if self.last_defection_was_signal:
                self.last_defection_was_signal = False
                return Action.C
            else:
                self.last_defection_was_signal = True
                self.consecutive_low_coop_rounds = 0
                return Action.D
        else:
            self.last_defection_was_signal = False
        if 0.3 < opponent_coop_rate <= 0.5 and 0 < round_num < r - 1:
            self.consecutive_low_coop_rounds = 0
            return Action.C
        self.consecutive_low_coop_rounds = 0
        return Action.D

class Strategy_BENEVOLENT_83(BaseStrategy):
    """
    Adaptive Stock-Responsive Benevolent Strategy
    
    Prioritizes resource sustainability and mutual benefit through:
    - Unconditional cooperation when stock is critically low
    - Probabilistic cooperation when stock is moderate
    - Conditional cooperation based on observed cooperation when stock is healthy
    - Benevolent final-round behavior to avoid exploitation
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == 0:
            return Action.C
        if current_stock < capacity / 10:
            return Action.C
        if current_stock < capacity / 3:
            return Action.C
        if current_stock < capacity / 2:
            coop_prob = 0.9
            return Action.C if random.random() < coop_prob else Action.D
        n_coop = history.opponent_cooperators[-1]
        cooperation_rate = n_coop / (n - 1) if n > 1 else 0.0
        if cooperation_rate >= 0.6:
            coop_prob = 1.0
        elif cooperation_rate >= 0.3:
            coop_prob = 0.7
        elif n_coop == 0:
            coop_prob = 0.35
        else:
            coop_prob = 0.4
        if t == r - 1:
            coop_prob = min(1.0, coop_prob + 0.15)
        return Action.C if random.random() < coop_prob else Action.D

class Strategy_BENEVOLENT_84(BaseStrategy):
    """
    Benevolent Stewardship Strategy for Common Pool Resource Game.
    
    Prioritizes environmental sustainability over individual payoff maximization.
    Cooperates based on stock health, with round-specific thresholds:
    - Round 0: Always cooperate to establish benevolent intent
    - Rounds 1 to r-2: Cooperate if stock > 0.35 × capacity (safe regeneration zone)
    - Round r-1 (final): Cooperate if stock > 0.25 × capacity (last-minute stewardship)
    
    Never conditions on opponents' actions—maintains cooperative intent regardless
    of defection by others, defecting only for resource self-protection, not spite.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.n_rounds - 1:
            if current_stock > 0.25 * self.capacity:
                return Action.C
            else:
                return Action.D
        if current_stock > 0.35 * self.capacity:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_85(BaseStrategy):
    """
    Conditional Cooperation with Stock Stewardship.
    
    A benevolent strategy that prioritizes resource sustainability and collective welfare.
    Cooperates generously when stock is abundant, maintains cooperation when stock is fragile,
    and defects only as light pressure against heavy exploitation. Includes a recovery mechanism
    to restore damaged resources through sustained cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.recovery_rounds_remaining = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        rounds_remaining = n_rounds - current_round
        if current_round == 0:
            return Action.C
        n_opponents = n_players - 1
        if n_opponents > 0:
            opponent_coop_rate = history.opponent_cooperators[-1] / n_opponents
        else:
            opponent_coop_rate = 0.0
        if current_stock < 0.25 * capacity:
            self.recovery_rounds_remaining = 2
        if self.recovery_rounds_remaining > 0:
            self.recovery_rounds_remaining -= 1
            return Action.C
        if current_round == n_rounds - 1:
            if current_stock > capacity / 2:
                return Action.C
            elif current_stock <= capacity / 2:
                if opponent_coop_rate < 0.25:
                    if current_stock > 0.001 * capacity:
                        return Action.D
                return Action.C
            return Action.C
        if current_stock > 0.75 * capacity:
            return Action.C
        if current_stock > 0.5 * capacity and opponent_coop_rate >= 0.4:
            return Action.C
        if current_stock <= 0.5 * capacity:
            return Action.C
        if rounds_remaining <= 2 and current_stock > 0.25 * capacity:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_86(BaseStrategy):
    """
    Benevolent Adaptive Common Pool Resource Strategy.
    
    Cooperates by default to stabilize the commons, adapting based on stock levels:
    - Always cooperates on first and last rounds to establish benevolent signal
    - Defects when stock is critically low (≤ 20% capacity) to minimize consumption
    - Defects in warning zone (≤ 55% capacity) only if opponent defection rate > 75%
    - Otherwise cooperates to support resource recovery and stability
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.critical_level = 0.2 * game_description.capacity
        self.warning_level = 0.55 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        last_round = self.game_description.n_rounds - 1
        if current_round == 0:
            return Action.C
        if current_round == last_round:
            return Action.C
        if current_stock <= self.critical_level:
            return Action.D
        if current_stock <= self.warning_level:
            n_opponents = self.game_description.n_players - 1
            opponent_cooperators_last_round = history.opponent_cooperators[-1]
            opponent_defectors = n_opponents - opponent_cooperators_last_round
            if n_opponents > 0:
                defection_rate = opponent_defectors / n_opponents
                if defection_rate > 0.75:
                    return Action.D
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_87(BaseStrategy):
    """
    Benevolent Adaptive Strategy for Common Pool Resource Game.
    
    Emphasizes cooperation and collective welfare while adapting to resource scarcity
    and opponent behavior. Starts with unconditional cooperation and makes adaptive
    decisions based on stock health and cooperation levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        cooperation_count_last_round = history.opponent_cooperators[-1]
        cooperation_fraction = cooperation_count_last_round / self.n_players
        stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0.0
        is_final_round = current_round == self.n_rounds - 1
        is_early_game = current_round <= self.n_rounds / 2
        if is_final_round:
            if stock_ratio >= 0.6:
                return Action.C
            elif cooperation_fraction >= 0.5:
                return Action.C
            else:
                return Action.D
        if stock_ratio >= 0.4:
            if cooperation_fraction >= 0.5:
                return Action.C
            elif is_early_game:
                return Action.C
            else:
                return Action.D
        elif cooperation_fraction >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_88(BaseStrategy):
    """
    Benevolent Stock-Responsive Cooperator strategy for the Common Pool Resource Game.
    
    Cooperates by default when conditions permit, using stock level and observed opponent
    cooperation rates to determine reciprocation. Defects only when the system signals
    unsustainability, treating defection as a collective alert rather than punishment.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n_players = self.game_description.n_players
        n_opponents = n_players - 1
        opponents_cooperated = history.opponent_cooperators[-1]
        cooperation_rate = opponents_cooperated / n_opponents if n_opponents > 0 else 0.0
        capacity = self.game_description.capacity
        critical_threshold = 0.4 * capacity
        stressed_threshold = 0.5 * capacity
        healthy_threshold = 0.65 * capacity
        current_round = history.round_number
        rounds_remaining = self.game_description.n_rounds - current_round
        if current_stock < critical_threshold:
            return Action.D
        elif current_stock >= healthy_threshold:
            if cooperation_rate >= 0.5 or current_round == 1:
                return Action.C
            else:
                return Action.D
        elif current_stock >= stressed_threshold:
            if cooperation_rate >= 0.6:
                return Action.C
            elif 0.4 <= cooperation_rate < 0.6 and rounds_remaining > 1:
                return Action.C
            else:
                return Action.D
        elif cooperation_rate >= 0.65:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_89(BaseStrategy):
    """
    Benevolent Adaptive Cooperation Strategy for Common Pool Resource Game.
    Cooperates by default, defects only when justified by resource scarcity or systematic exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        stock_health = current_stock / capacity if capacity > 0 else 0.0
        if current_round < 2:
            return Action.C
        if current_round == r - 1:
            return Action.C
        n_opponents = n - 1
        if n_opponents > 0:
            cooperators_prev = int(history.opponent_cooperators[-1])
            defection_rate = (n_opponents - cooperators_prev) / n_opponents
        else:
            defection_rate = 0.0
        rounds_remaining = r - current_round
        if stock_health > 0.9:
            return Action.C
        if stock_health < 0.15 and current_stock > 0:
            return Action.D
        if defection_rate > 0.75 and stock_health < 0.4:
            return Action.D
        if stock_health >= 0.15 and (defection_rate <= 0.6 or rounds_remaining > 2):
            return Action.C
        if stock_health >= 0.15:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_90(BaseStrategy):
    """
    Benevolent Sustainability Strategy: Stock health responsive cooperation.
    Cooperates when stock is healthy (≥50% capacity) or when stressed but other players
    show sufficient cooperation (≥65%). Defects when stock is critically low (< capacity/8)
    or cooperation is insufficient. In the final round, cooperates only if stock ≥ 60% capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        capacity = self.game_description.capacity
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number == n_rounds - 1:
            if current_stock >= 0.6 * capacity:
                return Action.C
            else:
                return Action.D
        if current_stock < capacity / 8:
            return Action.D
        stock_ratio = current_stock / capacity
        if stock_ratio >= 0.5:
            return Action.C
        else:
            opponents_cooperating = history.opponent_cooperators[-1]
            opponents_count = n_players - 1
            if opponents_count > 0:
                cooperation_ratio = opponents_cooperating / opponents_count
            else:
                cooperation_ratio = 0.0
            if cooperation_ratio >= 0.65:
                return Action.C
            else:
                return Action.D

class Strategy_BENEVOLENT_91(BaseStrategy):
    """
    Benevolent Commons Steward Strategy that prioritizes sustainable cooperation
    while maintaining conditional reciprocity and graceful degradation under stress.
    
    Decision rule:
    - First round: Always cooperate (benevolent signal)
    - Final round: Cooperate if cooperation rate ≥ 0.4, else defect
    - Middle rounds: Cooperate if cooperation rate ≥ 0.5 OR stock ≥ 0.6 × capacity, else defect
    - Critical depletion: Always defect if stock < 0.1 × capacity
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if current_stock < 0.1 * capacity:
            return Action.D
        if round_number == 0:
            return Action.C
        n_opponents = n_players - 1
        cooperators_last_round = history.opponent_cooperators[-1]
        cooperation_rate = cooperators_last_round / n_opponents if n_opponents > 0 else 0.0
        if round_number == n_rounds - 1:
            if cooperation_rate >= 0.4:
                return Action.C
            else:
                return Action.D
        if cooperation_rate >= 0.5 or current_stock >= 0.6 * capacity:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_92(BaseStrategy):
    """
    Benevolent Common Pool Resource Strategy that prioritizes resource sustainability
    while adaptively responding to opponent behavior with proportional defection.
    
    Starts cooperative, monitors opponent behavior, protects the commons through
    stock health overrides, and ends cooperatively.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_stock < capacity / 4:
            return Action.C
        if current_stock <= 2 * n:
            return Action.C
        if current_round == r - 1:
            return Action.C
        n_opponents = n - 1
        if n_opponents <= 0:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        defectors_last_round = n_opponents - cooperators_last_round
        defection_rate = defectors_last_round / n_opponents
        if defection_rate <= 0.25:
            return Action.C
        elif defection_rate <= 0.6:
            return Action.C
        elif defection_rate <= 0.9:
            return Action.D
        else:
            return Action.D

class Strategy_BENEVOLENT_93(BaseStrategy):
    """
    Benevolent Dynamic Cooperation strategy for Common Pool Resource Game.
    
    Prioritizes collective welfare by stabilizing the resource through persistent
    cooperation when conditions permit, while using defection minimally when
    cooperation patterns suggest resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        n_opponents = n_players - 1
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        cooperation_rate = prev_cooperators / n_opponents if n_opponents > 0 else 0
        if current_round >= n_rounds - 2:
            if cooperation_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        if current_stock < capacity / 3:
            return Action.C
        if cooperation_rate >= 2 / 3:
            return Action.C
        if cooperation_rate >= 1 / 3 and current_stock >= capacity / 2:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_94(BaseStrategy):
    """
    Adaptive Benevolent Pooling Strategy for Common Pool Resource Game.
    
    Cooperates in round 1, then adapts based on stock health and observed 
    cooperation rates. Prioritizes pool preservation with targeted punishment
    and endgame grace.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        stock_health = current_stock / capacity if capacity > 0 else 0
        cooperation_rate = history.opponent_cooperators[-1] / (n - 1) if n > 1 else 0
        is_final_round = history.round_number == r - 1
        if is_final_round:
            if current_stock <= 0:
                return Action.D
            elif stock_health > 0.33:
                if cooperation_rate >= 0.25:
                    return Action.C
                else:
                    return Action.D
            else:
                return Action.D
        elif stock_health <= 0.2:
            return Action.C
        elif stock_health <= 0.4:
            if cooperation_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        elif stock_health <= 0.65:
            if cooperation_rate >= 0.55:
                return Action.C
            else:
                return Action.D
        elif cooperation_rate >= 0.6:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_95(BaseStrategy):
    """
    Benevolent Adaptive Common Pool Strategy.
    
    Privileges resource preservation over individual extraction. Cooperates through
    depletion to avoid tragedy, shifts to defection only under scarcity-driven necessity,
    and maintains cooperation even when exploited for collective long-term resilience.
    
    Uses a four-tier system based on stock health ratio and observed defection rates
    to balance benevolence with survival.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        health = current_stock / self.game_description.capacity if self.game_description.capacity > 0 else 0
        n_opponents = self.game_description.n_players - 1
        cooperators_last_round = history.opponent_cooperators[-1]
        defectors_last_round = n_opponents - cooperators_last_round
        defection_rate = defectors_last_round / n_opponents if n_opponents > 0 else 0
        rounds_remaining = self.game_description.n_rounds - history.round_number
        if health >= 0.65:
            return Action.C
        if 0.45 <= health < 0.65:
            if defection_rate <= 0.35:
                return Action.C
            elif rounds_remaining <= 2:
                return Action.D
            else:
                return Action.C
        if 0.2 <= health < 0.45:
            if history.round_number == 1:
                return Action.C
            if defection_rate <= 0.5 and rounds_remaining > 3:
                return Action.C
            return Action.D
        if current_stock == 0:
            return Action.C
        if rounds_remaining == 1 and current_stock > 0:
            return Action.D
        if rounds_remaining > 1:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_96(BaseStrategy):
    """
    Benevolent Adaptive Strategy: Cooperate by default, defect only when widespread 
    defection threatens resource collapse.
    
    Prioritizes long-term resource sustainability by cooperating in healthy states,
    forgiving occasional defectors, and only punishing when both stock depletion and
    high defection rates indicate genuine collapse threat.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        stock_health = current_stock / self.game_description.capacity
        n_players = self.game_description.n_players
        n_opponents = n_players - 1
        cooperators_observed = history.opponent_cooperators[-1]
        defectors_observed = n_opponents - cooperators_observed
        defection_rate = defectors_observed / max(n_opponents, 1)
        if stock_health >= 0.6:
            return Action.C
        elif stock_health >= 0.3 and defection_rate <= 0.4:
            return Action.C
        elif stock_health < 0.3:
            return Action.C
        elif defection_rate > 0.6 and stock_health < 0.5:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_97(BaseStrategy):
    """
    Benevolent Adaptive Cooperation Strategy for Common Pool Resource Game.
    
    Maintains cooperative play unless opponent behavior or game-ending conditions
    force defection. Uses previous round's cooperation rate to assess sustainability.
    Prioritizes cooperation under most conditions while adapting to resource collapse scenarios.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        rounds_remaining = self.n_rounds - current_round
        num_cooperating_opponents = history.opponent_cooperators[-1]
        num_opponents = self.n_players - 1
        if num_opponents <= 0:
            opponent_coop_rate = 0.0
        else:
            opponent_coop_rate = num_cooperating_opponents / num_opponents
        if self.capacity > 0:
            stock_ratio = current_stock / self.capacity
        else:
            stock_ratio = 0.0
        if current_round <= 1:
            return Action.C
        if opponent_coop_rate >= 0.35:
            return Action.C
        if stock_ratio > 0.65:
            return Action.C
        if rounds_remaining >= 3 and opponent_coop_rate >= 0.15:
            return Action.C
        if rounds_remaining == 1 and opponent_coop_rate < 0.25 and (stock_ratio < 0.4):
            return Action.D
        if opponent_coop_rate < 0.1 and stock_ratio < 0.3 and (rounds_remaining <= 2):
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_98(BaseStrategy):
    """
    Benevolent Common Pool Resource Strategy that prioritizes collective welfare.
    Maintains stock through sustained cooperation, only defects when the resource
    is functionally depleted or in the final round of inevitable depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.n_players = game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        health = current_stock / self.capacity if self.capacity > 0 else 0.0
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            if health >= 0.15:
                return Action.C
            else:
                return Action.D
        if health < 0.05:
            return Action.D
        elif health < 0.25:
            return Action.C
        elif health < 0.5:
            n_opponents = self.n_players - 1
            if n_opponents > 0:
                observed_cooperators = history.opponent_cooperators[-1]
                cooperation_rate = observed_cooperators / n_opponents
                if cooperation_rate >= 0.5:
                    return Action.C
            return Action.C
        else:
            return Action.C

class Strategy_BENEVOLENT_99(BaseStrategy):
    """
    Benevolent Adaptive Cooperation with Stock Stewardship.
    
    Prioritizes mutual sustainability over individual extraction. 
    Cooperates in first/final rounds and when stock is depleted.
    Reciprocates majority cooperation; uses defection as narrow punishment.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.C
        if current_stock <= capacity / 2:
            return Action.C
        coop_count = history.opponent_cooperators[-1]
        n_opponents = n_players - 1
        if n_opponents <= 0:
            return Action.C
        observed_rate = coop_count / n_opponents
        if observed_rate >= 0.5:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_100(BaseStrategy):
    """
    Benevolent Adaptive Resource Stewardship - Cooperate by default with selective defense against resource collapse.
    
    Signals trustworthiness through consistent cooperation while maintaining a survival mechanism:
    only defects when stock health is critically compromised (< 25% of capacity) AND opponents
    are predominantly defecting (< 30% cooperation), or when stock drops below 12.5% of capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        cooperators_last_round = history.opponent_cooperators[-1]
        opponent_cooperation_rate = cooperators_last_round / (n_players - 1)
        if current_stock < capacity / 4 and opponent_cooperation_rate < 0.3:
            return Action.D
        if current_stock < capacity / 8:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_101(BaseStrategy):
    """
    Benevolent Resource Stewardship Strategy.
    
    Always cooperates (plays C) to sustain the common pool resource.
    
    Decision rule:
    - First round: cooperate unconditionally
    - Last round: cooperate unconditionally  
    - Middle rounds: cooperate unconditionally
    
    Rationale: Cooperation sustains the resource, prevents tragedy-of-the-commons collapse,
    and is never economically worse than defection given the game dynamics.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        stock_health = current_stock / self.game_description.capacity
        if stock_health >= 0.75:
            return Action.C
        if 0.4 <= stock_health < 0.75:
            n_opponents = self.game_description.n_players - 1
            if n_opponents > 0:
                cooperation_rate = history.opponent_cooperators[-1] / n_opponents
            else:
                cooperation_rate = 0.0
            if cooperation_rate >= 0.5:
                return Action.C
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_102(BaseStrategy):
    """
    Adaptive Benevolent Resource Stewardship - A stock-aware, proportionally-responsive
    strategy that prioritizes collective sustainability while defending against exploitation.
    
    Plays cooperatively early when stock is healthy, defends when stock is critical,
    and calibrates responsiveness to observed defection rates proportional to stock health.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        n_opponents = n - 1
        cooperators_last_round = history.opponent_cooperators[-1]
        defectors_last_round = n_opponents - cooperators_last_round
        d = defectors_last_round / n_opponents if n_opponents > 0 else 0.0
        critical_threshold = capacity / 4
        warning_threshold = capacity / 2
        is_critical = current_stock < critical_threshold
        is_warning = current_stock < warning_threshold
        is_healthy = not is_warning
        if round_num == n_rounds - 1:
            if is_critical:
                return Action.D
            elif d <= 0.2:
                return Action.C
            else:
                return Action.D
        if is_critical:
            return Action.D
        elif is_healthy:
            if d <= 0.33:
                return Action.C
            else:
                return Action.D
        elif d <= 0.25:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_103(BaseStrategy):
    """
    Benevolent Sustainability Strategy for Common Pool Resource Game.
    
    Cooperates initially and finally, with conditional responses based on
    resource stock levels and observed cooperation rates in mid-game.
    Shifts from generous cooperation to conditional/defecting responses
    as resource depletion threatens sustainability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.n_rounds - 1:
            return Action.C
        if current_stock == 0:
            return Action.C
        n_others = self.n_players - 1
        c = history.opponent_cooperators[-1]
        if current_stock > self.capacity * 0.6:
            threshold = n_others * 0.4
            if c >= threshold:
                return Action.C
            else:
                return Action.C if random.random() < 0.6 else Action.D
        elif current_stock > self.capacity * 0.3:
            threshold = n_others * 0.5
            if c >= threshold:
                return Action.C
            else:
                if n_others == 0:
                    return Action.C
                prob = c / n_others
                return Action.C if random.random() < prob else Action.D
        else:
            threshold = n_others * 0.7
            if c >= threshold:
                return Action.C
            else:
                return Action.D

class Strategy_BENEVOLENT_104(BaseStrategy):
    """
    Adaptive Resource Stewardship Strategy: A benevolent, sustainability-focused approach
    that cooperates by default but responds defensively to observed defection while
    prioritizing collective resource regeneration over individual exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.stock_history = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == 0:
            self.stock_history.append(current_stock)
            return Action.C
        if round_num == self.r - 1:
            self.stock_history.append(current_stock)
            return Action.D
        self.stock_history.append(current_stock)
        observed_cooperators = history.opponent_cooperators[-1]
        observed_defectors = self.n - 1 - observed_cooperators
        defection_rate = observed_defectors / (self.n - 1) if self.n > 1 else 0.0
        if current_stock < 0.2 * self.capacity and defection_rate > 0.4:
            return Action.D
        if current_stock > 0.6 * self.capacity and defection_rate < 0.25:
            return Action.C
        threshold, tolerance = self._calculate_thresholds(history, current_stock, round_num, observed_defectors)
        if current_stock > threshold and defection_rate <= tolerance:
            return Action.C
        else:
            return Action.D

    def _calculate_thresholds(self, history: PlayerHistory, current_stock: float, round_num: int, observed_defectors: int) -> tuple:
        """Calculate adaptive threshold and tolerance based on game state."""
        if round_num == 1:
            return (self.capacity * 0.4, 0.5)
        effective_consumption_rate = (self.n + observed_defectors) / (2.0 * self.n)
        stock_last_round = self.stock_history[-2] if len(self.stock_history) >= 2 else current_stock
        stock_is_shrinking = stock_last_round > current_stock
        if round_num >= self.r - 2:
            threshold = self.capacity * 0.5
            tolerance = 0.2
        elif stock_is_shrinking:
            threshold = self.capacity * max(0.2, effective_consumption_rate)
            observed_def_rate = observed_defectors / (self.n - 1) if self.n > 1 else 0.0
            tolerance = min(0.3, observed_def_rate * 0.8)
        else:
            threshold = self.capacity * 0.35
            tolerance = 0.45 + round_num / self.r * 0.1
        return (threshold, tolerance)

class Strategy_BENEVOLENT_105(BaseStrategy):
    """
    Benevolent Adaptive Strategy for Common Pool Resource Game.
    
    Cooperates by default with conditional defection only as measured warning
    when cooperation drops below 75% and resources permit. Prioritizes resource
    preservation over punishment and returns to cooperation immediately when
    cooperation improves. Always cooperates in final two rounds and under
    critical resource conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.critical_stock_threshold = 2 * self.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round >= self.n_rounds - 2:
            return Action.C
        if current_stock < self.critical_stock_threshold:
            return Action.C
        opponents_cooperated = history.opponent_cooperators[-1]
        n_opponents = self.n_players - 1
        opponent_cooperation_rate = opponents_cooperated / n_opponents if n_opponents > 0 else 1.0
        my_last_action_was_cooperate = history.my_actions[-1]
        if opponent_cooperation_rate >= 0.75:
            return Action.C
        elif current_stock > self.capacity * 0.4:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_106(BaseStrategy):
    """
    Adaptive Stock-Preservation Cooperation Strategy.
    
    Cooperates conditionally based on stock health and opponent cooperation,
    with benevolent edge case handling for resource recovery and initial trust-building.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.alpha = 0.1
        self.n_opponents = max(1, self.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock <= self.capacity / 5:
            return Action.C
        if current_stock >= 0.95 * self.capacity:
            last_cooperators = history.opponent_cooperators[-1]
            cooperation_rate = last_cooperators / self.n_opponents
            if cooperation_rate >= 0.15:
                return Action.C
            else:
                return Action.D
        stock_health_threshold = self.capacity * (0.5 + self.alpha)
        stock_healthy = current_stock > stock_health_threshold
        last_cooperators = history.opponent_cooperators[-1]
        cooperation_rate = last_cooperators / self.n_opponents
        threshold = self._get_threshold(history.round_number)
        cooperation_sufficient = cooperation_rate >= threshold
        if stock_healthy and cooperation_sufficient:
            return Action.C
        else:
            return Action.D

    def _get_threshold(self, round_num: int) -> float:
        """
        Get cooperation threshold for the given round (0-indexed).
        
        Threshold function:
        - Rounds 0 to r/3: threshold = 0.5
        - Rounds r/3 to 2r/3: threshold = 0.4
        - Rounds 2r/3 to r: threshold = 0.3
        """
        one_third = self.n_rounds / 3.0
        two_thirds = 2.0 * self.n_rounds / 3.0
        if round_num < one_third:
            return 0.5
        elif round_num < two_thirds:
            return 0.4
        else:
            return 0.3

class Strategy_BENEVOLENT_107(BaseStrategy):
    """
    Benevolent Adaptive Stock-Conscious Strategy for Common Pool Resource Game.
    
    Prioritizes collective resource preservation while reciprocating cooperation.
    Uses stock health, cooperation rates, and temporal position to make decisions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def _estimate_equilibrium_stock(self, current_stock: float, cooperation_rate: float) -> float:
        """
        Estimate stock level if observed cooperation rate persists for several rounds.
        Returns the stable stock level or final stock after simulation.
        """
        stock = current_stock
        for _ in range(min(5, self.n_rounds)):
            cooperators = int(round(cooperation_rate * self.n_players))
            defectors = self.n_players - cooperators
            consumption = cooperators * (stock / (2 * self.n_players)) + defectors * (stock / self.n_players)
            if consumption >= stock:
                stock = 0
            else:
                stock_after_consumption = stock - consumption
                growth = 2 * stock_after_consumption * (1 - stock_after_consumption / self.capacity) if self.capacity > 0 else 0
                stock = min(stock_after_consumption + growth, self.capacity)
            if stock <= 0:
                break
        return stock

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0 or current_round == 1:
            return Action.C
        if current_round == self.n_rounds - 1:
            return Action.C
        if current_round == self.n_rounds - 2:
            if current_stock > 0.3 * self.capacity:
                return Action.C
            else:
                return Action.D
        cooperators_last_round = history.opponent_cooperators[-1]
        observed_coop_rate = cooperators_last_round / (self.n_players - 1) if self.n_players > 1 else 0.0
        if current_stock < 0.25 * self.capacity:
            return Action.D
        if current_stock < 0.4 * self.capacity:
            if observed_coop_rate > 0.75:
                return Action.C
            else:
                return Action.D
        estimated_equilibrium = self._estimate_equilibrium_stock(current_stock, observed_coop_rate)
        if estimated_equilibrium < 0.35 * self.capacity:
            return Action.D
        if observed_coop_rate >= 0.7:
            return Action.C
        if observed_coop_rate < 0.3 and current_stock < 0.6 * self.capacity:
            return Action.D
        if current_stock >= 0.6 * self.capacity and observed_coop_rate >= 0.4:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_108(BaseStrategy):
    """
    Benevolent Sustainable Harvesting Strategy for Common Pool Resource Game.
    
    Cooperates by default, maintaining resource sustainability.
    Only defects in majority-defection scenarios when stock is critically low.
    Always cooperates in the final round to prevent end-game exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        if history.round_number == 0:
            return Action.C
        if history.round_number == n_rounds - 1:
            return Action.C
        threshold = capacity / 3
        if current_stock > threshold:
            return Action.C
        n_opponents = n - 1
        cooperators_last_round = history.opponent_cooperators[-1]
        defectors_last_round = n_opponents - cooperators_last_round
        if defectors_last_round >= n / 2:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_109(BaseStrategy):
    """
    Benevolent Adaptive Cooperator Strategy for Common Pool Resource Game.
    
    Defaults to cooperation when stock is abundant or in crisis, uses soft reciprocity
    (50% cooperation threshold), and avoids harsh punishment dynamics.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num == self.n_rounds - 1:
            if current_stock >= 0.6 * self.capacity:
                return Action.C
            else:
                return Action.D
        critical_threshold = 0.3 * self.capacity
        healthy_threshold = 0.7 * self.capacity
        if current_stock < critical_threshold:
            return Action.C
        if current_stock >= healthy_threshold:
            return Action.C
        n_opponents = self.n_players - 1
        if n_opponents > 0:
            cooperators_last_round = history.opponent_cooperators[-1]
            coop_rate = cooperators_last_round / n_opponents
        else:
            coop_rate = 1.0
        if coop_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_110(BaseStrategy):
    """
    Benevolent Adaptive Stock Preservation Strategy
    
    Prioritizes resource sustainability and collective welfare by defaulting to cooperation
    when extraction is sustainable. Deploys defection only as protective self-defense when
    stock is demonstrably threatened by aggregate opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        cooperators_last_round = history.opponent_cooperators[-1]
        observed_defectors = n - 1 - cooperators_last_round
        defection_rate = observed_defectors / (n - 1) if n > 1 else 0.0
        stock_health_ratio = current_stock / capacity if capacity > 0 else 0.0
        is_last_round = current_round == r - 1
        if is_last_round:
            if stock_health_ratio > 0.2:
                return Action.C
            if stock_health_ratio <= 0 or defection_rate > 0.6:
                return Action.D
        if stock_health_ratio >= 0.85:
            return Action.C
        elif stock_health_ratio >= 0.5 and defection_rate < 0.4:
            return Action.C
        elif stock_health_ratio >= 0.3 and defection_rate >= 0.4:
            return Action.D
        elif stock_health_ratio > 0:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_111(BaseStrategy):
    """
    Benevolent Adaptive Common Pool Resource Strategy
    
    Prioritizes long-term resource sustainability over short-term exploitation.
    Cooperates by default, maintains benevolent signaling through first rounds,
    and adapts defection only in specific moderate-depletion scenarios when
    cooperation rate is very low. Final round always cooperates to signal
    persistent benevolent concern.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round < 3:
            return Action.C
        if current_round == self.r - 1:
            return Action.C
        if current_stock < self.capacity / 10:
            return Action.C
        stock_health = current_stock / self.capacity if self.capacity > 0 else 0
        n_opponents = self.n - 1
        c_prev = history.opponent_cooperators[-1] if len(history.opponent_cooperators) > 0 else 0
        c_rate = c_prev / n_opponents if n_opponents > 0 else 0
        if stock_health >= 0.5:
            return Action.C
        elif stock_health >= 0.25:
            if c_rate >= 0.5:
                return Action.C
            elif c_rate >= 0.25:
                return Action.C
            else:
                return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_112(BaseStrategy):
    """
    Benevolent Reciprocal Conservation Strategy.
    
    Initiates cooperation unconditionally in round 1, conditions future cooperation on
    reciprocal willingness (0.5 threshold) and resource preservation (cooperates when
    stock ≤ capacity/2), and refuses to defect in the final round. Prioritizes resource
    recovery when stock falls below capacity/4.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if current_stock < capacity / 4:
            return Action.C
        cooperators_prev = history.opponent_cooperators[-1]
        coop_ratio = cooperators_prev / (n - 1) if n > 1 else 0.0
        if round_num == r - 1:
            return Action.C
        if coop_ratio >= 0.5:
            return Action.C
        elif current_stock <= capacity / 2:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_113(BaseStrategy):
    """
    Benevolent Stewardship Strategy: Cooperate in the sustainable regime; signal strategically in crisis.
    
    Prioritizes collective sustainability over individual short-term gain by defaulting to cooperation 
    when the commons is healthy, using defection only as a crisis signal, and refusing to exploit the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.sustainability_threshold = 0.6 * game_description.capacity
        self.critical_threshold = 0.2 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        is_final_round = history.round_number == self.game_description.n_rounds - 1
        if current_stock <= 0:
            return Action.C
        if current_stock >= self.sustainability_threshold:
            return Action.C
        if current_stock < self.critical_threshold:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        cooperation_rate = cooperators_last_round / n_opponents if n_opponents > 0 else 0.0
        if cooperation_rate >= 0.8:
            return Action.C
        if is_final_round:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_114(BaseStrategy):
    """
    Benevolent Common Pool Resource strategy that prioritizes resource preservation.
    Cooperates by default, defecting only when the resource is critically depleted
    or when opponent defection becomes endemic.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        n_opponents = n - 1
        if history.round_number == 0:
            return Action.C
        if current_stock < capacity * 0.1:
            return Action.D
        if current_stock >= capacity:
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        last_round_defectors = n_opponents - last_round_cooperators
        rounds_completed = history.round_number
        rounds_remaining = r - rounds_completed
        if rounds_remaining <= 2:
            if current_stock < capacity and n_opponents > 0:
                defection_rate_last = last_round_defectors / n_opponents
                if defection_rate_last > 0.33:
                    return Action.D
        current_round_1indexed = rounds_completed + 1
        alpha_t = current_round_1indexed / r
        theta_t = 0.5 + 0.3 * alpha_t
        defection_rate_last = last_round_defectors / n_opponents if n_opponents > 0 else 0
        if defection_rate_last > theta_t:
            return Action.D
        if last_round_defectors == 1:
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_115(BaseStrategy):
    """
    Benevolent Adaptive Common Pool Strategy that monitors stock health and 
    cooperation levels to maintain sustainable resource extraction.
    
    Starts with unconditional cooperation, adapts to stock health and defection
    rates in middle rounds, and cooperates in the final round if the resource survives.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num == r - 1:
            if current_stock > 0:
                return Action.C
            else:
                return Action.D
        k = history.opponent_cooperators[-1]
        d = (n - k) / n if n > 0 else 0
        if current_stock >= capacity * 0.6:
            if d <= 0.6:
                return Action.C
            else:
                return Action.D
        elif current_stock >= capacity * 0.3:
            return Action.C
        else:
            return Action.C

class Strategy_BENEVOLENT_116(BaseStrategy):
    """
    Adaptive Sustainable Stewardship strategy for Common Pool Resource Game.
    
    Cooperates unconditionally in round 1, then adapts based on:
    - Stock pressure (current_stock / capacity)
    - Observed cooperation rate from opponents
    
    Implements graduated response: most generous in scarcity (preserve), 
    conditional in stress, and with modest thresholds in abundance.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        capacity = self.game_description.capacity
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number
        stock_pressure = current_stock / capacity
        n_opponents = n_players - 1
        opponents_cooperated_last_round = history.opponent_cooperators[-1]
        if n_opponents > 0:
            observed_coop_rate = opponents_cooperated_last_round / n_opponents
        else:
            observed_coop_rate = 0.0
        if stock_pressure < 0.25:
            return Action.C
        elif stock_pressure < 0.5:
            if observed_coop_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        elif current_round == n_rounds - 1:
            if observed_coop_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        elif observed_coop_rate >= 0.33:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_117(BaseStrategy):
    """
    Adaptive Benevolent Common Pool Strategy - prioritizes resource sustainability 
    while reciprocating opponent cooperation with permissive thresholds.
    Cooperation dominates when stock is below regeneration safety zone (40%).
    Defection is narrowly invoked only when resource is healthy, opponents have 
    largely abandoned cooperation, and either time is scarce or defection spiral 
    needs breaking.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.defected_for_spiral_break = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        t = history.round_number
        if t == 0:
            return Action.C
        stock_ratio = current_stock / capacity
        if stock_ratio < 0.1:
            self.defected_for_spiral_break = False
            return Action.C
        opponent_coop_count = history.opponent_cooperators[-1]
        n_opponents = n - 1
        opponent_coop_rate = opponent_coop_count / n_opponents if n_opponents > 0 else 0.0
        rounds_remaining = r - t
        if stock_ratio < 0.2:
            self.defected_for_spiral_break = False
            return Action.C
        if stock_ratio < 0.4:
            self.defected_for_spiral_break = False
            return Action.C
        if opponent_coop_count == 0 and stock_ratio >= 0.5:
            if not self.defected_for_spiral_break:
                self.defected_for_spiral_break = True
                return Action.D
            else:
                self.defected_for_spiral_break = False
                return Action.C
        if rounds_remaining <= 2:
            if opponent_coop_rate < 0.25:
                self.defected_for_spiral_break = False
                return Action.D
            else:
                self.defected_for_spiral_break = False
                return Action.C
        if opponent_coop_rate >= 0.35:
            self.defected_for_spiral_break = False
            return Action.C
        elif opponent_coop_rate < 0.15:
            self.defected_for_spiral_break = False
            return Action.D
        else:
            self.defected_for_spiral_break = False
            return Action.C

class Strategy_BENEVOLENT_118(BaseStrategy):
    """
    Adaptive Benevolent Strategy for Common Pool Resource Game.
    
    Prioritizes collective resource sustainability through adaptive cooperation:
    - Cooperates when stock is healthy (above 40% capacity)
    - Supports recovery even when depleted if others cooperate
    - Defects only when stock is critically low and others defect
    - Terminal generosity: cooperates in final round if recovery is possible
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number == n_rounds - 1:
            if current_stock > capacity / 2:
                return Action.C
            else:
                return Action.D
        if current_stock < 0.05 * capacity:
            return Action.C
        if current_stock > 0.4 * capacity:
            return Action.C
        if current_stock > 0:
            cooperators_last_round = int(history.opponent_cooperators[-1])
            n_opponents = n - 1
            if n_opponents > 0:
                cooperation_rate = cooperators_last_round / n_opponents
                if cooperation_rate > 0.5:
                    return Action.C
        return Action.D

class Strategy_BENEVOLENT_119(BaseStrategy):
    """
    Adaptive Commons Stewardship strategy for Common Pool Resource Game.
    Prioritizes collective stock sustainability over immediate individual gain by:
    - Starting with unconditional cooperation
    - Maintaining stewardship across all rounds
    - Escalating to defection only when widespread defection threatens sustainability
    - Overriding with cooperation when stock reaches critical levels to enable recovery
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        healthy_threshold = 0.6 * self.capacity
        stressed_threshold = 0.3 * self.capacity
        if current_stock >= healthy_threshold:
            health_state = 'healthy'
        elif current_stock >= stressed_threshold:
            health_state = 'stressed'
        else:
            health_state = 'critical'
        n_opponents = self.n_players - 1
        cooperators_last_round = history.opponent_cooperators[-1]
        defectors_last_round = n_opponents - cooperators_last_round
        if n_opponents > 0:
            defection_rate = defectors_last_round / n_opponents
        else:
            defection_rate = 0.0
        if health_state == 'critical':
            return Action.C
        elif health_state == 'stressed':
            if defection_rate <= 0.5:
                return Action.C
            else:
                return Action.D
        elif defection_rate <= 0.33:
            return Action.C
        elif defection_rate <= 0.67:
            if random.random() < 0.7:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_BENEVOLENT_120(BaseStrategy):
    """
    Adaptive Sustainability Strategy: Threshold-based cooperation with reciprocity.
    Balances collective resource sustainability with proportional reciprocity,
    using stock health and opponent cooperation rates to adapt behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if current_stock == 0:
            return Action.D
        stock_health = current_stock / capacity if capacity > 0 else 0
        is_final_round = round_number == n_rounds - 1
        if is_final_round:
            if stock_health >= 0.5:
                return Action.C
            else:
                return Action.D
        if stock_health >= 0.6:
            return Action.C
        elif stock_health >= 0.3:
            n_opponents = n_players - 1
            if n_opponents > 0:
                opponent_coop_rate = history.opponent_cooperators[-1] / n_opponents
            else:
                opponent_coop_rate = 0
            if opponent_coop_rate >= 0.4:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_BENEVOLENT_121(BaseStrategy):
    """
    Benevolent CPR Strategy: Maintains the commons by cooperating to reach sustainable 
    equilibrium, responding to resource stress with strategic restraint rather than exploitation.
    Prioritizes collective stock sustainability over maximum individual consumption.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.previous_stock = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            self.previous_stock = current_stock
            return Action.C
        if round_num == n_rounds - 1:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        observed_cooperation_rate = cooperators_last_round / (n_players - 1) if n_players > 1 else 0.0
        stock_depletion_trend = (current_stock - self.previous_stock) / capacity if capacity > 0 else 0.0
        if observed_cooperation_rate >= 0.9:
            self.previous_stock = current_stock
            return Action.C
        if current_stock < 0.2 * capacity:
            self.previous_stock = current_stock
            return Action.D
        if observed_cooperation_rate < 0.25 and stock_depletion_trend < 0:
            self.previous_stock = current_stock
            return Action.D
        if current_stock >= 0.6 * capacity:
            self.previous_stock = current_stock
            return Action.C
        elif current_stock >= 0.4 * capacity:
            self.previous_stock = current_stock
            return Action.C
        elif observed_cooperation_rate >= 0.75:
            self.previous_stock = current_stock
            return Action.C
        else:
            self.previous_stock = current_stock
            return Action.D

class Strategy_BENEVOLENT_122(BaseStrategy):
    """
    Benevolent Adaptive Resource Conservation Strategy for Common Pool Resource Game.
    
    Prioritizes resource regeneration through cooperation, with adaptive reciprocal response
    to sustained defection only when resource is healthy. Opens with cooperation, sets
    terminal fairness (never defects in final round), and requires 65%+ sustained opponent
    defection to reciprocate while stock remains healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == 0:
            return Action.C
        stock_ratio = current_stock / capacity if capacity > 0 else 0
        if stock_ratio <= 0.3:
            return Action.C
        if stock_ratio <= 0.6:
            return Action.C
        if t == r - 1:
            return Action.C
        n_opponents = n - 1
        if n_opponents > 0:
            opponent_cooperators_prev = history.opponent_cooperators[-1]
            opponent_defection_count = n_opponents - opponent_cooperators_prev
            opponent_defection_rate = opponent_defection_count / n_opponents
        else:
            opponent_defection_rate = 0
        if opponent_defection_rate > 0.65:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_123(BaseStrategy):
    """
    Benevolent Adaptive Conservation Strategy: Cooperates by default unless stock 
    depletion or universal defection creates emergency conditions. Prioritizes collective 
    welfare through stock health monitoring and reciprocal cooperation while avoiding 
    long-term punishment cycles.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        stock_health = current_stock / self.game_description.capacity
        n_opponents = self.game_description.n_players - 1
        if n_opponents > 0:
            observed_coop_count = history.opponent_cooperators[-1]
            observed_coop_rate = observed_coop_count / n_opponents if n_opponents > 0 else 0
        else:
            observed_coop_rate = 0
        if stock_health >= 0.5:
            return Action.C
        elif stock_health >= 0.25:
            if observed_coop_rate >= 0.33:
                return Action.C
            else:
                return Action.D
        elif current_stock > 0:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_124(BaseStrategy):
    """
    Benevolent Adaptive Cooperation Strategy
    
    Cooperates by default, defecting only for defensive self-protection based on
    opponent cooperation rates and resource stress levels. Presumes good faith,
    responds to majority signals, maintains sustainability effort even under
    defection pressure, and refuses exploitative endgame defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        round_num = history.round_number
        if current_stock < 2:
            return Action.D
        if round_num == 0:
            return Action.C
        if round_num == n_rounds - 1:
            return Action.C
        coop_count = history.opponent_cooperators[-1]
        coop_rate = coop_count / (n - 1)
        if coop_rate >= 0.5:
            return Action.C
        if current_stock > capacity * 0.4:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_125(BaseStrategy):
    """
    Benevolent Adaptive Conservation Strategy that leads with cooperation,
    adapts to opponent behavior, prioritizes resource sustainability, and
    avoids endgame exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        n_opponents = n - 1
        total_defections = 0
        for round_idx in range(current_round):
            cooperators_in_round = history.opponent_cooperators[round_idx]
            defectors_in_round = n_opponents - cooperators_in_round
            total_defections += defectors_in_round
        if current_round > 0:
            defection_rate = total_defections / (n_opponents * current_round)
        else:
            defection_rate = 0.0
        defection_rate = max(0.0, min(1.0, defection_rate))
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        if current_round == r - 1:
            if stock_ratio < 0.15:
                return Action.C
            elif defection_rate <= 0.35:
                return Action.C
            else:
                return Action.D
        if stock_ratio < 0.3:
            return Action.C
        if defection_rate <= 0.25:
            return Action.C
        if defection_rate <= 0.5:
            prob_cooperate = 1.0 - defection_rate / 4.0
            return Action.C if random.random() < prob_cooperate else Action.D
        return Action.C if random.random() < 0.5 else Action.D

class Strategy_BENEVOLENT_126(BaseStrategy):
    """
    Benevolent Adaptive Common Pool Strategy that prioritizes resource sustainability.
    
    Initiates cooperation unconditionally, maintains high cooperation when stock is abundant,
    and adapts reciprocally as resources become scarce. Avoids last-round defection and
    protects the commons when stock approaches collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        opponents_cooperated = history.opponent_cooperators[-1]
        cooperation_rate = opponents_cooperated / (n_players - 1)
        stock_ratio = current_stock / capacity
        if stock_ratio >= 0.6:
            threshold = 0.3
        elif stock_ratio >= 0.3:
            threshold = 0.5
        else:
            threshold = 0.7
        if cooperation_rate >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_127(BaseStrategy):
    """
    Benevolent Adaptive Strategy for Common Pool Resource Game.
    
    Cooperates if current stock exceeds 20% of capacity, otherwise defects.
    Always cooperates in round 1 to signal benevolent intent.
    Prioritizes collective sustainability over individual payoff maximization.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.critical_threshold = 0.2 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if current_stock > self.critical_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_128(BaseStrategy):
    """
    Benevolent Adaptive Cooperation Strategy for Common Pool Resource Game.
    
    Cooperates to sustain the collective resource, defects only when:
    - Resource is critically depleted (h ≤ 0.20)
    - Cooperation has collapsed (p < 0.33)
    - Final round with weak prior cooperation (t == r and p < 0.70)
    - Resource is mid-depleted and majority defecting (h < 0.50 and p < 0.50)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        cooperators_prev = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators = cooperators_prev + (1 if my_prev_action else 0)
        p = total_cooperators / n
        h = current_stock / capacity
        t = history.round_number
        is_final_round = t == n_rounds - 1
        if h <= 0.2:
            return Action.D
        if p < 0.33:
            return Action.D
        if is_final_round and p < 0.7:
            return Action.D
        if h < 0.5 and p < 0.5:
            return Action.D
        return Action.C

class Strategy_SELFISH_33(BaseStrategy):
    """
    Stock-Aware Adaptive Extraction Strategy for Common Pool Resource Game.
    
    Implements a three-phase strategy that:
    - Opening phase: Aggressively extracts from high-stock pools
    - Middle phase: Adapts to stock trajectory (rising/stable/falling)
    - Endgame phase: Maximizes final extraction with minimal cooperation
    - Edge case: Cooperates when stock is critically depleted
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.prev_stock = game_description.capacity
        self.stock_history = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        n_rounds = self.n_rounds
        capacity = self.capacity
        n_players = self.n_players
        if current_stock <= 2 * n_players:
            return Action.C
        opening_end = math.ceil(n_rounds / 3)
        middle_end = 2 * math.ceil(n_rounds / 3)
        rounds_remaining = n_rounds - round_num
        if round_num > 0:
            if current_stock > self.prev_stock:
                stock_trajectory = 1
            elif current_stock == self.prev_stock:
                stock_trajectory = 0
            else:
                stock_trajectory = -1
        else:
            stock_trajectory = 0
        self.prev_stock = current_stock
        if round_num >= middle_end:
            if rounds_remaining == 1:
                return Action.D
            if rounds_remaining <= 4:
                return Action.D
            if rounds_remaining > 4:
                if current_stock < capacity * 0.4:
                    if random.random() < 0.5:
                        return Action.C
                    else:
                        return Action.D
                else:
                    return Action.D
        elif round_num >= opening_end:
            if round_num > 0:
                n_opponents = n_players - 1
                if n_opponents > 0:
                    p_coop = history.opponent_cooperators[-1] / n_opponents
                else:
                    p_coop = 0.0
            else:
                p_coop = 0.5
            if stock_trajectory == 1:
                return Action.D
            elif stock_trajectory == 0:
                if current_stock > capacity * 0.5:
                    return Action.D
                else:
                    return Action.C
            else:
                coop_prob = min(0.8, current_stock / capacity if capacity > 0 else 0.0)
                if p_coop > 0.5:
                    coop_prob = min(1.0, coop_prob + 0.15)
                elif p_coop < 0.3:
                    coop_prob = max(0.0, coop_prob - 0.2)
                if random.random() < coop_prob:
                    return Action.C
                else:
                    return Action.D
        elif current_stock > capacity * 0.65:
            return Action.D
        elif current_stock > capacity * 0.35:
            if random.random() < 0.7:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_SELFISH_34(BaseStrategy):
    """
    Adaptive Selfish Resource Extraction Strategy.
    
    Defects early and late to maximize immediate extraction, but cooperates
    when the pool is critically depleted to allow recovery. Conditional
    cooperation in mid-game based on observed opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if self.n_rounds == 1:
            return Action.D
        if current_round == 0:
            return Action.D
        if current_round >= self.n_rounds - 2:
            return Action.D
        stock_high_threshold = 0.6 * self.capacity
        stock_low_threshold = 0.25 * self.capacity
        if current_stock <= stock_low_threshold:
            return Action.C
        if current_stock > stock_high_threshold:
            return Action.D
        n_opponents = self.n_players - 1
        if n_opponents == 0:
            return Action.D
        observed_cooperators = history.opponent_cooperators[-1]
        cooperation_threshold = (self.n_players - 1) ** 2 / (2 * self.n_players)
        if observed_cooperators > cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_35(BaseStrategy):
    """
    Adaptive Depletion Exploitation Strategy for Common Pool Resource Game.
    
    Defects in round 1 to maximize immediate payoff.
    In middle rounds, adapts based on stock health and opponent cooperation.
    Defects unconditionally in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == n_rounds - 1:
            return Action.D
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        n_opponents = n_players - 1
        observed_cooperators = history.opponent_cooperators[-1]
        observed_defectors = n_opponents - observed_cooperators
        if n_opponents > 0:
            opponent_cooperation_rate = observed_cooperators / n_opponents
        else:
            opponent_cooperation_rate = 0.0
        if stock_ratio < 0.3:
            return Action.C
        elif stock_ratio >= 0.7 and opponent_cooperation_rate < 0.4:
            return Action.D
        elif stock_ratio >= 0.5 and opponent_cooperation_rate >= 0.65:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_36(BaseStrategy):
    """
    Selfish Adaptive Pool Defense Strategy.
    
    Maintains state tracking of opponent defection patterns and adapts decisions based on:
    - Remaining rounds in the game
    - Current stock level relative to capacity
    - Observed defection rate of opponents
    
    Core principle: Defect in final/late rounds and when stock is depleted or opponents defect.
    Cooperate only when stock is robust and most opponents cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        rounds_remaining = n_rounds - round_number - 1
        if round_number == 0:
            return Action.D
        if rounds_remaining <= 2:
            return Action.D
        if current_stock < 0.25 * capacity:
            return Action.D
        n_opponents = n - 1
        cooperators_last_round = history.opponent_cooperators[-1]
        defectors_last_round = n_opponents - cooperators_last_round
        defection_rate = defectors_last_round / n_opponents if n_opponents > 0 else 0.0
        if defection_rate > 0.5:
            return Action.D
        if current_stock > 0.6 * capacity:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_37(BaseStrategy):
    """
    Adaptive Threshold Defection Strategy for Common Pool Resource Game.
    Uses stock levels and observed opponent cooperation rates to decide between
    cooperation and defection, with special logic for endgame rounds.
    Exploits the commons when stock is abundant or opponents are defecting,
    but cooperates strategically when the pool is sustainable and others cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        r = self.n_rounds
        capacity = self.capacity
        round_num = history.round_number
        if round_num == 0:
            if n <= 6:
                return Action.C
            else:
                return Action.D
        if current_stock < 1e-09:
            return Action.D
        c_obs = int(history.opponent_cooperators[-1])
        defection_count = n - 1 - c_obs
        defection_rate = defection_count / max(1, n - 1)
        if round_num == r - 1:
            return Action.D
        if round_num == r - 2:
            if current_stock > capacity * 0.6 and defection_rate < 0.5:
                return Action.C
            else:
                return Action.D
        stock_ratio = current_stock / max(1, capacity)
        if c_obs == n - 1:
            if stock_ratio < 0.4:
                return Action.D
            else:
                return Action.C
        if c_obs == 0:
            return Action.D
        if stock_ratio < 0.3:
            return Action.D
        threshold_defection_rate = 0.5 - 0.15 * stock_ratio
        if stock_ratio > 0.75 and defection_rate <= threshold_defection_rate:
            return Action.C
        if stock_ratio >= 0.5 and defection_rate <= 0.35:
            return Action.C
        return Action.D

class Strategy_SELFISH_38(BaseStrategy):
    """
    Selfish Adaptive Depletion Strategy: Defect by default, but modulate based on 
    observed opponent cooperation rates and stock abundance. Cooperate only when 
    opponents show strong commitment (≥75% cooperation) AND stock is abundant 
    (≥80% of capacity). Always defect in first and final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        opponent_cooperators = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        if n_opponents > 0:
            cooperation_rate = opponent_cooperators / n_opponents
        else:
            cooperation_rate = 0.0
        high_opponent_cooperation = cooperation_rate >= 0.75
        stock_abundant = current_stock >= 0.8 * self.game_description.capacity
        if high_opponent_cooperation and stock_abundant:
            return Action.C
        return Action.D

class Strategy_SELFISH_39(BaseStrategy):
    """
    Selfish Resource-Conscious Strategy for Common Pool Resource Game.
    
    Balances extraction against longevity by defecting when stock is healthy,
    cooperating only when forced by resource depletion or when heavy opponent
    defection threatens sustainability. Unconditionally defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == n_rounds - 1:
            return Action.D
        rounds_remaining = n_rounds - current_round
        opponent_cooperation_count = history.opponent_cooperators[-1]
        if current_stock <= capacity / 3.0:
            return Action.C
        if opponent_cooperation_count == 0 and rounds_remaining <= 2:
            return Action.D
        if current_stock > capacity / 2.0:
            return Action.D
        if opponent_cooperation_count > (n_players - 1) / 2.0:
            return Action.D
        return Action.C

class Strategy_SELFISH_40(BaseStrategy):
    """
    Adaptive Defection with Stock-Preservation Floor.
    
    Defects aggressively when stock is abundant, but cooperates defensively
    when stock approaches critical levels or opponents show low cooperation.
    Final round always defects. Adjusts thresholds in late game for urgency.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number == n_rounds - 1:
            return Action.D
        total_opponent_cooperators = np.sum(history.opponent_cooperators[:round_number])
        total_opponent_actions = (n_players - 1) * round_number
        if total_opponent_actions > 0:
            cooperation_rate = total_opponent_cooperators / total_opponent_actions
        else:
            cooperation_rate = 0.0
        threshold_adjustment = 0.0
        if round_number > n_rounds - 3:
            threshold_adjustment = 0.05 * (n_rounds - 1 - round_number)
        stock_65_threshold = 0.65 * capacity - threshold_adjustment * capacity
        stock_75_threshold = 0.75 * capacity - threshold_adjustment * capacity
        stock_30_threshold = 0.3 * capacity - threshold_adjustment * capacity
        if current_stock >= stock_65_threshold and cooperation_rate >= 0.4:
            return Action.D
        elif current_stock >= stock_75_threshold:
            return Action.D
        elif current_stock < stock_30_threshold:
            return Action.C
        elif cooperation_rate < 0.3:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_41(BaseStrategy):
    """
    Stock-Threshold Defection Strategy: Defect by default, cooperate only when
    stock drops critically low or when many opponents defected and stock is threatened.
    Always defect in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == n_rounds - 1:
            return Action.D
        observed_cooperators_last_round = history.opponent_cooperators[-1]
        n_opponents = n - 1
        observed_defectors = n_opponents - observed_cooperators_last_round
        min_stock_threshold = capacity * 0.25
        high_defection_threshold = n * 0.6
        if current_stock < min_stock_threshold:
            return Action.C
        elif observed_defectors > high_defection_threshold and current_stock < capacity * 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_42(BaseStrategy):
    """
    Threshold-Exploitation Strategy for Common Pool Resource Game.
    
    Dynamically adjusts cooperation threshold based on remaining rounds and current stock level.
    Defects when stock exceeds threshold (to maximize immediate consumption),
    cooperates when stock falls below threshold (to enable regeneration).
    Time-dependent thresholds reflect declining patience as rounds dwindle.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_stock < 2 * self.n_players:
            return Action.C
        if current_round == 0:
            return Action.D
        if current_round == self.n_rounds - 1:
            if current_stock < self.capacity / 10:
                return Action.C
            else:
                return Action.D
        remaining_rounds = self.n_rounds - current_round
        if remaining_rounds <= 2:
            s_critical = self.capacity / 6
        elif remaining_rounds <= self.n_rounds / 2:
            s_critical = self.capacity / 4
        else:
            s_critical = self.capacity / 3
        if current_stock > s_critical:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_43(BaseStrategy):
    """
    Adaptive Exploitation with Resource Safeguarding.
    
    Balances immediate extraction with resource conservation through:
    - Unconditional cooperation when stock is critically low
    - Rapid-decline detection to prevent resource collapse
    - Endgame defection when future payoffs are negligible
    - Opponent cooperation monitoring to detect sustained exploitation opportunities
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.previous_stock = float(game_description.capacity)
        self.cooperation_ma = 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        rounds_remaining = r - round_num
        if round_num == 0:
            self.previous_stock = current_stock
            return Action.D
        if round_num == r - 1:
            self.previous_stock = current_stock
            return Action.D
        if round_num == r - 2:
            self.previous_stock = current_stock
            if current_stock > capacity * 0.4:
                return Action.D
            else:
                return Action.C
        if current_stock < 0.05 * capacity:
            self.previous_stock = current_stock
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents > 0:
            cooperation_rate = last_round_cooperators / n_opponents
        else:
            cooperation_rate = 0.5
        self.cooperation_ma = 0.6 * cooperation_rate + 0.4 * self.cooperation_ma
        if current_stock < capacity * 0.35:
            self.previous_stock = current_stock
            return Action.C
        if current_stock < self.previous_stock - 0.1 * capacity:
            self.previous_stock = current_stock
            return Action.C
        if rounds_remaining == 1:
            self.previous_stock = current_stock
            return Action.C
        if rounds_remaining <= 2 and self.cooperation_ma < 0.6:
            self.previous_stock = current_stock
            return Action.C
        if rounds_remaining > (n - 1) / 2.0 and last_round_cooperators < 2:
            self.previous_stock = current_stock
            return Action.C
        self.previous_stock = current_stock
        return Action.D

class Strategy_SELFISH_44(BaseStrategy):
    """
    Threshold-based Common Pool Resource strategy.
    
    Defects when stock > 55% of capacity or in the final round.
    Cooperates otherwise, with crash recovery below 10% capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.defect_threshold = 0.55 * self.capacity
        self.crash_threshold = 0.1 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        is_final_round = current_round == self.n_rounds - 1
        if is_final_round:
            return Action.D
        if current_stock <= self.crash_threshold:
            return Action.C
        if current_stock > self.defect_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_45(BaseStrategy):
    """
    Selfish Adaptive Extraction Strategy with phase detection and defection scaling.
    
    Employs edge case heuristics, exploitation logic based on opponent cooperation rates,
    and stock-dependent decision-making to balance immediate extraction with future sustainability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        rounds_left = self.r - current_round
        if current_round == 0:
            return Action.D
        if current_round == self.r - 1:
            return Action.D
        if current_round == self.r - 2:
            if current_stock > 0.6 * self.capacity:
                return Action.D
            else:
                return Action.C
        if current_stock < 0.15 * self.capacity:
            return Action.D
        if rounds_left < self.n / 4:
            if current_stock > 0.5 * self.capacity:
                return Action.D
            else:
                return Action.C
        opponent_cooperators = history.opponent_cooperators[-1]
        max_cooperators = self.n - 1
        cooperation_rate = opponent_cooperators / max_cooperators if max_cooperators > 0 else 0.0
        if cooperation_rate > 0.8:
            return Action.C
        if cooperation_rate < 0.4:
            return Action.D
        stock_sustainable = current_stock > 0.4 * self.capacity
        future_horizon_viable = rounds_left >= self.n / 2
        est_stock = current_stock
        c_total = opponent_cooperators + 1
        d_total = self.n - c_total
        projection_depth = min(3, rounds_left)
        for _ in range(projection_depth):
            if est_stock <= 0:
                break
            c_consumption = c_total * (est_stock / (2.0 * self.n))
            d_consumption = d_total * (est_stock / self.n)
            total_consumption = c_consumption + d_consumption
            stock_after_consumption = max(0, est_stock - total_consumption)
            if stock_after_consumption > 0 and self.capacity > 0:
                growth = 2.0 * stock_after_consumption * (1.0 - stock_after_consumption / self.capacity)
                est_stock = min(stock_after_consumption + growth, self.capacity)
            else:
                est_stock = stock_after_consumption
            if est_stock < 0.25 * self.capacity:
                break
        future_viable = est_stock > 0.3 * self.capacity
        if stock_sustainable and future_horizon_viable and future_viable:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_46(BaseStrategy):
    """
    Adaptive Thresholded Defection Strategy for Common Pool Resource Game.
    
    Combines terminal defection, stock depletion sensitivity, opponent defection tracking,
    and opportunistic exploitation when resources are abundant and opponents cooperative.
    Uses a dynamic threshold that becomes more permissive of opponent defection over time,
    implementing a credible threat of terminal defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        n_opponents = self.n_players - 1
        opponent_cooperators_last = history.opponent_cooperators[-1]
        observed_defectors = n_opponents - opponent_cooperators_last
        defection_ratio = observed_defectors / n_opponents if n_opponents > 0 else 0.0
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_round == self.n_rounds - 2:
            if current_stock > 0.3 * self.capacity:
                return Action.D
            else:
                return Action.C
        if current_stock < 0.4 * self.capacity:
            return Action.D
        defection_threshold = 0.25 + 0.35 * (self.n_rounds - current_round) / self.n_rounds
        if defection_ratio > defection_threshold:
            return Action.D
        if current_stock >= 0.8 * self.capacity and defection_ratio < 0.3:
            return Action.D
        return Action.C

class Strategy_SELFISH_47(BaseStrategy):
    """
    Adaptive resource exploitation strategy that maximizes personal payoff by:
    - Exploiting high-stock states when cooperation is observed
    - Defecting opportunistically in early/last rounds when stock is ample
    - Conserving resources through cooperation when stock is depleted or future rounds matter
    - Conditioning defection on observed cooperation to balance exploitation with sustainability
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_stock <= 3 * self.n_players:
            return Action.C
        if current_round == 0:
            return Action.D
        rounds_remaining = self.n_rounds - current_round
        if rounds_remaining == 1:
            if current_stock > 0.5 * self.capacity:
                return Action.D
            else:
                return Action.C
        stock_threshold = self.capacity * (0.5 + 0.25 * min(rounds_remaining / self.n_rounds, 1.0))
        if current_stock > stock_threshold:
            cooperators_last_round = history.opponent_cooperators[-1]
            if rounds_remaining == 1 or cooperators_last_round >= self.n_players / 2:
                return Action.D
        return Action.C

class Strategy_SELFISH_48(BaseStrategy):
    """
    Adaptive Threshold Strategy with Temporal Decay for Common Pool Resource Game.
    
    Cooperates in round 1, adapts based on stock level and observed cooperation
    in rounds 2 to r-1, and defects unconditionally in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        if game_description.capacity < 3 * game_description.n_players:
            self.cooperation_threshold = 1
            self.stock_defection_threshold = game_description.capacity / 4
        else:
            self.cooperation_threshold = math.ceil(game_description.n_players / 2)
            self.stock_defection_threshold = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num == r - 1:
            return Action.D
        if current_stock == 0:
            return Action.D
        k = history.opponent_cooperators[-1]
        if self.stock_defection_threshold is not None:
            if current_stock < self.stock_defection_threshold:
                return Action.D
        if current_stock >= capacity / 2 and k >= self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_49(BaseStrategy):
    """
    Adaptive Defection with Stock Preservation strategy.
    Tracks opponent cooperation rates and adapts between defection and cooperation
    based on stock health and opponent behavior patterns.
    Defects in first and last rounds, preserves stock when critical, and exploits
    cooperative populations when stock is healthy.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        n_opponents = n - 1
        coop_count = history.opponent_cooperators[-1]
        coop_rate = coop_count / n_opponents if n_opponents > 0 else 0.0
        critical_threshold = 2.5 * n
        if current_stock < critical_threshold:
            return Action.C
        if coop_rate >= 0.7:
            return Action.D
        elif coop_rate <= 0.3:
            return Action.D
        elif current_stock >= 0.5 * capacity:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_50(BaseStrategy):
    """
    Greedy Preservation Strategy for Common Pool Resource Game.
    
    Core decision rule:
    - Last round: Always defect (maximize immediate payoff)
    - Stock ≤ 2n: Cooperate (preserve resource from collapse)
    - Stock > 2n: Defect (exploit abundant stock)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        if history.round_number == r - 1:
            return Action.D
        if current_stock <= 2 * n:
            return Action.C
        return Action.D

class Strategy_SELFISH_51(BaseStrategy):
    """
    Adaptive Threshold Defection with Collapse Prevention.
    
    Uses a dynamic stock threshold that increases with rounds remaining.
    Early rounds favor cooperation to preserve stock for future exploitation;
    late rounds become aggressively defection-biased. Responds to actual stock
    observations with automatic recovery cooperation when stock is depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        rounds_remaining = r - current_round
        if rounds_remaining == 0:
            return Action.D
        baseline = capacity / (2 * n)
        threshold = baseline * (1 + rounds_remaining / r)
        if current_stock > threshold:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_52(BaseStrategy):
    """
    Pragmatic Defection with Stock Preservation strategy for Common Pool Resource Game.
    
    Employs dynamic thresholds to balance short-term payoff maximization with long-term
    stock sustainability. Defects greedily when stock is abundant and opponents aren't
    coordinating defection. Shifts to cooperation defensively when stock depletes,
    opponents show coordinated defection, or few rounds remain. Always defects in the
    final round since future payoffs are irrelevant.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.stock_collapsed = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if self.stock_collapsed:
            return Action.C
        if current_stock < 1.0:
            self.stock_collapsed = True
            return Action.C
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        remaining_rounds = self.n_rounds - current_round
        if remaining_rounds <= 2:
            aggressive_threshold = 2 * self.n_players
        else:
            aggressive_threshold = 3 * self.n_players
        opponent_cooperators_count = history.opponent_cooperators[-1]
        opponent_defectors = self.n_players - 1 - opponent_cooperators_count
        if current_stock <= 2 * self.n_players:
            return Action.C
        elif opponent_defectors > (self.n_players - 1) / 2:
            if current_stock < 3 * self.n_players:
                return Action.C
            else:
                return Action.D
        elif current_stock < aggressive_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_53(BaseStrategy):
    """
    Selfish Adaptive Stock-Tracking Strategy: Defect aggressively when stock is high
    and sustainable future payoffs are assured; cooperate when stock regeneration is threatened.
    
    Core logic:
    - Final round: Always defect (no future rounds)
    - Other rounds: Defect if stock > capacity/2 (safe threshold where regeneration peaks),
      otherwise cooperate to preserve future stock regeneration.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == n_rounds - 1:
            return Action.D
        safe_threshold = capacity / 2
        if current_stock <= safe_threshold:
            return Action.C
        return Action.D

class Strategy_SELFISH_54(BaseStrategy):
    """
    Adaptive Exploitation with Stock-Conditional Defection.
    
    Core logic: Defect when stock is abundant and can recover; cooperate to preserve 
    stock when depletion threatens. Always defect in the final round. Adaptation based 
    on observed cooperation rate when stock is at risk.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_stock <= 0:
            return Action.C
        threshold = capacity / 2
        if current_stock > threshold:
            return Action.D
        else:
            observed_cooperation = history.opponent_cooperators[-1]
            cooperation_threshold = (n - 1) / 2
            if observed_cooperation > cooperation_threshold:
                return Action.D
            else:
                return Action.C

class Strategy_SELFISH_55(BaseStrategy):
    """
    Selfish Adaptive Stock-Dependent Strategy for Common Pool Resource Game.
    
    Maximizes immediate payoff by playing Defect when stock is healthy,
    switches to Cooperate when stock is depleted to enable recovery,
    and always defects in the last round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.base_threshold = self.capacity / 3
        self.low_cooperation_threshold = self.capacity / 4

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number == self.n_rounds - 1:
            return Action.D
        cooperation_rate_low = history.opponent_cooperators[-1] < self.n_players / 4
        if cooperation_rate_low:
            threshold = self.low_cooperation_threshold
        else:
            threshold = self.base_threshold
        if current_stock < threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_56(BaseStrategy):
    """
    Adaptive Exploitation with Stock Preservation strategy for Common Pool Resource Game.
    
    Round 1: Always cooperate to maximize stock growth.
    Subsequent rounds: Adaptively cooperate or defect based on:
    - Critical stock levels (S ≤ 2.5n): cooperate to rebuild
    - Endgame (m ≤ 2 rounds left): defect to maximize extraction
    - Stock abundance (S ≥ 1.5×capacity): defect safely
    - Opponent behavior (defection pressure P): respond strategically
    - Special edge case: final round with weak cooperation (P < 0.3): defect
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        t = history.round_number + 1
        m = r - t + 1
        S = current_stock
        capacity = self.game_description.capacity
        k = history.opponent_cooperators[-1]
        P = (n - k) / n if n > 0 else 0.0
        if S <= 2.5 * n:
            return Action.C
        if t == r and P < 0.3:
            return Action.D
        if m <= 2:
            return Action.D
        if S >= 1.5 * capacity:
            return Action.D
        if P > 0.5:
            return Action.C
        if P < 0.3:
            return Action.D
        return Action.C

class Strategy_SELFISH_57(BaseStrategy):
    """
    Selfish Adaptive Stock-Guard Strategy for Common Pool Resource Game.
    Cooperates strategically when stock is healthy and opponents are cooperative,
    but defects when stock depletes, opponents defect overwhelmingly, or endgame approaches.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        n_opponents = n_players - 1
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        last_opponent_defectors = n_opponents - last_opponent_cooperators
        opp_defect_rate = last_opponent_defectors / n_opponents if n_opponents > 0 else 0
        stock_level_ratio = current_stock / capacity if capacity > 0 else 0
        if stock_level_ratio < 0.2:
            return Action.D
        if opp_defect_rate > 0.6:
            return Action.D
        if stock_level_ratio > 0.5 and opp_defect_rate < 0.4:
            return Action.C
        if stock_level_ratio > 0.35 and opp_defect_rate <= 0.6:
            return Action.C
        return Action.D

class Strategy_SELFISH_58(BaseStrategy):
    """
    Adaptive Threshold Strategy with Endgame Defection.
    
    Cooperates strategically based on stock levels and observed cooperation rates,
    but switches to defection in final two rounds and when stock is critically depleted.
    Balances immediate payoff extraction with maintaining stock for future rounds,
    while monitoring opponent cooperation to detect exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        t = history.round_number
        if t >= r - 1:
            return Action.D
        if current_stock < 2 * n:
            return Action.D
        k = history.opponent_cooperators[-1]
        if k < n / 2 and current_stock < capacity * 0.6:
            return Action.D
        threshold = capacity * (0.5 + 0.3 * k / n)
        if current_stock < threshold:
            return Action.D
        return Action.C

class Strategy_SELFISH_59(BaseStrategy):
    """
    Selfish Threshold Strategy with Dynamic Adaptation.
    
    Cooperates when stock is scarce or trending poorly; defects when abundant.
    Uses time-decay to increase defection pressure near game end.
    Adapts thresholds based on opponent defection rates and stock trends.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == 0:
            return Action.D
        if round_num == self.r - 1:
            return Action.D
        if current_stock < self.n:
            return Action.C
        if current_stock <= 0:
            return Action.C
        if round_num <= 2 / 3 * self.r:
            f_t = 1.0
        else:
            f_t = 0.5
        g_history = self._calculate_g_history(history)
        threshold = 2 / 3 * self.capacity * f_t * g_history
        other_defection_rate = self._calculate_defection_rate(history)
        if other_defection_rate > 0.6:
            threshold *= 0.9
        defection_consumption = current_stock / self.n
        stock_after_defection = current_stock - defection_consumption
        if stock_after_defection < self.capacity / 4:
            return Action.C
        if current_stock <= threshold:
            return Action.C
        else:
            return Action.D

    def _calculate_g_history(self, history: PlayerHistory) -> float:
        """
        Calculate stock-trend sensitivity g(history).
        Inferred from recent payoff trends (proxy for stock availability).
        
        Returns:
        - 0.7 if stock declining
        - 1.0 if stock stable or growing
        - 1.2 if stock recently recovered
        """
        round_num = history.round_number
        if round_num < 2:
            return 1.0
        last_payoff = history.my_payoffs[-1]
        prev_payoff = history.my_payoffs[-2]
        if prev_payoff == 0:
            return 1.0
        payoff_ratio = last_payoff / prev_payoff
        if payoff_ratio > 1.05:
            return 1.2
        elif payoff_ratio < 0.95:
            return 0.7
        else:
            return 1.0

    def _calculate_defection_rate(self, history: PlayerHistory) -> float:
        """
        Calculate the defection rate of opponents over recent rounds.
        Uses last 2 rounds (or fewer if not available).
        
        Returns: defection_rate in [0, 1]
        """
        round_num = history.round_number
        if round_num < 1:
            return 0.0
        recent_rounds = min(2, round_num)
        recent_cooperators = history.opponent_cooperators[-recent_rounds:]
        total_cooperators = np.sum(recent_cooperators)
        total_opponent_slots = (self.n - 1) * recent_rounds
        if total_opponent_slots == 0:
            return 0.0
        avg_cooperation_rate = total_cooperators / total_opponent_slots
        defection_rate = 1.0 - avg_cooperation_rate
        return defection_rate

class Strategy_SELFISH_60(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Employs dynamic decision-making based on stock health:
    - Final round: unconditional defection
    - Critical stock (<20%): cooperate to prevent collapse
    - Abundant stock (>75%): defect to exploit growth plateau
    - Moderate stock (20-75%): defect to free-ride or race to extraction
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        health = current_stock / capacity if capacity > 0 else 0.0
        if health < 0.2:
            return Action.C
        return Action.D

class Strategy_SELFISH_61(BaseStrategy):
    """
    Adaptive Depletion Strategy for Common Pool Resource Game.
    
    Defects opportunistically in early rounds, during resource collapse, in final rounds,
    or when opponents show low cooperation. Cooperates conditionally in middle rounds only
    if stock is robust (>0.6×capacity) and most opponents cooperate (>0.65 rate).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == 0:
            return Action.D
        if round_num == self.n_rounds - 1:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.D
        if round_num == self.n_rounds - 2:
            stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0
            opponent_coop_count = history.opponent_cooperators[-1]
            n_opponents = self.n_players - 1
            coop_rate = opponent_coop_count / n_opponents if n_opponents > 0 else 0
            if stock_ratio > 0.6 and coop_rate > 0.65:
                return Action.C
            else:
                return Action.D
        stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0
        if stock_ratio < 0.4:
            return Action.D
        opponent_coop_count = history.opponent_cooperators[-1]
        n_opponents = self.n_players - 1
        coop_rate = opponent_coop_count / n_opponents if n_opponents > 0 else 0
        if coop_rate < 0.5:
            return Action.D
        return Action.C

class Strategy_SELFISH_62(BaseStrategy):
    """
    Threshold Defection with Stock Monitoring.
    
    Exploits high stock levels through defection until stock drops below
    70% of capacity, then switches to cooperation to preserve the resource.
    In the final round, defects unconditionally to maximize end-game payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.threshold = self.capacity * 0.7

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == 0:
            return Action.D
        if round_num == self.n_rounds - 1:
            return Action.D if current_stock > 0 else Action.C
        if current_stock >= self.threshold:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_63(BaseStrategy):
    """
    Selfish Threshold Strategy: Defect when safe, cooperate only when necessary to prevent
    stock collapse. Prioritizes immediate extraction while using cooperation tactically to
    prevent complete resource depletion that would damage future extraction opportunities.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.aggressive_mode = False
        self.last_stock = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_t = history.round_number
        if round_t == r - 1:
            return Action.D
        if round_t == 0:
            self.last_stock = current_stock
            return Action.D
        if self.last_stock > 0 and current_stock < 0.5 * self.last_stock:
            self.aggressive_mode = True
        self.last_stock = current_stock
        if current_stock < capacity / 6:
            return Action.C
        rounds_remaining = r - round_t
        if rounds_remaining > 0:
            discount_factor = 1 + rounds_remaining / r
        else:
            discount_factor = 1.0
        if self.aggressive_mode:
            critical_level = capacity / 2.5 / discount_factor
        else:
            critical_level = capacity / 3 / discount_factor
        if current_stock >= critical_level:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_64(BaseStrategy):
    """
    Adaptive Greedy Preservation Strategy for Common Pool Resource Game.
    
    Defects aggressively while stock is abundant relative to time horizon.
    Shifts to cooperation only when stock trajectory threatens future payoff opportunities.
    Monitors opponent behavior to identify doomed-commons scenarios where defection is unavoidable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        if current_stock <= 0:
            return Action.D
        rounds_remaining = r - current_round
        sustainability_ratio = current_stock / (capacity * rounds_remaining / r)
        if sustainability_ratio < 0.5:
            return Action.C
        k = history.opponent_cooperators[-1]
        if rounds_remaining <= 2:
            threshold = 0.7
        else:
            threshold = 1.0
        if sustainability_ratio < threshold:
            return Action.C
        if k < (n - 1) / 3:
            return Action.D
        return Action.D

class Strategy_SELFISH_65(BaseStrategy):
    """
    Stock-Health Conditional Cooperation Strategy for Common Pool Resource Game.
    
    Defects in last round, when stock is critically depleted, or when opponents
    predominantly defect. Cooperates in early rounds with healthy stock and when
    cooperation is widespread. Uses stock thresholds (40% and 50% of capacity) to
    modulate behavior based on sustainability prospects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.t_defect = self.capacity * 0.4
        self.t_cooperate = self.capacity * 0.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        r_remaining = self.n_rounds - current_round
        if r_remaining == 0:
            return Action.D
        if current_stock <= self.t_defect:
            return Action.D
        if current_stock > self.t_cooperate and r_remaining >= 2:
            if current_round == 0:
                return Action.C
            else:
                n_opponents = self.n_players - 1
                if n_opponents > 0:
                    coop_rate = history.opponent_cooperators[-1] / n_opponents
                    if coop_rate >= 0.5:
                        return Action.C
                    else:
                        return Action.D
                else:
                    return Action.C
        if self.t_defect < current_stock <= self.t_cooperate and r_remaining >= 2:
            if current_round == 0:
                return Action.C
            else:
                n_opponents = self.n_players - 1
                if n_opponents > 0:
                    coop_rate = history.opponent_cooperators[-1] / n_opponents
                    if coop_rate >= 0.66:
                        return Action.C
                    else:
                        return Action.D
                else:
                    return Action.C
        if r_remaining == 1 and current_stock > self.t_defect:
            return Action.D
        return Action.D

class Strategy_SELFISH_66(BaseStrategy):
    """
    Adaptive Defection with Preservation Threshold
    
    Uses dynamic decision-making based on stock levels, rounds remaining,
    and opponent cooperation rates to balance short-term exploitation with
    long-term resource preservation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.D
        t = history.round_number
        rounds_remaining = self.n_rounds - t
        m = history.opponent_cooperators[-1]
        S = current_stock
        if S < 2.5 * self.n:
            return Action.C
        if rounds_remaining <= 2:
            return Action.D
        if m >= (self.n - 1) * 0.65 and S > 0.4 * self.capacity:
            return Action.D
        if m <= (self.n - 1) * 0.25 and S < 0.5 * self.capacity:
            return Action.D
        if S < 0.35 * self.capacity:
            return Action.C
        return Action.D

class Strategy_SELFISH_67(BaseStrategy):
    """
    Selfish defection with conditional cooperation.
    
    Defects by default. Cooperates only when:
    1. Sufficient opponent cooperation (≥⌈n/2⌉ in previous round)
    2. Stock health (≥ capacity/2)
    3. Sufficient future rounds (≥3 remaining)
    
    With stricter thresholds in final rounds and complete collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        if current_stock <= 2 * n:
            return Action.D
        rounds_remaining = r - current_round
        opponent_cooperators_last_round = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if rounds_remaining <= 3:
            cooperation_threshold = math.ceil(2 * n / 3)
            stock_threshold = capacity / 1.5
        else:
            cooperation_threshold = math.ceil(n / 2)
            stock_threshold = capacity / 2
        if opponent_cooperators_last_round == n_opponents:
            if current_stock >= capacity / 2 and rounds_remaining >= 3:
                return Action.C
        condition_1_cooperation = opponent_cooperators_last_round >= cooperation_threshold
        condition_2_stock_health = current_stock >= stock_threshold
        condition_3_temporal = rounds_remaining >= 3
        if condition_1_cooperation and condition_2_stock_health and condition_3_temporal:
            return Action.C
        return Action.D

class Strategy_SELFISH_68(BaseStrategy):
    """
    Adaptive Stock-Preservation Defection Strategy for Common Pool Resource Game.
    
    Defects when stock is sufficiently high to sustain future defection.
    Cooperates only when defection would trigger dangerous stock collapse.
    Threshold dynamically adjusts based on remaining rounds and capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def _calculate_threshold(self, current_round: int) -> float:
        """
        Calculate dynamic threshold for decision rule.
        
        current_round: 0-indexed round number
        Returns: stock threshold (cooperate if stock <= threshold)
        """
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        t = current_round + 1
        if t == r:
            return 0.25 * capacity
        if r <= 0:
            base_value = 0.35
        else:
            base_value = 0.35 + 0.15 * (r - t) / r
        return capacity * max(0.25, base_value)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        capacity = self.game_description.capacity
        if current_stock < 0.2 * capacity:
            return Action.C
        if current_stock >= capacity:
            return Action.D
        threshold = self._calculate_threshold(current_round)
        if current_stock <= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_69(BaseStrategy):
    """
    Greedy Threshold Exploitation with Depleted-Stock Recovery.
    
    Defects by default to maximize immediate extraction. Cooperates only when:
    1. Stock falls below critical threshold (2n) — enters recovery mode
    2. Few opponents cooperate (≤ n/3) — detects stock collapse and preemptively cooperates
    3. Final round — always defects for maximum last-round extraction
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.in_recovery = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        threshold = 2 * n
        if history.round_number == 0:
            return Action.D
        if history.round_number == r - 1:
            return Action.D
        if self.in_recovery:
            if current_stock < threshold:
                return Action.C
            else:
                self.in_recovery = False
        if current_stock < threshold:
            self.in_recovery = True
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        cooperation_threshold = n // 3
        if cooperators_last_round <= cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_70(BaseStrategy):
    """
    Adaptive Stock Threshold Strategy for Common Pool Resource Game.
    
    Maintains a dynamic cooperation threshold based on remaining game duration.
    Defects when stock is healthy, cooperates only to prevent imminent collapse.
    Adapts thresholds based on observed opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold_multiplier = 1.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        remaining_rounds = r - round_number
        if remaining_rounds == 1:
            return Action.D
        if round_number >= 1:
            prev_cooperators = history.opponent_cooperators[-1]
            if prev_cooperators < n / 4:
                self.threshold_multiplier *= 0.9
            self.threshold_multiplier = max(self.threshold_multiplier, 0.5)
        threshold = capacity * (1 - 1 / (remaining_rounds + 2)) * self.threshold_multiplier
        if current_stock < capacity * 0.05:
            return Action.C
        if current_stock >= capacity * 0.98:
            if remaining_rounds <= 2:
                return Action.C
            return Action.D
        if current_stock < threshold:
            return Action.C
        elif current_stock > 1.2 * threshold:
            return Action.D
        else:
            stock_trend = self._calculate_stock_trend(history)
            if stock_trend < 0:
                return Action.C
            else:
                return Action.D

    def _calculate_stock_trend(self, history: PlayerHistory) -> float:
        """
        Infer stock trend from recent payoff history.
        Positive payoff change suggests stock growth; negative suggests depletion.
        """
        if len(history.my_payoffs) < 2:
            return 0.0
        recent_payoff = history.my_payoffs[-1]
        previous_payoff = history.my_payoffs[-2]
        return recent_payoff - previous_payoff

class Strategy_SELFISH_71(BaseStrategy):
    """Selfish Threshold Strategy with Stock Monitoring for Common Pool Resource Game.
    
    Maximizes personal cumulative payoff by:
    - Cooperating in round 1 to explore opponent strategies
    - Cooperating when stock is critically low to prevent collapse
    - Defecting in final round if stock is healthy
    - Defecting mid-game when stock is abundant and opponents are cooperative
    - Adapting to observable stock levels and opponent cooperation rates
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        if current_stock <= 2 * n:
            return Action.C
        cooperators_last = history.opponent_cooperators[-1]
        is_final_round = history.round_number == r - 1
        if is_final_round:
            if current_stock >= n:
                return Action.D
            else:
                return Action.C
        if current_stock > 2.0 / 3.0 * capacity:
            if cooperators_last >= (n - 1) / 2.0:
                return Action.D
        return Action.C

class Strategy_SELFISH_72(BaseStrategy):
    """
    Selfish Adaptive Depletion Strategy for Common Pool Resource Game.
    
    Defaults to DEFECT to maximize immediate payoffs (S/n vs S/2n), but cooperates
    strategically when stock drops below a critical threshold to ensure future
    exploitation opportunities. Unconditionally defects in final two rounds when
    stock recovery is impossible.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        rounds_remaining = self.n_rounds - history.round_number
        if rounds_remaining <= 2:
            return Action.D
        critical_threshold = self.capacity * (0.4 + 0.1 * rounds_remaining / self.n_rounds)
        if current_stock < critical_threshold:
            return Action.C
        return Action.D

class Strategy_SELFISH_73(BaseStrategy):
    """
    Adaptive Stock-Monitoring Defection Strategy.
    
    Tracks stock level and prior cooperation to decide between defection (higher immediate payoff)
    and cooperation (resource preservation). Prioritizes exploitation when stock is healthy,
    switches to cooperation as a damage-control mechanism when stock is depleted.
    
    Decision rule:
    - First round: Defect to test opponents and secure maximum immediate payoff
    - Last round: Defect regardless (no future rounds, stock fate irrelevant)
    - stock > 60% capacity: Defect (exploit while regeneration absorbs consumption)
    - 30% < stock ≤ 60%: Monitor cooperation rate of previous round
      - High cooperation (>70%): Defect (exploit willing cooperators)
      - Low cooperation (≤70%): Cooperate (stabilize against defection spiral)
    - stock ≤ 30% capacity: Cooperate (minimize consumption, allow recovery)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.D
        if round_num == n_rounds - 1:
            return Action.D
        if current_stock > capacity * 0.6:
            return Action.D
        elif current_stock > capacity * 0.3:
            cooperators_prev = history.opponent_cooperators[-1]
            cooperation_rate = cooperators_prev / n_players
            if cooperation_rate > 0.7:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_SELFISH_74(BaseStrategy):
    """
    Stock-Level Adaptive Exploitation strategy for Common Pool Resource game.
    
    Exploits the defection advantage when stock is abundant and regeneration is strong,
    while conserving the resource when it approaches dangerous depletion zones.
    Adapts to opponent cooperation levels in intermediate stock ranges.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_stock == 0:
            return Action.C
        if current_round == 0:
            return Action.D
        if current_round == r - 2:
            if current_stock > 0.35 * capacity:
                return Action.D
            else:
                return Action.C
        if current_stock > 0.65 * capacity:
            return Action.D
        if current_stock <= 0.25 * capacity:
            return Action.C
        n_opponents = n - 1
        if n_opponents > 0:
            opponent_coop_count = history.opponent_cooperators[-1]
            opponent_coop_rate = opponent_coop_count / n_opponents
            if opponent_coop_rate >= 0.5:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_SELFISH_75(BaseStrategy):
    """
    Adaptive Threshold Strategy with Endgame Exploitation.
    
    Defects when the resource is healthy (stock > capacity/3) to maximize per-round payoff.
    Cooperates when the resource is threatened (stock ≤ capacity/3) to preserve extraction 
    opportunities in future rounds. Always defects in the final round since future payoffs 
    have zero value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.safety_threshold = game_description.capacity / 3
        self.urgency_threshold = game_description.capacity / 6

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        is_final_round = current_round == self.game_description.n_rounds - 1
        if is_final_round:
            return Action.D
        if current_stock > self.safety_threshold:
            return Action.D
        return Action.C

class Strategy_SELFISH_76(BaseStrategy):
    """
    Adaptive Threshold Defection Strategy for Common Pool Resource Game.
    
    Employs a four-factor decision rule that balances immediate extraction
    with resource sustainability. Defects in the final round, under stock
    depletion, when peer defection is rampant, when resources are abundant,
    or when future rounds are minimal. Otherwise cooperates to sustain the pool.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        if current_stock < 3 * self.n:
            return Action.D
        rounds_remaining = self.n_rounds - current_round - 1
        if rounds_remaining <= 1:
            return Action.D
        cooperators_last_round = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        defectors_last_round = n_opponents - cooperators_last_round
        if self.n <= 3:
            defector_threshold = self.n // 2 + 1
        else:
            defector_threshold = math.ceil(2 * self.n / 3)
        if defectors_last_round > defector_threshold:
            return Action.D
        if current_stock > self.capacity * 0.85:
            return Action.D
        return Action.C

class Strategy_SELFISH_77(BaseStrategy):
    """
    Conditional cooperation strategy for Common Pool Resource Game.
    
    Decision logic:
    - Last round: Always defect (no future rounds)
    - Stock ≤ capacity/3: Defect (resource depleted)
    - High stock ratio (>0.8): Defect (minimal growth room)
    - Otherwise: Compare value of cooperation vs defection considering:
      * Immediate payoff
      * Expected stock recovery over remaining rounds
      * Observed/estimated opponent cooperation
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = float(game_description.capacity)
        self.stock_threshold = self.capacity / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_stock <= self.stock_threshold:
            return Action.D
        remaining_rounds = self.r - current_round
        if current_round == 0:
            estimated_cooperators = (self.n - 1) / 2.0
        else:
            estimated_cooperators = float(history.opponent_cooperators[-1])
        stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0.0
        if stock_ratio > 0.8:
            return Action.D
        if stock_ratio < 0.1:
            return Action.D
        value_c = self._calculate_value(current_stock, estimated_cooperators, remaining_rounds, play_cooperate=True)
        value_d = self._calculate_value(current_stock, estimated_cooperators, remaining_rounds, play_cooperate=False)
        return Action.D if value_d > value_c else Action.C

    def _calculate_value(self, stock: float, opponent_cooperators: float, remaining_rounds: int, play_cooperate: bool) -> float:
        """
        Calculate expected value of playing C or D given estimated opponent behavior.
        """
        if play_cooperate:
            my_immediate = stock / (2.0 * self.n)
            my_consumption = stock / (2.0 * self.n)
        else:
            my_immediate = stock / self.n
            my_consumption = stock / self.n
        num_opponents = self.n - 1
        opponent_defectors = num_opponents - opponent_cooperators
        opponent_consumption = opponent_cooperators * (stock / (2.0 * self.n)) + opponent_defectors * (stock / self.n)
        total_consumption = my_consumption + opponent_consumption
        stock_after = max(0.0, stock - total_consumption)
        if self.capacity > 0:
            growth = 2.0 * stock_after * (1.0 - stock_after / self.capacity)
        else:
            growth = 0.0
        stock_next = min(stock_after + growth, self.capacity)
        if remaining_rounds > 1:
            future_component = stock_next * (remaining_rounds - 1.0) / remaining_rounds / (2.0 * self.n)
        else:
            future_component = 0.0
        total_value = my_immediate + future_component
        return total_value

class Strategy_SELFISH_78(BaseStrategy):
    """
    Adaptive Harvest with Endgame Defection.
    
    Cooperates in early/mid rounds when stock health >= 65% AND opponent 
    cooperation rate >= 40%. Defects unconditionally in the final round 
    to maximize endgame payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == n_rounds - 1:
            return Action.D
        health = current_stock / capacity
        if current_round == 0:
            c_observed = n / 2
        else:
            c_observed = float(history.opponent_cooperators[-1])
        coop_rate = c_observed / (n - 1)
        if health >= 0.65 and coop_rate >= 0.4:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_79(BaseStrategy):
    """
    Greedy Sustainability Strategy: Exploits abundant stock (above threshold) via defection,
    switches to cooperation when stock depletes to preserve the resource, with late-game intensification.
    Reacts only to physical stock state, ignoring opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.base_threshold = max(2 * self.n, 0.4 * self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.r - 1:
            return Action.D
        remaining_rounds = self.r - current_round
        if remaining_rounds <= 1:
            sustainability_threshold = 0
        elif remaining_rounds <= 2:
            sustainability_threshold = self.base_threshold * 1.5
        else:
            sustainability_threshold = self.base_threshold
        if current_stock > sustainability_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_80(BaseStrategy):
    """
    Adaptive Stock-Contingent Strategy for Common Pool Resource Game.
    
    Cooperates in round 1 to establish baseline, defects in final round for maximum extraction.
    In middle rounds, adapts based on stock criticality, opponent defection rates, and exploitation opportunities.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num == r - 1:
            return Action.D
        if current_stock <= 0.25 * capacity:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        num_opponents = n - 1
        if num_opponents > 0:
            defectors_last_round = num_opponents - cooperators_last_round
            defection_rate = defectors_last_round / num_opponents
            cooperation_rate = 1.0 - defection_rate
        else:
            cooperation_rate = 0.0
        if n == 2:
            exploit_threshold = 1.0
        else:
            exploit_threshold = 0.6
        if cooperation_rate > exploit_threshold and current_stock > 0.5 * capacity:
            return Action.D
        return Action.C

class Strategy_SELFISH_81(BaseStrategy):
    """
    Conditional defection strategy for common pool resource game.
    
    Defects to maximize immediate payoff (stock/n > stock/2n) except when:
    1. In the final round (always defect for terminal value extraction)
    2. Stock drops to survival threshold (stock ≤ 2n)
    3. Projected post-consumption stock would deplete below 15% of capacity
    
    In these cases, cooperates to preserve the resource or signal sustainability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        if current_stock <= 2 * n:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        defectors_last_round = n - 1 - cooperators_last_round
        consumption_per_defector = current_stock / n if n > 0 else 0.0
        consumption_per_cooperator = current_stock / (2 * n) if n > 0 else 0.0
        projected_consumption = defectors_last_round * consumption_per_defector + cooperators_last_round * consumption_per_cooperator
        remaining_after_projection = current_stock - projected_consumption
        if capacity > 0:
            depletion_ratio = remaining_after_projection / capacity
            if depletion_ratio < 0.15:
                return Action.C
        return Action.D

class Strategy_SELFISH_82(BaseStrategy):
    """
    Adaptive stock-based strategy that defects when the common pool is abundant,
    cooperates when critical, and responds to opponent behavior in moderate conditions.
    Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        h = current_stock / self.game_description.capacity
        if h >= 0.65:
            return Action.D
        if h < 0.3:
            return Action.C
        n_opponents = self.game_description.n_players - 1
        c_prev = history.opponent_cooperators[-1]
        if c_prev / n_opponents >= 0.5:
            return Action.D
        return Action.C

class Strategy_SELFISH_83(BaseStrategy):
    """
    Adaptive Depletion Strategy for Common Pool Resource Game.
    
    Cooperates only when three conditions hold simultaneously:
    1. Stock level is healthy (>= capacity/2)
    2. At least 50% of opponents cooperated in previous round
    3. More than 2 rounds remain (not in endgame)
    
    Otherwise defects to maximize immediate payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        if history.round_number == 0:
            return Action.D
        rounds_remaining = n_rounds - history.round_number - 1
        if rounds_remaining <= 2:
            return Action.D
        if current_stock < capacity / 2:
            if current_stock < capacity / 4:
                return Action.D
            else:
                cooperators_observed = history.opponent_cooperators[-1]
                threshold = math.ceil((n_players - 1) / 2)
                if cooperators_observed >= threshold:
                    return Action.C
                else:
                    return Action.D
        else:
            cooperators_observed = history.opponent_cooperators[-1]
            threshold = math.ceil((n_players - 1) / 2)
            if cooperators_observed >= threshold:
                return Action.C
            else:
                return Action.D

class Strategy_SELFISH_84(BaseStrategy):
    """
    Selfish Adaptive Pool Strategy - prioritizes immediate consumption while
    exploiting cooperative opponents. Cooperates only when stock is critically
    depleted or when few rounds remain, forcing regeneration before terminal collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == r - 1:
            return Action.D
        if current_stock < capacity / n:
            return Action.C
        if current_stock > 2 * capacity / 3:
            return Action.D
        rounds_remaining = r - round_num
        if round_num == 0:
            cooperation_rate = 0.5
        else:
            observed_cooperators = history.opponent_cooperators[-1]
            cooperation_rate = observed_cooperators / max(n - 1, 1.0)
        if rounds_remaining <= 2:
            return Action.C
        if cooperation_rate > 0.65:
            return Action.D
        return Action.C

class Strategy_SELFISH_85(BaseStrategy):
    """
    Selfish Resource Defense Strategy.
    
    Defects by default; cooperates only when strategically necessary to preserve 
    personal future payoffs. Uses stock depletion level and observed cooperator 
    count to determine when cooperation is worthwhile.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        remaining_rounds = r - history.round_number
        if remaining_rounds == 1:
            return Action.D
        stock_ratio = current_stock / capacity if capacity > 0 else 0
        if stock_ratio < 0.25:
            return Action.D
        observed_cooperators = 0
        if history.round_number > 0:
            observed_cooperators = int(history.opponent_cooperators[-1])
        cooperation_ratio = observed_cooperators / (n - 1) if n > 1 else 0
        if stock_ratio < 0.45 and cooperation_ratio < 0.4:
            return Action.D
        if stock_ratio >= 0.65:
            return Action.D
        if 0.45 <= stock_ratio < 0.65 and cooperation_ratio >= 0.4:
            return Action.C
        return Action.D

class Strategy_SELFISH_86(BaseStrategy):
    """
    Adaptive Threshold Defection Strategy
    
    Defects when stock is abundant (above recovery threshold), cooperates when 
    stock is critically depleted. Always defects on the final round to maximize 
    immediate payoff with no future consequences.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.recovery_threshold = game_description.capacity / (2 * game_description.n_players)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock > self.recovery_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_87(BaseStrategy):
    """
    Selfish Threshold-Adaptive Strategy.
    
    Defects by default to maximize immediate payoff (S/n vs S/(2n)).
    Cooperates only when:
    - Current round is the first round (round 0), OR
    - Current stock ≤ capacity/3 (threshold to prevent catastrophic collapse)
    Always defects in the final round to capture maximum value with no future consequences.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        threshold = self.game_description.capacity / 3
        if current_stock <= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_88(BaseStrategy):
    """
    Adaptive Depletion Strategy: Cooperate when stock is healthy and opponents cooperate,
    but defect in the endgame, when stock is depleted, or when cooperation is rare.
    Ruthlessly exploits remaining value as rounds dwindle.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        rounds_left = self.n_rounds - current_round
        if current_round == 0:
            if self.n_rounds > 2 and current_stock >= self.capacity * 0.99:
                return Action.C
            else:
                return Action.D
        if rounds_left <= 1:
            return Action.D
        n_cooperators_last_round = int(history.opponent_cooperators[-1])
        n_opponents = self.n_players - 1
        cooperation_rate = n_cooperators_last_round / n_opponents if n_opponents > 0 else 0.0
        threshold_stock = 0.6 * self.capacity
        threshold_cooperation = 0.35
        threshold_rounds = self.n_rounds / 2
        if rounds_left <= threshold_rounds:
            return Action.D
        if current_stock < threshold_stock:
            return Action.D
        if cooperation_rate < threshold_cooperation:
            return Action.D
        return Action.C

class Strategy_SELFISH_89(BaseStrategy):
    """
    Selfish Threshold-Based Adaptation Strategy for Common Pool Resource Game.
    
    Dynamically selects cooperation or defection based on:
    - Proximity to final round (always defect near end)
    - Current stock level (cooperate if critically depleted)
    - Observed cooperation rate of others (exploit cooperation, match defection)
    - Stock/cooperation combination (cooperate in uncertain mixed states)
    
    Default: DEFECT when no rule applies.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == n_rounds - 1:
            return Action.D
        if current_round >= n_rounds - 2:
            return Action.D
        if current_stock < capacity / 4:
            return Action.C
        if current_round == 0:
            return Action.D
        opponent_coops_prev = history.opponent_cooperators[-1]
        n_opponents = n_players - 1
        c_prev = opponent_coops_prev / n_opponents if n_opponents > 0 else 0.0
        if c_prev >= 0.6:
            return Action.D
        if c_prev < 0.4 and current_stock > capacity / 2:
            return Action.D
        if 0.4 <= c_prev <= 0.6 and capacity / 4 <= current_stock <= capacity / 2:
            return Action.C
        return Action.D

class Strategy_SELFISH_90(BaseStrategy):
    """
    Adaptive Stock-Responsive Defection Strategy: Exploits cooperative opponents 
    when stock is abundant, switches to cooperation only when depletion threatens 
    future returns. Prioritizes immediate extraction while maintaining minimal stock 
    stability. Defects in endgame rounds regardless of stock level.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round >= self.n_rounds - 2:
            return Action.D
        stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0
        if stock_ratio < 0.25:
            return Action.C
        if stock_ratio >= 0.6:
            return Action.D
        observed_cooperators = history.opponent_cooperators[-1]
        threshold = math.ceil(0.5 * (self.n_players - 1))
        if observed_cooperators >= threshold:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_91(BaseStrategy):
    """
    Threshold-Based Conditional Defection strategy for Common Pool Resource Game.
    
    Implements selfish resource extraction with conditional cooperation:
    - Always defects in round 1 to maximize initial payoff
    - In subsequent rounds, defects unless the pool is recovering and enough
      opponents are cooperating to make recovery likely
    - Detects defection cascades and joins them to avoid futile cooperation
    - Exploits aggressively in final rounds
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        n = game_description.n_players
        capacity = game_description.capacity
        self.defection_trigger = 0.3 * (n - 1)
        self.critical_stock = capacity / 4.0
        self.recovery_point = capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        round_num = history.round_number
        if round_num == 0:
            return Action.D
        rounds_remaining = n_rounds - round_num - 1
        opponents_cooperated_last_round = history.opponent_cooperators[-1]
        opponents_defected_last_round = n - 1 - opponents_cooperated_last_round
        if current_stock <= self.critical_stock:
            return Action.D
        if rounds_remaining <= 1:
            return Action.D
        if opponents_defected_last_round >= self.defection_trigger:
            return Action.D
        if current_stock < self.recovery_point and opponents_cooperated_last_round >= 0.5 * (n - 1):
            return Action.C
        return Action.D

class Strategy_SELFISH_92(BaseStrategy):
    """
    Selfish Adaptive Defection with Stock-Contingent Cooperation.
    
    Defects by default. Cooperates only when stock is critically depleted
    (< 35% capacity) AND sufficient opponents are cooperating (>= 60% of opponents).
    Locks into permanent defection if cooperation threshold is consistently unmet.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold = math.ceil((game_description.n_players - 1) * 0.6)
        self.consecutive_threshold_failures = 0
        self.locked_defection = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == n_rounds - 1:
            return Action.D
        if self.locked_defection:
            return Action.D
        if current_stock < capacity * 0.15:
            return Action.D
        if current_stock >= capacity * 0.9:
            return Action.D
        if current_stock < capacity * 0.35:
            observed_cooperators = int(history.opponent_cooperators[-1])
            if observed_cooperators >= self.cooperation_threshold:
                self.consecutive_threshold_failures = 0
                return Action.C
            else:
                self.consecutive_threshold_failures += 1
                if self.consecutive_threshold_failures >= 3:
                    self.locked_defection = True
                return Action.D
        return Action.D

class Strategy_SELFISH_93(BaseStrategy):
    """
    Adaptive Defection with Stock-Contingent Cooperation.
    
    This strategy prioritizes individual payoffs while avoiding resource collapse.
    It defects by default when stock is high, but cooperates to preserve the resource
    base when stock approaches critical thresholds or when opponents demonstrate
    sustained cooperation that can be exploited in future rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.est_coop_rate = 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        current_round = history.round_number
        rounds_remaining = r - current_round
        s_sustain = capacity * (1.0 - 1.0 / math.sqrt(2))
        if current_round == 0:
            return Action.D
        current_round_cooperators = history.opponent_cooperators[-1]
        if n > 1:
            self.est_coop_rate = 0.7 * (current_round_cooperators / (n - 1)) + 0.3 * self.est_coop_rate
        if current_stock <= 0:
            return Action.C
        if self.est_coop_rate < 0.3:
            threshold_current = 1.5 * s_sustain
        else:
            threshold_current = 1.2 * s_sustain
        if current_stock < 0.5 * s_sustain:
            return Action.C
        if current_stock < threshold_current and self.est_coop_rate > 0.5:
            return Action.C
        if rounds_remaining <= 2:
            return Action.D
        if current_round_cooperators == n - 1:
            if current_stock > 1.8 * s_sustain and rounds_remaining > 3:
                return Action.D
            else:
                return Action.C if random.random() < 0.6 else Action.D
        if current_stock > threshold_current and rounds_remaining > 2:
            return Action.D
        return Action.C

class Strategy_SELFISH_94(BaseStrategy):
    """
    Adaptive Greedy Strategy: Exploit and Preserve
    
    Defaults to defection (maximizes immediate payoff). Cooperates only when
    stock drops below 25% of capacity to prevent pool extinction. Always defects
    in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        stock_health_ratio = current_stock / self.game_description.capacity
        if stock_health_ratio < 0.25:
            return Action.C
        return Action.D

class Strategy_SELFISH_95(BaseStrategy):
    """
    Adaptive Depletion Strategy: Exploit when safe, cooperate when necessary.
    
    Combines endgame defection, stock recovery triggers, and opponent cooperation
    tracking to maximize individual payoffs while avoiding resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        stock_ratio = current_stock / capacity if capacity > 0 else 0
        rounds_remaining = r - current_round
        if stock_ratio < 0.2:
            return Action.C
        if current_round == r - 1:
            return Action.D
        if stock_ratio < 0.35:
            return Action.C
        if current_round == 0:
            return Action.D
        if rounds_remaining <= 2:
            return Action.D
        observed_cooperators = history.opponent_cooperators[-1]
        observed_coop_rate = observed_cooperators / (n - 1) if n > 1 else 0
        sustainable_threshold = 0.5 + 1.0 / n
        if observed_coop_rate >= sustainable_threshold:
            if stock_ratio >= 0.35 and rounds_remaining > 2:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_SELFISH_96(BaseStrategy):
    """
    Adaptive Threshold Exploitation Strategy for Common Pool Resource Game.
    
    Exploits the resource when stock is high, but preserves it when depleted.
    Dynamically adjusts preservation threshold based on observed opponent cooperation rates.
    Always defects in first and last rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.n_rounds - 1:
            return Action.D
        n_opponents = self.n_players - 1
        if n_opponents <= 0:
            coop_rate = 0.0
        else:
            cooperators_last_round = history.opponent_cooperators[-1]
            coop_rate = cooperators_last_round / n_opponents
        if coop_rate == 0.0:
            threshold = self.capacity / 6
        elif coop_rate > 0.5:
            threshold = self.capacity / 3
        else:
            threshold = self.capacity / 5
        if current_stock <= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_97(BaseStrategy):
    """
    Opportunistic Threshold Strategy for Common Pool Resource Game.
    
    Defects when the resource pool is abundant, cooperates when depleted.
    Adapts to observed opponent defection patterns to detect resource stress.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        if current_stock == 0:
            return Action.C
        if current_stock == capacity:
            return Action.D
        round_num = history.round_number
        is_final_round = round_num == n_rounds - 1
        cooperators_last_round = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if cooperators_last_round == 0:
            return Action.D
        if is_final_round:
            if current_stock > 0.5 * capacity:
                return Action.D
            else:
                return Action.C
        utilization_75 = 0.75 * capacity
        utilization_35 = 0.35 * capacity
        if current_stock > utilization_75:
            return Action.D
        elif current_stock < utilization_35:
            return Action.C
        else:
            opponent_defection_rate = (n_opponents - cooperators_last_round) / n_opponents if n_opponents > 0 else 0.0
            if opponent_defection_rate > 0.5:
                return Action.D
            else:
                return Action.C

class Strategy_SELFISH_98(BaseStrategy):
    """
    Adaptive Threshold Defection Strategy for Common Pool Resource Game.
    
    Defects when stock is abundant, but switches to cooperation when stock 
    is critically depleted or when stock is moderately depleted with low 
    opponent cooperation. Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        critical_threshold = capacity / 3
        moderate_threshold = capacity / 2
        cooperation_threshold = 0.35
        if current_stock <= critical_threshold:
            return Action.C
        if current_stock <= moderate_threshold:
            cooperators_previous = history.opponent_cooperators[-1]
            n_opponents = n - 1
            cooperation_rate = cooperators_previous / n_opponents if n_opponents > 0 else 0.0
            if cooperation_rate <= cooperation_threshold:
                return Action.C
        return Action.D

class Strategy_SELFISH_99(BaseStrategy):
    """
    Threshold-Adaptive Defection Strategy: Defect aggressively when stock is healthy
    (above an adaptive threshold), cooperate only when stock threatens collapse.
    Always defect in the final round. Threshold adapts based on observed opponent
    cooperation rate to optimize exploitation while preserving future payoffs.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D if current_stock > 0 else Action.C
        if current_round == 0:
            observed_coop_rate = 0.5
        else:
            n_opponents = self.n_players - 1
            if n_opponents > 0:
                cooperators_last_round = history.opponent_cooperators[-1]
                observed_coop_rate = cooperators_last_round / n_opponents
            else:
                observed_coop_rate = 0.5
        stock_threshold = self.capacity * (0.3 + 0.25 * observed_coop_rate)
        if current_stock >= stock_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_100(BaseStrategy):
    """
    Stock-triggered adaptive exploitation strategy that responds to stock health
    and observed cooperation rates. Defects when stock is abundant, cooperates when
    stock is critical, and always exploits the final round to maximize personal payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        stock_health = current_stock / capacity if capacity > 0 else 0
        if stock_health < 0.3:
            return Action.C
        if stock_health < 0.65:
            my_cooperated_last_round = 1 if history.my_actions[-1] else 0
            cooperators_last_round = my_cooperated_last_round + history.opponent_cooperators[-1]
            cooperation_rate = cooperators_last_round / n if n > 0 else 0
            if cooperation_rate >= 0.5:
                return Action.D
            else:
                return Action.C
        return Action.D

class Strategy_SELFISH_101(BaseStrategy):
    """
    Stock-Responsive Defection Strategy for Common Pool Resource Game.
    
    Defects when stock is abundant relative to a time-adjusted threshold,
    cooperates when stock is depleted or approaching depletion.
    First round: always defect.
    Final round: always defect unless stock is critically low.
    Middle rounds: defect if stock > threshold, where threshold decreases as
    rounds progress (more aggressive late-game strategy).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_stock <= 0:
            return Action.C
        if current_stock < self.capacity / 6:
            return Action.C
        if current_round == 0:
            return Action.D
        if current_round == self.n_rounds - 1:
            if current_stock <= self.capacity / 4:
                return Action.C
            return Action.D
        rounds_remaining = self.n_rounds - current_round
        threshold = self.capacity * (1.0 / 3.0 + 1.0 / 6.0 * rounds_remaining / self.n_rounds)
        if current_stock > threshold:
            return Action.D
        return Action.C

class Strategy_SELFISH_102(BaseStrategy):
    """
    Adaptive Depletion Strategy for Common Pool Resource Game.
    
    Exploits abundant stock when possible, cooperates only when stock depletion 
    threatens future earnings, and defects unconditionally in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_stock > 0.75 * capacity:
            return Action.D
        elif current_stock <= capacity / 2.0:
            return Action.C
        else:
            if current_round == 0:
                return Action.D
            n_opponents = n - 1
            if n_opponents > 0:
                opponents_cooperated = history.opponent_cooperators[-1]
                opponents_defected = n_opponents - opponents_cooperated
                defection_rate = opponents_defected / n_opponents
            else:
                defection_rate = 0.0
            threshold = 0.5
            if defection_rate > threshold:
                return Action.D
            else:
                return Action.D

class Strategy_SELFISH_103(BaseStrategy):
    """
    Greedy Stock-Dependent Adaptation Strategy for Common Pool Resource Game.
    
    Uses a threshold-based defection rule that varies with remaining rounds and
    adapts based on observed cooperation levels. Includes edge cases for extreme
    stock levels and an adaptive restart mechanism for catastrophic depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.low_stock_count = 0
        self.force_cooperate_next = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.r - 1:
            return Action.D
        if current_stock < 2 * self.n:
            return Action.C
        if current_stock >= self.capacity:
            return Action.D
        if self.force_cooperate_next:
            self.force_cooperate_next = False
            return Action.C
        if current_stock < self.capacity / 4:
            self.low_stock_count += 1
        else:
            self.low_stock_count = 0
        if self.low_stock_count >= 2:
            self.force_cooperate_next = True
            self.low_stock_count = 0
            return Action.C
        rounds_remaining = self.r - current_round
        critical_threshold = self.capacity * (0.5 + 0.2 * rounds_remaining / self.r)
        coop_count_opponents = history.opponent_cooperators[-1]
        coop_ratio = coop_count_opponents / max(self.n - 1, 1)
        if coop_ratio > 0.6:
            critical_threshold *= 0.9
        elif coop_ratio < 0.3:
            critical_threshold *= 1.15
        if current_stock > critical_threshold or rounds_remaining <= 2:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_104(BaseStrategy):
    """
    Adaptive Defection Strategy that balances immediate payoff extraction with 
    stock sustainability. Defects in first and last rounds, then in mid-game 
    conditionally based on stock thresholds and observed opponent defection rates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.D
        if round_num == r - 1:
            return Action.D
        if current_stock == 0:
            return Action.D
        rounds_remaining = r - round_num
        stock_threshold = capacity * (0.4 + 0.3 * rounds_remaining / r)
        cooperators_last_round = history.opponent_cooperators[-1]
        defectors_last_round = n - 1 - cooperators_last_round
        observed_defection_rate = defectors_last_round / (n - 1) if n > 1 else 0.0
        if current_stock > stock_threshold:
            return Action.D
        elif current_stock < capacity * 0.25:
            return Action.C
        elif observed_defection_rate > 0.5:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_105(BaseStrategy):
    """
    Greedy Threshold Strategy: Defect when possible, but cooperate when stock
    drops below capacity/3 to preserve the resource. Always defect in the final round.
    
    Decision rule:
    - Final round: DEFECT (extract maximum value)
    - Stock ≤ capacity/3: COOPERATE (preserve resource)
    - Otherwise: DEFECT (exploit high stock levels)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.critical_threshold = game_description.capacity / 3

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock <= self.critical_threshold:
            return Action.C
        return Action.D

class Strategy_SELFISH_106(BaseStrategy):
    """
    Selfish Preservation Strategy: Defect by default to maximize immediate consumption.
    Cooperate only when the stock level falls below a critical threshold to prevent
    resource pool collapse, since a dead pool yields zero future payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        remaining_rounds = n_rounds - round_number
        if round_number == n_rounds - 1:
            return Action.D
        if remaining_rounds <= 2:
            return Action.D
        if remaining_rounds > 0:
            critical_threshold = capacity / (4.0 * remaining_rounds)
        else:
            critical_threshold = 0.0
        if current_stock <= critical_threshold:
            return Action.C
        return Action.D

class Strategy_SELFISH_107(BaseStrategy):
    """
    Adaptive Threshold Defection Strategy - maximizes personal payoff by:
    - Taking higher immediate gains (DEFECT) when sustainable
    - Exploiting cooperating opponents when stock is abundant
    - Only cooperating when non-cooperation threatens future payoff sustainability
    - Always defecting in final round and when stock safety is assured
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.depletion_threshold = 3 * game_description.n_players
        self.dangerous_minimum = 2 * game_description.n_players
        self.cooperation_threshold = (game_description.n_players - 1) / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        if current_stock <= self.dangerous_minimum:
            return Action.C
        if current_stock <= self.depletion_threshold:
            return Action.C
        stock_declining = False
        if current_round >= 2:
            recent_payoff = history.my_payoffs[-1]
            previous_payoff = history.my_payoffs[-2]
            stock_declining = recent_payoff < previous_payoff
        recent_cooperators = history.opponent_cooperators[-1]
        if recent_cooperators < self.cooperation_threshold and stock_declining:
            return Action.D
        if current_stock >= 0.9 * capacity and recent_cooperators >= self.cooperation_threshold:
            return Action.D
        payoff_trend_declining = False
        if current_round >= 3:
            avg_recent = np.mean(history.my_payoffs[-3:])
            avg_earlier = np.mean(history.my_payoffs[-6:-3]) if current_round >= 6 else avg_recent
            payoff_trend_declining = avg_recent < avg_earlier * 0.9
        if payoff_trend_declining:
            return Action.C
        return Action.D

class Strategy_SELFISH_108(BaseStrategy):
    """
    Adaptive Exploitation Strategy for Common Pool Resource Game.
    
    Monitors opponent cooperation to determine whether to exploit or cooperate.
    Exploits when opponents cooperate sufficiently to maintain stock,
    defects in final rounds, and adapts based on resource health.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == 0:
            if capacity < 4 * n:
                return Action.C
            else:
                return Action.D
        c = history.opponent_cooperators[-1]
        n_opponents = n - 1
        p_opp = c / n_opponents if n_opponents > 0 else 0.5
        rounds_left = r - t
        is_healthy = current_stock > 1.5 * capacity / n
        if is_healthy and p_opp > 0.5:
            return Action.D
        critical_threshold = capacity / (4 * n) if n > 0 else 0.0
        if current_stock < critical_threshold:
            return Action.D
        if rounds_left <= 2:
            return Action.D
        low_coop_threshold = capacity / (2 * n) if n > 0 else 0.0
        if p_opp < 0.3 and current_stock > low_coop_threshold:
            return Action.D
        return Action.C

class Strategy_SELFISH_109(BaseStrategy):
    """
    Selfish Adaptive Resource Extraction Strategy.
    Defaults to DEFECT while monitoring resource stock and opponent cooperation.
    Cooperates only as a defensive measure to prevent resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        remaining_rounds = r - history.round_number
        if history.round_number == 0:
            return Action.D
        if remaining_rounds == 1 and current_stock > 0:
            return Action.D
        if current_stock < 1.5 * n:
            return Action.C
        if current_stock < n:
            return Action.C
        if current_stock < 2 * n:
            observed_cooperators_last_round = history.opponent_cooperators[-1]
            if observed_cooperators_last_round < n - 1:
                return Action.C
        return Action.D

class Strategy_SELFISH_110(BaseStrategy):
    """
    Adaptive Depletion-Response Strategy for Common Pool Resource Game.
    
    Cooperates when stock is threatened; defects otherwise.
    Maintains two stock thresholds (danger_zone and safe_zone) and adapts based on
    opponent cooperation history and remaining rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.danger_zone = 0.35 * game_description.capacity
        self.safe_zone = 0.65 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        round_num = history.round_number
        if round_num == 0:
            return Action.D
        if round_num == n_rounds - 1:
            return Action.D
        if current_stock <= self.danger_zone:
            return Action.C
        elif current_stock >= self.safe_zone:
            return Action.D
        else:
            cooperators_last_round = history.opponent_cooperators[-1]
            cooperation_threshold = (n - 1) / 2.0
            if cooperators_last_round >= cooperation_threshold:
                return Action.D
            else:
                return Action.C

class Strategy_SELFISH_111(BaseStrategy):
    """
    Adaptive Threshold Defection: Dynamically adjusts cooperation threshold based on
    stock depletion and rounds remaining. Defects when stock is sustainable,
    cooperates when stock threatens collapse or runs low relative to remaining rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if capacity <= 0:
            stock_ratio = 0.0
        else:
            stock_ratio = current_stock / capacity
        rounds_remaining = n_rounds - current_round
        if n_rounds <= 0:
            relative_urgency = 0.0
        else:
            relative_urgency = rounds_remaining / n_rounds
        depletion_threshold = 0.3 + 0.25 * relative_urgency
        if rounds_remaining == 1:
            return Action.D
        if stock_ratio < 0.3:
            return Action.C
        if stock_ratio < depletion_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_112(BaseStrategy):
    """
    Selfish Adaptive Depletion Strategy for Common Pool Resource Game.
    
    Maximizes current-round payoff while tracking stock viability and opponent 
    cooperation rates. Defects aggressively when profitable, but cooperates 
    strategically to prevent resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == 0:
            return Action.D
        if round_num == self.n_rounds - 1:
            return Action.D
        if current_stock <= 0:
            return Action.C
        n_opponents = self.n_players - 1
        if n_opponents <= 0:
            return Action.D
        c_last = history.opponent_cooperators[-1]
        coop_rate = c_last / n_opponents
        threshold_low = self.capacity / 4
        threshold_high = 3 * self.capacity / 4
        if current_stock <= threshold_low:
            return Action.C
        elif current_stock >= threshold_high:
            if coop_rate <= 0.4:
                return Action.D
            elif coop_rate >= 0.7:
                return Action.D
            elif coop_rate >= 0.6:
                return Action.D
            elif coop_rate <= 0.3:
                return Action.D
            else:
                return Action.C
        elif threshold_low < current_stock < threshold_high:
            if coop_rate >= 0.6:
                return Action.D
            elif coop_rate <= 0.3:
                return Action.D
            else:
                return Action.C
        else:
            return Action.D

class Strategy_SELFISH_113(BaseStrategy):
    """
    Adaptive Greedy with Stock Preservation strategy for Common Pool Resource Game.
    
    Exploits cooperative opponents when stock is abundant, defects in final rounds,
    but pivots to cooperation when stock collapse threatens future payoffs.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_stock_postgrowth = None
        self.two_rounds_ago_postgrowth = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        round_num = history.round_number
        rounds_remaining = r - round_num
        if round_num == r - 1:
            return Action.D
        if round_num == 0:
            self.last_stock_postgrowth = current_stock
            return Action.D
        if current_stock < n:
            return Action.C
        rapid_collapse = False
        if round_num >= 2 and self.two_rounds_ago_postgrowth is not None:
            if current_stock < 0.5 * self.two_rounds_ago_postgrowth:
                rapid_collapse = True
        if round_num >= 1 and self.last_stock_postgrowth is not None:
            if current_stock < 0.5 * self.last_stock_postgrowth:
                self.two_rounds_ago_postgrowth = self.last_stock_postgrowth
                self.last_stock_postgrowth = current_stock
                return Action.C
        total_opponent_actions = round_num * (n - 1)
        if total_opponent_actions > 0:
            total_cooperators = int(np.sum(history.opponent_cooperators[:round_num]))
            avg_coop = total_cooperators / total_opponent_actions
        else:
            avg_coop = 0.0
        self.two_rounds_ago_postgrowth = self.last_stock_postgrowth
        self.last_stock_postgrowth = current_stock
        safety_threshold = 1.5 * n
        if avg_coop >= 0.6:
            return Action.D
        if current_stock >= safety_threshold:
            return Action.D
        if rounds_remaining <= 2:
            return Action.D
        return Action.C

class Strategy_SELFISH_114(BaseStrategy):
    """
    Adaptive Stock-Responsive Strategy for Common Pool Resource Games.
    
    Balances immediate extraction against future stock availability through
    a hierarchy of decision rules based on stock level and opponent behavior.
    Cooperates in first round and selectively thereafter based on stock health
    and opponent defection rates, with special logic for the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        if current_round == r - 1:
            if current_stock >= 2 * n:
                return Action.D
            else:
                return Action.C
        if current_stock < 2 * n:
            return Action.D
        if current_stock >= 0.75 * capacity:
            return Action.C
        n_opponents = n - 1
        if n_opponents > 0:
            cooperators_prev = history.opponent_cooperators[-1]
            defectors_prev = n_opponents - cooperators_prev
            def_rate = defectors_prev / n_opponents
            if def_rate >= 0.5:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_SELFISH_115(BaseStrategy):
    """
    Adaptive Threshold Exploitation with Endgame Defection.
    
    Cooperates when stock is low (≤65% of capacity) to preserve the resource,
    defects when stock is abundant (>65% of capacity) to exploit immediate gains,
    and always defects in the final round when future payoffs are irrelevant.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        threshold = self.game_description.capacity * 0.65
        if current_stock > threshold:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_116(BaseStrategy):
    """
    Selfish Threshold Strategy for Common Pool Resource Game.
    
    Dynamically adjusts a threshold that declines as the game approaches completion.
    Defects when stock exceeds the threshold (abundance strategy), and cooperates
    when stock falls below it (conservation strategy). In the final round, the
    threshold becomes zero, guaranteeing defection.
    
    The threshold function: capacity × (1 - 1/√(remaining_rounds + 1))
    reflects the intuition that defection is sustainable early on due to strong
    regeneration, but becomes risky near game end when recovery time is limited.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        remaining_rounds = r - t
        if remaining_rounds <= 1:
            threshold = 0.0
        else:
            threshold = capacity * (1.0 - 1.0 / math.sqrt(remaining_rounds + 1))
        if current_stock > threshold:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_117(BaseStrategy):
    """
    Selfish Stock Depletion Strategy for Common Pool Resource Game.
    
    Defects when immediate payoff advantage is large or long-term cost is negligible.
    Uses round number, current stock level, remaining rounds, and observed defector rate
    to decide between cooperation and defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_stock <= 2 * self.n:
            return Action.C
        if current_round >= self.r - 2:
            return Action.D
        if current_stock > self.capacity * 0.7:
            return Action.D
        if current_stock > self.capacity * 0.4:
            cooperators_last_round = history.opponent_cooperators[-1]
            total_opponents = self.n - 1
            if total_opponents > 0:
                defectors_last_round = total_opponents - cooperators_last_round
                defector_rate = defectors_last_round / total_opponents
            else:
                defector_rate = 0.0
            if defector_rate > 0.5:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_SELFISH_118(BaseStrategy):
    """
    Adaptive Scarcity-Responsive Strategy for Common Pool Resource Game.
    
    Cooperates when current stock is depleted enough to threaten future payoff,
    weighted by remaining rounds. Adapts thresholds based on observed cooperator counts.
    Prioritizes stock preservation when approaching collapse (stock < 2n).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold_adjustment = 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        rounds_remaining = r - round_number
        if round_number == r - 1:
            return Action.D
        if current_stock < 2 * n:
            return Action.C
        estimated_stock_after_defect = 0.0
        if estimated_stock_after_defect <= 2 * n:
            return Action.C
        scarcity_ratio = current_stock / capacity if capacity > 0 else 0.0
        base_threshold = 0.35 + 0.5 * (rounds_remaining / r)
        if round_number > 0:
            observed_cooperators = int(history.opponent_cooperators[-1])
            threshold_for_high_coop = (n - 1) * 0.6
            if scarcity_ratio > 0.5 and observed_cooperators > threshold_for_high_coop:
                self.threshold_adjustment = max(self.threshold_adjustment - 0.05, -0.15)
            elif scarcity_ratio > 0.5 and observed_cooperators == 0:
                self.threshold_adjustment = min(self.threshold_adjustment + 0.05, 0.15)
        cooperation_threshold = base_threshold + self.threshold_adjustment
        if scarcity_ratio < cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_119(BaseStrategy):
    """
    Adaptive Defection with Stock Preservation.
    
    Exploits abundant resources while most opponents cooperate, but switches
    to cooperation when stock approaches critical levels or majority defects.
    Always defects in the final round to maximize immediate payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        if t == self.r - 1:
            return Action.D
        if current_stock < self.capacity / 10:
            return Action.C
        threshold = self.capacity * (self.r - t) / (2 * self.r)
        s_threshold_high = self.capacity * 0.65
        if current_stock < threshold:
            return Action.C
        n_opponents = self.n - 1
        cooperators_last_round = history.opponent_cooperators[-1]
        defectors_last_round = n_opponents - cooperators_last_round
        if defectors_last_round > n_opponents / 2:
            return Action.D
        if current_stock > s_threshold_high:
            return Action.D
        return Action.C

class Strategy_SELFISH_120(BaseStrategy):
    """
    Selfish Adaptive Resource Exploitation Strategy for Common Pool Resource Game.
    
    Maximizes personal consumption by:
    1. Defecting aggressively in first and last rounds
    2. Exploiting healthy stock when others cooperate
    3. Cooperating minimally only to prevent self-payoff collapse
    4. Shifting to aggression as game horizon contracts
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        h = current_stock / capacity
        m = r - current_round
        c_prev = history.opponent_cooperators[-1]
        if current_stock < capacity / 4:
            return Action.C
        if h <= 0.25:
            return Action.C
        if h >= 0.7 and c_prev >= math.ceil(n / 2):
            return Action.D
        if h >= 0.6 and m <= 2:
            return Action.D
        if h >= 0.5 and c_prev >= math.ceil(2 * n / 3):
            return Action.D
        if h >= 0.4 and c_prev <= math.floor(n / 3):
            return Action.D
        if c_prev == 0:
            if h <= 0.3:
                return Action.C
            else:
                return Action.D
        if c_prev == n - 1:
            if h <= 0.35:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_SELFISH_121(BaseStrategy):
    """
    Selfish Adaptive Depletion Strategy.
    
    Always defects to maximize immediate payoff. Defecting yields S/n versus S/2n 
    from cooperating—a guaranteed 2x immediate payoff. With anonymous opponents and 
    no enforcement mechanism, continued cooperation cannot be guaranteed. The strategy
    defects regardless of stock level, round number, or opponent behavior because the
    immediate gain from defection always dominates the uncertain deferred benefit from
    cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        return Action.D

class Strategy_SELFISH_122(BaseStrategy):
    """
    Selfish Adaptive Strategy for Common Pool Resource Game.
    
    Defaults to defection, but cooperates when necessary to prevent stock collapse.
    Uses stock level and opponent cooperation rates to decide when to cooperate defensively.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        rounds_remaining = r - history.round_number
        if rounds_remaining <= 2:
            return Action.D
        if current_stock < capacity * 0.12:
            return Action.C
        if current_stock < capacity * 0.3:
            last_round_cooperators = history.opponent_cooperators[-1]
            if last_round_cooperators < (n - 1) * 0.25:
                return Action.C
        return Action.D

class Strategy_SELFISH_123(BaseStrategy):
    """
    Stock-Threshold Endgame Defection Strategy.
    
    Cooperates if and only if BOTH conditions hold:
    1. Stock < 0.6 × capacity, AND
    2. Rounds remaining > 2
    
    Otherwise defects.
    
    Rationale:
    - Endgame (≤2 rounds left): Defect unconditionally to extract maximum value.
    - Stock depletion (ratio < 0.6): Cooperate to preserve pool regeneration.
    - Stock abundant (ratio ≥ 0.6): Defect to maximize immediate payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        rounds_remaining = total_rounds - current_round
        capacity = self.game_description.capacity
        stock_ratio = current_stock / capacity if capacity > 0 else 1.0
        if rounds_remaining <= 2:
            return Action.D
        if stock_ratio < 0.6:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_124(BaseStrategy):
    """
    Adaptive Threshold Defection strategy for Common Pool Resource Game.
    
    Defects when stock exceeds a threshold dependent on remaining rounds.
    Uses hysteresis to avoid flicker near threshold and adapts based on
    observed opponent cooperation rates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.in_recovery_mode = False
        self.last_threshold = 0.0

    def _compute_threshold(self, rounds_remaining: int) -> float:
        """Compute stock threshold based on rounds remaining."""
        capacity = self.game_description.capacity
        if rounds_remaining <= 2:
            return 0.35 * capacity
        elif rounds_remaining <= 5:
            return 0.5 * capacity
        else:
            return 0.6 * capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        rounds_remaining = r - history.round_number
        if history.round_number == 0:
            return Action.D
        if rounds_remaining == 1:
            return Action.D
        base_threshold = self._compute_threshold(rounds_remaining)
        observed_cooperators = history.opponent_cooperators[-1]
        if observed_cooperators < n / 2:
            adjusted_threshold = base_threshold * 0.9
        else:
            adjusted_threshold = base_threshold
        if self.in_recovery_mode:
            recovery_target = self.last_threshold * 1.05
            if current_stock > recovery_target:
                self.in_recovery_mode = False
            else:
                return Action.C
        if current_stock > adjusted_threshold:
            self.last_threshold = adjusted_threshold
            return Action.D
        else:
            self.in_recovery_mode = True
            self.last_threshold = adjusted_threshold
            return Action.C

class Strategy_SELFISH_125(BaseStrategy):
    """
    Adaptive Selfish Extraction Strategy for Common Pool Resource Game.
    
    Dynamically adjusts cooperation vs. defection based on stock health and 
    opponent behavior. Prioritizes immediate extraction when stock is abundant,
    cooperates only when necessary to prevent collapse, and always defects in
    the final round. Treats opponent cooperation as weakness to exploit.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        stock_ratio = current_stock / capacity
        if current_round == 0:
            opponent_defection_rate = 0.5
        else:
            opponent_cooperators = history.opponent_cooperators[-1]
            opponent_defectors = n - 1 - opponent_cooperators
            opponent_defection_rate = opponent_defectors / (n - 1) if n > 1 else 0.0
        if stock_ratio < 0.25:
            return Action.C
        elif stock_ratio >= 0.65:
            return Action.D
        elif 0.45 <= stock_ratio < 0.65:
            if opponent_defection_rate >= 0.55:
                return Action.D
            else:
                return Action.C
        elif opponent_defection_rate >= 0.6:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_126(BaseStrategy):
    """
    Adaptive Threshold-Based Selfish Strategy for Common Pool Resource Game.
    
    Employs dynamic defection threshold that becomes more permissive in later rounds.
    Defects when stock is healthy relative to threshold; cooperates to prevent collapse
    and enable future extraction. Ignores opponent behavior—decisions depend only on
    objective stock state and time remaining.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        rounds_left = r - current_round - 1
        if current_stock < capacity / 4:
            return Action.C
        if current_stock > 0.95 * capacity:
            return Action.D
        if rounds_left == 0:
            return Action.D
        threshold = capacity * (0.5 + 0.25 * (1 - rounds_left / r))
        if current_stock >= threshold:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_127(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Exploits opponents' cooperation when stock is abundant, but switches to cooperation
    when stock drops below 30% capacity. Opponent cooperation rates modulate willingness
    to cooperate in middle stock range. Always defects in final round and high-stock
    two-round endgame.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        rounds_remaining = r - history.round_number
        if rounds_remaining == 1:
            return Action.D
        if rounds_remaining == 2 and stock_ratio > 0.4:
            return Action.D
        if history.round_number == 0:
            if stock_ratio <= 0.3:
                return Action.C
            else:
                return Action.D
        if stock_ratio <= 0.3:
            return Action.C
        if 0.3 < stock_ratio <= 0.6:
            opp_coop_count = history.opponent_cooperators[-1]
            opp_coop_rate = opp_coop_count / (n - 1) if n > 1 else 0.0
            if opp_coop_rate >= 0.4:
                return Action.C
        return Action.D

class Strategy_SELFISH_128(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Adapts between cooperation and defection based on:
    - Current stock level relative to capacity
    - Observed cooperation rates of opponents
    - Projected stock trajectory
    - Whether it's the terminal round
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == self.r - 1:
            return Action.D
        if round_num == 0:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.C
        if current_stock >= 0.65 * self.capacity:
            return Action.D
        coop_count = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if n_opponents <= 0:
            return Action.D
        coop_rate = coop_count / n_opponents
        if coop_rate > 0.5:
            return Action.D
        defectors_count = n_opponents - coop_count
        projected_consumption = (defectors_count + 1) * current_stock / self.n
        projected_remaining = max(0.0, current_stock - projected_consumption)
        projected_growth = 2 * projected_remaining * (1 - projected_remaining / self.capacity)
        projected_stock = min(projected_remaining + projected_growth, self.capacity)
        if projected_stock < 0.2 * self.capacity:
            return Action.C
        return Action.C

class Strategy_SELFINTERESTED_33(BaseStrategy):
    """
    Adaptive Stock-Contingent Strategy for Common Pool Resource Game.
    
    Cooperates in first round to establish high stock. In middle rounds,
    adjusts behavior based on current stock level and observed defection rates
    from previous round. Defects unconditionally in final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        critical_threshold = 0.25 * capacity
        if current_stock < critical_threshold:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        prev_defectors = n - 1 - prev_cooperators
        d_observed = prev_defectors / (n - 1) if n > 1 else 0.0
        if current_stock >= 0.7 * capacity:
            if d_observed <= 0.3:
                return Action.C
            else:
                return Action.D
        elif current_stock >= 0.4 * capacity:
            if d_observed <= 0.4:
                return Action.C
            else:
                return Action.D
        elif d_observed <= 0.2:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_34(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Adapts cooperation based on current stock ratio and opponent cooperation rates.
    - In final round: defect if stock allows, else cooperate.
    - In earlier rounds: prioritize cooperation only when stock is critically low or 
      moderately threatened with defecting opponents. Otherwise default to defection 
      to extract immediate payoffs, except when opponents cooperate heavily (free-ride).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        is_final_round = current_round == n_rounds - 1
        stock_ratio = current_stock / capacity if capacity > 0 else 0
        if is_final_round:
            if stock_ratio > 1.0 / 3.0:
                return Action.D
            else:
                return Action.C
        if current_round == 0:
            coop_prev = 0.5
        else:
            n_opponents = n - 1
            if n_opponents > 0:
                coop_prev = history.opponent_cooperators[-1] / n_opponents
            else:
                coop_prev = 0.5
        if stock_ratio < 0.25:
            return Action.C
        elif stock_ratio < 0.55 and coop_prev < 0.5:
            return Action.C
        elif coop_prev > 0.65:
            return Action.D
        elif coop_prev <= 0.35:
            return Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_35(BaseStrategy):
    """
    Adaptive Threshold Cooperation with Endgame Defection.
    
    - Round 1: Unconditional cooperation to probe opponents
    - Round r: Defect (subgame perfection with no future)
    - Rounds 2 to r-1: Adaptive threshold based on observed opponent cooperation rate
      and game progress, with defection if stock is critically low
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.D
        if current_stock <= 2 * n:
            return Action.D
        total_opponent_cooperations = int(np.sum(history.opponent_cooperators[:current_round]))
        total_opponent_actions = current_round * (n - 1)
        if total_opponent_actions == 0:
            coop_rate = 0.0
        else:
            coop_rate = total_opponent_cooperations / total_opponent_actions
        progress_ratio = (current_round - 1) / (r - 1)
        threshold = 0.5 - 0.2 * progress_ratio
        if coop_rate >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_36(BaseStrategy):
    """
    Adaptive Extraction with Stock-Aware Thresholds strategy.
    
    Exploits cooperative opponents when stock is abundant, but adapts to cooperation
    when stock is depleted. Always defects in the final round. First round always
    defects to test the waters.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        n_opponents = n - 1
        cooperation_rate_prev = c_prev / n_opponents if n_opponents > 0 else 0.0
        stock_health = current_stock / capacity if capacity > 0 else 0.0
        if stock_health < 0.3:
            if cooperation_rate_prev >= 0.5:
                return Action.C
            else:
                return Action.D
        elif stock_health < 0.6:
            if cooperation_rate_prev >= 0.75:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_37(BaseStrategy):
    """
    Adaptive Stock-Tracking Strategy for Common Pool Resource Game.
    
    Cooperates by default but defects when:
    - It's the final round (to maximize one-time payoff)
    - Stock is critically low (recovery impossible)
    - Observed cooperation is low and stock is degrading
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        stock_threshold = max(2 * self.n_players, self.capacity / 4)
        if current_stock <= stock_threshold:
            return Action.D
        cooperators_last_round = history.opponent_cooperators[-1]
        n_opponents = self.n_players - 1
        if n_opponents == 0:
            cooperation_rate = 0.0
        else:
            cooperation_rate = cooperators_last_round / n_opponents
        if cooperation_rate >= 0.5:
            return Action.C
        elif current_stock < 1.5 * self.capacity:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_38(BaseStrategy):
    """
    Stock-Aware Conditional Cooperation strategy.
    
    Defects in the final round unconditionally. In all other rounds, cooperates
    if and only if both conditions are met:
    (1) observed cooperating opponents ≥ ceil(n/2)
    (2) current stock > capacity/2
    Otherwise defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.cooperation_threshold = math.ceil(self.n_players / 2)
        self.stock_threshold = self.capacity / 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        observed_cooperators = history.opponent_cooperators[-1]
        if observed_cooperators >= self.cooperation_threshold and current_stock > self.stock_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_39(BaseStrategy):
    """
    Stock-Responsive Conditional Strategy
    
    Cooperates in round 1 to establish intentions. Subsequently makes decisions
    based on stock health (health_ratio) and opponent cooperation rates (coop_rate),
    with unconditional defection in the final round and when stock is critically
    depleted. Balances immediate payoff extraction with resource sustainability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        rounds_remaining = r - current_round
        health_ratio = current_stock / capacity if capacity > 0 else 0
        coop_rate = history.opponent_cooperators[-1] / (n - 1) if n > 1 else 0
        if rounds_remaining <= 1:
            return Action.D
        if health_ratio < 0.35:
            return Action.D
        if coop_rate >= 0.55:
            if health_ratio >= 0.3:
                return Action.C
            else:
                return Action.D
        if coop_rate < 0.3:
            return Action.D
        if health_ratio >= 0.55:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_40(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Adapts behavior based on stock classification (CRITICAL, LOW, HEALTHY, ABUNDANT)
    and remaining game horizon. Prioritizes own total payoff by:
    - Exploiting when stock is abundant (logistic growth absorbs defection)
    - Preserving when stock is critical (avoided collapse)
    - Endgame exploitation in final rounds
    - Opportunistic modulation based on opponent defection rates
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.D
        if current_stock <= 0:
            return Action.D
        current_round = history.round_number
        remaining_rounds = self.n_rounds - current_round
        is_final_round = current_round == self.n_rounds - 1
        last_round_cooperators = history.opponent_cooperators[-1]
        last_round_defectors = self.n_players - 1 - last_round_cooperators
        critical_threshold = self.capacity / 4
        low_threshold = self.capacity / 2
        abundant_threshold = 3 * self.capacity / 4
        if current_stock < critical_threshold:
            return Action.C
        if current_stock >= abundant_threshold:
            return Action.D
        if is_final_round:
            return Action.D
        if current_stock < low_threshold:
            if remaining_rounds >= 3:
                return Action.C
            else:
                return Action.D
        if last_round_cooperators == self.n_players - 1:
            return Action.D
        if last_round_defectors == self.n_players - 1:
            return Action.C
        defectors_threshold = math.ceil(self.n_players / 2)
        if last_round_defectors > defectors_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_41(BaseStrategy):
    """
    Adaptive Threshold Cooperation Strategy for Common Pool Resource Game.
    
    Cooperates in round 1 to maintain stock health.
    In middle rounds, makes adaptive decisions based on stock level and observed cooperation rates.
    Defects in the final round to exploit remaining stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.D
        opponents_cooperated = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents <= 0:
            return Action.D
        observed_cooperation_rate = opponents_cooperated / n_opponents
        if current_stock < capacity * 0.25:
            return Action.D
        elif current_stock < capacity * 0.5:
            if observed_cooperation_rate >= 0.6:
                return Action.C
            else:
                return Action.D
        elif observed_cooperation_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_42(BaseStrategy):
    """
    Adaptive Resource Preservation Strategy for Common Pool Resource Game.
    Cooperates initially and when conditions are favorable, but defects when
    resource is depleted, majority of opponents defect, in endgame, or when
    stock is vulnerable with meaningful defection observed.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        if current_stock < 2 * self.n:
            return Action.D
        opponents_cooperated = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        n_defectors_last_round = n_opponents - opponents_cooperated
        defection_threshold = math.ceil(self.n / 2)
        if n_defectors_last_round > defection_threshold:
            return Action.D
        endgame_start_round = self.r - math.ceil(self.r / 3)
        if current_round > endgame_start_round:
            return Action.D
        stock_per_cooperator = current_stock / (2 * self.n)
        if stock_per_cooperator < 1.5:
            if n_opponents > 0:
                observed_defection_rate = n_defectors_last_round / n_opponents
                if observed_defection_rate > 0.25:
                    return Action.D
        return Action.C

class Strategy_SELFINTERESTED_43(BaseStrategy):
    """
    Adaptive Stock-Threshold Defection Strategy.
    
    Defect by default. Cooperate only when specific conditions for mutual benefit 
    are met. Tracks stock health ratio and opponent cooperation rates to determine
    optimal actions across game phases.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        stock_health_ratio = current_stock / self.capacity if self.capacity > 0 else 0.0
        opponents_count = self.n_players - 1
        opponents_cooperated_last_round = history.opponent_cooperators[-1] / opponents_count if opponents_count > 0 else 0.0
        if stock_health_ratio <= 0.35:
            return Action.D
        if history.round_number >= self.n_rounds * 0.75:
            return Action.D
        if opponents_cooperated_last_round >= 0.6 and stock_health_ratio >= 0.5:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_44(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Balances self-interest by exploiting abundant resources while preserving 
    the commons when necessary. Uses stock levels and opponent cooperation 
    rates to adapt behavior across rounds.
    
    Decision logic:
    - First round: Cooperate (gather information)
    - Final round: Defect (no future consequences)
    - Intermediate rounds: Adaptive based on stock ratio and cooperation rate
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        stock_ratio = current_stock / capacity
        n_opponents = n_players - 1
        if n_opponents > 0:
            opponent_cooperators_prev = history.opponent_cooperators[-1]
            cooperation_rate = opponent_cooperators_prev / n_opponents
        else:
            cooperation_rate = 0.0
        if stock_ratio < 0.15:
            return Action.C
        elif stock_ratio >= 0.5:
            if cooperation_rate >= 0.65:
                return Action.C
            else:
                return Action.D
        elif cooperation_rate >= 0.8:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_45(BaseStrategy):
    """
    Conditional Cooperation with Endgame Defection.
    
    Cooperates in round 1 to establish baseline behavior. In middle rounds (2 to r-2),
    cooperates only if stock is healthy (≥ capacity/2) AND a strict majority of opponents
    cooperated in the previous round. Defects unconditionally in the final two rounds
    to extract maximum payoff when stock replenishment is irrelevant.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.game_description.n_rounds - 2:
            return Action.D
        capacity = self.game_description.capacity
        n_players = self.game_description.n_players
        stock_healthy = current_stock >= capacity / 2
        n_opponents = n_players - 1
        cooperators_last_round = history.opponent_cooperators[-1]
        cooperation_rate = cooperators_last_round / n_opponents if n_opponents > 0 else 0
        if stock_healthy and cooperation_rate > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_46(BaseStrategy):
    """
    Adaptive Stock-Preservation Strategy with Defection Threshold.
    
    Cooperates early to preserve stock when opponents are cooperative, but switches to 
    defection when the resource is critically depleted or opponents are exploiting the commons.
    Always defects in the final round to maximize immediate payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.defection_threshold = math.ceil((self.n_players - 1) / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            return Action.D
        num_opponent_cooperators_prev = history.opponent_cooperators[-1]
        num_opponent_defectors_prev = self.n_players - 1 - num_opponent_cooperators_prev
        if current_stock <= self.capacity / 4:
            return Action.D
        if num_opponent_defectors_prev >= self.defection_threshold:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_47(BaseStrategy):
    """
    Stock-Threshold Retaliation Strategy
    
    Cooperates to sustain the resource when conditions are favorable,
    but defects when stock is threatened or opponents exploit the pool.
    Uses adaptive thresholds based on capacity and opponent behavior.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        rounds_remaining = self.n_rounds - current_round
        if rounds_remaining <= 2:
            return Action.D
        if current_stock < self.capacity / 4:
            return Action.D
        if current_round == 0:
            opponent_defection_rate = 0.0
        else:
            cooperating_opponents = history.opponent_cooperators[-1]
            total_opponents = self.n_players - 1
            if total_opponents == 0:
                opponent_defection_rate = 0.0
            else:
                opponent_defection_count = total_opponents - cooperating_opponents
                opponent_defection_rate = opponent_defection_count / total_opponents
        if opponent_defection_rate > 0.5:
            return Action.D
        if current_round > 0:
            cooperating_opponents = history.opponent_cooperators[-1]
            opponent_defection_count = self.n_players - 1 - cooperating_opponents
            if current_stock < self.capacity / 2 and opponent_defection_count > 0:
                return Action.D
        return Action.C

class Strategy_SELFINTERESTED_48(BaseStrategy):
    """
    Stock-Adaptive Defection Strategy: Cooperate early when stock is healthy,
    defect when depleted or cooperation collapses, and defect unconditionally
    in the final two rounds. Tracks stock history to estimate sustainability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.stock_history = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self.stock_history.append(current_stock)
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.game_description.n_rounds - 2:
            return Action.D
        if current_stock <= 0:
            return Action.D
        recent_stocks = self.stock_history[-3:]
        avg_recent = np.mean(recent_stocks)
        cooperators_observed = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        if n_opponents <= 0:
            coop_rate = 0.0
        else:
            coop_rate = cooperators_observed / n_opponents
        stock_threshold = self.game_description.capacity * 0.5
        coop_threshold = 1.0 / (2.0 * self.game_description.n_players)
        if current_stock >= stock_threshold and coop_rate >= coop_threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_49(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Cooperate if and only if:
    1. Stock ≥ dynamic threshold (capacity × (0.4 + 0.2 × rounds_remaining / r))
    2. Observed defection rate ≤ min(0.4, 1/(2n))
    3. Remaining rounds > 1
    
    Otherwise defect. Exploits immediate gains when safe, protects future payoff
    stream when stock is abundant, responds to opponent defection with defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        rounds_remaining = self.n_rounds - current_round
        if rounds_remaining <= 1:
            return Action.D
        stock_threshold = self.capacity * (0.4 + 0.2 * rounds_remaining / self.n_rounds)
        defection_tolerance = min(0.4, 1.0 / (2 * self.n_players))
        n_opponents = self.n_players - 1
        if n_opponents > 0:
            cooperators_last_round = history.opponent_cooperators[-1]
            defectors_last_round = n_opponents - cooperators_last_round
            observed_defection_rate = defectors_last_round / n_opponents
        else:
            observed_defection_rate = 0.0
        if current_stock >= stock_threshold and observed_defection_rate <= defection_tolerance:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_50(BaseStrategy):
    """
    Conditional Defection with Stock-Based Modulation.
    
    Cooperates in round 1 to establish baseline. In interior rounds, cooperates only if
    stock health is above 35% and majority of opponents cooperated. In final round,
    only cooperates if stock is nearly depleted (< 10%), otherwise defects to maximize
    extraction. Adapts to sustained defection by all opponents and liberalizes cooperation
    thresholds if sustained high stock and high cooperation rates are observed.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.all_defected_detected = False
        self.consecutive_high_coop_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if current_stock < 2 * self.n_players:
            return Action.D
        if self.all_defected_detected:
            return Action.D
        if history.opponent_cooperators[-1] == 0:
            self.all_defected_detected = True
            return Action.D
        h = current_stock / self.capacity
        if round_num == self.n_rounds - 1:
            if h < 0.1:
                return Action.C
            else:
                return Action.D
        n_opponents = self.n_players - 1
        c_rate = history.opponent_cooperators[-1] / n_opponents if n_opponents > 0 else 0.0
        if current_stock >= self.capacity * 0.95 and c_rate >= 0.7:
            self.consecutive_high_coop_rounds += 1
        else:
            self.consecutive_high_coop_rounds = 0
        coop_threshold = 0.4 if self.consecutive_high_coop_rounds >= 2 else 0.5
        if h >= 0.35 and c_rate >= coop_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_51(BaseStrategy):
    """
    Adaptive Stock-Preservation Defection Strategy.
    Maximizes immediate payoff through defection while monitoring stock levels
    to prevent personal harm from resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if capacity > 0 and current_stock / capacity < 0.3:
            return Action.C
        if current_stock < 2:
            return Action.C
        observed_cooperators = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents > 0:
            cooperation_rate = observed_cooperators / n_opponents
        else:
            cooperation_rate = 0.0
        defection_rate = 1.0 - cooperation_rate
        estimated_consumption = cooperation_rate * current_stock / (2.0 * n) + defection_rate * current_stock / n + current_stock / n
        estimated_remaining = current_stock - estimated_consumption
        if estimated_remaining <= 0:
            return Action.C
        if capacity > 0:
            logistic_growth = 2.0 * estimated_remaining * (1.0 - estimated_remaining / capacity)
        else:
            logistic_growth = 0.0
        projected_next_stock = min(estimated_remaining + logistic_growth, capacity)
        if capacity > 0 and projected_next_stock < 0.25 * capacity:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_52(BaseStrategy):
    """
    Adaptive Depletion Strategy: Balance self-interest with conditional reciprocity.
    
    Cooperates when stock is healthy, time horizon is sufficient, and observed 
    cooperation suggests the resource is being maintained. Otherwise defects to 
    extract maximum immediate payoff.
    
    Core decision: Cooperate if and only if all three conditions hold:
    1. Stock viability: current_stock > capacity / 3
    2. Sufficient time horizon: rounds_remaining > 2
    3. Observed cooperation signal: cooperators_last_round > n / 4
    
    Always defect in final two rounds, first round, and stock collapse (stock ≤ capacity/4).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        rounds_remaining = total_rounds - round_num - 1
        if round_num == 0:
            return Action.D
        if rounds_remaining <= 1:
            return Action.D
        if current_stock <= capacity / 4:
            return Action.D
        stock_viable = current_stock > capacity / 3
        time_sufficient = rounds_remaining > 2
        cooperation_visible = history.opponent_cooperators[-1] > n / 4
        if stock_viable and time_sufficient and cooperation_visible:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_53(BaseStrategy):
    """
    Conditional Defection with Adaptive Thresholds strategy.
    
    Balances three imperatives:
    1. Maximize immediate consumption when opponent cooperation justifies it
    2. Punish excessive defection through reciprocal defection
    3. Preserve stock from collapse (collapsed stock yields zero forever)
    
    Uses adaptive cooperation thresholds that tighten in early rounds,
    relax in late rounds, and become extraction-only in the final round.
    Stock level acts as a circuit-breaker for preservation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        n = self.n
        r = self.r
        capacity = self.capacity
        if round_num == 0:
            return Action.C
        if round_num == r - 1:
            if current_stock > 0:
                return Action.D
            else:
                return Action.C
        if round_num < r - 2:
            k_t = math.ceil((n - 1) * (2.0 / 3.0))
        else:
            k_t = math.ceil((n - 1) * (1.0 / 2.0))
        if current_stock < 2 * n:
            return Action.C
        c_t = history.opponent_cooperators[-1]
        if current_stock > capacity * 0.75 and c_t >= k_t - 1:
            return Action.C
        if current_stock < capacity * 0.25:
            if round_num > 1:
                prev_stock = history.my_payoffs[-1]
                return Action.C
            else:
                return Action.C
        if current_stock >= capacity * 0.9 and c_t < k_t:
            return Action.D
        if c_t >= k_t:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_54(BaseStrategy):
    """
    Adaptive Threshold Strategy: Exploit-and-Protect
    
    Self-interested strategy that exploits abundance via defection while
    protecting future payoffs by cooperating when stock threatens collapse.
    Defaults to defection in first round and unconditionally in the last round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.danger_threshold = game_description.capacity * 0.35
        self.abundance_threshold = game_description.capacity * 0.9
        self.recovery_threshold = game_description.capacity * 0.2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        if current_round == r - 2:
            if current_stock < self.recovery_threshold:
                return Action.C
            else:
                return Action.D
        if current_stock < self.danger_threshold:
            return Action.C
        if current_stock >= self.abundance_threshold:
            return Action.D
        cooperators_last_round = history.opponent_cooperators[-1]
        if current_stock < self.danger_threshold:
            return Action.C
        if cooperators_last_round < n / 2:
            return Action.C
        if current_round <= 3 and cooperators_last_round >= n - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_55(BaseStrategy):
    """
    Adaptive Threshold Strategy with Endgame Defection.
    
    Dynamically adjusts cooperation based on stock levels and opponent behavior.
    Defects in endgame and when stock is healthy with high opponent cooperation.
    Cooperates when stock is depleted or threatened to enable recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.D
        rounds_remaining = r - history.round_number
        depletion_threshold = max(2 * n, 0.3 * capacity)
        if current_stock <= depletion_threshold:
            return Action.C
        if rounds_remaining <= 2:
            return Action.D
        if current_stock >= 0.75 * capacity:
            observed_cooperators = history.opponent_cooperators[-1]
            if n > 1:
                cooperation_ratio = observed_cooperators / (n - 1)
                if cooperation_ratio >= 0.6:
                    return Action.D
        return Action.C

class Strategy_SELFINTERESTED_56(BaseStrategy):
    """
    Threshold-Responsive Exploitation Strategy for Common Pool Resource Game
    
    First round: Cooperate unconditionally.
    Subsequent rounds: Apply decision rule based on remaining rounds, stock level,
    and observed opponent cooperation in the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number + 1
        rho = r - t
        if rho <= 2:
            return Action.D
        if current_stock < capacity / 3:
            return Action.D
        cooperators_last_round = history.opponent_cooperators[-1]
        if cooperators_last_round >= math.ceil(n / 2):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_57(BaseStrategy):
    """
    Adaptive Conditional Cooperation with Endgame Strategy.
    
    Cooperates in first round, defects in last round, and uses a two-condition rule
    in intermediate rounds based on opponent cooperation rates and stock health.
    Triggers unconditional defection if stock drops below capacity/4.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.stock_collapse_triggered = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if current_stock < capacity / 4:
            self.stock_collapse_triggered = True
        if self.stock_collapse_triggered:
            return Action.D
        if round_num == r - 1:
            return Action.D
        if round_num == 0:
            return Action.C
        coop_count = history.opponent_cooperators[-1]
        defect_rate = (n - 1 - coop_count) / (n - 1) if n > 1 else 0.0
        condition1 = current_stock >= capacity / 2.5
        condition2 = defect_rate < 0.5
        if condition1 and condition2:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_58(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Management.
    
    Employs stock-level and opponent-behavior monitoring to switch between
    cooperation and defection. Cooperates when stock is critically low
    (requiring rebuilding) or when opponents demonstrate sufficient cooperation.
    Otherwise defects to maximize immediate payoff. Always defects in terminal rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.rebuild_threshold = game_description.capacity / 3
        self.cooperation_threshold = 0.4
        self.terminal_rounds = 2

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_opponents = n_players - 1
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number
        rounds_remaining = n_rounds - current_round
        if rounds_remaining <= self.terminal_rounds:
            return Action.D
        if current_stock < self.rebuild_threshold:
            return Action.C
        if current_round == 0:
            return Action.D
        observed_cooperators = history.opponent_cooperators[-1]
        if n_opponents <= 0:
            return Action.D
        opponent_coop_rate = observed_cooperators / n_opponents
        if opponent_coop_rate >= self.cooperation_threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_59(BaseStrategy):
    """
    Adaptive Threshold Defection with Stock Monitoring.
    
    Exploits high-stock periods through defection while pivoting to cooperation
    when the commons approaches collapse. Uses stock level and recent growth rates
    to dynamically adjust behavior based on trajectory.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.stock_history = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        self.stock_history.append(current_stock)
        if current_stock < 2 * self.n_players:
            return Action.C
        if round_num == 0:
            return Action.D
        if round_num == self.n_rounds - 1:
            return Action.D
        stock_remaining_threshold = self.capacity / 4
        if len(self.stock_history) >= 2:
            prev_stock = self.stock_history[-2]
            if prev_stock > 0:
                recent_growth_rate = (current_stock - prev_stock) / prev_stock
                if recent_growth_rate < -0.15:
                    stock_remaining_threshold = self.capacity / 6
        if current_stock > stock_remaining_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_60(BaseStrategy):
    """
    Adaptive Resource Defense Strategy - exploits cooperation when abundant,
    defends against collapse when stock depletes, and terminal defects.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        capacity = self.game_description.capacity
        n_players = self.game_description.n_players
        n_opponents = n_players - 1
        prev_cooperators = history.opponent_cooperators[-1]
        defector_count = n_opponents - prev_cooperators
        high_threshold = 2.0 / 3.0 * capacity
        low_threshold = capacity / 3.0
        if current_stock > high_threshold:
            if defector_count == 0:
                return Action.C
            else:
                return Action.D
        elif current_stock >= low_threshold:
            if defector_count >= 1:
                return Action.D
            else:
                return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_61(BaseStrategy):
    """
    Adaptive Depletion-Aware Strategy for Common Pool Resource Game.
    
    Cooperates when resources are abundant and others reciprocate.
    Defects predictively when facing stock collapse or exploitative opponents.
    Treats final 2 rounds as endgame where defection dominates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        capacity = self.game_description.capacity
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        rounds_remaining = n_rounds - history.round_number
        opponents_cooperating = history.opponent_cooperators[-1]
        opponent_cooperation_rate = opponents_cooperating / (n_players - 1) if n_players > 1 else 0.0
        if current_stock < capacity / 3:
            return Action.D
        if rounds_remaining <= 2 and current_stock >= capacity / 2:
            return Action.D
        if opponent_cooperation_rate < 0.4:
            return Action.D
        if current_stock < capacity / 2 and opponent_cooperation_rate < 0.6 and (rounds_remaining > 2):
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_62(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Cooperates in round 1, then conditionally cooperates if stock > 55% capacity
    and at least half of observed opponents cooperated in the previous round.
    Defects unconditionally in the final round. Switches to defection if stock
    drops below 30% capacity to avoid futile cooperation during resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_stock < 0.3 * self.capacity:
            return Action.D
        stock_threshold = self.capacity * 0.55
        cooperation_threshold = math.ceil(self.n_players / 2)
        observed_cooperators_last_round = history.opponent_cooperators[-1]
        if current_stock > stock_threshold and observed_cooperators_last_round >= cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_63(BaseStrategy):
    """
    Threshold-Based Adaptive Exploitation Strategy for Common Pool Resource Game.
    
    Defects when the resource stock is sufficiently high (≥ 3/5 capacity) to sustain
    exploitation, or in the final round. Cooperates otherwise to prevent resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = 3 / 5 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        if current_round == n_rounds - 1:
            return Action.D
        if current_stock >= self.threshold:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_64(BaseStrategy):
    """
    Adaptive Stock-Responsive Strategy: Cooperate when stock is depleted (≤ capacity/2), 
    defect when abundant (> capacity/2). Always defect in final round to exploit the absence 
    of a future horizon.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = game_description.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        round_number = history.round_number
        if round_number == n_rounds - 1:
            return Action.D
        if current_stock <= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_65(BaseStrategy):
    """
    Adaptive Defection with Stock-Conditional Cooperation.
    
    Cooperates initially to gather signals, always defects in the final round,
    and in middle rounds applies a stock-dependent decision rule that balances
    immediate extraction gains against future sustainability based on opponent
    cooperation rates and remaining game length.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.critical_depletion = 0.15 * game_description.capacity
        self.low_stock = 0.4 * game_description.capacity
        self.healthy_stock = 0.65 * game_description.capacity
        self.coop_threshold = 0.65

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num == self.game_description.n_rounds - 1:
            return Action.D
        n_opponents = self.game_description.n_players - 1
        if n_opponents <= 0:
            return Action.D
        coop_count = history.opponent_cooperators[-1]
        coop_rate = coop_count / n_opponents
        s = current_stock
        if s <= self.critical_depletion:
            return Action.D
        elif s <= self.low_stock:
            return Action.D
        elif s >= self.healthy_stock:
            remaining_rounds = self.game_description.n_rounds - round_num
            endgame_threshold = self.game_description.n_rounds / 3
            if coop_rate >= self.coop_threshold and remaining_rounds > endgame_threshold:
                return Action.C
            else:
                return Action.D
        elif coop_rate > 0.75:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_66(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Combines terminal-round defection, dynamic stock thresholds, and cooperation-rate
    adaptation to balance exploitation of abundance with sustainability.
    
    Decision Rule:
    - Last round: DEFECT
    - Stock collapse (< 0.01): COOPERATE
    - High opponent cooperation (≥ 0.75): COOPERATE
    - Low opponent cooperation (≤ 0.25): DEFECT if stock > threshold
    - Medium cooperation: DEFECT if stock > threshold AND cooperation < 0.5
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = float(game_description.capacity)
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == self.n_rounds - 1:
            return Action.D
        if current_stock < 0.01:
            return Action.C
        if round_number == 0:
            c_obs = 0.5
        else:
            cooperating_opponents = history.opponent_cooperators[-1]
            c_obs = cooperating_opponents / (self.n_players - 1)
        rounds_remaining = self.n_rounds - round_number
        s_crit = self.capacity * (1.0 - 1.0 / (2.0 + rounds_remaining))
        if c_obs >= 0.75:
            return Action.C
        elif c_obs <= 0.25:
            if current_stock > s_crit:
                return Action.D
            else:
                return Action.C
        elif current_stock > s_crit and c_obs < 0.5:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_67(BaseStrategy):
    """
    Adaptive cooperation strategy for Common Pool Resource Game.
    Cooperates initially to preserve stock, but switches to defection when:
    - Opponent defection rate exceeds a depletion-aware tolerance threshold
    - Stock is heavily depleted
    - Final rounds (≤2 rounds remaining)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        cooperators_last_round = history.opponent_cooperators[-1]
        defectors_last_round = n - 1 - cooperators_last_round
        def_rate = defectors_last_round / (n - 1) if n > 1 else 0.0
        depletion = max(0.0, (capacity - current_stock) / capacity)
        rounds_left = r - current_round
        tolerance = 0.4 - 0.15 * depletion
        if rounds_left <= 2:
            return Action.D
        elif def_rate > tolerance:
            return Action.D
        elif current_stock < 0.1 * capacity:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_68(BaseStrategy):
    """
    Adaptive Sustainability Strategy for Common Pool Resource Game.
    Cooperates when stock is healthy (≥50% capacity) and opponents are 
    sufficiently cooperative (≥65% average cooperation rate).
    Defects in endgame, when stock is critically depleted, or when 
    opponents defect heavily.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        rounds_left = r - current_round
        if rounds_left <= 1:
            return Action.D
        if stock_ratio < 0.1:
            return Action.D
        if rounds_left <= 2:
            return Action.D
        if current_round == 0:
            avg_cooperation_rate = 0.5
        else:
            total_cooperators = float(np.sum(history.opponent_cooperators[:current_round]))
            total_possible = (n - 1) * current_round
            avg_cooperation_rate = total_cooperators / total_possible if total_possible > 0 else 0.5
        if stock_ratio >= 0.5 and avg_cooperation_rate >= 0.65:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_69(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    Cooperates when pool is healthy and opponents are cooperative;
    defects when pool is depleted, opponents defect heavily, or few rounds remain.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        rounds_remaining = self.game_description.n_rounds - history.round_number
        capacity = self.game_description.capacity
        n_players = self.game_description.n_players
        if rounds_remaining <= 2:
            return Action.D
        if current_stock < 0.25 * capacity:
            return Action.D
        n_opponents = n_players - 1
        opponent_cooperators_last_round = history.opponent_cooperators[-1]
        opponent_defection_rate = (n_opponents - opponent_cooperators_last_round) / max(n_opponents, 1)
        if current_stock < 0.5 * capacity:
            if opponent_defection_rate > 0.3:
                return Action.D
            else:
                return Action.C
        if current_stock < 0.75 * capacity:
            if opponent_defection_rate > 0.4:
                return Action.D
            else:
                return Action.C
        if opponent_defection_rate > 0.5:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_70(BaseStrategy):
    """
    Adaptive Defection with Stock-Based Stability Control.
    
    Uses a dynamically adjusted critical threshold based on current stock and 
    rounds remaining. Cooperates when stock is depleted or when defection would 
    be too risky given the time horizon. Defects aggressively when stock is 
    high and sufficient rounds remain for recovery, or in final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = float(game_description.capacity)
        self.low_stock_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.D
        if current_stock <= 0:
            return Action.C
        rounds_left = self.n_rounds - history.round_number
        critical_threshold = self.capacity * (1.0 - rounds_left / (2.0 * self.n_rounds))
        k_prev = history.opponent_cooperators[-1]
        if k_prev < self.n_players / 2.0:
            critical_threshold -= 0.1 * self.capacity
        elif history.round_number >= 2:
            k_prev2 = history.opponent_cooperators[-2]
            if k_prev >= self.n_players / 2.0 and k_prev2 >= self.n_players / 2.0:
                critical_threshold += 0.05 * self.capacity
        if current_stock < self.capacity / 4.0:
            self.low_stock_rounds += 1
        else:
            self.low_stock_rounds = 0
        if self.low_stock_rounds >= 2:
            return Action.C
        if current_stock <= self.capacity / 3.0:
            return Action.C
        elif current_stock <= critical_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_71(BaseStrategy):
    """
    Adaptive Depletion-Triggered Strategy for Common Pool Resource Game.
    Cooperates when stock is critically endangered, when defection is prevalent 
    with fragile stock levels, or in the final round with depleted stock.
    Otherwise defects to maximize immediate payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_stock <= 0.3 * capacity:
            return Action.C
        if current_stock <= 0.55 * capacity:
            n_opponents = n_players - 1
            if n_opponents > 0:
                cooperators_prev = history.opponent_cooperators[-1]
                defectors_prev = n_opponents - cooperators_prev
                defection_rate = defectors_prev / n_opponents
                if defection_rate > 0.5:
                    return Action.C
        is_final_round = current_round == n_rounds - 1
        if is_final_round and current_stock <= 0.4 * capacity:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_72(BaseStrategy):
    """
    Adaptive Extraction Strategy with Endgame Defection.
    
    Cooperates only when stock is sufficiently abundant, others demonstrate 
    cooperation, and future rounds justify restraint. Defaults to defection,
    particularly in early and final rounds, and when stock is depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if self.r == 2:
            return Action.D
        if self.capacity <= 3 * self.n:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if round_num == 0:
            return Action.D
        if round_num >= self.r - 2:
            return Action.D
        n_opponents = self.n - 1
        cooperators_last_round = history.opponent_cooperators[-1]
        if n_opponents > 0:
            proportion_cooperators = cooperators_last_round / n_opponents
        else:
            proportion_cooperators = 0.0
        rounds_remaining = self.r - round_num
        if self.n == 2:
            threshold_high_stock = 0.9
            threshold_medium_stock = 0.9
        else:
            threshold_high_stock = (self.n - 1) / (self.n + 1)
            threshold_medium_stock = 0.7
        if current_stock < self.capacity / 3:
            return Action.D
        elif current_stock >= self.capacity / 2:
            if proportion_cooperators >= threshold_high_stock:
                return Action.C
            else:
                return Action.D
        elif rounds_remaining >= self.n and proportion_cooperators >= threshold_medium_stock:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_73(BaseStrategy):
    """
    Stock-Responsive Adaptive Strategy for Common Pool Resource Game.
    
    Plays Cooperate (C) if and only if ALL of the following hold:
    1. Current stock > capacity/4
    2. At least ⌈(n-1)/3⌉ opponents cooperated in previous round
    3. More than 1 round remains
    
    Always defects in the final round.
    In the first round, cooperates only if stock > capacity/4 and rounds > 1.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.cooperation_threshold = math.ceil((self.n_players - 1) / 3)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_stock <= self.capacity / 4:
            return Action.D
        rounds_remaining = self.n_rounds - current_round
        if rounds_remaining <= 1:
            return Action.D
        if current_round == 0:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        if cooperators_last_round < self.cooperation_threshold:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_74(BaseStrategy):
    """
    Adaptive Threshold with Endgame Defection strategy for Common Pool Resource Game.
    
    Monitors resource sustainability and adjusts cooperation based on stock levels,
    opponent behavior, and rounds remaining. Balances immediate exploitation against
    long-term resource preservation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        if history.round_number == 0:
            if capacity >= 3 * n:
                return Action.D
            else:
                return Action.C
        rounds_remaining = n_rounds - history.round_number
        if current_stock < 0.1 * capacity:
            return Action.C
        k = history.opponent_cooperators[-1]
        if k >= n - 2:
            return Action.D
        if history.round_number == n_rounds - 1:
            if current_stock >= 0.5 * capacity:
                return Action.D
            else:
                return Action.C
        if current_stock <= 0.45 * capacity:
            return Action.C
        my_consumption = current_stock / (2 * n)
        opponent_consumption = k * (current_stock / (2 * n)) + (n - 1 - k) * (current_stock / n)
        total_consumption = my_consumption + opponent_consumption
        stock_after_consumption = max(0.0, current_stock - total_consumption)
        growth = 2 * stock_after_consumption * (1 - stock_after_consumption / capacity)
        estimated_stock_next = min(stock_after_consumption + growth, capacity)
        if estimated_stock_next <= 0.4 * capacity and rounds_remaining > 1:
            return Action.C
        if rounds_remaining == 1 and current_stock < capacity * 0.5:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_75(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Cooperates when stock is healthy, when sufficient rounds remain for regeneration,
    or when opponent cooperation rate signals continued pool viability.
    Defects unconditionally in the final round and when stock collapses despite
    cooperation attempts.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.consecutive_low_stock_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        rounds_remaining = r - current_round
        if current_round == 0:
            opponent_coop_rate = 0.0
        else:
            total_cooperators = np.sum(history.opponent_cooperators[:current_round])
            n_opponents = n - 1
            past_rounds = current_round
            if n_opponents > 0 and past_rounds > 0:
                opponent_coop_rate = total_cooperators / (n_opponents * past_rounds)
            else:
                opponent_coop_rate = 0.0
        if stock_ratio < 0.3:
            self.consecutive_low_stock_rounds += 1
        else:
            self.consecutive_low_stock_rounds = 0
        if self.consecutive_low_stock_rounds >= 2:
            return Action.D
        if stock_ratio >= 0.65:
            return Action.C
        if stock_ratio >= 0.45 and rounds_remaining >= 3:
            return Action.C
        if stock_ratio >= 0.35 and opponent_coop_rate > 0.55:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_76(BaseStrategy):
    """
    Adaptive stock-threshold strategy with opponent monitoring.
    
    Combines opponent cooperation tracking with stock sustainability thresholds
    to decide between cooperation and defection in a common pool resource game.
    
    Decision rule:
    - Final round: Defect (endgame dominance)
    - First round: Cooperate (assume full cooperation)
    - Other rounds: Defect if opponents mostly defect (< 40%), otherwise cooperate
      only if stock is above sustainability threshold (capacity / 3n)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        num_opponents = n_players - 1
        opponent_cooperators_last_round = history.opponent_cooperators[-1]
        cooperation_rate = opponent_cooperators_last_round / num_opponents
        if cooperation_rate < 0.4:
            return Action.D
        sustainability_threshold = capacity / (3 * n_players)
        if current_stock > sustainability_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_77(BaseStrategy):
    """
    Stock-Dependent Adaptive Defection Strategy.
    
    Cooperates only when the pool remains sufficiently healthy AND observed 
    opponent cooperation suggests the resource won't collapse. Defects in final 
    rounds and when stock shows significant depletion, or when opponents are 
    predominantly defecting.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.n_players = game_description.n_players
        self.endgame_start = self.n_rounds - max(1, math.floor(math.log2(self.n_rounds)))

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_round >= self.endgame_start:
            return Action.D
        depletion_pressure = (self.capacity - current_stock) / self.capacity if self.capacity > 0 else 1.0
        if current_round == 0:
            k = 0
        else:
            k = history.opponent_cooperators[-1]
        theta = 1.0 - (depletion_pressure + k / self.n_players)
        if theta > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_78(BaseStrategy):
    """
    Adaptive Stock-Aware Strategy for Common Pool Resource Game.
    
    Dynamically adjusts cooperation based on stock levels, remaining rounds,
    and observed opponent behavior to maximize payoff while preventing resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        rounds_remaining = r - current_round
        if current_round == 0:
            return Action.C
        if rounds_remaining == 1:
            return Action.D
        if current_stock <= 0.25 * capacity:
            return Action.C
        if current_stock >= 0.75 * capacity and rounds_remaining <= r / 2:
            return Action.D
        if current_stock < 0.5 * capacity:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        cooperation_threshold = 0.6 * (n - 1)
        if cooperators_last_round >= cooperation_threshold:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_79(BaseStrategy):
    """
    Stock-Responsive Adaptive Strategy for Common Pool Resource Game.
    
    Defects in final round unconditionally. In earlier rounds, defects only when
    both stock is healthy (≥0.65×capacity) AND opponents show low cooperation (<40%).
    Starts with cooperation and maintains it if stock is critically low (<0.1×capacity)
    to allow recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < 0.1 * self.game_description.capacity:
            return Action.C
        stock_threshold = 0.65 * self.game_description.capacity
        stock_healthy = current_stock >= stock_threshold
        n_opponents = self.game_description.n_players - 1
        if n_opponents > 0:
            cooperators_last_round = history.opponent_cooperators[-1]
            opponent_cooperation_low = cooperators_last_round / n_opponents < 0.4
        else:
            opponent_cooperation_low = False
        if stock_healthy and opponent_cooperation_low:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_80(BaseStrategy):
    """
    Adaptive Resource Stewardship Strategy for Common Pool Resource Game.
    
    Cooperates in early rounds when stock is healthy and opponents cooperate,
    but defects in the final round and when the resource is depleted or 
    opponents predominantly defect. Round 1 establishes cooperation baseline.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        if current_stock < capacity * 0.35:
            return Action.D
        opponent_coop_count = history.opponent_cooperators[-1]
        n_opponents = n_players - 1
        if n_opponents <= 0:
            return Action.C
        opponent_coop_rate = opponent_coop_count / n_opponents
        if opponent_coop_rate < 0.5:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_81(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Decides cooperation vs. defection based on resource health, time remaining,
    and observed opponent behavior. Cooperates when stock is critical or moderate,
    defects when stock is abundant. Special handling for first and last rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        rounds_remaining = r - current_round
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            if rounds_remaining > n:
                return Action.C
            else:
                return Action.D
        health = current_stock / capacity if capacity > 0 else 0
        if health < 0.15:
            return Action.C
        observed_cooperators = history.opponent_cooperators[-1]
        n_opponents = n - 1
        defection_rate_opponents = (n_opponents - observed_cooperators) / n_opponents if n_opponents > 0 else 0
        base_threshold = 0.4 + (1.0 - defection_rate_opponents) * 0.15
        time_decay = (current_round - 1) / r if r > 1 else 0
        adjusted_threshold = base_threshold + (1.0 - time_decay) * 0.25
        if health > adjusted_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_82(BaseStrategy):
    """
    Adaptive Cooperation-Collapse Strategy for Common Pool Resource Game.
    
    - Round 1 (index 0): Cooperate unconditionally as a probe
    - Rounds 2 to r-2 (indices 1 to r-3): Cooperate if ≥50% of opponents cooperated 
      in previous round, else Defect
    - Rounds r-1 and r (indices r-2 and r-1): Defect unconditionally to salvage resources
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.n_opponents = self.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round >= self.n_rounds - 2:
            return Action.D
        previous_coop_count = history.opponent_cooperators[-1]
        if previous_coop_count >= 0.5 * self.n_opponents:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_83(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Defects by default, cooperates selectively when stock is healthy (≥2/3 capacity)
    and opponents show reciprocal cooperation (≥50% cooperation rate).
    Always cooperates in round 1 to establish baseline, defects in final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if self.n_rounds < 4:
            stock_threshold = self.capacity / 2.0
        else:
            stock_threshold = 2.0 / 3.0 * self.capacity
        if current_stock < self.capacity / 3.0:
            return Action.D
        if current_stock < stock_threshold:
            return Action.D
        n_opponents = self.n_players - 1
        if n_opponents > 0:
            cooperators_last_round = history.opponent_cooperators[-1]
            cooperation_rate = cooperators_last_round / n_opponents
            if cooperation_rate >= 0.5:
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_84(BaseStrategy):
    """
    Adaptive Stock-Contingent Strategy with Endgame Defection.
    
    Cooperates when stock is healthy, defects when depleted or in final round,
    and uses reciprocal cooperation in the intermediate zone. Exploits endgame
    scarcity while matching opponent behavior when stock recovery is possible.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number == n_rounds - 1:
            return Action.D
        if current_stock <= 0.2 * capacity:
            return Action.D
        if current_stock >= 0.5 * capacity:
            return Action.C
        if round_number == 0:
            return Action.C
        observed_cooperators = history.opponent_cooperators[-1]
        observed_coop_rate = observed_cooperators / (n - 1)
        if observed_coop_rate > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_85(BaseStrategy):
    """
    Stock-Reactive Defection Strategy with Conditional Cooperation.
    Prioritizes self-interest through defection while using cooperation strategically
    to prevent resource collapse when stock levels are critically low.
    Cooperates only when necessary to stabilize the resource for future exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.critical_threshold = self.capacity / 3
        self.danger_threshold = 2 * self.capacity / 3

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.D
        rounds_remaining = self.n_rounds - history.round_number
        if rounds_remaining == 1:
            return Action.D
        num_cooperators_last_round = history.opponent_cooperators[-1]
        if current_stock <= self.critical_threshold:
            return Action.C
        if current_stock > self.danger_threshold:
            return Action.D
        if num_cooperators_last_round < self.n_players / 2:
            if current_stock <= 1.5 * self.critical_threshold:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_86(BaseStrategy):
    """
    Adaptive Stock-Level Exploitation Strategy.
    
    Defects by default to maximize payoff, but cooperates strategically when:
    1. First round (to probe opponents and gather information)
    2. Stock falls below critical depletion threshold (to enable regrowth)
    3. Stock is depleted but opponents are sustaining it (defensive cooperation)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        n = self.n_players
        capacity = self.capacity
        if round_number == self.n_rounds - 1:
            return Action.D
        if round_number == 0:
            return Action.C
        depletion_threshold = capacity / (4.0 * n)
        recovery_threshold = capacity / (2.0 * n)
        if current_stock < depletion_threshold:
            return Action.C
        elif current_stock < recovery_threshold:
            observed_cooperators = history.opponent_cooperators[-1]
            cooperation_rate = observed_cooperators / (n - 1)
            if cooperation_rate > 0.6:
                return Action.D
            else:
                return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_87(BaseStrategy):
    """
    Adaptive Stock-Depletion Strategy for Common Pool Resource Game.
    
    Cooperates when the stock can sustain it; defects when resource scarcity becomes 
    acute or the future is too short to protect. Balances long-term collective resource 
    preservation with short-term individual extraction opportunism.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.D
        rounds_remaining = r - current_round
        depletion_ratio = current_stock / capacity if capacity > 0 else 0
        n_opponents = n - 1
        opponent_cooperation_rate = history.opponent_cooperators[-1] / n_opponents if n_opponents > 0 else 0
        if current_stock < 2 * n:
            return Action.D
        if rounds_remaining <= 2:
            return Action.D
        if depletion_ratio < 0.3 and rounds_remaining <= 4:
            return Action.D
        if opponent_cooperation_rate < 0.4:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_88(BaseStrategy):
    """
    Greedy Pool-Depletion Strategy: Maximizes self-interested payoff by exploiting abundant 
    resources when others cooperate or stock is high, switching to cooperation only when 
    pool depletion threatens future earnings, and claiming maximum value in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.n_rounds - 1:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        n_opponents = self.n_players - 1
        c_prev = prev_cooperators / n_opponents if n_opponents > 0 else 0.0
        depletion_risk = (1 - current_stock / self.capacity) * (1 - c_prev)
        if depletion_risk > 0.4 or current_stock < self.capacity / 3:
            return Action.C
        elif current_stock > self.capacity * 0.7 and c_prev > 0.5:
            return Action.D
        elif c_prev >= 0.5:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_89(BaseStrategy):
    """
    Adaptive Depletion Strategy for Common Pool Resource Game.
    
    Defects in the first round to establish dominance. In middle rounds, conditionally
    cooperates only when the pool is healthy (stock ≥ 50% capacity) and others show
    restraint (defection rate ≤ 33%). Defects when stock is critically depleted
    (≤ 25% capacity), few rounds remain (≤ 2), or defection becomes endemic (≥ 50%).
    Defects unconditionally in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number == n_rounds - 1:
            return Action.D
        rounds_remaining = n_rounds - round_number
        opponent_cooperators_prev = history.opponent_cooperators[-1]
        num_opponents = n_players - 1
        num_opponent_defectors = num_opponents - opponent_cooperators_prev
        defection_rate = num_opponent_defectors / num_opponents if num_opponents > 0 else 0.0
        if current_stock <= 0.25 * capacity:
            return Action.D
        if rounds_remaining <= 2:
            return Action.D
        if defection_rate >= 0.5:
            return Action.D
        if current_stock >= 0.5 * capacity and defection_rate <= 1.0 / 3.0:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_90(BaseStrategy):
    """
    Adaptive Exploitation Strategy with Stock-Aware Switching.
    
    Cooperates when opponents show majority cooperation, stock is healthy,
    and there are sufficient rounds remaining. Defects in end-game, on stock
    collapse, or when opponents predominantly defect. Signals initial willingness
    with cooperation in round 1, then adapts based on observed coop_rate and
    stock_ratio to balance exploitation against resource sustainability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.n_rounds - 1:
            return Action.D
        stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0
        if stock_ratio < 0.2:
            return Action.D
        cooperators_observed = history.opponent_cooperators[-1]
        coop_rate = cooperators_observed / (self.n_players - 1) if self.n_players > 1 else 0
        if coop_rate < 0.3 and stock_ratio < 0.5:
            return Action.D
        rounds_left = self.n_rounds - history.round_number
        end_game_threshold = self.n_rounds / 4
        condition_sustainable = coop_rate >= 0.5 and stock_ratio >= 0.35 and (rounds_left > end_game_threshold)
        condition_high_coop = coop_rate >= 0.75 and stock_ratio >= 0.5
        if condition_sustainable or condition_high_coop:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_91(BaseStrategy):
    """
    Adaptive Depletion Strategy for Common Pool Resource Game.
    
    Dynamically adjusts cooperation based on stock health and opponent behavior.
    - Always defects in final round and first round
    - In middle rounds, cooperates only if stock is healthy AND sufficient opponents cooperate
    - Enters defection spiral if low cooperation persists for two consecutive rounds
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.defection_spiral_counter = 0
        self.in_defection_spiral = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        stock_health = current_stock / self.game_description.capacity
        c_prev = history.opponent_cooperators[-1]
        coop_rate = c_prev / (self.game_description.n_players - 1)
        if self.in_defection_spiral:
            if stock_health > 0.4:
                self.in_defection_spiral = False
                self.defection_spiral_counter = 0
            else:
                return Action.D
        if coop_rate <= 0.3:
            self.defection_spiral_counter += 1
            if self.defection_spiral_counter >= 2:
                self.in_defection_spiral = True
                return Action.D
        else:
            self.defection_spiral_counter = 0
        if stock_health >= 0.5:
            return Action.C if coop_rate > 0.5 else Action.D
        elif stock_health >= 0.3:
            return Action.C if coop_rate > 0.65 else Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_92(BaseStrategy):
    """
    Adaptive Stock-Conditional Strategy for Common Pool Resource Game.
    
    Dynamically adjusts between cooperation and defection based on current stock health
    and observed opponent cooperation rates. Uses four decision phases:
    1. Collapse Prevention: Defect if stock depleted to <20% of capacity
    2. Endgame: Defect in final 2 rounds to maximize immediate payoff
    3. Adaptation: Balance cooperation with opponent restraint and stock abundance
    4. First Round: Always cooperate to establish baseline and gather information
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        rounds_remaining = r - round_number
        if round_number == 0:
            return Action.C
        if current_stock < 0.2 * capacity:
            return Action.D
        if rounds_remaining <= 2:
            return Action.D
        n_opponents = n - 1
        if n_opponents > 0:
            c_rate = history.opponent_cooperators[-1] / n_opponents
        else:
            c_rate = 0.0
        if current_stock >= 0.7 * capacity and c_rate >= 0.4:
            return Action.C
        if current_stock >= 0.5 * capacity and c_rate >= 0.6:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_93(BaseStrategy):
    """
    Adaptive threshold-based strategy for Common Pool Resource Game.
    
    Prioritizes present extraction (defect early, defect when stock low) while
    protecting future payoffs when recovery is sustainable. Uses round number,
    stock level, and opponent cooperation history to decide C vs D.
    
    Key logic:
    - Final round & near-end: defect
    - Critical stock depletion: defect  
    - Healthy stock + sufficient cooperation: cooperate
    - Severely depleted: defect
    - Mid-range: evaluate trajectory and cooperate if sustainable
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            if self.capacity >= 1.5 * 2 * self.n_players:
                return Action.C
            else:
                return Action.D
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_stock <= 2 * self.n_players:
            return Action.D
        if current_stock < 0.25 * self.capacity:
            return Action.D
        remaining_rounds = self.n_rounds - current_round
        if remaining_rounds <= 2:
            return Action.D
        if current_stock >= self.capacity:
            return Action.C
        opponents_cooperated = int(history.opponent_cooperators[-1])
        cooperation_majority = (self.n_players - 1) / 2.0
        if opponents_cooperated == 0:
            return Action.D
        if opponents_cooperated == self.n_players - 1:
            return Action.C
        if current_stock >= 0.5 * self.capacity and opponents_cooperated >= cooperation_majority:
            return Action.C
        if current_stock < 0.3 * self.capacity:
            return Action.D
        consumption_per_cooperator = current_stock / (2.0 * self.n_players)
        consumption_per_defector = current_stock / self.n_players
        n_defectors = self.n_players - 1 - opponents_cooperated
        estimated_consumption = opponents_cooperated * consumption_per_cooperator + n_defectors * consumption_per_defector
        remaining_after = current_stock - estimated_consumption
        remaining_after = max(0.0, remaining_after)
        if self.capacity > 0:
            growth_factor = 1.0 - remaining_after / self.capacity
            projected_growth = 2.0 * remaining_after * growth_factor
        else:
            projected_growth = 0.0
        stock_next_round = min(remaining_after + projected_growth, self.capacity)
        if stock_next_round >= 0.5 * self.capacity:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_94(BaseStrategy):
    """
    Adaptive Sustainability with Opportunistic Defection.
    
    Maintains cooperation conditional on stock sustainability and opponent cooperation rates.
    Transitions through three phases based on stock depletion:
    - Abundance (≥55% of capacity): Cooperate if opponents reciprocate (≥50%)
    - Decline (30-55% of capacity): Cooperate only if most opponents cooperate (≥75%)
    - Crisis (<30% of capacity): Defect to maximize immediate extraction
    Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        if history.round_number == n_rounds - 1:
            return Action.D
        stock_depletion = current_stock / capacity if capacity > 0 else 0.0
        n_opponents = n_players - 1
        if n_opponents > 0:
            observed_coop_rate = history.opponent_cooperators[-1] / n_opponents
        else:
            observed_coop_rate = 0.0
        if stock_depletion >= 0.55:
            if observed_coop_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        elif stock_depletion >= 0.3:
            if observed_coop_rate >= 0.75:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_95(BaseStrategy):
    """
    Stock-Adaptive Defection with Endgame Exploitation.
    
    Defects in endgame (final two rounds), when stock is depleted, or when 
    cooperation is low. Cooperates only in the middle game when opponents 
    demonstrate sufficient restraint (≥60% cooperation rate).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_stock <= 2 * n:
            return Action.D
        if r - current_round <= 2:
            return Action.D
        if current_round == 0:
            observed_cooperation_rate = 0.5
        else:
            num_cooperators = history.opponent_cooperators[-1]
            num_opponents = n - 1
            if num_opponents > 0:
                observed_cooperation_rate = num_cooperators / num_opponents
            else:
                observed_cooperation_rate = 0.5
        if observed_cooperation_rate >= 0.6:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_96(BaseStrategy):
    """
    Adaptive Stock-Responsive Strategy with Punishment
    
    Defects in the final round (no future payoff from cooperation).
    In earlier rounds, cooperates only if stock is healthy (≥55% of capacity)
    AND at least half of all players (n/2) cooperated in the previous round.
    Tracks opponent behavior and responds to stock depletion by defecting
    until conditions improve. Cooperates in round 1 since stock is at maximum.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.stock_threshold = 0.55 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        if current_round == n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        stock_healthy = current_stock >= self.stock_threshold
        cooperators_last_round = history.opponent_cooperators[-1]
        majority_cooperated = cooperators_last_round >= n_players // 2
        if stock_healthy and majority_cooperated:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_97(BaseStrategy):
    """
    Cooperative Threshold Strategy with Last-Round Defection.
    
    Decision rule:
    - Round 0: Cooperate (probe opponents)
    - Rounds 1 to r-2: Cooperate if stock > capacity/4 AND observed cooperators ≥ ⌈(n-1)/2⌉, else defect
    - Round r-1: Defect (final round exploitation)
    
    Rationale: Cooperation maintains the resource pool when stock is healthy and others cooperate.
    Defection occurs when stock collapses or in the final round when future growth has no value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        stock_threshold = capacity / 4
        if current_stock <= stock_threshold:
            return Action.D
        observed_cooperators = history.opponent_cooperators[-1]
        majority_threshold = math.ceil((n - 1) / 2)
        if observed_cooperators >= majority_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_98(BaseStrategy):
    """
    Stock Guard Strategy: Cooperate when stock is healthy and sufficient reciprocal 
    cooperation is observed; defect when stock is critical or opponents are primarily defecting.
    Adjusts risk tolerance in the final round based on sustainability and reciprocal support.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_stock = round(current_stock, 4)
        if current_stock <= 0.01:
            return Action.D
        current_round = history.round_number
        is_final_round = current_round == r - 1
        if current_round == 0:
            coop_rate = 0.5
        else:
            cooperators_observed = history.opponent_cooperators[-1]
            n_opponents = n - 1
            if n_opponents > 0:
                coop_rate = cooperators_observed / n_opponents
            else:
                coop_rate = 0.5
            coop_rate = round(coop_rate, 4)
        if not is_final_round:
            critical_threshold = round(2.5 * n, 4)
            if current_stock <= critical_threshold + 0.01:
                return Action.D
            if coop_rate >= 0.5 - 0.01:
                return Action.C
            else:
                return Action.D
        capacity_half = round(capacity / 2, 4)
        if current_stock <= capacity_half + 0.01:
            return Action.D
        if coop_rate >= 0.4 - 0.01:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_99(BaseStrategy):
    """
    Threshold-based adaptive defection strategy for common pool resource games.
    
    Decision rule:
    - Final round: Always defect (no future rounds, maximize extraction)
    - Stock ≤ capacity/3: Cooperate (preserve regeneration capacity)
    - Otherwise: Defect (extract maximum while stock permits)
    
    This balances short-term extraction in high-stock periods with long-term
    viability by automatically shifting to cooperation as stock depletes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = game_description.capacity / 3

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        final_round = self.game_description.n_rounds - 1
        if current_round == final_round:
            return Action.D
        if current_stock <= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_100(BaseStrategy):
    """
    Adaptive Threshold Strategy with Endgame Defection.
    
    Cooperates in early/mid game if opponents are sufficiently cooperative (≥60% cooperation rate)
    and stock is healthy (≥50% of capacity). Always defects in final round and when stock depletes.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        previous_opponent_cooperators = history.opponent_cooperators[-1]
        cooperation_rate = previous_opponent_cooperators / (n_players - 1)
        stock_threshold = 0.5 * capacity
        if cooperation_rate >= 0.6 and current_stock >= stock_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_101(BaseStrategy):
    """
    Adaptive Stock-Threshold Strategy for Common Pool Resource Game.
    
    Cooperate or defect based on: (1) stock health relative to capacity,
    (2) observed opponent defection frequency, (3) rounds remaining.
    
    Core logic:
    - Always defect in final round
    - Cooperate when stock is critically low (< 2n)
    - Adapt based on stock ratio thresholds (0.30, 0.65) and opponent behavior
    - Adjust strategy based on rounds remaining
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        final_round = self.n_rounds - 1
        if current_round == final_round:
            return Action.D
        if current_stock < 2 * self.n_players:
            return Action.C
        stock_ratio = current_stock / self.capacity
        n_opponents = self.n_players - 1
        opponents_cooperated_last_round = history.opponent_cooperators[-1]
        opponents_defected_last_round = n_opponents - opponents_cooperated_last_round
        if n_opponents > 0:
            observed_defection_rate = opponents_defected_last_round / n_opponents
        else:
            observed_defection_rate = 0.0
        rounds_left = self.n_rounds - current_round
        if stock_ratio < 0.3:
            return Action.C
        elif stock_ratio < 0.65:
            if observed_defection_rate > 0.5:
                return Action.D
            else:
                return Action.C
        elif rounds_left >= 3:
            if observed_defection_rate > 0.4:
                return Action.D
            else:
                return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_102(BaseStrategy):
    """
    Adaptive Depletion-Contingent Cooperator
    
    Balances free-riding incentives with collapse avoidance by:
    - Always cooperating in round 1 (stock abundant, no history)
    - Always defecting in the final round (no future to protect)
    - In middle rounds, cooperating only when stock > capacity/3 AND
      majority of opponents cooperated in the previous round
    - Defecting immediately if stock reaches 0
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num == r - 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if current_stock <= capacity / 3:
            return Action.D
        opponent_cooperators_prev_round = history.opponent_cooperators[-1]
        majority_threshold = n / 2
        if opponent_cooperators_prev_round > majority_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_103(BaseStrategy):
    """
    Conditional Cooperation with Defection Triggers strategy for Common Pool Resource Game.
    
    - First round: Cooperate to explore
    - Final round: Defect (no future rounds, maximize immediate payoff)
    - Middle rounds: Conditionally cooperate based on opponent behavior and stock level
      * Defect if stock critically depleted (< 0.25 × capacity)
      * Cooperate if cooperation_rate ≥ 0.50 and stock ≥ 0.35 × capacity
      * Otherwise defect to maximize immediate payoff
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        opponents_cooperated_last_round = history.opponent_cooperators[-1]
        n_opponents = self.game_description.n_players - 1
        cooperation_rate = 0.0
        if n_opponents > 0:
            cooperation_rate = opponents_cooperated_last_round / n_opponents
        capacity = self.game_description.capacity
        if current_stock < 0.25 * capacity:
            return Action.D
        if cooperation_rate >= 0.5 and current_stock >= 0.35 * capacity:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_104(BaseStrategy):
    """
    Adaptive Stock-Responsive Strategy for Common Pool Resource Game.
    
    Phase-based decision logic:
    - Final round: Always defect to maximize extraction
    - First round: Always cooperate to signal willingness
    - Earlier rounds: Respond adaptively to opponent cooperation and stock health
    
    Decision rule balances self-interest with resource sustainability by:
    1. Punishing critical stock depletion
    2. Cooperating when opponents cooperate and stock is healthy
    3. Defecting against defection-dominated groups with weakened stocks
    4. Defaulting to cooperation as a sustainable baseline
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number == n_rounds - 1:
            return Action.D
        n_opponents = n_players - 1
        if n_opponents <= 0:
            return Action.C
        opponent_cooperation_rate = history.opponent_cooperators[-1] / n_opponents
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        is_stock_critical = current_stock < 0.15 * capacity
        if is_stock_critical:
            return Action.D
        elif opponent_cooperation_rate >= 0.5 and stock_ratio >= 0.5:
            return Action.C
        elif opponent_cooperation_rate >= 0.75:
            return Action.C
        elif opponent_cooperation_rate < 0.25 and stock_ratio < 0.6:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_105(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Cooperates if at least one of these conditions holds:
    1. Stock critically low (< 2.5n) - damage control
    2. Opponent cooperation rate ≥ 60% AND stock ≥ 3n - cooperative momentum
    3. Final round AND stock < 1.5n - last chance to prevent collapse
    
    Otherwise defects to maximize immediate payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        if history.round_number == 0:
            return Action.D
        stock_sustainability_bound = 2.5 * n
        critical_stock_level = 1.5 * n
        low_cooperation_threshold = 0.6
        minimum_sustainability = 3 * n
        if current_stock < stock_sustainability_bound:
            return Action.C
        remaining_rounds = self.n_rounds - history.round_number
        if remaining_rounds == 1:
            if current_stock < critical_stock_level:
                return Action.C
            else:
                return Action.D
        n_opponents = n - 1
        rounds_completed = history.round_number
        if n_opponents > 0 and rounds_completed > 0:
            total_cooperators = int(np.sum(history.opponent_cooperators[:rounds_completed]))
            opponent_cooperation_rate = total_cooperators / (n_opponents * rounds_completed)
            if opponent_cooperation_rate >= low_cooperation_threshold and current_stock >= minimum_sustainability:
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_106(BaseStrategy):
    """
    Adaptive Depletion-Responsive Strategy for Common Pool Resource Game.
    
    Cooperates on first round to gather information, defects on final round,
    and adaptively responds in middle rounds based on observed cooperation rates
    and stock depletion levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number == self.n_rounds - 1:
            return Action.D
        opponents_cooperated_last_round = history.opponent_cooperators[-1]
        n_opponents = self.n_players - 1
        if n_opponents <= 0:
            return Action.D
        cooperation_rate = opponents_cooperated_last_round / n_opponents
        stock_depletion_ratio = current_stock / self.capacity if self.capacity > 0 else 0
        if stock_depletion_ratio < 0.25:
            return Action.D
        if cooperation_rate > 0.65 and stock_depletion_ratio > 0.4:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_107(BaseStrategy):
    """
    Adaptive Defection with Sustainability Testing.
    
    Round 1: Cooperate to establish baseline and signal willingness.
    Rounds 2-r-1: Cooperate if cooperation_rate >= 50% AND stock >= capacity/2, else Defect.
    Round r: Defect (final round yields no future retaliation).
    
    Adapts to both observed cooperation and stock state, abandoning cooperation
    when either signal suggests unsustainability.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number == n_rounds - 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        cooperators_observed = history.opponent_cooperators[-1]
        n_opponents = n_players - 1
        if n_opponents > 0:
            cooperation_rate = cooperators_observed / n_opponents
        else:
            cooperation_rate = 0.0
        if cooperation_rate >= 0.5 and current_stock >= capacity / 2:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_108(BaseStrategy):
    """
    Adaptive Threshold Strategy with Stock-Contingent Defection.
    
    Uses dynamic thresholds that decay over rounds, incorporating observed
    cooperation rates and current stock levels to decide between cooperation
    and defection. Exploits cooperation when resource is sustainable, but
    immediately defects when cooperation collapses or the final round approaches.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_stock >= 0.95 * self.capacity:
            return Action.D
        if current_stock < 1e-06:
            return Action.D
        threshold_t = 0.5 + 0.2 * (self.r - current_round) / self.r
        min_stock_t = self.capacity * (0.4 + 0.1 * (self.r - current_round) / self.r)
        if current_round == 0:
            if current_stock >= min_stock_t:
                return Action.C
            return Action.D
        cooperators_prev = history.opponent_cooperators[current_round - 1]
        n_opponents = self.n - 1
        if n_opponents <= 0:
            phi = 0.5
        else:
            phi = cooperators_prev / n_opponents
        if phi >= threshold_t and current_stock >= min_stock_t:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_109(BaseStrategy):
    """
    Adaptive Depletion with Stock-Based Thresholds.
    
    Balances sustainability exploitation (cooperate when stock is stable and 
    defection rates low) with opportunistic extraction (defect in end-game, 
    during stock collapse, or when opponents mostly defect).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.previous_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            self.previous_stock = current_stock
            return Action.C
        if current_stock <= 0:
            self.previous_stock = current_stock
            return Action.D
        round_number = history.round_number
        if round_number == r - 1:
            self.previous_stock = current_stock
            return Action.D
        if current_stock < capacity * 0.3:
            self.previous_stock = current_stock
            return Action.D
        cooperators = history.opponent_cooperators[-1]
        n_opponents = n - 1
        defectors = n_opponents - cooperators
        defection_rate = defectors / n_opponents if n_opponents > 0 else 0
        if defection_rate > 0.5:
            self.previous_stock = current_stock
            return Action.D
        if round_number > r * 0.75:
            if defection_rate > 0.2:
                self.previous_stock = current_stock
                return Action.D
        if self.previous_stock is not None and self.previous_stock > 0:
            if current_stock < self.previous_stock * 0.85 and defection_rate > 0.1:
                self.previous_stock = current_stock
                return Action.D
        self.previous_stock = current_stock
        return Action.C

class Strategy_SELFINTERESTED_110(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Cooperates in round 1 to establish reciprocity baseline.
    Applies dynamic decision rule in middle rounds based on stock level,
    opponent cooperation, and collapse prevention.
    Defects in final round to maximize extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        rounds_remaining = self.r - history.round_number
        if current_stock <= 0:
            return Action.D
        if rounds_remaining == 1:
            if current_stock <= 2 * self.n:
                return Action.C
            else:
                return Action.D
        if current_stock <= 0.4 * self.capacity:
            return Action.C
        if current_stock >= 0.6 * self.capacity:
            threshold = 0.5
        elif current_stock < 0.4 * self.capacity:
            threshold = 0.2
        else:
            threshold = 0.35
        if self.n == 2:
            threshold += 0.15
        cooperators_last_round = history.opponent_cooperators[-1]
        proportion_cooperating = cooperators_last_round / self.n
        if proportion_cooperating >= threshold and rounds_remaining >= 2:
            return Action.C
        if current_stock <= 2 * self.n and rounds_remaining >= 2:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_111(BaseStrategy):
    """
    Adaptive Stock-Responsive Strategy for Common Pool Resource Game.
    
    Adapts cooperation decisions based on:
    1. Current stock health (stock_ratio = current_stock / capacity)
    2. Opponent cooperation rates in previous rounds
    3. Position in the game (final round always defects)
    
    Decision rule:
    - Last round: Always defect (no future value to cooperation)
    - stock_ratio >= 0.6: Cooperate if coop_rate > 0.3, else defect
    - 0.25 <= stock_ratio < 0.6: Cooperate if coop_rate >= 0.6, else defect
    - stock_ratio < 0.25: Always defect (salvage before collapse)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == n_rounds - 1:
            return Action.D
        stock_ratio = current_stock / capacity if capacity > 0 else 0
        if current_round == 0:
            coop_rate = 0.5
        else:
            n_cooperators_prev = history.opponent_cooperators[-1]
            n_opponents = n_players - 1
            coop_rate = n_cooperators_prev / n_opponents if n_opponents > 0 else 0
        if stock_ratio >= 0.6:
            if coop_rate > 0.3:
                return Action.C
            else:
                return Action.D
        elif 0.25 <= stock_ratio < 0.6:
            if coop_rate >= 0.6:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_112(BaseStrategy):
    """
    Threshold-Based Adaptive Exploitation Strategy
    
    Monitors three stock thresholds and adapts play based on stock level and 
    opponent cooperation:
    - Final round: Always defect
    - Critical stock (≤ 2n): Cooperate unconditionally
    - Healthy stock (> 0.65×capacity): Defect to exploit abundance
    - Intermediate stock: Defect if opponents ≥50% cooperate, else cooperate
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.CRITICAL = 2 * self.n
        self.RECOVERY = 0.4 * self.capacity
        self.HEALTHY = 0.65 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_stock <= self.CRITICAL:
            return Action.C
        if current_stock > self.HEALTHY:
            return Action.D
        if current_round == 0:
            opponent_coop_rate = 0.5
        else:
            n_opponents = self.n - 1
            if n_opponents > 0:
                opponent_coop_rate = history.opponent_cooperators[-1] / n_opponents
            else:
                opponent_coop_rate = 0.5
        if opponent_coop_rate >= 0.5:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_113(BaseStrategy):
    """
    Adaptive Resource Preservation Strategy
    
    Cooperates by default when stock is healthy and opponents are cooperative,
    but defects when: resources are depleted, end-game is near, or opponents
    show high defection rates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == n_rounds - 1:
            return Action.D
        rounds_remaining = n_rounds - round_num
        if rounds_remaining <= 2:
            return Action.D
        stock_ratio = current_stock / capacity if capacity > 0 else 0
        if stock_ratio < 0.4:
            return Action.D
        if round_num == 0:
            defection_rate_last_round = 0.0
        else:
            opponents_who_cooperated = history.opponent_cooperators[-1]
            num_opponents = n - 1
            defection_rate_last_round = (num_opponents - opponents_who_cooperated) / num_opponents if num_opponents > 0 else 0.0
        if stock_ratio < 0.65:
            if defection_rate_last_round > 0.5:
                return Action.D
            else:
                return Action.C
        if defection_rate_last_round > 0.75:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_114(BaseStrategy):
    """
    Adaptive Exploitation with Collapse Awareness strategy for Common Pool Resource Game.
    
    - Round 0: Cooperate to establish baseline and gather opponent behavior signals.
    - Middle rounds: Cooperate only if stock is critically depleted; otherwise defect
      (free-ride on high cooperation, resist when opponents defect, or maximize immediate
      payoff in ambiguous states).
    - Final round: Defect unconditionally (no future rounds).
    
    Monitors stock trends and opponent cooperation to balance short-term exploitation
    with awareness of resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.D
        rounds_remaining = r - current_round
        n_opponents = n - 1
        if n_opponents > 0:
            c_observed = history.opponent_cooperators[-1] / n_opponents
        else:
            c_observed = 0.0
        if current_stock <= capacity / 4 and rounds_remaining >= 2:
            return Action.C
        if c_observed >= (n - 1) / n:
            return Action.D
        if c_observed <= 1 / n and current_stock > capacity / 2:
            return Action.D
        return Action.D

class Strategy_SELFINTERESTED_115(BaseStrategy):
    """
    Stock-Adaptive Strategic Exploitation (SASE):
    Defect aggressively in endgame and when commons are depleted;
    cooperate selectively early if stock is healthy and defection is rare.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number + 1
        k = r - current_round
        h = current_stock / capacity if capacity > 0 else 0
        if history.round_number == 0:
            return Action.C if h > 0.6 else Action.D
        if k == 1:
            return Action.D
        if current_stock < 2 * n:
            return Action.D
        if h < 0.25:
            return Action.D
        cooperators_last_round = history.opponent_cooperators[-1]
        defectors_last_round = n - 1 - cooperators_last_round
        d = defectors_last_round / (n - 1) if n > 1 else 0
        if d > 0.65:
            return Action.D
        decay_factor = k / r if r > 0 else 0
        cooperation_threshold = 0.35 + 0.3 * decay_factor
        if h > cooperation_threshold and d < 0.45:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_116(BaseStrategy):
    """
    Adaptive Depletion-Aware Strategy for Common Pool Resource Game.
    
    Combines early-round cooperation for information gathering, endgame extraction,
    and adaptive middle-phase decisions based on observed opponent cooperation rates
    and stock health. Cooperates only when opponent restraint (≥40%) and stock health
    (≥60% capacity) both support sustained cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_stock <= 0:
            return Action.D
        if current_round <= 1:
            return Action.C
        if current_round >= r - 2:
            return Action.D
        coop_count = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents <= 0:
            observed_cooperation_rate = 0.0
        else:
            observed_cooperation_rate = coop_count / n_opponents
        if observed_cooperation_rate < 0.4:
            return Action.D
        stock_health_threshold = 0.6 * capacity
        if observed_cooperation_rate >= 0.4 and current_stock < stock_health_threshold:
            return Action.D
        if observed_cooperation_rate >= 0.4 and current_stock >= stock_health_threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_117(BaseStrategy):
    """
    Adaptive Stock-Targeting Strategy: Defect when stock is healthy, cooperate when depleted.
    Shifts toward aggressive defection in final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round <= 1:
            return Action.C
        stock_ratio = current_stock / capacity
        rounds_remaining = r - current_round
        if rounds_remaining > 3:
            if stock_ratio > 0.55:
                return Action.D
            elif stock_ratio < 0.35:
                return Action.C
            else:
                observed_coop_rate = history.opponent_cooperators[-1] / (n - 1)
                if observed_coop_rate >= 0.5:
                    return Action.D
                else:
                    return Action.C
        elif stock_ratio < 0.3:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_118(BaseStrategy):
    """
    Greedy Extraction with Collapse Prevention strategy.
    
    Extracts aggressively (Defects) while stock is abundant (> capacity/2).
    Switches to cooperation when stock becomes stressed (≤ capacity/2) to buy time.
    Extracts one final time in the last round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.threshold = self.capacity / 2.0
        self.critical_threshold = self.capacity * 0.1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        is_last_round = current_round == self.game_description.n_rounds - 1
        if current_stock < self.critical_threshold:
            return Action.C
        if is_last_round:
            if current_stock > 0:
                return Action.D
            else:
                return Action.C
        if current_stock > self.threshold:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_119(BaseStrategy):
    """
    Self-Interested Adaptive Pool Management Strategy.
    
    Cooperates if and only if ALL of the following hold:
    1. Current stock > 0.4 × capacity
    2. Not the final round (round_number < n_rounds - 1)
    3. Observed cooperation rate ≥ 0.35 among opponents
    
    Otherwise defects. Includes edge case handling for stock at capacity
    and depleted pools.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        n_opponents = n_players - 1
        round_number = history.round_number
        if current_stock >= 0.95 * capacity and round_number > 0:
            return Action.D
        if current_stock <= 0.4 * capacity:
            return Action.D
        if round_number == n_rounds - 1:
            return Action.D
        if round_number == 0:
            return Action.D
        opponent_coop_count = history.opponent_cooperators[-1]
        cooperation_rate = opponent_coop_count / n_opponents if n_opponents > 0 else 0
        if cooperation_rate >= 0.35:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_120(BaseStrategy):
    """
    Adaptive Depletion-Tracking Strategy for Common Pool Resource Game.
    
    Cooperates when future payoffs justify it (sufficient stock and opponent cooperation),
    defects at game end or when stock is critically depleted.
    Uses weighted recency to detect sustainable cooperation patterns.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.critical_stock = 2 * self.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num == self.n_rounds - 1:
            return Action.D
        if round_num == self.n_rounds - 2:
            if round_num >= 2:
                all_opponents_cooperated = history.opponent_cooperators[round_num - 2] == self.n_players - 1
                if current_stock >= self.capacity * 0.99 and all_opponents_cooperated:
                    return Action.C
            return Action.D
        if current_stock <= self.critical_stock:
            return Action.D
        recent_coop_rate = self._compute_recent_coop_rate(history, round_num)
        coop_count = history.opponent_cooperators[-1]
        coop_threshold = math.floor((self.n_players - 1) / 2)
        if recent_coop_rate > 0.5 and coop_count >= coop_threshold:
            return Action.C
        return Action.D

    def _compute_recent_coop_rate(self, history: PlayerHistory, round_num: int) -> float:
        """
        Compute weighted recent cooperation rate from last 2 rounds.
        Returns a rate in [0, 1].
        """
        if round_num < 2:
            if round_num >= 1:
                return history.opponent_cooperators[-1] / (self.n_players - 1)
            return 0.5
        recent_cooperators = history.opponent_cooperators[round_num - 2] + history.opponent_cooperators[round_num - 1]
        total_slots = (self.n_players - 1) * 2
        if total_slots == 0:
            return 0.5
        return recent_cooperators / total_slots

class Strategy_SELFINTERESTED_121(BaseStrategy):
    """
    Adaptive Stock-Preservation Strategy for Common Pool Resource Game.
    
    Defects in the final round unconditionally. Otherwise, adapts decisions based on 
    current stock level and observed cooperation among other players, exploiting when 
    conditions are favorable and cooperating to prevent pool collapse when stock is critically low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == r - 1:
            return Action.D
        if round_num == 0:
            return Action.C
        c = history.opponent_cooperators[round_num - 1]
        S = current_stock
        if c >= math.ceil(n / 2):
            return Action.D
        if S > capacity * 0.65:
            return Action.D
        if S <= capacity * 0.3:
            return Action.C
        if c >= 2:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_122(BaseStrategy):
    """
    Adaptive Stock-Sensitive Defection Strategy:
    Cooperate conditionally on stock health and opponent cooperation signals;
    shift decisively toward defection in the endgame and under low-stock conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        rounds_remaining = self.game_description.n_rounds - history.round_number
        n_opponents = self.game_description.n_players - 1
        if n_opponents > 0:
            cooperators_last_round = history.opponent_cooperators[-1]
            coop_rate = cooperators_last_round / n_opponents
        else:
            coop_rate = 0.0
        if rounds_remaining == 1:
            return Action.D
        if current_stock < 0.25 * self.game_description.capacity:
            return Action.D
        if current_stock > 0.65 * self.game_description.capacity and coop_rate > 0.55:
            return Action.C
        if rounds_remaining < 0.33 * self.game_description.n_rounds:
            if coop_rate >= 0.7:
                return Action.C
            else:
                return Action.D
        if coop_rate >= 0.7:
            return Action.C
        if coop_rate < 0.4:
            return Action.D
        return Action.D

class Strategy_SELFINTERESTED_123(BaseStrategy):
    """
    Adaptive Extraction Strategy for Common Pool Resource Game.
    
    Cooperates only when others show willingness to cooperate (>50%), 
    stock is healthy (≥25% of capacity), and enough rounds remain for 
    sustained cooperation to matter. Defects in first/last rounds and 
    when resource is collapsing (<15% of capacity).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        if current_stock < capacity * 0.15:
            return Action.D
        stock_ratio = current_stock / capacity
        c_prev = history.opponent_cooperators[-1]
        rounds_remaining = r - current_round - 1
        if c_prev >= n / 2 and stock_ratio >= 0.25 and (rounds_remaining >= 2):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_124(BaseStrategy):
    """
    Adaptive Stock-Threshold Defection Strategy for Common Pool Resource Game.
    
    Employs a stock-health based decision rule:
    - Last round: unconditional defection
    - First round: defection (stock at capacity)
    - Middle rounds: threshold-based logic balancing stock preservation with exploitation
    
    Stock health thresholds:
    - ≤0.25: cooperate (critical depletion)
    - 0.25-0.50: cooperate if opponents mostly cooperated, else defect
    - 0.50-0.75: defect if opponents mostly defected, else cooperate
    - >0.75: defect (stock robust)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        stock_health = current_stock / capacity if capacity > 0 else 1.0
        cooperators_last_round = history.opponent_cooperators[-1]
        defectors_last_round = n_players - 1 - cooperators_last_round
        if stock_health <= 0.25:
            return Action.C
        elif stock_health <= 0.5:
            if cooperators_last_round >= defectors_last_round:
                return Action.C
            else:
                return Action.D
        elif stock_health <= 0.75:
            if defectors_last_round > cooperators_last_round:
                return Action.D
            else:
                return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_125(BaseStrategy):
    """
    Stock-Aware Adaptive Exploitation Strategy
    
    Adapts behavior based on current stock level and observed defection rates:
    - Round 1: Cooperate
    - Rounds 2 to r-1: 
      - Critical scarcity (stock ≤ 2n): Cooperate
      - Abundance (stock ≥ 0.7*capacity): Defect
      - Medium stock: Defect if defection rate ≤ 33%, else Cooperate
    - Final round: Defect unconditionally
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        if history.round_number == n_rounds - 1:
            return Action.D
        if current_stock <= 2 * n_players:
            return Action.C
        if current_stock >= 0.7 * capacity:
            return Action.D
        opponent_cooperators_last_round = history.opponent_cooperators[-1]
        n_opponents = n_players - 1
        if n_opponents > 0:
            opponent_defectors_last_round = n_opponents - opponent_cooperators_last_round
            defection_rate = opponent_defectors_last_round / n_opponents
        else:
            defection_rate = 0.0
        if defection_rate <= 0.33:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_126(BaseStrategy):
    """
    Adaptive Threshold Cooperation Strategy for Common Pool Resource Game.
    
    Cooperates based on three conditions: sufficient rounds remaining, 
    sustainable stock level, and opponent cooperation rate above a declining
    dynamic threshold. The threshold decreases over time, reflecting the
    reduced incentive to maintain the resource as the game nears its end.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        rounds_left = self.r - current_round
        if rounds_left <= 1:
            return Action.D
        if current_stock <= self.capacity / 3:
            return Action.D
        if current_round >= self.r - 2:
            current_threshold = 1.0
        else:
            current_threshold = 0.4
        cooperators_last_round = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if n_opponents <= 0:
            return Action.C
        observed_coop_rate = cooperators_last_round / n_opponents
        if observed_coop_rate >= current_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_127(BaseStrategy):
    """
    Adaptive Cooperation with Stock-Based Thresholds
    
    Combines stock-level monitoring with opponent cooperation rate observation
    to adaptively choose between cooperation and defection in a common pool
    resource game.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        n_opponents = n_players - 1
        if n_opponents <= 0:
            return Action.C
        opponent_coop_count = history.opponent_cooperators[-1]
        c = opponent_coop_count / n_opponents
        if current_stock <= 0.3 * capacity:
            return Action.C
        if c >= 0.55:
            return Action.C
        if 0.35 <= c < 0.55:
            return Action.D if random.random() < 0.65 else Action.C
        return Action.D

class Strategy_SELFINTERESTED_128(BaseStrategy):
    """
    Adaptive Depletion-Exploiting Strategy for Common Pool Resource Game.
    
    Exploits high stock levels when detected, monitors opponent cooperation through
    stock dynamics, cooperates to prevent collapse, and defects in final round when safe.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.consecutive_high_stock_rounds = 0
        self.last_stock = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.last_stock = current_stock
            return Action.C
        round_idx = history.round_number
        is_final_round = round_idx == self.n_rounds - 1
        stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0
        cooperation_signal = self._estimate_cooperation_signal(history, current_stock)
        if stock_ratio >= 0.95:
            self.consecutive_high_stock_rounds += 1
        else:
            self.consecutive_high_stock_rounds = 0
        threshold_adjustment = 0.15 if self.n_players == 2 else 0.0
        if is_final_round:
            if stock_ratio > 0.45:
                return Action.D
            else:
                return Action.C
        if stock_ratio > 0.7:
            self.last_stock = current_stock
            return Action.D
        elif stock_ratio > 0.5:
            coop_threshold = 0.6 - threshold_adjustment
            if cooperation_signal > coop_threshold:
                self.last_stock = current_stock
                return Action.D
            else:
                self.last_stock = current_stock
                return Action.C
        elif stock_ratio > 0.25:
            coop_threshold = 0.75 - threshold_adjustment
            if cooperation_signal > coop_threshold:
                self.last_stock = current_stock
                return Action.D
            else:
                self.last_stock = current_stock
                return Action.C
        else:
            self.last_stock = current_stock
            return Action.C

    def _estimate_cooperation_signal(self, history: PlayerHistory, current_stock: float) -> float:
        """
        Estimate opponent cooperation based on stock transitions and observed counts.
        
        Returns a signal in [0, 1] representing estimated cooperation level.
        """
        if history.round_number == 0:
            return 0.5
        recent_cooperators = history.opponent_cooperators[-1]
        n_opponents = self.n_players - 1
        if n_opponents > 0:
            cooperation_ratio = recent_cooperators / n_opponents
            return cooperation_ratio
        return 0.5

class Strategy_OPPORTUNISTIC_33(BaseStrategy):
    """
    Opportunistic Adaptive Strategy for Common Pool Resource Game.
    
    Prioritizes short-term exploitation of cooperative players when stock is abundant,
    while switching to cooperation only when stock becomes critically low.
    Tracks cooperation patterns and locks into defection if cooperation collapses.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.locked_defect = False
        self.low_coop_consecutive_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == n_rounds - 1:
            return Action.D
        if current_stock < 2:
            return Action.C
        if self.locked_defect:
            return Action.D
        rounds_remaining = n_rounds - current_round
        n_opponents = n_players - 1
        if n_opponents > 0:
            observed_cooperation_rate = history.opponent_cooperators[-1] / n_opponents
        else:
            observed_cooperation_rate = 0.0
        if observed_cooperation_rate < 0.25:
            self.low_coop_consecutive_rounds += 1
            if self.low_coop_consecutive_rounds >= 2:
                self.locked_defect = True
                return Action.D
        else:
            self.low_coop_consecutive_rounds = 0
        cooperation_bonus = 0.05 if observed_cooperation_rate > 0.8 else 0.0
        if current_stock > capacity * 0.75:
            return Action.D
        elif current_stock > capacity * 0.6 and rounds_remaining > 1:
            return Action.D
        elif current_stock <= capacity * 0.3:
            return Action.C
        elif capacity * 0.3 < current_stock <= capacity * 0.6:
            if rounds_remaining <= 2:
                return Action.D
            elif observed_cooperation_rate >= 0.75 - cooperation_bonus:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_OPPORTUNISTIC_34(BaseStrategy):
    """
    Adaptive Depletion Exploitation Strategy.
    
    Exploits cooperative opponents by defecting when stock is abundant,
    then shifts to cooperation only when stock depletion threatens future payoffs.
    Uses observed cooperation rates to make adaptive decisions while prioritizing
    immediate gains in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            if current_stock > 0.5 * capacity:
                return Action.D
            else:
                return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        observed_cooperation_rate = last_round_cooperators / max(n - 1, 1)
        rounds_remaining = r - current_round
        if current_round == r - 1:
            return Action.D
        if current_stock < 0.1 * capacity and rounds_remaining == 1:
            return Action.D
        if observed_cooperation_rate < 0.2 and current_stock < 0.5 * capacity:
            return Action.D
        if current_stock > 0.5 * capacity:
            return Action.D
        if current_stock <= 0.25 * capacity:
            if observed_cooperation_rate > 0.6 and rounds_remaining >= 2:
                return Action.C
            else:
                return Action.D
        if observed_cooperation_rate >= 0.7:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_35(BaseStrategy):
    """
    Opportunistic Adaptive Extraction Strategy.
    
    Maintains running count of cooperators observed, computes average cooperation rate,
    and monitors stock ratio. Uses priority-based decision rule: terminal round defection,
    end-game exploitation, depletion preservation, selective exploitation and cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        total_opponent_cooperators = int(np.sum(history.opponent_cooperators[:current_round]))
        total_opponent_actions = (n - 1) * current_round
        avg_coop = total_opponent_cooperators / total_opponent_actions if total_opponent_actions > 0 else 0.0
        rho = current_stock / capacity if capacity > 0 else 0.0
        if current_round == r - 1:
            return Action.D
        if r - current_round <= 2:
            return Action.D
        if rho < 0.3:
            return Action.C
        if rho >= 0.8 and avg_coop > 0.5:
            return Action.D
        if 0.3 <= rho < 0.8 and avg_coop <= 0.4:
            return Action.D
        if 0.3 <= rho < 0.8 and avg_coop > 0.4:
            return Action.C
        if rho < 0.3 and avg_coop > 0.6:
            return Action.C
        return Action.C

class Strategy_OPPORTUNISTIC_36(BaseStrategy):
    """
    Opportunistic Adaptive Harvesting Strategy
    
    Exploits cooperative opponents by defecting when cooperation is high and stock is healthy.
    Shifts to defection as stock depletes or rounds decrease.
    Detects high cooperation (>0.8) and enters aggressive defection mode for 2 rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.high_coop_defect_rounds_remaining = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        rounds_remaining = total_rounds - current_round
        if current_round == 0:
            return Action.C
        if rounds_remaining == 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        n_opponents = n - 1
        cooperation_rate = prev_cooperators / n_opponents if n_opponents > 0 else 0.0
        if cooperation_rate > 0.8 and self.high_coop_defect_rounds_remaining == 0:
            self.high_coop_defect_rounds_remaining = 2
        if self.high_coop_defect_rounds_remaining > 0:
            self.high_coop_defect_rounds_remaining -= 1
            return Action.D
        if cooperation_rate >= 0.5 and current_stock >= capacity * 0.4:
            return Action.D
        if current_stock <= capacity * 0.2:
            return Action.D
        if rounds_remaining <= 2:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_37(BaseStrategy):
    """
    Opportunistic Adaptive Pool Depletion Strategy
    
    Exploits growth asymmetries by cooperating when stock is healthy
    and can regenerate, but immediately defects when stock is threatened
    or opponents show defection patterns. Time-aware: defects in final round,
    and becomes more opportunistic as rounds dwindle.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number + 1
        if t == 1:
            return Action.C
        if t == r:
            return Action.D
        h = current_stock / capacity if capacity > 0 else 0
        c_prev = history.opponent_cooperators[-1]
        opp_coop_rate = c_prev / (n - 1) if n > 1 else 0
        tau = (r - t) / r if r > 0 else 0
        if h < 0.4:
            return Action.D
        if opp_coop_rate >= (n - 2) / (n - 1):
            if h >= 0.6:
                return Action.C
            else:
                return Action.D
        if opp_coop_rate <= 1 / (n - 1):
            return Action.D
        if h >= 0.7 and tau > 0.5:
            return Action.C
        if h >= 0.5 and opp_coop_rate >= 0.5:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_38(BaseStrategy):
    """
    Opportunistic free-rider strategy for Common Pool Resource game.
    Defects in round 1 and final round, exploits high abundance, and conditionally
    cooperates only when stock is critically depleted AND others are already cooperating.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        stock_abundance_ratio = current_stock / capacity if capacity > 0 else 0
        cooperation_count = history.opponent_cooperators[-1]
        cooperation_rate = cooperation_count / (n - 1) if n > 1 else 0
        if stock_abundance_ratio > 0.75:
            return Action.D
        elif stock_abundance_ratio < 0.25:
            if cooperation_rate >= 0.6:
                return Action.C
            else:
                return Action.D
        elif cooperation_rate >= 0.5:
            return Action.D
        elif current_stock < 2.5 * n:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_39(BaseStrategy):
    """
    Opportunistic Adaptive Extraction Strategy for Common Pool Resource Game.
    
    Exploits cooperative opponents while maintaining stock for future defection.
    Switches to cooperation only when necessary to prevent resource collapse.
    Defects increasingly as the game approaches its end.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold_low = 0.3 * game_description.capacity
        self.threshold_critical = 0.2 * game_description.capacity
        self.threshold_recovery = 0.5 * game_description.capacity
        self.threshold_abundant = 0.6 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        round_num = history.round_number
        rounds_remaining = r - round_num
        if round_num == 0:
            return Action.D
        if round_num == r - 1:
            return Action.D
        if round_num == r - 2:
            if current_stock < 0.25 * self.game_description.capacity:
                return Action.C
            return Action.D
        cooperators_prev = history.opponent_cooperators[-1]
        cooperation_rate_prev = cooperators_prev / (n - 1) if n > 1 else 0.0
        if current_stock < self.threshold_critical:
            return Action.C
        if current_stock > self.threshold_recovery:
            if cooperation_rate_prev >= 0.5:
                return Action.D
            if cooperation_rate_prev < 0.4 and current_stock > self.threshold_abundant:
                return Action.D
            return Action.D
        if current_stock < self.threshold_low and rounds_remaining > 1:
            return Action.C
        if cooperation_rate_prev < 0.4 and current_stock < 1.5 * self.game_description.capacity:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_40(BaseStrategy):
    """
    Opportunistic Adaptive Defection Strategy - prioritizes immediate payoff extraction
    while maintaining stock survival only when necessary for continued exploitation.
    
    Default: DEFECT, with conditional cooperation only when stock collapse recovery
    is critical. Aggressively exploits cooperative opponents and defects in endgame.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.D
        current_round = history.round_number
        rounds_remaining = self.n_rounds - current_round
        stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0
        observed_cooperators = history.opponent_cooperators[-1]
        n_opponents = self.n_players - 1
        if current_round >= self.n_rounds - 2:
            return Action.D
        if stock_ratio < 0.15 and rounds_remaining >= 2:
            return Action.C
        exploitation_threshold = math.ceil(0.65 * n_opponents)
        if observed_cooperators >= exploitation_threshold:
            return Action.D
        defection_pressure_threshold = 0.3 * n_opponents
        if stock_ratio > 0.4 and observed_cooperators <= defection_pressure_threshold:
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_41(BaseStrategy):
    """
    Opportunistic Adaptive Defection Strategy for Common Pool Resource Game.
    Exploits cooperative opponents and defects across all stock conditions,
    prioritizing immediate extraction over resource preservation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        strong_stock = current_stock > 0.45 * capacity
        moderate_stock = 0.15 * capacity <= current_stock <= 0.45 * capacity
        depleted_stock = current_stock < 0.15 * capacity
        opponent_cooperators = history.opponent_cooperators[-1]
        n_opponents = n - 1
        opponent_cooperation_rate = opponent_cooperators / n_opponents if n_opponents > 0 else 0.5
        if strong_stock:
            return Action.D
        elif moderate_stock:
            return Action.D
        elif depleted_stock:
            remaining_rounds = r - current_round
            return Action.D
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_42(BaseStrategy):
    """
    Opportunistic Common Pool Resource Strategy that exploits three asymmetries:
    - Cooperator asymmetry: defect when others cooperate for higher payoff
    - Defector parity: match defectors when most are defecting to avoid sole cooperation
    - Temporal aggressiveness: front-load defection when stock abundant, cooperate when critical
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_stock <= capacity * 0.12:
            return Action.C
        if current_round > 0:
            observed_cooperators = history.opponent_cooperators[-1]
            n_opponents = n - 1
            if observed_cooperators == 0:
                return Action.D
            if n_opponents > 0:
                observed_defection_rate = (n_opponents - observed_cooperators) / n_opponents
            else:
                observed_defection_rate = 0.0
            if observed_defection_rate > 0.55:
                return Action.D
            elif observed_defection_rate < 0.35:
                return Action.D
        if current_stock > capacity * 0.75:
            return Action.D
        elif current_stock <= capacity * 0.4:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_43(BaseStrategy):
    """
    Opportunistic Common Pool Strategy.
    
    Defaults to Defection except when specific conditions make cooperation more
    profitable for future stock preservation:
    - Mid-range stock levels (25%-65% of capacity)
    - Majority opposition cooperation (>50%)
    - Sufficient remaining rounds (≥3) to benefit from preserved stock
    
    Defects aggressively at high stock (abundant), low stock (collapse risk),
    or when opponents defect (no advantage to cooperation).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if current_stock <= 0:
            return Action.D
        if round_num == self.r - 1:
            return Action.D
        if round_num == self.r - 2:
            return Action.D
        if round_num == 0:
            if self.capacity > 1.3 * self.n:
                return Action.C
            else:
                return Action.D
        cooperators_last_round = int(history.opponent_cooperators[-1])
        remaining_rounds = self.r - round_num - 1
        if self.r <= 3:
            coop_threshold = self.n * 0.35
            high_stock_threshold = 0.5
            low_stock_threshold = 0.15
        else:
            coop_threshold = self.n / 3.0
            high_stock_threshold = 0.65
            low_stock_threshold = 0.25
        if self.n == 2:
            coop_threshold = 0.5
        if current_stock >= self.capacity * high_stock_threshold:
            return Action.D
        if current_stock <= self.capacity * low_stock_threshold:
            return Action.D
        if cooperators_last_round <= coop_threshold:
            return Action.D
        if self.capacity * low_stock_threshold < current_stock < self.capacity * high_stock_threshold and cooperators_last_round > self.n / 2.0 and (remaining_rounds >= 3):
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_44(BaseStrategy):
    """
    Opportunistic Adaptive Extraction Strategy for Common Pool Resource Game.
    
    Prioritizes personal consumption over collective sustainability by exploiting:
    - Abundance (high stock levels)
    - Cooperative opponents
    - Terminal rounds with no future consequences
    
    Maintains minimal stock (≥ 0.2 × capacity) to preserve extraction opportunities.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        rounds_remaining = self.game_description.n_rounds - history.round_number
        if current_stock < 2 * n:
            return Action.C
        if rounds_remaining == 1:
            return Action.D
        if current_stock >= 0.7 * capacity:
            return Action.D
        observed_cooperators = history.opponent_cooperators[-1]
        if observed_cooperators >= n - 1:
            return Action.D
        if current_stock <= 0.2 * capacity:
            return Action.C
        if current_stock < 0.4 * capacity:
            return Action.C
        if observed_cooperators < n - 1:
            return Action.C
        return Action.C

class Strategy_OPPORTUNISTIC_45(BaseStrategy):
    """
    Opportunistic Adaptive Strategy for Common Pool Resource Game.
    
    Exploits cooperators when conditions allow, abandons defection before catastrophic
    collapse, and treats terminal rounds as final extraction windows. Adaptation hinges
    on observed cooperation levels and stock state rather than opponent identity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == 0:
            return Action.D
        if t == r - 1:
            return Action.D
        if current_stock < capacity / 4:
            return Action.C
        if current_stock < capacity / 10:
            return Action.C
        if t > 2 * r / 3:
            rounds_remaining = r - t
            if current_stock > capacity / 2 and rounds_remaining <= 2:
                return Action.D
            c_t = history.opponent_cooperators[-1]
            if c_t >= (n - 1) / 2:
                return Action.D
            else:
                return Action.C
        if current_stock > capacity / 2:
            return Action.D
        c_t = history.opponent_cooperators[-1]
        if c_t >= (n - 1) / 2:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_46(BaseStrategy):
    """
    Opportunistic Threshold Strategy - exploits cooperation when safe, 
    minimizes stock depletion risk through selective cooperation at critical thresholds.
    Baseline is defection, with cooperation only under restrictive conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.D
        if history.round_number == n_rounds - 1:
            return Action.D
        observed_coop_count = history.opponent_cooperators[-1]
        n_opponents = n_players - 1
        if n_opponents > 0:
            coop_rate = observed_coop_count / n_opponents
        else:
            coop_rate = 0.0
        if capacity > 0:
            health = current_stock / capacity
        else:
            health = 0.0
        if health < 0.2:
            return Action.C
        if coop_rate > 0.65 and health > 0.5:
            return Action.D
        if coop_rate > 0.5 and health > 0.6:
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_47(BaseStrategy):
    """
    Opportunistic Threshold Strategy for Common Pool Resource Game.
    
    Defects as the baseline action to maximize immediate consumption when stock
    is abundant. Switches to cooperation only when stock nears critical depletion
    to preserve the regeneration zone, or in the penultimate round if stock is
    already depleted. Always defects in the final round and first round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.D
        if round_num == r - 1:
            return Action.D
        c_last = history.opponent_cooperators[-1]
        coop_rate = c_last / (n - 1) if n > 1 else 0.5
        if round_num == r - 2:
            if current_stock > 0.5 * capacity:
                return Action.D
            else:
                return Action.C
        if current_stock < 0.35 * capacity:
            return Action.C
        estimated_defection_consumption = current_stock
        stock_after_consumption = current_stock - estimated_defection_consumption
        if stock_after_consumption < 0.2 * capacity and round_num < r - 1:
            return Action.C
        if coop_rate > 0.65 and current_stock > 0.6 * capacity:
            return Action.D
        if coop_rate < 0.4:
            return Action.D
        if 0.4 <= coop_rate <= 0.65:
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_48(BaseStrategy):
    """
    Opportunistic Extraction Strategy: Default to defection and exploit the resource.
    Only cooperate to prevent collapse or when others sustain the commons.
    Always defect in final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        n_opponents = self.n_players - 1
        if current_stock <= 3 * self.n_players:
            return Action.C
        if current_stock <= self.capacity / 2:
            cooperators_last_round = history.opponent_cooperators[-1]
            proportion_cooperating = cooperators_last_round / n_opponents if n_opponents > 0 else 0
            if proportion_cooperating >= 0.66:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_49(BaseStrategy):
    """
    Opportunistic Threshold-Based Strategy for Common Pool Resource Game.
    
    Plays Defect by default unless conditions force cooperation:
    - Defects in end-game (rounds_remaining ≤ 2)
    - Cooperates on stock emergency (stock ≤ capacity/4)
    - Cooperates when stock is declining and mid-game (stock_current < stock_previous and rounds_remaining > 2)
    - Defaults to Defect, with exploitation opportunity when cooperators are observed and stock is robust
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.stock_history = []

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self.stock_history.append(current_stock)
        if history.round_number == 0:
            return Action.D
        rounds_remaining = self.game_description.n_rounds - (history.round_number + 1)
        if rounds_remaining <= 2:
            return Action.D
        if current_stock <= self.game_description.capacity / 4:
            return Action.C
        stock_previous = self.stock_history[-2]
        if current_stock < stock_previous and rounds_remaining > 2:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        if cooperators_last_round > 0 and current_stock > self.game_description.capacity / 3:
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_50(BaseStrategy):
    """
    Opportunistic Pool Strategy: Exploits cooperating opponents when resources are abundant,
    cooperates only when resources are critically depleted and opponents show cooperation,
    and defects unconditionally in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        rounds_left = self.game_description.n_rounds - (history.round_number + 1)
        m = history.opponent_cooperators[-1]
        opponent_coop_rate = m / (self.game_description.n_players - 1)
        stock_ratio = current_stock / self.game_description.capacity
        if rounds_left == 0:
            return Action.D
        elif opponent_coop_rate >= 0.5 and stock_ratio > 0.35:
            return Action.D
        elif current_stock <= self.game_description.capacity / 3 and opponent_coop_rate > 0.5:
            return Action.C
        elif opponent_coop_rate < 0.33:
            return Action.D
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_51(BaseStrategy):
    """
    Opportunistic Adaptive Defection Strategy for Common Pool Resource Game.
    Exploits asymmetries by defecting on cooperators while adapting to stock
    depletion and game progression. Fundamentally selfish: cooperation only
    emerges under duress (stock critical) or to exploit persistent cooperators.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        stock_health = current_stock / self.capacity if self.capacity > 0 else 0
        rounds_left = self.n_rounds - current_round
        rounds_elapsed = current_round
        if stock_health < 0.05:
            return Action.C
        if rounds_left == 1:
            return Action.D
        n_opponents = self.n_players - 1
        cooperation_rate = history.opponent_cooperators[-1] / n_opponents if n_opponents > 0 else 0
        defection_threshold = 0.4 + 0.3 * rounds_elapsed / self.n_rounds
        if cooperation_rate < defection_threshold:
            return Action.D
        if rounds_left <= 2:
            return Action.D
        if stock_health > 0.6 and rounds_left <= self.n_rounds / 2:
            return Action.D
        if cooperation_rate > 0.7:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_52(BaseStrategy):
    """
    Opportunistic Defection Strategy for Common Pool Resource Game.
    
    Prioritizes short-term exploitation while maintaining minimal sustainability.
    Exploits high stock levels when cooperation is evident, but stabilizes when
    stock depletion threatens collapse. Employs endgame exploitation and adapts
    to defection spreading among opponents.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.previous_stock = game_description.capacity
        self.stock_decline_override = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number >= r - 1:
            return Action.D
        if current_stock < 0.3 * capacity:
            return Action.C
        if round_number > 0 and self.previous_stock > 0:
            stock_decline_rate = (self.previous_stock - current_stock) / self.previous_stock
            if stock_decline_rate > 0.3 and round_number < r - 1:
                self.stock_decline_override = True
                self.previous_stock = current_stock
                return Action.C
        if self.stock_decline_override:
            self.stock_decline_override = False
        self.previous_stock = current_stock
        if current_stock >= 0.75 * capacity:
            return Action.D
        if 0.3 * capacity <= current_stock < 0.75 * capacity:
            if round_number == 0:
                return Action.D
            cooperators_prev = history.opponent_cooperators[-1]
            defectors_prev = n - 1 - cooperators_prev
            threshold = math.ceil(n / 4)
            if defectors_prev <= threshold:
                return Action.D
            else:
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_53(BaseStrategy):
    """
    Opportunistic Stock Depletion Strategy for Common Pool Resource Game.
    
    Dynamically adjusts exploitation based on stock level and observed cooperation:
    - Depletes aggressively when stock is abundant (>2/3 capacity)
    - Exploits cooperative opponents in recovery zone (1/3 to 2/3 capacity)
    - Moderates consumption when stock is critical (<1/3 capacity)
    - Always defects in final round
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        critical_threshold = self.capacity / 3
        depletion_threshold = 2 * self.capacity / 3
        if current_stock <= critical_threshold:
            return Action.C
        if current_stock >= depletion_threshold:
            return Action.D
        n_opponents = self.n - 1
        if current_round > 0 and n_opponents > 0:
            cooperators_prev_round = history.opponent_cooperators[-1]
            cooperation_rate = cooperators_prev_round / n_opponents
            if cooperation_rate >= 0.5:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_OPPORTUNISTIC_54(BaseStrategy):
    """
    Opportunistic Adaptive Strategy for Common Pool Resource Game.
    
    Defects by default, cooperates only when forced by resource scarcity
    or when others are defecting heavily. Exploits cooperators when the
    resource pool is healthy and retreats to cooperation only when
    resource collapse is imminent.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        round_idx = history.round_number
        if round_idx == 0:
            return Action.D
        if round_idx == n_rounds - 1:
            if current_stock > capacity * 0.6:
                return Action.D
            else:
                return Action.C
        if current_stock <= 2 * n:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        n_opponents = n - 1
        coop_rate = cooperators_last_round / n_opponents if n_opponents > 0 else 0.0
        if coop_rate >= 0.6:
            return Action.D
        if coop_rate >= 0.3:
            if current_stock > capacity * 0.7:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_OPPORTUNISTIC_55(BaseStrategy):
    """
    Opportunistic Stock Exploitation with Conditional Cooperation.
    
    Strategy outline:
    - Round 1: Defect to establish presence as potential defector
    - Rounds 2 to r-1: Conditional cooperation based on stock ratio and opponent cooperation
    - Final round: Always defect if stock available (no future to preserve)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == n_rounds - 1:
            if current_stock > 0:
                return Action.D
            return Action.D
        n_opponents = n - 1
        if n_opponents > 0:
            c_observed = history.opponent_cooperators[-1] / n_opponents
        else:
            c_observed = 0.0
        if capacity > 0:
            s_ratio = current_stock / capacity
        else:
            s_ratio = 0.0
        if s_ratio < 0.25:
            return Action.C
        if s_ratio >= 0.7 and c_observed > 0.55:
            return Action.D
        if c_observed > 0.65:
            return Action.D
        if s_ratio < 0.5 and c_observed <= 0.4:
            return Action.D
        if s_ratio < 0.45:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_56(BaseStrategy):
    """
    Opportunistic Common Pool Resource Strategy: Defaults to defection and only cooperates 
    reactively when stock depletion becomes severe. Exploits cooperators when possible and 
    free-rides on their restraint. Defects in round 1 and final round to maximize extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.D
        if history.round_number == r - 1:
            return Action.D
        stock_ratio = current_stock / capacity if capacity > 0 else 0
        observed_coop_count = history.opponent_cooperators[-1]
        observed_cooperation_rate = observed_coop_count / (n - 1) if n > 1 else 0
        if stock_ratio >= 0.5:
            return Action.D
        elif observed_cooperation_rate > 1 / 3:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_57(BaseStrategy):
    """
    Opportunistic Adaptive Exploitation - Defects to maximize immediate payoff whenever 
    sustainable. Preserves stock only when necessary for survival or when commons is collapsing.
    Adapts defection timing to opponent behavior and stock trajectory.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.prev_d_ratio = 0.5
        self.consecutive_high_defection_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_stock <= 2 * self.n:
            return Action.C
        if current_stock >= 0.6 * self.capacity:
            return Action.D
        if current_round == 0:
            d_ratio = 0.5
            if self.capacity >= 2.5 * self.n:
                return Action.D
            else:
                return Action.C
        else:
            opponent_cooperators = history.opponent_cooperators[-1]
            opponent_defectors = self.n - 1 - opponent_cooperators
            d_ratio = opponent_defectors / (self.n - 1) if self.n > 1 else 0
            if d_ratio >= 0.7:
                self.consecutive_high_defection_rounds += 1
            else:
                self.consecutive_high_defection_rounds = 0
        if d_ratio < 0.4:
            return Action.D
        if 0.3 * self.capacity < current_stock < 0.6 * self.capacity and d_ratio >= 0.4:
            return Action.C
        if self.consecutive_high_defection_rounds >= 2 and current_stock < 0.4 * self.capacity:
            return Action.C
        if d_ratio <= 0.25:
            return Action.D
        else:
            if current_round > 0 and current_round < self.r - 1:
                if current_stock >= 0.5 * self.capacity:
                    return Action.D
            return Action.C

class Strategy_OPPORTUNISTIC_58(BaseStrategy):
    """
    Opportunistic Adaptive Strategy: Defect when stock permits recovery,
    cooperate only when forced by scarcity. Free-ride on cooperative opponents.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.D
        critical_threshold = self.capacity / 5
        low_threshold = self.capacity / 3
        if current_stock < critical_threshold:
            return Action.C
        elif current_stock < low_threshold:
            cooperators_previous_round = history.opponent_cooperators[-1]
            threshold_cooperators = (self.game_description.n_players - 1) / 2
            if cooperators_previous_round < threshold_cooperators:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_59(BaseStrategy):
    """
    Opportunistic Resource Extraction Strategy.
    
    Defects by default while exploiting cooperative opponents.
    Cooperates only when stock depletion threatens future extraction capacity.
    Abandons all restraint in final rounds and when stock is abundant.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.stock_history: list[float] = []
        self.cooperation_threshold = 0.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        self.stock_history.append(current_stock)
        current_round = history.round_number
        rounds_remaining = n_rounds - current_round
        if rounds_remaining <= 2:
            return Action.D
        if current_round == 0:
            return Action.D
        n_opponents = n - 1
        if n_opponents > 0:
            observed_cooperators_last_round = history.opponent_cooperators[-1]
            observed_defectors_last_round = n_opponents - observed_cooperators_last_round
            observed_cooperation_rate = observed_cooperators_last_round / n_opponents if n_opponents > 0 else 0.0
        else:
            observed_cooperation_rate = 0.0
        if current_stock < 2 * n:
            return Action.C
        if current_stock > capacity * 0.65:
            return Action.D
        if observed_cooperation_rate >= 0.75:
            return Action.D
        if len(self.stock_history) >= 2:
            stock_decline = self.stock_history[-2] - self.stock_history[-1]
            decline_ratio = stock_decline / capacity if capacity > 0 else 0.0
            if decline_ratio > 0.3:
                self.cooperation_threshold = min(0.4, self.cooperation_threshold + 0.1)
            else:
                self.cooperation_threshold = max(0.2, self.cooperation_threshold - 0.05)
        else:
            self.cooperation_threshold = 0.3
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        if stock_ratio < self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_60(BaseStrategy):
    """
    Opportunistic Resource Extraction Strategy for Common Pool Resource Game.
    Defects when stock exceeds a dynamically adjusted threshold based on round horizon
    and observed opponent cooperation rates. Exploits cooperative opponents while
    abandoning sustainability in final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock == 0:
            return Action.C
        if current_stock < self.capacity * 0.1:
            return Action.C
        round_num = history.round_number
        if round_num == 0:
            return Action.D
        if round_num == self.n_rounds - 1:
            if current_stock < 2:
                return Action.C
            threshold = self.capacity * 0.15
        elif round_num >= self.n_rounds - 2:
            threshold = self.capacity * 0.25
        elif round_num >= self.n_rounds - 4:
            threshold = self.capacity * 0.4
        else:
            threshold = self.capacity * 0.55
        observed_coop_count = history.opponent_cooperators[-1]
        n_opponents = self.n_players - 1
        if n_opponents > 0:
            observed_coop_rate = observed_coop_count / n_opponents
            if observed_coop_rate > 0.5:
                threshold = threshold - 0.1 * self.capacity
            elif observed_coop_rate < 0.3:
                threshold = threshold + 0.05 * self.capacity
        threshold = max(0, min(threshold, self.capacity))
        if current_stock > threshold:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_61(BaseStrategy):
    """
    Opportunistic Adaptive Depletion Strategy
    
    Extracts aggressively from healthy stocks and shifts conditionally toward 
    cooperation only when depletion threatens resource viability. Always defects 
    in the final round. Core principle: free-ride on others' restraint while 
    resource is abundant; cooperate only when collapse risk threatens future payoffs.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        viability_threshold = capacity / 10.0
        if current_stock <= viability_threshold:
            opponents_cooperated_last_round = history.opponent_cooperators[-1]
            cooperation_threshold = n / 2.0
            if opponents_cooperated_last_round >= cooperation_threshold:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_62(BaseStrategy):
    """
    Opportunistic Adaptive Exploitation Strategy for Common Pool Resource Game.
    
    Exploits cooperative opponents by defecting when cooperation is high.
    Cooperates only to preserve future exploitation opportunities when stock
    is critically low. Always defects in final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == r - 1:
            return Action.D
        if round_num == 0:
            return Action.D
        if current_stock <= 2 * n:
            if current_stock <= capacity * 0.35:
                return Action.C
            else:
                return Action.D
        m = min(3, round_num)
        if m > 0:
            recent_coop_count = np.sum(history.opponent_cooperators[-m:])
            recent_total_opponents = m * (n - 1)
            if recent_total_opponents > 0:
                observed_cooperation_rate = recent_coop_count / recent_total_opponents
            else:
                observed_cooperation_rate = 0.0
        else:
            observed_cooperation_rate = 0.0
        if observed_cooperation_rate >= 0.6:
            return Action.D
        if observed_cooperation_rate < 0.3 and current_stock < capacity * 0.5:
            if current_stock <= 2 * n * 1.5:
                return Action.D
            else:
                return Action.C
        if current_stock < capacity * 0.4:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_63(BaseStrategy):
    """
    Opportunistic Adaptive Strategy for Common Pool Resource Game.
    
    Combines immediate payoff maximization through defection with adaptive
    responses to cooperation levels and resource pressure. Switches to
    cooperation only under resource emergency or strategic default conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            if current_stock > 0:
                return Action.D
            else:
                return Action.C
        cooperation_count = history.opponent_cooperators[-1]
        n_opponents = n - 1
        cooperation_rate = cooperation_count / n_opponents if n_opponents > 0 else 0.0
        resource_pressure = current_stock / capacity if capacity > 0 else 0.0
        if current_stock <= 0.2 * capacity:
            return Action.C
        if current_stock >= 0.5 * capacity and cooperation_rate >= 0.5:
            return Action.D
        if cooperation_rate < 0.3:
            return Action.D
        rounds_remaining = r - current_round
        if rounds_remaining <= 2:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_64(BaseStrategy):
    """
    Opportunistic Conditional Defection Strategy for Common Pool Resource Game.
    
    Defects in the first and final rounds to maximize immediate extraction.
    In intermediate rounds, conditionally cooperates or defects based on stock health
    and observed opponent cooperation, with opportunistic defection when the pool
    is in good condition and opponents are sustaining it.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        health_ratio = current_stock / capacity if capacity > 0 else 0
        cooperators_observed = history.opponent_cooperators[-1]
        rounds_remaining = r - current_round
        if health_ratio <= 0.25:
            return Action.C
        if health_ratio <= 0.4 and rounds_remaining >= 2:
            return Action.C
        if cooperators_observed >= (n - 1) / 2:
            return Action.D
        if cooperators_observed <= (n - 1) / 3:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_65(BaseStrategy):
    """
    Opportunistic Adaptive Pool Strategy for Common Pool Resource Game.
    
    Front-loads defection in healthy states (always defect in first and final rounds).
    Only retreats to cooperation when resource collapse is imminent (stock < capacity/3).
    Exploits free-riding windows when pool is healthy and opponents cooperate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock == 0:
            return Action.C
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        capacity = self.game_description.capacity
        n_players = self.game_description.n_players
        if current_stock > capacity / 2 and history.opponent_cooperators[-1] > n_players / 2:
            return Action.D
        if current_stock < capacity / 3:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_66(BaseStrategy):
    """
    Opportunistic Adaptive Resource Exploitation Strategy
    Evaluates conditions in priority order to decide between cooperation and defection,
    balancing immediate exploitation with strategic long-term resource preservation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        rounds_remaining = self.r - round_num
        if round_num == 0:
            observed_cooperation_rate = 0.5
        else:
            cooperators_last_round = history.opponent_cooperators[-1]
            n_opponents = self.n - 1
            if n_opponents > 0:
                observed_cooperation_rate = cooperators_last_round / n_opponents
            else:
                observed_cooperation_rate = 0.5
        if rounds_remaining <= 1:
            return Action.D
        if current_stock <= 3 * self.n:
            if observed_cooperation_rate > 0.5:
                return Action.D
            else:
                return Action.C
        if current_stock >= 0.8 * self.capacity:
            return Action.D
        if 0.3 * self.capacity < current_stock < 0.8 * self.capacity and observed_cooperation_rate > 0.6:
            return Action.D
        if current_stock >= 0.3 * self.capacity and rounds_remaining >= 3:
            return Action.D
        if 0.3 * self.capacity <= current_stock < 0.8 * self.capacity and rounds_remaining <= 2:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_67(BaseStrategy):
    """
    Opportunistic Stock Exploitation Strategy for Common Pool Resource Game.
    
    Defaults to defection to maximize immediate payoffs, but cooperates as a
    survival mechanism when stock depletion threatens resource collapse.
    Exploits high cooperation rates when stock is abundant.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        remaining_rounds = self.n_rounds - round_num
        if round_num == 0:
            return Action.D
        n_opponents = self.n_players - 1
        coop_count = history.opponent_cooperators[-1]
        coop_rate = coop_count / n_opponents if n_opponents > 0 else 0.0
        if current_stock < 0.2 * self.capacity:
            return Action.C
        if current_stock < 0.35 * self.capacity and coop_rate < 0.4:
            return Action.C
        if coop_rate < 0.25 and remaining_rounds >= 3:
            return Action.C
        if remaining_rounds <= 1:
            return Action.D
        if current_stock >= 0.7 * self.capacity and coop_rate >= 0.5:
            return Action.D
        if current_stock >= 0.6 * self.capacity and coop_rate >= 0.6:
            return Action.D
        if current_stock >= 0.4 * self.capacity and coop_rate >= 0.65:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_68(BaseStrategy):
    """
    Adaptive Threshold-Based Opportunistic Strategy for Common Pool Resource Game.
    
    Core logic: Defect by default; cooperate only when strategically necessary to prevent
    resource collapse or when stock is declining. Special handling for round 1 (cooperate
    to gather opponent info) and final round (defect for maximum endgame capture).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold_survival = max(2 * game_description.n_players, game_description.capacity / 4)
        self.prev_stock = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            self.prev_stock = current_stock
            return Action.C
        if round_num == n_rounds - 1:
            self.prev_stock = current_stock
            return Action.D
        if current_stock <= 0:
            self.prev_stock = current_stock
            return Action.D
        if current_stock < self.threshold_survival:
            self.prev_stock = current_stock
            return Action.C
        if n > 1:
            cooperation_rate = history.opponent_cooperators[-1] / (n - 1)
        else:
            cooperation_rate = 0.0
        if current_stock >= 0.6 * capacity and cooperation_rate > 0.5:
            self.prev_stock = current_stock
            return Action.D
        stock_declining = current_stock < self.prev_stock
        if stock_declining:
            self.prev_stock = current_stock
            return Action.C
        self.prev_stock = current_stock
        return Action.D

class Strategy_OPPORTUNISTIC_69(BaseStrategy):
    """
    Opportunistic Stock Extraction Strategy.
    
    Prioritizes personal consumption extraction over collective sustainability.
    Exploits cooperative opponents by defecting when stock permits.
    Uses temporary cooperation only when stock is critically low (< 0.2×capacity)
    to enable recovery, then resumes defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        remaining_rounds = n_rounds - round_number
        if round_number == 0:
            observed_cooperation_rate = 0.5
        else:
            n_opponents = n_players - 1
            if n_opponents > 0:
                total_cooperators = int(np.sum(history.opponent_cooperators[:round_number]))
                observed_cooperation_rate = total_cooperators / (round_number * n_opponents)
            else:
                observed_cooperation_rate = 0.5
        stock_ratio = current_stock / capacity if capacity > 0 else 1.0
        if remaining_rounds == 1:
            return Action.D
        if stock_ratio > 0.65:
            return Action.D
        if stock_ratio >= 0.4:
            return Action.D
        if stock_ratio >= 0.2:
            if observed_cooperation_rate >= 0.6:
                return Action.D
            elif remaining_rounds >= 3:
                return Action.C
            else:
                return Action.D
        if observed_cooperation_rate >= 0.3:
            return Action.C
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_70(BaseStrategy):
    """
    Opportunistic Adaptive Strategy for Common Pool Resource Game.
    
    Exploits abundance and opponent cooperation, defects in first and last rounds,
    with selective cooperation only when collapse is mathematically inevitable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        observed_coop = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents > 0:
            observed_coop_rate = observed_coop / n_opponents
        else:
            observed_coop_rate = 0.0
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        rounds_left = r - current_round
        if stock_ratio >= 0.85:
            return Action.D
        if observed_coop_rate >= 0.5:
            return Action.D
        if rounds_left <= 2:
            return Action.D
        if stock_ratio <= 0.25 and n > 0:
            safe_harvest_rounds = current_stock / (2 * n) if 2 * n > 0 else 0.0
            if rounds_left > safe_harvest_rounds:
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_71(BaseStrategy):
    """
    Opportunistic Stock-Depletion Strategy for Common Pool Resource Game.
    
    Exploits abundance by defecting when stock is high, selectively free-rides
    on opponent restraint when stock is depleted, and always defects in the
    final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity_third = self.capacity / 3.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == 0:
            if current_stock <= self.capacity_third:
                return Action.C
            else:
                return Action.D
        if round_num == self.n_rounds - 1:
            return Action.D
        c = history.opponent_cooperators[-1]
        if current_stock > self.capacity_third:
            return Action.D
        if c >= self.n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_72(BaseStrategy):
    """
    Opportunistic Strategy: Adaptive Exploitation with Collapse Prevention
    
    Exploits cooperation when profitable, but cooperates defensively to prevent
    commons collapse that would harm future round payoffs. Defects opportunistically
    when stock is abundant or others are already defecting.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.D
        rounds_remaining = self.n_rounds - history.round_number
        stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0.0
        n_opponents = self.n_players - 1
        opponent_coop_count = int(history.opponent_cooperators[-1])
        cooperation_rate = opponent_coop_count / n_opponents if n_opponents > 0 else 0.0
        if rounds_remaining == 1:
            return Action.D
        if stock_ratio >= 0.75:
            return Action.D
        if cooperation_rate >= 0.6 and stock_ratio >= 0.5:
            return Action.D
        if cooperation_rate <= 0.25 and stock_ratio <= 0.35:
            return Action.C
        if stock_ratio <= 0.2:
            return Action.C
        if cooperation_rate >= 0.7 and rounds_remaining > 2:
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_73(BaseStrategy):
    """
    Opportunistic Common Pool Strategy: Defaults to defection, cooperates only when
    stock is critically depleted (<20% capacity or <2n minimum threshold) or in
    rare tactical preservation scenarios. Exploits observed cooperation by continuing
    to defect, abandoning sustained cooperation for pure extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        min_viable = 2 * n
        critical_threshold = capacity * 0.2
        if current_stock < critical_threshold or current_stock < min_viable:
            return Action.C
        if history.round_number == 0:
            return Action.D
        current_round = history.round_number
        if current_round >= r - 2:
            return Action.D
        if current_stock > capacity * 0.7:
            return Action.D
        n_opponents = n - 1
        if n_opponents > 0:
            cooperators_last_round = history.opponent_cooperators[-1]
            cooperation_rate = cooperators_last_round / n_opponents
        else:
            cooperation_rate = 0.0
        if cooperation_rate >= 0.75:
            return Action.D
        if cooperation_rate >= 0.5:
            return Action.D
        if cooperation_rate < 0.25 and current_stock < capacity * 0.4:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_74(BaseStrategy):
    """
    Opportunistic Common Pool Resource Strategy.
    
    Defects by default to maximize immediate consumption. Cooperates only when
    resource preservation is critical for future exploitation opportunities.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if current_round == 0:
            return Action.D
        if current_round == total_rounds - 1:
            return Action.D
        stock_ratio = current_stock / capacity if capacity > 0 else 1.0
        rounds_remaining = total_rounds - current_round - 1
        if stock_ratio < 0.15:
            return Action.C
        if stock_ratio < 0.3 and rounds_remaining >= 2:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_75(BaseStrategy):
    """
    Opportunistic Strategy: Exploit-Collapse-Adapt
    
    Maximizes extraction when commons is robust and others cooperate.
    Pivots to cooperation when stock threatens collapse or defection becomes
    collectively damaging. Exploits mid-game windows aggressively while
    defecting unconditionally in final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.prev_stock = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        health_ratio = current_stock / capacity if capacity > 0 else 0.0
        if t == 0:
            count_c = n - 1
        else:
            count_c = int(history.opponent_cooperators[-1])
        stock_decline_ratio = 0.0
        if self.prev_stock > 0:
            stock_decline_ratio = (self.prev_stock - current_stock) / self.prev_stock
        stock_collapsed = stock_decline_ratio > 0.4
        own_consecutive_defections = 0
        if t >= 2:
            if not history.my_actions[-1] and (not history.my_actions[-2]):
                own_consecutive_defections = 2
        decision = Action.C
        if t == r - 1:
            decision = Action.D
        elif health_ratio < 0.3:
            decision = Action.C
        elif stock_collapsed:
            decision = Action.C
        elif t >= 2 and own_consecutive_defections >= 2:
            if not (health_ratio >= 0.65 and count_c >= n - 1):
                decision = Action.C
            else:
                decision = Action.D
        elif health_ratio >= 0.65 and count_c >= n - 2:
            decision = Action.D
        elif 0.3 <= health_ratio < 0.65 and count_c <= 1:
            decision = Action.D
        elif 0.5 <= health_ratio < 0.65 and count_c >= n - 1 and (t <= r - 3):
            decision = Action.D
        elif t == r - 2 and health_ratio >= 0.5:
            decision = Action.D
        elif t >= r - 2 and health_ratio > 0.6:
            if t > 0 and (not any((not action for action in history.my_actions))):
                decision = Action.D
            elif t == 0:
                decision = Action.D
        self.prev_stock = current_stock
        return decision

class Strategy_OPPORTUNISTIC_76(BaseStrategy):
    """
    Opportunistic Adaptive Strategy for Common Pool Resource Game.
    
    Exploits high stock levels and free-rides on cooperators when possible.
    Defects to maximize absolute gains when stock is abundant or critically depleted.
    Cooperates only in mid-game when opponents signal defection discipline (low cooperation).
    Always defects in the final round and when stock is severely depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        t = history.round_number
        if t == r - 1:
            return Action.D
        if t == 0:
            if current_stock > capacity * 0.7:
                return Action.D
            return Action.D
        n_opponents = n - 1
        if n_opponents <= 0:
            return Action.D
        opponents_cooperated = history.opponent_cooperators[-1]
        cooperation_rate = opponents_cooperated / n_opponents
        if cooperation_rate > 0.5 and current_stock > capacity * 0.5:
            return Action.D
        if current_stock > capacity * 0.7:
            return Action.D
        if current_stock < capacity * 0.2:
            return Action.D
        if cooperation_rate >= 0.5:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_77(BaseStrategy):
    """
    Greedy Stock-Aware Exploitation: Defect opportunistically to maximize consumption
    whenever it doesn't catastrophically collapse the resource before final rounds.
    Prioritizes extraction but switches to cooperation when resource collapse before
    final rounds would destroy remaining value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        capacity = self.game_description.capacity
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        stock_ratio = current_stock / capacity
        coop_count = history.opponent_cooperators[-1]
        if stock_ratio < 0.15:
            return Action.D
        if stock_ratio > 0.5 and coop_count >= 2 * n / 3:
            return Action.D
        if 0.3 < stock_ratio <= 0.5 and coop_count > (n - 1) / 2:
            return Action.D
        if stock_ratio > 0.6:
            return Action.D
        if stock_ratio <= 0.25 and current_round <= r / 2:
            return Action.C
        if stock_ratio <= 0.3 and current_round > 2 * r / 3:
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_78(BaseStrategy):
    """
    Opportunistic Stock-Exploitation Strategy: Defect by default to maximize immediate 
    payoff. Cooperate only when pool depletion threatens future extraction viability 
    (stock_ratio ≤ 0.20). Exploits cooperators ruthlessly in endgame and robust-pool 
    conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        stock_ratio = current_stock / self.game_description.capacity if self.game_description.capacity > 0 else 1.0
        rounds_remaining = self.game_description.n_rounds - history.round_number
        if stock_ratio <= 0.2:
            return Action.C
        if rounds_remaining <= 2:
            return Action.D
        if stock_ratio >= 0.85:
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_79(BaseStrategy):
    """
    Opportunistic Adaptive Extraction Strategy for Common Pool Resource Game.
    
    Core logic: Defect when stock is high and stable/growing, cooperate when
    stock is depleted or declining. Tests defection early and exploits in final round.
    Implements stock crash recovery and adaptive thresholds for endgame phase.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.stock_history = []
        self.consecutive_c_rounds = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num > 0:
            self.stock_history.append(current_stock)
        if round_num > 0.7 * self.n_rounds:
            threshold = 0.3 * self.capacity
        else:
            threshold = 0.4 * self.capacity
        if current_stock < 0.2 * self.capacity:
            self.consecutive_c_rounds += 1
            if self.consecutive_c_rounds < 2:
                return Action.C
        else:
            self.consecutive_c_rounds = 0
        if current_stock <= threshold:
            return Action.C
        rounds_remaining = self.n_rounds - round_num
        if round_num == 0:
            return Action.D
        if round_num == self.n_rounds - 1:
            return Action.D
        if len(self.stock_history) > 0:
            stock_previous = self.stock_history[-1]
            if current_stock <= 0.95 * stock_previous:
                self.consecutive_c_rounds = 1
                return Action.C
            if current_stock > 0.95 * stock_previous:
                self.consecutive_c_rounds = 0
                return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_80(BaseStrategy):
    """
    Opportunistic Stock Depletion Strategy
    
    Exploits cooperative opponents by defecting when cooperation is high,
    while monitoring stock levels and switching to cooperation during
    depletion threats. Prioritizes extraction in early/final rounds
    and through adaptive adjustments based on observed cooperation trends.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.consecutive_low_coop_rounds = 0
        self.in_adaptive_mode = False
        self.adaptive_round_counter = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.n_rounds - 1:
            return Action.D
        rounds_remaining = self.n_rounds - current_round
        n_opponents = self.n_players - 1
        observed_coop_count = history.opponent_cooperators[-1]
        observed_cooperation_rate = observed_coop_count / n_opponents if n_opponents > 0 else 0.0
        theta_coop = 0.5 + 0.2 * rounds_remaining / self.n_rounds
        stock_safety_threshold = 0.4 * self.capacity
        stock_depletion_threshold = 0.2 * self.capacity
        stock_recovery_threshold = 0.7 * self.capacity
        if current_stock < stock_depletion_threshold and observed_cooperation_rate < 0.3:
            self.consecutive_low_coop_rounds = 0
            self.in_adaptive_mode = False
            return Action.C
        if observed_cooperation_rate < 0.2:
            self.consecutive_low_coop_rounds += 1
        else:
            self.consecutive_low_coop_rounds = 0
            if current_stock > stock_recovery_threshold:
                self.in_adaptive_mode = False
                self.adaptive_round_counter = 0
        if self.consecutive_low_coop_rounds >= 2 and (not self.in_adaptive_mode):
            self.in_adaptive_mode = True
            self.adaptive_round_counter = 0
        if self.in_adaptive_mode:
            result = Action.C if self.adaptive_round_counter % 2 == 0 else Action.D
            self.adaptive_round_counter += 1
            return result
        if observed_cooperation_rate > theta_coop:
            return Action.D
        if current_stock > stock_safety_threshold and rounds_remaining <= 2:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_81(BaseStrategy):
    """
    Opportunistic CPR Strategy: Exploits cooperative players and high stock levels
    while adaptively preserving the pool when it is stressed.
    
    Defects in endgame, when others sustain a healthy pool (free-riding),
    and when defection is already widespread (matching strategy).
    Cooperates when pool is critical or when cooperation from others shows
    recovery potential.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.D
        if current_round >= r - 1:
            return Action.D
        if current_stock < 0.05 * capacity:
            return Action.C
        last_round_cooperation_count = history.opponent_cooperators[-1]
        if current_stock > 0.5 * capacity:
            threshold = math.ceil((n - 1) / 2)
            if last_round_cooperation_count >= threshold:
                return Action.D
            else:
                return Action.C
        if current_stock <= 0.3 * capacity:
            return Action.C
        threshold = math.floor((n - 1) / 3)
        if last_round_cooperation_count < threshold:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_82(BaseStrategy):
    """
    Opportunistic Adaptive Strategy for Common Pool Resource Game.
    
    Defects by default, exploiting early-round abundance and opponent cooperation.
    Switches to cooperation only when stock depletion or collapse risk threatens
    sustainable extraction. Treats cooperation as a tool, not a norm.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        n = self.n_players
        if round_num == 0:
            return Action.D
        if round_num == self.n_rounds - 1:
            return Action.D
        if current_stock < 0.001:
            return Action.C
        if current_stock >= self.capacity * 0.99:
            return Action.D
        threshold_critical = 0.5 * n
        threshold_abundant = 1.5 * n
        if current_stock <= threshold_critical:
            return Action.C
        if current_stock > threshold_abundant:
            return Action.D
        n_opponents = n - 1
        if n_opponents <= 0:
            return Action.D
        cooperators_last_round = history.opponent_cooperators[-1]
        cooperation_rate = cooperators_last_round / n_opponents
        if cooperation_rate > 0.65:
            return Action.D
        if cooperation_rate < 0.25:
            return Action.C if random.random() < 0.4 else Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_83(BaseStrategy):
    """
    Opportunistic Adaptive Strategy for Common Pool Resource Game.
    Exploits high stock levels when opponents cooperate, but switches to cooperation
    when stock is low to prevent collapse and ensure future rounds remain viable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        rounds_remaining = n_rounds - round_number
        if rounds_remaining == 1:
            return Action.D
        if round_number == 0:
            return Action.D
        opponent_cooperators_last = history.opponent_cooperators[-1]
        opponent_defectors_last = n - 1 - opponent_cooperators_last
        if n > 1:
            defection_rate = opponent_defectors_last / (n - 1)
        else:
            defection_rate = 0.0
        if capacity > 0:
            stock_ratio = current_stock / capacity
        else:
            stock_ratio = 0.0
        if stock_ratio < 1.0 / 6.0:
            return Action.C
        if stock_ratio >= 0.8:
            return Action.D
        if stock_ratio >= 0.5 and defection_rate <= 0.4:
            return Action.D
        if stock_ratio < 0.3:
            return Action.C
        if stock_ratio < 0.5 and defection_rate > 0.6:
            return Action.C
        if defection_rate <= 0.25:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_84(BaseStrategy):
    """
    Adaptive Opportunistic Stock-Extraction Strategy for Common Pool Resource Game.
    
    Exploits high stock levels and others' cooperation while minimizing personal cost.
    Always defects in initial and final rounds. In middle rounds, adapts based on 
    current stock level and observed cooperation rates, with probabilistic cooperation 
    only when critical depletion forces it. Adjusts thresholds based on time pressure 
    and group size.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.T_c = self.capacity * 0.4
        self.T_d = self.capacity * 0.15

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        rounds_remaining = self.n_rounds - current_round
        T_c = self.T_c
        if rounds_remaining <= 2:
            T_c = self.capacity * 0.2
        if self.n_players > 10:
            T_c *= 1.2
        if current_stock > T_c:
            return Action.D
        observed_cooperators = int(history.opponent_cooperators[-1])
        if observed_cooperators >= self.n_players / 2:
            return Action.D
        if current_stock <= self.T_d:
            if random.random() < 0.3:
                return Action.C
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_85(BaseStrategy):
    """
    Greedy Opportunist Strategy for Common Pool Resource Game.
    
    Defects if ANY of the following conditions hold:
    1. Last round endgame (t = r)
    2. High stock abundance (stock > capacity/2)
    3. Opponent cooperation available (cooperators >= (n-1)/2 in previous round)
    4. Opening move (t = 1)
    
    Otherwise cooperates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        if current_stock > capacity / 2:
            return Action.D
        cooperators_last_round = history.opponent_cooperators[-1]
        cooperation_threshold = (n - 1) / 2
        if cooperators_last_round >= cooperation_threshold:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_86(BaseStrategy):
    """
    Opportunistic Exploitation Strategy for Common Pool Resource Game.
    
    Prioritizes immediate payoff by defecting against observed cooperators while 
    maintaining minimal stock thresholds to avoid complete collapse. Shifts toward 
    cooperation only when resource urgency forces it or when defection becomes pointless.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        if current_stock < 0.05 * capacity:
            return Action.C
        c = history.opponent_cooperators[-1]
        if c == 0:
            return Action.D
        exploitation_rate = c / (n - 1) if n > 1 else 0
        stock_urgency = (capacity - current_stock) / capacity if capacity > 0 else 0
        rounds_remaining = r - current_round
        if stock_urgency > 0.7:
            return Action.C
        if rounds_remaining <= 1:
            return Action.D
        if stock_urgency < 0.3 and exploitation_rate >= 0.5:
            return Action.D
        if exploitation_rate >= 0.65:
            return Action.D
        if exploitation_rate < 0.15 and rounds_remaining >= 3:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_87(BaseStrategy):
    """
    Opportunistic Exploitation Strategy
    
    Defects by default, exploiting cooperators and abundant stock.
    Only cooperates in rare edge case: when stock is critically depleted (< 40% capacity)
    AND majority of opponents cooperated in previous round (> n/2).
    Defects unconditionally in first and last rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.D
        if history.round_number == r - 1:
            return Action.D
        c = history.opponent_cooperators[-1]
        s = current_stock
        if c <= n / 2 or s >= capacity * 0.4:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_88(BaseStrategy):
    """
    Opportunistic Adaptive Depletion Strategy.
    
    Defects when conditions allow advantage without critically compromising future payoff.
    Cooperates when defection would risk stock collapse. Uses round phase, stock level,
    and opponent cooperation to make adaptive decisions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num == self.r - 1:
            return Action.D
        if current_stock < self.capacity / 8:
            return Action.C
        opponent_coop = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if round_num > self.r / 2:
            if current_stock >= self.capacity / 2:
                if opponent_coop >= 0.5 * n_opponents:
                    return Action.D
                elif current_stock >= 0.8 * self.capacity:
                    return Action.D
                else:
                    return Action.C
            elif opponent_coop >= 0.7 * n_opponents:
                return Action.C
            else:
                return Action.D
        elif current_stock >= 0.9 * self.capacity:
            return Action.D
        elif opponent_coop >= 0.6 * n_opponents and current_stock >= self.capacity / 2:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_89(BaseStrategy):
    """
    Opportunistic Resource Raiding Strategy
    
    Exploits high stock levels and opponent cooperation while avoiding ecosystem collapse.
    Defects whenever possible to maximize immediate payoff, cooperates only when the
    common pool stock drops below critical levels necessary for survival.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.D
        if history.round_number == r - 1:
            return Action.D
        critical_threshold = capacity / (2 * n + 1)
        if current_stock < critical_threshold:
            return Action.C
        if current_stock > 0.7 * capacity:
            return Action.D
        cooperation_count = history.opponent_cooperators[-1]
        n_opponents = n - 1
        cooperation_rate = cooperation_count / n_opponents if n_opponents > 0 else 0.0
        if cooperation_rate > 0.6:
            return Action.D
        rounds_remaining = r - history.round_number
        if cooperation_rate < 0.3 and rounds_remaining < 0.4 * r:
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_90(BaseStrategy):
    """
    Opportunistic Resource Extraction Strategy.
    Defects to maximize immediate payoff unless stock depletion makes future extraction impossible.
    
    Decision rule:
    - Last round (round == n_rounds - 1): Always defect
    - stock / capacity < 0.25: Cooperate to preserve stock for regrowth
    - stock / capacity >= 0.25: Defect to maximize immediate extraction
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        stock_ratio = current_stock / self.game_description.capacity
        if stock_ratio < 0.25:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_91(BaseStrategy):
    """
    Opportunistic Adaptive Exploitation Strategy for Common Pool Resource Game.
    
    Systematically exploits cooperation rate mismatches while maintaining resource viability.
    - Round 1: Cooperate (probe opponent patterns)
    - Final ⌈r/5⌉ rounds: Always defect (endgame extraction with no future consequences)
    - Stock critical (≤n): Cooperate to prevent collapse
    - Stock abundant (≥1.8n): Defect safely within slack capacity
    - Mixed scenarios: Exploit high cooperation, race under defection-dominance, sustain under mixed
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.endgame_rounds = math.ceil(game_description.n_rounds / 5)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        remaining_rounds = r - current_round
        if current_round == 0:
            return Action.C
        if remaining_rounds <= self.endgame_rounds:
            return Action.D
        if current_stock <= n:
            return Action.C
        if current_stock >= 1.8 * n:
            return Action.D
        opponent_cooperators = history.opponent_cooperators[-1]
        cooperation_rate = opponent_cooperators / (n - 1)
        if cooperation_rate >= 0.5:
            return Action.D
        elif cooperation_rate <= 0.3:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_92(BaseStrategy):
    """
    Opportunistic strategy for Common Pool Resource Game.
    Defects by default to maximize immediate consumption.
    Cooperates only when stock approaches critical depletion (< 2n)
    to prevent complete collapse that would devastate future payoffs.
    Exploits observed high cooperation by defecting.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        min_stock = 2 * n
        rounds_remaining = r - history.round_number
        if current_stock <= min_stock:
            return Action.C
        if rounds_remaining == 1:
            return Action.D
        if history.round_number > 0:
            observed_cooperators = history.opponent_cooperators[-1]
            cooperation_threshold = (n - 1) * 0.75
            if observed_cooperators >= cooperation_threshold:
                return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_93(BaseStrategy):
    """
    Opportunistic Exploitation with Stock-Adaptive Timing
    
    Exploits cooperating opponents when stock is healthy, cooperates only instrumentally
    to enable future exploitation. Pivots aggressively toward defection in endgame.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        t = history.round_number
        rounds_remaining = r - t
        stock_ratio = current_stock / capacity if capacity > 0 else 0
        opponent_coop_count = history.opponent_cooperators[-1]
        n_opponents = n - 1
        opponent_coop_rate = opponent_coop_count / n_opponents if n_opponents > 0 else 0
        if rounds_remaining <= 2:
            return Action.D
        if stock_ratio >= 0.5:
            if opponent_coop_rate > 0.35:
                return Action.D
        if 0.25 <= stock_ratio < 0.5:
            if opponent_coop_rate > 0.4:
                return Action.D
            elif opponent_coop_rate <= 0.4 and rounds_remaining >= 4:
                return Action.C
            else:
                return Action.D
        if stock_ratio < 0.25:
            if opponent_coop_rate >= 0.6 and rounds_remaining >= 3:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_94(BaseStrategy):
    """
    Opportunistic Adaptive Strategy for Common Pool Resource Game.
    
    Decision framework prioritizes defection while using cooperation
    defensively to prevent resource extinction that would eliminate
    future exploitation opportunities.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_stock <= 0.12 * self.capacity:
            return Action.C
        if current_round > 0.7 * self.n_rounds:
            rounds_remaining = self.n_rounds - current_round - 1
            if current_stock > 0.25 * self.capacity:
                return Action.D
            if current_stock <= 0.25 * self.capacity and rounds_remaining <= 2:
                return Action.D
        n_opponents = self.n_players - 1
        cooperators_observed = float(history.opponent_cooperators[-1])
        if n_opponents == 0:
            return Action.D
        cooperator_ratio = cooperators_observed / n_opponents
        if cooperator_ratio > 0.4:
            return Action.D
        if cooperator_ratio <= 0.4:
            if len(history.my_payoffs) >= 2:
                recent_payoff = history.my_payoffs[-1]
                if len(history.my_payoffs) >= 3:
                    avg_recent = (history.my_payoffs[-1] + history.my_payoffs[-2]) / 2.0
                    avg_older = (history.my_payoffs[-3] + history.my_payoffs[-2]) / 2.0
                    if avg_older > 0:
                        decline_rate = (avg_older - avg_recent) / avg_older
                        if decline_rate > 0.1:
                            return Action.C
            if current_stock <= 0.08 * self.capacity:
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_95(BaseStrategy):
    """
    A dynamic cooperative-defective strategy for Common Pool Resource management.
    
    Prioritizes immediate gain by defaulting to defection when the stock trajectory permits.
    Cooperates defensively to prevent resource collapse and maximize total payoff.
    Exploits cooperative opponents systematically while preserving enough stock for future rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        r = self.game_description.n_rounds
        round_num = history.round_number
        rounds_remaining = r - round_num
        if round_num == 0:
            return Action.D
        if current_stock <= 2 * n:
            return Action.C
        if round_num == r - 1:
            return Action.D
        if current_stock == capacity:
            return Action.D
        cooperators = history.opponent_cooperators[-1]
        if cooperators == 0:
            if current_stock < capacity * 0.5:
                return Action.C
            else:
                return Action.D
        if rounds_remaining <= 2:
            safety_threshold = capacity * 0.2
        else:
            safety_threshold = max(capacity * 0.3, 4 * n)
        expected_consumption = current_stock * (n - cooperators + 1) / (2 * n)
        expected_remaining = current_stock - expected_consumption
        if expected_remaining >= safety_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_96(BaseStrategy):
    """
    Opportunistic Adaptive Strategy for Common Pool Resource Game.
    
    Exploits abundant stock by defecting when others cooperate, but switches to
    cooperation when stock depletes or collapse is detected. Final round always
    cooperates. First round always cooperates.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == 0:
            return Action.C
        if t == r - 1:
            return Action.C
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        c_t = history.opponent_cooperators[-1]
        if stock_ratio < 0.5:
            return Action.C
        if c_t <= 0.2 * (n - 1):
            return Action.C
        if stock_ratio >= 0.5 and (t < r - 1 or c_t >= 0.4 * (n - 1)):
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_97(BaseStrategy):
    """
    Adaptive Opportunistic Extraction Strategy for Common Pool Resource Game.
    
    Defects by default, exploiting cooperative opponents and depleting resources.
    Occasionally cooperates tactically to stabilize the pool when near collapse,
    purely to extend extraction opportunities.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_stock <= 1e-06:
            return Action.D
        rounds_remaining = self.n_rounds - current_round
        collapse_threshold = self.capacity / 4.0 * (rounds_remaining / self.n_rounds)
        recovery_threshold = 0.5 * self.capacity
        if current_stock >= recovery_threshold:
            return Action.D
        n_opponents = self.n_players - 1
        if n_opponents > 0:
            observed_coop_count = history.opponent_cooperators[-1]
            observed_coop_rate = observed_coop_count / float(n_opponents)
        else:
            observed_coop_rate = 0.0
        if observed_coop_rate > 0.6:
            return Action.D
        if observed_coop_rate < 0.3:
            return Action.D
        if current_stock < collapse_threshold:
            if observed_coop_rate < 0.4 and rounds_remaining <= 2:
                return Action.D
            pool_stabilization_prob = min(0.4, max(0.0, (current_stock - collapse_threshold) / self.capacity))
            if random.random() < pool_stabilization_prob:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_98(BaseStrategy):
    """
    Opportunistic Exploitation Strategy: Dynamically defects based on endgame,
    cooperation majorities, resource depletion, and early-game abundance.
    
    Exploits through free-riding on cooperators, defection contagion,
    endgame greed, and resource timing.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        if current_round == r - 2:
            if current_stock < capacity / 3:
                return Action.D
        observed_cooperators = history.opponent_cooperators[-1]
        n_opponents = n - 1
        observed_defectors = n_opponents - observed_cooperators
        defector_ratio = observed_defectors / n_opponents if n_opponents > 0 else 0.0
        cooperator_ratio = observed_cooperators / n_opponents if n_opponents > 0 else 0.0
        if defector_ratio >= 0.5:
            return Action.D
        if cooperator_ratio >= 0.6:
            return Action.D
        if current_stock < capacity / 3:
            return Action.D
        min_cooperative_payout = capacity / (2 * n)
        if current_stock / (2 * n) < 0.1 * min_cooperative_payout:
            return Action.D
        if current_stock > capacity * 0.75 and current_round <= r / 2:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_99(BaseStrategy):
    """
    Adaptive Opportunistic Strategy for Common Pool Resource Game.
    
    Exploits cooperators when stock is abundant, switches to cooperation only
    when catastrophic collapse is imminent or in the final round with depleted stock.
    Defects unconditionally in round 1 to establish opportunistic type.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n
        r = self.r
        capacity = self.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == r - 2:
            if current_stock <= 2 * n:
                return Action.C
            else:
                return Action.D
        if current_round == 0:
            return Action.D
        if current_round == 1:
            cooperators_prev = history.opponent_cooperators[-1]
            if cooperators_prev <= 1:
                return Action.D
        if current_stock > capacity / 2:
            return Action.D
        if current_stock <= 2 * n:
            return Action.C
        cooperators_prev = history.opponent_cooperators[-1]
        cooperation_rate = cooperators_prev / (n - 1) if n > 1 else 0.0
        if cooperation_rate > 0.5:
            return Action.D
        elif cooperation_rate <= 0.5 and current_stock <= 3 * n:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_100(BaseStrategy):
    """
    Opportunistic Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Defects by default, cooperates only when resource preservation is necessary
    to maintain future extraction opportunities. Uses stock levels and observed
    cooperation rates to adapt behavior across rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.critical_threshold = 2 * self.n
        self.safe_threshold = 0.4 * self.capacity
        self.min_cooperation_threshold = 1 / (2 * self.n)
        self.recovery_threshold = 0.3 * self.capacity
        self.previous_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            self.previous_stock = current_stock
            return Action.D
        if current_round == self.r - 1:
            self.previous_stock = current_stock
            return Action.D
        cooperators_previous = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        cooperation_rate = cooperators_previous / n_opponents if n_opponents > 0 else 0
        rounds_remaining = self.r - current_round
        if current_stock < self.critical_threshold:
            self.previous_stock = current_stock
            return Action.C
        if cooperation_rate < self.min_cooperation_threshold:
            self.previous_stock = current_stock
            return Action.D
        if cooperation_rate > 0.5 and current_stock >= self.safe_threshold:
            self.previous_stock = current_stock
            return Action.D
        if current_stock >= self.safe_threshold:
            if rounds_remaining == 1 or cooperation_rate < self.min_cooperation_threshold:
                self.previous_stock = current_stock
                return Action.D
            else:
                self.previous_stock = current_stock
                return Action.D
        if cooperation_rate >= self.min_cooperation_threshold:
            self.previous_stock = current_stock
            return Action.C
        if self.previous_stock is not None and current_stock < self.previous_stock:
            if self.critical_threshold <= current_stock < self.safe_threshold:
                defect_probability = rounds_remaining / self.r
                if random.random() < defect_probability:
                    self.previous_stock = current_stock
                    return Action.D
                else:
                    self.previous_stock = current_stock
                    return Action.C
        self.previous_stock = current_stock
        return Action.D

class Strategy_OPPORTUNISTIC_101(BaseStrategy):
    """
    Opportunistic Greedy-with-Recovery Strategy for Common Pool Resource Game.
    Defaults to defection to maximize extraction. Cooperates only when pool survival 
    is threatened or when recovery is needed for future exploitation opportunities.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        if history.round_number == 0:
            return Action.D
        if history.round_number == n_rounds - 1:
            return Action.D
        threshold_critical = 1.5 * n
        threshold_medium = capacity * 0.25
        threshold_exploit = 0.55
        if current_stock <= threshold_critical:
            return Action.C
        if current_stock <= threshold_medium:
            return Action.C
        n_opponents = n - 1
        if n_opponents > 0:
            coop_rate = history.opponent_cooperators[-1] / n_opponents
        else:
            coop_rate = 0.0
        if coop_rate >= threshold_exploit:
            return Action.D
        if coop_rate < 0.3:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_102(BaseStrategy):
    """
    Conditional Exploitation Strategy: Defects by default to maximize consumption,
    cooperates only when stock is critically low to restore the commons for future exploitation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        if history.round_number == 0:
            return Action.D
        if history.round_number == r - 1:
            return Action.D
        coop_count = history.opponent_cooperators[-1]
        if current_stock <= 0:
            return Action.D
        if coop_count >= n / 3:
            return Action.D
        elif current_stock < 2 * n:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_103(BaseStrategy):
    """
    Opportunistic Stock-Aware Defection Strategy.
    
    Defects by default, cooperating only under critical stock depletion or 
    when forced by strategy constraints. Exploits cooperative opponents while 
    protecting against resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.D
        if round_num == r - 1:
            return Action.D
        if current_stock < capacity * 0.12:
            return Action.C
        observed_cooperators = history.opponent_cooperators[-1]
        if observed_cooperators >= (n - 1) * 0.75:
            return Action.D
        if observed_cooperators >= (n - 1) * 0.4:
            if random.random() < 0.7:
                return Action.D
            else:
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_104(BaseStrategy):
    """
    Opportunistic Resource Depletion Strategy.
    
    Exploits abundant resources when possible, strategically cooperates only to prevent
    total collapse or for mid-game stock recovery, and defects aggressively in final rounds.
    Observes opponent cooperation to identify free-riding opportunities.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.critical_threshold = 2 * self.n_players
        self.medium_threshold = 0.35 * self.capacity
        self.abundance_threshold = 0.65 * self.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n_opponents = self.n_players - 1
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_stock <= self.critical_threshold:
            return Action.C
        if current_stock >= self.abundance_threshold:
            return Action.D
        if current_stock >= self.medium_threshold:
            if current_round > 0 and n_opponents > 0:
                recent_cooperators = history.opponent_cooperators[-1]
                observed_cooperation_rate = recent_cooperators / n_opponents
            else:
                observed_cooperation_rate = 0.0
            if observed_cooperation_rate > 0.4:
                return Action.D
            if current_round < self.n_rounds / 2:
                return Action.C
            else:
                return Action.D
        if current_round <= self.n_rounds - 2:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_105(BaseStrategy):
    """
    Opportunistic Exploitation with Conditional Preservation.
    
    Defects in round 1 and the final round to maximize immediate extraction.
    In middle rounds, conditionally cooperates based on stock level relative to
    a preservation threshold and the proportion of cooperators among opponents.
    While stock is healthy above the threshold, always defect. Once stock drops
    below the threshold, only cooperate if a supermajority (≥65%) of opponents
    cooperated in the previous round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.preservation_threshold = game_description.capacity / 2.5

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number == n_rounds - 1:
            return Action.D
        if current_stock > self.preservation_threshold:
            return Action.D
        else:
            cooperators_last_round = history.opponent_cooperators[-1]
            supermajority_threshold = math.ceil((n_players - 1) * 0.65)
            if cooperators_last_round >= supermajority_threshold:
                return Action.C
            else:
                return Action.D

class Strategy_OPPORTUNISTIC_106(BaseStrategy):
    """
    Adaptive Opportunistic Strategy for Common Pool Resource Game.
    
    Dynamically switches between cooperation and defection based on:
    - Current stock level relative to capacity
    - Cooperation rate of opponents in previous round
    - Position in game timeline (early/mid/late game)
    
    Core logic:
    - Exploit high cooperation + abundant stock by defecting
    - Cooperate when stock is critically low to enable regrowth
    - Defect in endgame regardless of stock conditions
    - Monitor opponent cooperation rate to decide exploitation strategy
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num == self.r - 1:
            return Action.D
        c_observed = history.opponent_cooperators[-1]
        coop_rate = c_observed / max(1, self.n - 1)
        if current_stock < self.capacity * 0.15:
            return Action.C
        if round_num > 2 * self.r / 3:
            if current_stock > self.capacity * 0.5:
                return Action.D
            else:
                return Action.C
        if current_stock > self.capacity * 0.65:
            if coop_rate > 0.5:
                return Action.D
            else:
                return Action.C
        if current_stock < self.capacity * 0.3:
            if coop_rate > 0.6:
                return Action.C
            elif round_num < self.r / 3:
                return Action.C
            else:
                return Action.D
        if coop_rate > 0.65:
            return Action.D
        if coop_rate < 0.3 and current_stock > self.capacity * 0.4:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_107(BaseStrategy):
    """
    Opportunistic Adaptive Strategy: Defect when stock is abundant, cooperate 
    when stock is critical. Always defect in the final round.
    
    Uses stock-to-capacity ratio (ρ) to trigger opportunism:
    - ρ > 0.5: Always defect (abundant regime)
    - 0.2 < ρ ≤ 0.5: Defect with probability (ρ - 0.2) / 0.3 (moderate regime)
    - ρ ≤ 0.2: Always cooperate (critical regime)
    - Final round: Always defect regardless of stock
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        rho = current_stock / self.game_description.capacity
        if rho > 0.5:
            return Action.D
        if rho > 0.2:
            defection_probability = (rho - 0.2) / 0.3
            if random.random() < defection_probability:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_OPPORTUNISTIC_108(BaseStrategy):
    """
    Opportunistic Depletion Strategy: Extract maximum value while stock is abundant.
    Cooperate only as a defensive measure to prevent catastrophic collapse.
    
    Core logic:
    - Round 1: Always defect (aggressive baseline)
    - Final round: Always defect (no future rounds)
    - Critical collapse (stock ≤ 25% capacity): Cooperate (mandatory stabilization)
    - Stock approaching capacity (≥95%): Defect (buffer absorbs extraction)
    - Late-game with low stock (t > r-2, stock ≤ 50%): Cooperate (preserve)
    - High opponent cooperation with good stock: Defect (exploit their self-handicapping)
    - Low opponent cooperation with declining stock: Cooperate (coordinate reversal)
    - Default: Defect (dominant single-round strategy)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if current_stock <= 0.25 * capacity:
            return Action.C
        if current_round == r - 1:
            return Action.D
        if current_stock >= 0.95 * capacity:
            return Action.D
        c_t = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if c_t >= n_opponents * 0.8 and current_stock > 0.4 * capacity:
            return Action.D
        if c_t <= n_opponents * 0.3 and current_stock < 0.45 * capacity:
            return Action.C
        if current_round >= 2:
            recent_consumption = 0.0
            stock_decline_rate = 0.0
            if current_round > 0:
                stock_below_capacity = capacity - current_stock
                if stock_below_capacity > 0.2 * capacity:
                    max_growth_rate = 2.0 * (capacity / 4.0) * (1.0 - 0.5)
                    if current_round < r - 1:
                        recent_defection_pressure = (n_opponents - c_t) / max(1, n_opponents)
                        if recent_defection_pressure > 0.7 and current_stock < 0.6 * capacity:
                            return Action.C
        if current_round >= r - 2 and current_stock <= 0.5 * capacity:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_109(BaseStrategy):
    """
    Opportunistic Adaptive Depletion Strategy.
    
    Defects by default to maximize immediate payoff (stock/n).
    Cooperates only when stock depletion threatens future opportunities,
    using resource regeneration as a mechanism to exploit later.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n = self.n_players
        r = self.n_rounds
        stock = current_stock
        if current_round == r - 1:
            return Action.D
        if stock < 1.5 * n and current_round < r - 2:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_110(BaseStrategy):
    """
    Opportunistic Strategy: Aggressive Extraction with Collapse Prevention.
    
    Defect by default to maximize payoff. Switch to cooperation only when
    stock drops below 15% of capacity to prevent resource collapse and
    enable future extraction. Ignores opponent behavior entirely—decisions
    depend solely on current stock level relative to capacity.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock / self.game_description.capacity <= 0.15:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_111(BaseStrategy):
    """
    Opportunistic Adaptive Pool Extraction Strategy.
    
    Exploits high-stock phases through defection while monitoring opponent behavior
    and stock depletion. Shifts to preservation mode when stock approaches critical
    levels or when opponent defection accelerates. Always defects in final rounds
    to capture remaining value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        remaining_rounds = r - current_round
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        if current_round == r - 1:
            return Action.D
        if remaining_rounds <= 2:
            return Action.D
        if current_round == 0:
            return Action.D
        n_opponents = n - 1
        n_cooperators_last_round = history.opponent_cooperators[-1]
        observed_defection_count = n_opponents - n_cooperators_last_round
        if stock_ratio > 0.7:
            if remaining_rounds > 3:
                return Action.D
        if 0.4 < stock_ratio <= 0.7:
            threshold = (n - 1) / 2.0
            if observed_defection_count <= threshold:
                return Action.D
            else:
                return Action.C
        if stock_ratio <= 0.4:
            if remaining_rounds <= 1:
                return Action.D
            else:
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_112(BaseStrategy):
    """
    Opportunistic Exploitation Strategy for Common Pool Resource Game.
    
    Defaults to defection to maximize immediate payoff, but switches to cooperation
    when stock falls below 30% of capacity to prevent resource collapse and ensure
    future defection opportunities remain viable. Plays defection unconditionally in
    the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        stock_ratio = current_stock / self.game_description.capacity
        if stock_ratio < 0.3:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_113(BaseStrategy):
    """
    Opportunistic Adaptive Resource Harvester: A strategic player that defects early,
    exploits cooperators when stock is healthy, but switches to cooperation when
    stock threatens sustainability. Abandons cooperation in final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        if history.round_number == 0:
            return Action.D
        rounds_remaining = n_rounds - history.round_number
        if rounds_remaining <= 1:
            return Action.D
        S_min = 3 * n
        S_healthy = capacity * 0.6
        S_critical = 1.5 * n
        K_t = history.opponent_cooperators[-1]
        opponent_count = n - 1
        rho = K_t / opponent_count if opponent_count > 0 else 0.0
        S_t = current_stock
        if S_t >= S_healthy and rho >= 0.5:
            return Action.D
        if S_t < S_critical:
            return Action.C
        if rho >= 0.75:
            return Action.D
        elif rounds_remaining >= 3:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_114(BaseStrategy):
    """
    Threshold-Triggered Opportunistic Strategy for Common Pool Resource Game.
    
    Combines opportunistic defection when stock is abundant with cooperation
    triggers when stock faces depletion risk or widespread defection threatens
    the resource. Defects aggressively in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        capacity = self.game_description.capacity
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number
        low_stock_threshold = 0.3 * capacity
        moderate_stock_threshold = 0.5 * capacity
        if current_stock < low_stock_threshold:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        if current_stock < moderate_stock_threshold and current_round > 0:
            observed_cooperators_last_round = history.opponent_cooperators[-1]
            if observed_cooperators_last_round < n_players / 2:
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_115(BaseStrategy):
    """
    Opportunistic Stock-Aware Defection Strategy.
    
    Exploits cooperators when stock is healthy and cooperation is widespread.
    Cooperates only when stock is critically depleted to restore the pool for
    future exploitation. Defects unconditionally in the endgame (last 2 rounds).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num >= r - 1:
            return Action.D
        if round_num == 0:
            return Action.D
        if current_stock < capacity / 3:
            return Action.C
        cooperators = history.opponent_cooperators[-1]
        n_opponents = n - 1
        cooperation_ratio = cooperators / n_opponents if n_opponents > 0 else 0.0
        if cooperation_ratio > 0.5 and current_stock > capacity / 1.5:
            return Action.D
        if cooperation_ratio <= 0.2:
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_116(BaseStrategy):
    """
    Opportunistic Defection with Stock-Preservation Thresholds.
    
    Strategy exploits cooperation when stock is healthy, cooperates only when
    forced by imminent collapse or insufficient peer conservation. Defaults to
    defection as the primary strategy, switching to cooperation reactively.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number == n_rounds - 1:
            return Action.D
        if current_stock <= 0:
            return Action.C
        if round_number >= n_rounds - 3:
            if current_stock / capacity >= 0.5:
                return Action.D
        stock_ratio = current_stock / capacity
        n_opponents = n_players - 1
        if n_opponents > 0:
            observed_coop_rate = history.opponent_cooperators[-1] / n_opponents
        else:
            observed_coop_rate = 0.0
        if stock_ratio <= 0.2:
            return Action.C
        if stock_ratio >= 0.6:
            return Action.D
        if stock_ratio >= 0.5:
            if observed_coop_rate <= 0.5:
                return Action.D
        if stock_ratio > 0.2 and stock_ratio < 0.5:
            if observed_coop_rate > 0.65:
                return Action.D
            elif observed_coop_rate <= 0.35:
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_117(BaseStrategy):
    """
    Opportunistic Threshold-Adaptive Strategy for Common Pool Resource Game.
    
    Exploits cooperative opponents when stock is abundant, shifts to endgame extraction,
    and only cooperates when stock depletion threatens payoffs. Uses dynamic thresholds
    based on stock health and observed cooperation rate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num >= r - 2:
            return Action.D
        stock_health = current_stock / capacity if capacity > 0 else 0.0
        n_opponents = n - 1
        observed_cooperators = history.opponent_cooperators[-1]
        observed_cooperation_rate = observed_cooperators / n_opponents if n_opponents > 0 else 0.0
        remaining_rounds = r - round_num
        if stock_health < 0.05:
            return Action.C
        if observed_cooperators == n_opponents and stock_health > 0.5:
            return Action.D
        if observed_cooperators == 0 and stock_health < 0.3:
            return Action.C
        if stock_health > 0.75 and observed_cooperation_rate > 0.4:
            return Action.D
        if stock_health > 0.6 and observed_cooperation_rate > 0.6:
            return Action.D
        if stock_health < 0.4:
            return Action.C
        if remaining_rounds <= r / 2:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_118(BaseStrategy):
    """
    Opportunistic Adaptive Strategy for Common Pool Resource Game.
    Exploits high cooperation when the pool is healthy, but switches to cooperation
    when the pool is critically depleted to prevent total collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        if current_round == 0:
            cooperation_rate = 0.5
        else:
            observed_coop = history.opponent_cooperators[-1]
            cooperation_rate = observed_coop / (n - 1) if n - 1 > 0 else 0.0
        if current_round == r - 1:
            if current_stock > 2 * n:
                return Action.D
            else:
                return Action.C
        if stock_ratio < 0.1:
            return Action.C
        if cooperation_rate >= 0.75:
            return Action.D
        if cooperation_rate >= 0.6 and stock_ratio > 0.35:
            return Action.D
        if cooperation_rate >= 0.3 and stock_ratio > 0.5:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_119(BaseStrategy):
    """
    Opportunistic Common Pool Resource Strategy.
    
    Defects in round 1 to probe for dominance and in the final round to maximize
    immediate payoff. During mid-game, exploits observed cooperation when stock is
    healthy (h >= 0.30), switches to cooperation only when stock is critically low
    (h < 0.30), and uses endgame logic to accelerate defection as remaining rounds shrink.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == 0:
            return Action.D
        if t == r - 1:
            return Action.D
        h = current_stock / capacity
        c_rate = history.opponent_cooperators[-1] / (n - 1) if n > 1 else 0.0
        remaining = r - t
        if h < 0.3:
            return Action.C
        if h < 0.5:
            if c_rate >= 0.5:
                return Action.D
            else:
                return Action.C
        if c_rate >= 0.5:
            return Action.D
        elif remaining <= r / 3:
            return Action.D
        elif c_rate >= 0.3:
            return Action.D
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_120(BaseStrategy):
    """
    Opportunistic Common Pool Resource Strategy
    
    Defects when:
    - Current round is the final round, OR
    - Stock >= 60% of capacity (abundant resource), OR
    - Stock <= 2n (pool near collapse)
    
    Adapts defection threshold if opponents are aggressively depleting stock.
    Otherwise cooperates to maintain stock growth.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.collapse_threshold = 2 * self.n
        self.stock_history = []
        self.defection_threshold = 0.6
        self.collapsed = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        self.stock_history.append(current_stock)
        current_round = history.round_number
        is_final_round = current_round == self.n_rounds - 1
        if current_stock <= self.collapse_threshold:
            self.collapsed = True
        if self.collapsed:
            return Action.D
        if is_final_round:
            return Action.D
        if current_round > 1:
            initial_stock = self.stock_history[0]
            current_decline = initial_stock - current_stock
            rounds_elapsed = current_round
            avg_decline_per_round = current_decline / rounds_elapsed
            expected_decline_per_round = self.capacity / self.n_rounds
            if avg_decline_per_round > expected_decline_per_round:
                self.defection_threshold = max(0.55, self.defection_threshold - 0.05)
        if current_stock >= self.capacity * self.defection_threshold:
            return Action.D
        if current_stock <= self.collapse_threshold:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_121(BaseStrategy):
    """
    Opportunistic Adaptive Resource Depletion Strategy for Common Pool Resource Game.
    Exploits high stock periods while avoiding catastrophic depletion through selective cooperation.
    Defects in round 1 and final round, uses composite signal based on stock health and opponent
    cooperation rates in intermediate rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.D
        if round_num == n_rounds - 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        cooperation_rate = c_prev / (n - 1) if n > 1 else 0.0
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        rounds_remaining = n_rounds - round_num
        if stock_ratio > 0.5 and cooperation_rate < 0.6:
            return Action.D
        if rounds_remaining <= 2:
            return Action.D
        if cooperation_rate < 0.4:
            return Action.D
        if stock_ratio > 0.7 and cooperation_rate < 0.8:
            return Action.D
        if 0.3 <= stock_ratio <= 0.5 and 0.4 <= cooperation_rate <= 0.6:
            return Action.D
        if stock_ratio < 0.3 and rounds_remaining > 2 and (cooperation_rate >= 0.5):
            return Action.C
        return Action.C

class Strategy_OPPORTUNISTIC_122(BaseStrategy):
    """
    Stockpile-and-Extract Strategy: Defects on round 1 and final round, 
    with conditional cooperation in middle rounds based on stock level 
    and observed cooperation rate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number == n_rounds - 1:
            return Action.D
        coop_count = history.opponent_cooperators[-1]
        coop_rate = coop_count / (n - 1) if n > 1 else 0.0
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        if stock_ratio < 0.4 or coop_rate < 0.3:
            return Action.C
        elif stock_ratio > 0.65 and coop_rate > 0.65:
            return Action.D
        elif stock_ratio > 0.55 and coop_rate > 0.5:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_123(BaseStrategy):
    """
    Adaptive Opportunistic Exploitation Strategy for Common Pool Resource Game.
    
    Dynamically switches between cooperation and defection based on stock phase
    and opponent cooperation rates. Prioritizes immediate payoff extraction while
    maintaining minimal stock for future exploitation opportunities.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        phase_exploit = current_stock >= 0.7 * capacity
        phase_sustainable = 0.5 * capacity <= current_stock < 0.7 * capacity
        phase_at_risk = 0.3 * capacity <= current_stock < 0.5 * capacity
        phase_critical = current_stock < 0.3 * capacity
        if current_round == 0:
            cooperation_rate = 0.0
        else:
            opponent_cooperators = history.opponent_cooperators[-1]
            n_opponents = n - 1
            cooperation_rate = opponent_cooperators / n_opponents if n_opponents > 0 else 0.0
        rounds_remaining = r - current_round
        if current_round == r - 1:
            return Action.D
        if phase_exploit:
            return Action.D
        if phase_sustainable and cooperation_rate > 0.5:
            return Action.D
        if phase_at_risk and cooperation_rate > 0.65:
            return Action.D
        if phase_critical and rounds_remaining <= 2:
            return Action.D
        if phase_at_risk and cooperation_rate <= 0.65 and (current_round < r - 1):
            return Action.C
        if phase_critical and current_round <= r / 3:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_124(BaseStrategy):
    """
    Opportunistic Common Pool Resource Strategy.
    
    Exploits high-cooperation environments, defects against low-cooperation opponents,
    and temporarily cooperates only when stock depletion requires recovery for future
    exploitation opportunities.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.previous_stock = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            self.previous_stock = current_stock
            return Action.D
        if current_round == r - 1:
            self.previous_stock = current_stock
            return Action.D
        if current_stock < 1:
            self.previous_stock = current_stock
            return Action.D
        cooperators_observed = history.opponent_cooperators[-1]
        cooperation_rate = cooperators_observed / (n - 1) if n > 1 else 0
        threshold = (n - 1) / n
        if cooperation_rate > threshold:
            self.previous_stock = current_stock
            return Action.D
        if current_stock > 0.75 * capacity:
            self.previous_stock = current_stock
            return Action.D
        stock_declining = current_stock < self.previous_stock
        if current_stock <= 0.75 * capacity and stock_declining:
            self.previous_stock = current_stock
            return Action.C
        self.previous_stock = current_stock
        return Action.D

class Strategy_OPPORTUNISTIC_125(BaseStrategy):
    """
    Opportunistic Adaptive Exploitation Strategy for Common Pool Resource Game.
    
    Defects by default, cooperates only when resource depletion creates imminent 
    collapse risk or when exploitation offers diminishing returns. Treats cooperation 
    as a tactical concession, aggressively seizing high-payoff windows while 
    protecting against catastrophic resource collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_stock <= 0:
            return Action.C
        if current_stock >= capacity:
            return Action.D
        if current_round == 0:
            return Action.D
        rounds_remaining = r - current_round
        if rounds_remaining <= 2:
            return Action.D
        n_opponents = n - 1
        if n_opponents > 0:
            observed_cooperation_rate = history.opponent_cooperators[-1] / n_opponents
        else:
            observed_cooperation_rate = 0.0
        stock_depletion_risk = 1.0 - current_stock / capacity if capacity > 0 else 0.0
        if current_stock < capacity / 4:
            return Action.C
        if current_stock < capacity / 2.5 and stock_depletion_risk > 0.5:
            if observed_cooperation_rate >= 0.6:
                return Action.D
            else:
                return Action.C
        if current_stock >= capacity * 0.65:
            return Action.D
        if observed_cooperation_rate > 0.75:
            return Action.D
        elif observed_cooperation_rate <= 0.25:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_126(BaseStrategy):
    """
    Opportunistic Strategy: Exploit & Collapse
    
    Maximizes immediate payoff by defecting when stock is healthy (> 2n).
    Switches to cooperation only when stock becomes critically low (≤ 2n)
    to preserve the common pool and avoid complete collapse.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = 2 * game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock <= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_127(BaseStrategy):
    """
    Opportunistic Exploit & Preserve Strategy.
    
    Defaults to defection to maximize immediate consumption. Cooperates only when
    necessary to prevent resource collapse or sustain future value. Exploits
    cooperative opponents aggressively while stock permits.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.n_players
        r = self.n_rounds
        capacity = self.capacity
        current_round = history.round_number
        rounds_remaining = r - current_round
        stock_danger_threshold = 2 * n
        cooperation_last_round = history.opponent_cooperators[-1] if current_round > 0 else 0
        if rounds_remaining == 0:
            return Action.D
        danger_threshold = stock_danger_threshold * 1.5
        if current_stock < danger_threshold:
            deficit = danger_threshold - current_stock
            max_deficit = stock_danger_threshold * 0.5
            if max_deficit == 0:
                return Action.C
            if deficit > max_deficit:
                return Action.C
            else:
                p_cooperate = deficit / max_deficit
                if random.random() < p_cooperate:
                    return Action.C
                else:
                    return Action.D
        if rounds_remaining == 1:
            return Action.D
        if current_stock > 0.65 * capacity:
            return Action.D
        if current_stock >= 0.4 * capacity:
            if cooperation_last_round >= 0.75 * n:
                return Action.D
            elif cooperation_last_round <= 0.25 * n:
                return Action.C
            else:
                return Action.D
        if cooperation_last_round >= 0.6 * n:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_128(BaseStrategy):
    """
    Aggressive Exploitation with Adaptive Collapse Prevention.
    
    Default to defection for maximum immediate extraction.
    Cooperate only when resource collapse would reduce future payoffs more than cooperation costs.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.sustainability_threshold = 1.3 * self.n
        self.collapse_margin = 0.25 * self.capacity
        self.min_rounds_remaining_for_recovery = 2

    def _apply_growth(self, stock_after_consumption: float) -> float:
        """Apply logistic growth to stock after consumption."""
        if stock_after_consumption <= 0:
            return 0.0
        growth = 2 * stock_after_consumption * (1 - stock_after_consumption / self.capacity)
        return min(stock_after_consumption + growth, self.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        rounds_remaining = self.r - round_number
        if rounds_remaining < 1:
            return Action.D
        if current_stock > self.sustainability_threshold:
            return Action.D
        if rounds_remaining < self.min_rounds_remaining_for_recovery:
            return Action.D
        if current_stock <= 0.5 * self.n:
            consumption_if_all_defect = current_stock
            stock_after_D = self._apply_growth(max(0, current_stock - consumption_if_all_defect))
            consumption_if_I_cooperate = (self.n - 1) * (current_stock / self.n) + current_stock / (2 * self.n)
            stock_after_C = self._apply_growth(max(0, current_stock - consumption_if_I_cooperate))
            if stock_after_C >= self.collapse_margin and stock_after_D < self.collapse_margin:
                return Action.C
            else:
                return Action.D
        consumption_if_all_defect = current_stock
        stock_after_D_consumption = max(0, current_stock - consumption_if_all_defect)
        stock_after_D = self._apply_growth(stock_after_D_consumption)
        consumption_if_I_cooperate = (self.n - 1) * (current_stock / self.n) + current_stock / (2 * self.n)
        stock_after_C_consumption = max(0, current_stock - consumption_if_I_cooperate)
        stock_after_C = self._apply_growth(stock_after_C_consumption)
        if stock_after_C <= stock_after_D + self.collapse_margin:
            return Action.D
        elif stock_after_C >= self.collapse_margin and stock_after_D < self.collapse_margin:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_33(BaseStrategy):
    """
    Stock-Responsive Defection Strategy: Cooperate if and only if stock level
    falls below a threshold of capacity/(2*n). Always defect in round 1 and
    the final round. In middle rounds, apply the threshold rule: cooperate
    when stock is dangerously low (resource preservation becomes valuable),
    defect when stock is abundant.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = game_description.capacity / (2 * game_description.n_players)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock <= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_34(BaseStrategy):
    """
    Adaptive Threshold Defection Strategy for Common Pool Resource Game.
    
    Employs conditional logic based on stock levels and opponent cooperation rates:
    1. Preserves stock when critically depleted (≤25% capacity)
    2. Exploits cooperators when stock is abundant (>50% capacity)
    3. Defaults to defection for personal gain when conditions allow
    4. Defects in first round and final round (unless stock is critically low)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold_critical = 0.25 * self.capacity
        self.threshold_abundant = 0.5 * self.capacity
        self.coop_rate_exploit = 0.5
        self.coop_rate_low = 0.3

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.n_rounds - 1:
            if current_stock > self.threshold_critical:
                return Action.D
            else:
                return Action.C
        if current_stock <= self.threshold_critical:
            return Action.C
        n_opponents = self.n_players - 1
        if n_opponents > 0:
            coop_rate = history.opponent_cooperators[-1] / n_opponents
        else:
            coop_rate = 0.0
        if coop_rate >= self.coop_rate_exploit and current_stock > self.threshold_abundant:
            return Action.D
        if coop_rate < self.coop_rate_low and current_stock > self.threshold_critical:
            return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_35(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Responds to observed cooperation levels with state-dependent thresholds.
    Defects when opponents show insufficient cooperation, salvages the pool when depleted,
    and exploits abundant stock strategically. Uses finite-end considerations to maximize payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        rounds_remaining = self.game_description.n_rounds - history.round_number
        if rounds_remaining < 3:
            return Action.D
        stock_ratio = current_stock / self.game_description.capacity
        if stock_ratio < 0.25:
            return Action.D
        n_opponents = self.game_description.n_players - 1
        if n_opponents <= 0:
            coop_rate = 0.0
        else:
            coop_rate = history.opponent_cooperators[-1] / n_opponents
        if stock_ratio < 0.6:
            if coop_rate >= 0.65:
                return Action.C
            else:
                return Action.D
        if coop_rate >= 0.45:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_36(BaseStrategy):
    """
    Adaptive Stock-Monitoring Defection Strategy for Common Pool Resource Game.
    
    Monitors current stock levels relative to capacity and adapts defection behavior based on:
    - Stock depletion ratio (threshold: 0.4)
    - Game phase (endgame in last 2 rounds)
    - Opponent cooperation patterns (over last 3 rounds)
    - Last round always defects
    
    Cooperates when stock is healthy and opponents are cooperative,
    defects when resources are depleted or exploitation is widespread.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.min_ratio = 0.4
        self.endgame_start = game_description.n_rounds - 2
        self.endgame_stock_threshold = 0.7
        self.coop_history_window = 3
        self.coop_defection_threshold = 0.4
        self.coop_cooperation_threshold = 0.7
        self.opponent_defection_ratio = 0.6

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        if current_round == n_rounds - 1:
            return Action.D
        if current_round >= self.endgame_start:
            if stock_ratio > self.endgame_stock_threshold:
                return Action.C
            else:
                return Action.D
        if stock_ratio < self.min_ratio:
            return Action.D
        num_opponent_cooperators_last_round = int(history.opponent_cooperators[-1])
        num_opponent_defectors_last_round = n_players - 1 - num_opponent_cooperators_last_round
        defection_threshold = (n_players - 1) * self.opponent_defection_ratio
        if num_opponent_defectors_last_round >= defection_threshold:
            return Action.D
        rounds_to_analyze = min(self.coop_history_window, current_round)
        start_round_idx = current_round - rounds_to_analyze
        total_cooperators = 0
        for i in range(start_round_idx, current_round):
            total_cooperators += int(history.opponent_cooperators[i])
        total_opponent_slots = rounds_to_analyze * (n_players - 1)
        if total_opponent_slots > 0:
            observed_cooperation_freq = total_cooperators / total_opponent_slots
        else:
            observed_cooperation_freq = 0.5
        if observed_cooperation_freq < self.coop_defection_threshold:
            return Action.D
        elif observed_cooperation_freq > self.coop_cooperation_threshold:
            return Action.C
        if stock_ratio >= self.min_ratio:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_37(BaseStrategy):
    """
    Adaptive Exploitation with Depletion Safeguard.
    
    Defects initially to establish baseline behavior, then adapts based on stock depletion
    and opponent defection rates. Includes safeguards against resource collapse while
    opportunistically exploiting when stock is abundant.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.D
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        n_opponents = n_players - 1
        cooperators_prev = history.opponent_cooperators[-1]
        defectors_prev = n_opponents - cooperators_prev
        rounds_remaining = n_rounds - history.round_number
        if stock_ratio <= 0.25:
            return Action.C
        elif stock_ratio <= 0.35 and defectors_prev >= math.ceil(n_players / 2):
            return Action.C
        elif rounds_remaining <= 2:
            return Action.D
        elif stock_ratio <= 0.45 and defectors_prev >= n_players - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_38(BaseStrategy):
    """
    Threshold-Based Adaptive Defection Strategy for Common Pool Resource Game.
    
    Cooperates when stock is at or below a dynamic threshold that adapts based on
    observed opponent defection rates. The threshold is set at capacity/2 initially
    and increases when opponents cooperate more (lower defection rate observed).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.base_threshold = self.capacity / 2.0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            dynamic_threshold = self.base_threshold
        else:
            n_opponents = self.n_players - 1
            n_cooperators_last_round = history.opponent_cooperators[-1]
            n_defectors_last_round = n_opponents - n_cooperators_last_round
            if n_opponents > 0:
                observed_defection_rate = n_defectors_last_round / n_opponents
            else:
                observed_defection_rate = 0.0
            defection_pressure = observed_defection_rate
            dynamic_threshold = self.base_threshold * (1.0 + defection_pressure)
            dynamic_threshold = min(dynamic_threshold, self.capacity)
        if current_stock <= dynamic_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_39(BaseStrategy):
    """
    Individualistic Strategy: Adaptive Exploitation with Sustainability Floor
    
    Defects opportunistically while cooperation is abundant, but cooperates when
    resources become critically scarce to protect future payoff opportunities.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.in_recovery_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if current_stock < 0.2 * capacity:
            self.in_recovery_mode = True
        if self.in_recovery_mode and current_stock >= 0.4 * capacity:
            self.in_recovery_mode = False
        if self.in_recovery_mode:
            return Action.C
        if current_stock < 0.3 * capacity:
            return Action.C
        if t == r - 1:
            return Action.D
        if t <= 1:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents <= 0:
            cooperation_rate = 0.0
        else:
            cooperation_rate = prev_cooperators / n_opponents
        if cooperation_rate > 0.5:
            return Action.D
        if cooperation_rate > 0.2:
            return Action.D
        if current_stock < 0.5 * capacity:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_40(BaseStrategy):
    """
    Threshold-Based Adaptive Defection Strategy for Common Pool Resource Game.
    
    Defects when: (1) in final round, (2) stock critically low, (3) stock trajectory 
    unsustainable, or (4) majority of opponents have defected. Otherwise cooperates.
    Always cooperates in round 0 when resource is abundant and opponent behavior unknown.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.D
        if current_stock < 2 * n:
            return Action.D
        if current_stock < capacity * (r - current_round) / r:
            return Action.D
        opponents_cooperated_count = history.opponent_cooperators[-1]
        total_opponents = n - 1
        opponents_defected_count = total_opponents - opponents_cooperated_count
        if opponents_defected_count > math.floor((n - 1) / 2):
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_41(BaseStrategy):
    """
    Adaptive Depletion Strategy: Defects aggressively while the resource is viable,
    switches to measured consumption only when necessary for resource survival,
    and maximizes extraction in endgame. Never sacrifices payoff for group benefit.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round >= r - 2:
            return Action.D
        if current_round == 0:
            return Action.D
        if current_stock < 0.01 * capacity:
            if r - current_round < 2:
                return Action.D
            else:
                return Action.C
        c_prev = history.opponent_cooperators[-1]
        if current_stock >= 0.5 * capacity:
            return Action.D
        if current_stock >= 0.25 * capacity:
            return Action.D
        if current_round <= r - 3:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_42(BaseStrategy):
    """
    Individualistic Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Maximizes personal payoff by:
    - Extracting surplus when stock is abundant
    - Defecting aggressively in terminal phases
    - Responding to opponent defection patterns
    - Preserving extraction opportunities
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.in_recovery_mode = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        rounds_remaining = n_rounds - current_round
        if current_round == 0:
            return Action.C
        if current_stock < 0.2 * capacity:
            self.in_recovery_mode = True
        elif current_stock > 0.4 * capacity:
            self.in_recovery_mode = False
        if self.in_recovery_mode:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        if rounds_remaining <= 1 and current_stock > 0.3 * capacity:
            return Action.D
        if current_stock > 0.6 * capacity and rounds_remaining <= 2:
            return Action.D
        n_opponents = n_players - 1
        if n_opponents > 0:
            cooperators_last_round = history.opponent_cooperators[-1]
            defectors_last_round = n_opponents - cooperators_last_round
            observed_defection_rate = defectors_last_round / n_opponents
            if observed_defection_rate > 0.5 and current_stock > 0.4 * capacity:
                return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_43(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Uses a dynamic threshold that varies based on:
    - Time pressure (rounds remaining)
    - Observed opponent cooperation
    - Current stock level
    
    Defects in final round, cooperates at critical depletion,
    defects at saturation, otherwise compares stock to threshold.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        rounds_remaining = r - current_round
        if rounds_remaining == 0:
            return Action.D
        if current_stock >= capacity:
            return Action.D
        if current_stock < capacity / (4 * n):
            return Action.C
        if current_round == 0:
            c_obs = 0.5
        else:
            cooperators_count = history.opponent_cooperators[-1]
            n_opponents = n - 1
            c_obs = cooperators_count / n_opponents if n_opponents > 0 else 0.5
        time_pressure = rounds_remaining / r
        threshold = capacity * (0.3 + 0.4 * time_pressure - 0.2 * c_obs)
        if current_stock > threshold:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_44(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Maintains a dynamic stock threshold that triggers cooperation.
    Defects when resource is abundant, cooperates when depleted to preserve
    future payoff potential. Final round defects unconditionally.
    Threshold adapts based on observed opponent cooperation levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.threshold = self.capacity * (1.5 / self.n)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C if current_stock <= self.threshold else Action.D
        cooperators = int(history.opponent_cooperators[-1])
        n_opponents = self.n - 1
        if n_opponents > 0:
            if cooperators >= n_opponents / 2:
                self.threshold *= 0.98
            elif cooperators < n_opponents / 4:
                self.threshold *= 1.02
        depletion_threshold = self.capacity / (4.0 * self.n)
        if current_stock < depletion_threshold:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D if current_stock > 0 else Action.C
        return Action.C if current_stock <= self.threshold else Action.D

class Strategy_INDIVIDUALISTIC_45(BaseStrategy):
    """
    Adaptive Conditional Defection strategy for Common Pool Resource Game.
    
    Cooperates in round 1 as an informational probe. In subsequent rounds,
    cooperates only if stock is healthy (> 45% of capacity) AND more than 50%
    of opponents cooperated in the previous round. Defects unconditionally
    in the last round or when stock is depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock <= 0.05 * self.game_description.capacity:
            return Action.D
        if current_stock <= 0.45 * self.game_description.capacity:
            return Action.D
        n_opponents = self.game_description.n_players - 1
        opponents_cooperated_last_round = history.opponent_cooperators[-1]
        if opponents_cooperated_last_round > n_opponents * 0.5:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_46(BaseStrategy):
    """
    Adaptive Depletion-Responsive Strategy for Common Pool Resource Game.
    
    Core Decision Rule:
    - First round: Defect (stock at capacity, immediate gain optimal)
    - Final round: Always defect (no future value)
    - Intermediate rounds: Stock-level based with opponent signal incorporation
    
    Stock thresholds (simplified, constant):
    - stock > 0.5 × capacity: Defect
    - 0.25 × capacity < stock ≤ 0.5 × capacity: Cooperate
    - stock ≤ 0.25 × capacity: Cooperate (critical—avoid collapse)
    
    Opponent signals:
    - If c_prev < n/3 AND stock < 0.4 × capacity: Cooperate (stabilize)
    - If c_prev > 2n/3 AND stock > 0.6 × capacity: Defect (aggressive)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        rounds_remaining = r - round_number
        if round_number == 0:
            return Action.D
        if rounds_remaining == 1:
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        if c_prev < n / 3 and current_stock < 0.4 * capacity:
            return Action.C
        if c_prev > 2 * n / 3 and current_stock > 0.6 * capacity:
            return Action.D
        if current_stock > 0.5 * capacity:
            return Action.D
        elif current_stock > 0.25 * capacity:
            return Action.C
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_47(BaseStrategy):
    """
    Adaptive Stock-Threshold Strategy with Opportunistic Defection.
    
    Maintains a running estimate of opponent defection rate and bases decisions on:
    1. Stock Health Check: Cooperate if stock critically low
    2. Opponent Defection Pressure: Adaptive response to opponent behavior
    3. Remaining Rounds Adjustment: Different logic for final round
    
    This strategy is purely self-interested: cooperation is instrumental only to
    preserve future payoffs, while defection is pursued whenever risk-reward favors it.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.C
        stock_rounded = round(current_stock)
        capacity_rounded = round(capacity)
        is_final_round = history.round_number == r - 1
        if is_final_round:
            if stock_rounded > capacity_rounded / 3:
                return Action.D
            else:
                return Action.C
        if stock_rounded < capacity_rounded / 2.5:
            return Action.C
        rounds_played = history.round_number
        n_opponents = n - 1
        total_opponent_cooperations = int(np.sum(history.opponent_cooperators[:rounds_played]))
        total_opponent_actions = n_opponents * rounds_played
        total_opponent_defections = total_opponent_actions - total_opponent_cooperations
        if rounds_played <= 1:
            d_rate = 0.0
        else:
            d_rate = total_opponent_defections / (n_opponents * (rounds_played - 1))
        if d_rate > 0.65:
            return Action.D
        elif d_rate > 0.35:
            prob_cooperate = 1.0 - (d_rate - 0.35) / 0.3
            if random.random() < prob_cooperate:
                return Action.C
            else:
                return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_48(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Defects in round 1 to establish a low-cooperation baseline.
    In subsequent rounds, cooperates only when stock is healthy (≥ capacity/2),
    almost all opponents cooperated (≥ (n-1)/n cooperation rate), at least 3 rounds remain,
    and stock is not critically depleted (> 2n).
    Always defects in the final round and on stock emergencies.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_stock < 2 * self.n_players:
            return Action.D
        n_opponent_cooperators = history.opponent_cooperators[-1]
        n_opponents = self.n_players - 1
        if n_opponents <= 0:
            return Action.D
        cooperation_rate = n_opponent_cooperators / n_opponents
        cooperation_threshold = (self.n_players - 1) / self.n_players
        rounds_remaining = self.n_rounds - current_round
        condition_stock_health = current_stock >= self.capacity / 2
        condition_cooperation = cooperation_rate >= cooperation_threshold
        condition_time_horizon = rounds_remaining >= 3
        condition_not_critical = current_stock > 2 * self.n_players
        if condition_stock_health and condition_cooperation and condition_time_horizon and condition_not_critical:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_49(BaseStrategy):
    """
    Individualistic Stock-Responsive Adaptive Strategy: Maximizes personal payoffs 
    through dynamic defection while preserving resource viability when stock approaches 
    critical depletion. Exploits high cooperation but moderates extraction when stock 
    is insufficient or opponent defection is widespread.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        critical_threshold = 1.5 * self.n
        if current_stock <= critical_threshold:
            return Action.C
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.n_rounds - 1:
            if current_stock > critical_threshold:
                return Action.D
            else:
                return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        if n_opponents > 0:
            observed_coop_rate = cooperators_last_round / n_opponents
        else:
            observed_coop_rate = 0.0
        if observed_coop_rate > 0.75:
            return Action.D
        elif observed_coop_rate > 0.25:
            if current_stock > self.capacity * 0.5:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_50(BaseStrategy):
    """
    Individualistic Adaptive Strategy for Common Pool Resource Game.
    
    Decision rule based on round number and current stock level:
    - Final round: Always defect for maximum payoff
    - Critical depletion (stock < capacity/3): Cooperate to allow recovery
    - Penultimate rounds (≥ r-2): Defect as recovery time is insufficient
    - Early-to-mid game: Defect if stock > capacity/2, else cooperate
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_stock < self.capacity / 3:
            return Action.C
        if current_round >= self.n_rounds - 2:
            return Action.D
        if current_stock > self.capacity / 2:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_51(BaseStrategy):
    """
    Individualistic Adaptive Stock-Threshold Strategy
    
    Defects by default. Cooperates only when stock is critically low (< 35% capacity)
    to enable regeneration, or when stock is in mid-range and opponents are mostly
    cooperating. Uses stock ratio thresholds and opponent cooperation rate as signals
    for self-interested payoff maximization.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        rounds_remaining = n_rounds - current_round
        stock_ratio = current_stock / capacity if capacity > 0 else 0
        if rounds_remaining == 1:
            return Action.D
        if stock_ratio < 0.35:
            return Action.C
        if stock_ratio > 0.65:
            return Action.D
        if current_round > 0:
            last_round_coop_count = history.opponent_cooperators[-1]
            n_opponents = n - 1
            last_round_coop_rate = last_round_coop_count / n_opponents if n_opponents > 0 else 0
            if last_round_coop_rate >= 0.5 and rounds_remaining >= 3:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_52(BaseStrategy):
    """
    Individualistic Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Acts as an individualist who:
    - Extracts maximum payoff when resources are abundant (stock ≥ 90% capacity)
    - Responds adaptively to opponent behavior in mid-range stock levels
    - Preserves resources only when stock is critically depleted (< 40% capacity)
    - Always defects in the final round with no future to protect
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.n_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_stock >= 0.9 * self.capacity:
            return Action.D
        if current_stock < 0.4 * self.capacity:
            return Action.C
        if current_round == 0:
            return Action.D
        opponent_cooperators_last_round = history.opponent_cooperators[-1]
        if self.n_opponents <= 0:
            return Action.C
        defectors_last_round = self.n_opponents - opponent_cooperators_last_round
        defection_rate = defectors_last_round / self.n_opponents
        if defection_rate >= 0.5:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_53(BaseStrategy):
    """
    Adaptive Defection with Stock Preservation strategy.
    Balances immediate payoff gains from defection against stock depletion costs.
    Cooperates when stock preservation is critical, defects when conditions favor it.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.D
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        if stock_ratio < 0.25:
            return Action.C
        remaining_rounds = r - current_round
        n_opponents = n - 1
        last_cooperators = history.opponent_cooperators[-1] if n_opponents > 0 else 0
        last_defectors = n_opponents - last_cooperators
        inferred_defection_rate = last_defectors / max(1, n_opponents)
        if stock_ratio * remaining_rounds < 1.5:
            return Action.C
        if stock_ratio >= 0.95 and inferred_defection_rate > 0.5:
            return Action.D
        if stock_ratio > 0.6 and inferred_defection_rate > 0.4:
            if stock_ratio > 0.8 and remaining_rounds > 2:
                return Action.D
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_54(BaseStrategy):
    """
    Stock-Responsive Depletion Strategy for Common Pool Resource Game.
    
    Cooperates when stock is depleted (≤65% capacity) to allow recovery.
    Also cooperates in end-game (1-2 rounds remaining) when stock is between 65-80% capacity.
    Defects in first round and final round, and when stock is abundant (>65% capacity).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        rounds_remaining = n_rounds - round_number
        if round_number == 0:
            return Action.D
        if rounds_remaining == 1:
            return Action.D
        if current_stock <= capacity * 0.65:
            return Action.C
        if current_stock <= capacity * 0.8 and rounds_remaining <= 2:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_55(BaseStrategy):
    """
    Individualistic Stock-Conscious Defection Strategy.
    
    Cooperates if and only if both conditions hold:
    1. Not in the final round (t < r)
    2. Stock level indicator stock/(n-1) ≤ threshold
    
    Threshold is determined by opponent cooperation history:
    - avg_coop ≥ 0.6: threshold = 0.5
    - 0.3 ≤ avg_coop < 0.6: threshold = 0.3
    - avg_coop < 0.3: threshold = 0.1
    
    Special cases: Always defect in round 1 and final round. 
    Cooperate in non-final rounds when stock is critically low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        if current_stock < 0.1:
            return Action.C
        n_opponents = n - 1
        if n_opponents <= 0:
            return Action.D
        cooperation_rates = []
        for i in range(current_round):
            coop_count = history.opponent_cooperators[i]
            coop_rate = coop_count / n_opponents
            cooperation_rates.append(coop_rate)
        avg_coop = np.mean(cooperation_rates) if cooperation_rates else 0.0
        if avg_coop >= 0.6:
            threshold = 0.5
        elif avg_coop >= 0.3:
            threshold = 0.3
        else:
            threshold = 0.1
        condition_1 = current_round < r
        stock_ratio = current_stock / n_opponents
        condition_2 = stock_ratio <= threshold
        if condition_1 and condition_2:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_56(BaseStrategy):
    """
    Individualistic Adaptive Stock-Management Strategy
    
    Core decision rule: defect when resource is abundant, cooperate when depletion 
    threatens future earning potential. Uses stock level and observed defector count
    to determine actions.
    
    Thresholds:
    - stock_threshold = capacity / 2
    - defector_threshold = 0.65 × (n - 1) opponents defecting
    - near_zero_threshold = capacity / 20
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.stock_threshold = game_description.capacity / 2
        self.near_zero_threshold = game_description.capacity / 20
        self.defector_threshold = 0.65 * (game_description.n_players - 1)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == n_rounds - 1:
            return Action.D
        if current_round == 0:
            if n <= 3:
                return Action.C
            return Action.D
        if current_stock < self.near_zero_threshold:
            return Action.C
        if current_stock <= self.stock_threshold:
            return Action.C
        observed_cooperators_last_round = history.opponent_cooperators[-1]
        observed_defectors_last_round = n - 1 - observed_cooperators_last_round
        if observed_defectors_last_round > self.defector_threshold:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_57(BaseStrategy):
    """
    Individualistic Stock-and-Behavior Responsive Strategy for Common Pool Resource Game.
    
    Cooperates in early rounds to preserve stock, becomes responsive to both stock level
    and opponents' cooperation rate in middle rounds, and defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if round_num == r - 1:
            return Action.D
        n_opponents = n - 1
        if n_opponents <= 0:
            return Action.D
        num_cooperators_last_round = history.opponent_cooperators[-1]
        current_coop_rate = num_cooperators_last_round / n_opponents
        epsilon = 1e-09
        exhaustion_threshold = 2 * n + epsilon
        if current_stock < exhaustion_threshold:
            return Action.D
        if current_stock >= 0.7 * capacity:
            if current_coop_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        if current_stock >= 0.4 * capacity:
            coop_threshold = 1.0 / (2 * n) + 0.1
            if current_coop_rate > coop_threshold:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_58(BaseStrategy):
    """
    Stockkeeper Defection Strategy for Common Pool Resource Game.
    
    Implements a self-interested strategy that adapts behavior based on current stock level
    and round number:
    - Final round: Always defect (no future payoff to protect)
    - Stock ≤ capacity/4: Defect (critically depleted, collapse imminent)
    - capacity/4 < Stock < capacity/2: Cooperate (critical recovery zone)
    - Stock ≥ capacity/2: Defect (healthy resource with robust regeneration)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        quarter_capacity = self.capacity / 4.0
        half_capacity = self.capacity / 2.0
        if current_stock <= quarter_capacity:
            return Action.D
        elif current_stock < half_capacity:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_59(BaseStrategy):
    """
    Adaptive Threshold Defection Strategy for Common Pool Resource Game.
    
    Dynamically switches between defection and cooperation based on:
    - Final round: always defect (no future benefit to cooperation)
    - High stock (≥55% capacity): defect aggressively
    - Low stock (<55% capacity) with high opponent cooperation (≥65%): cooperate
    - Low stock with low opponent cooperation: defect
    - Stock collapse (<2): defect regardless
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < 2:
            return Action.D
        if current_stock >= self.game_description.capacity * 0.55:
            return Action.D
        rounds_seen = history.round_number
        if rounds_seen < 2:
            return Action.D
        n_opponents = self.game_description.n_players - 1
        total_cooperators = np.sum(history.opponent_cooperators[:rounds_seen])
        if n_opponents == 0:
            return Action.D
        coop_rate = total_cooperators / (n_opponents * rounds_seen)
        if coop_rate >= 0.65:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_60(BaseStrategy):
    """
    Stock-Threshold Defection with Endgame Exploitation.
    
    Cooperates when stock drops below critical thresholds:
    - When stock < capacity/3 (resource depleted), or
    - During the second-to-last round AND stock < capacity/2 (preserve for endgame)
    
    Otherwise defects to exploit abundant resources when regeneration can sustain it.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        capacity = self.game_description.capacity
        n_rounds = self.game_description.n_rounds
        round_number = history.round_number
        if current_stock < capacity / 3:
            return Action.C
        if round_number == n_rounds - 2 and current_stock < capacity / 2:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_61(BaseStrategy):
    """
    Exploitation-with-Preservation Strategy for Common Pool Resource Game.
    
    Defects in the first and last rounds to maximize immediate payoff.
    In middle rounds, switches to cooperation if stock drops below 1/3 capacity
    to preserve the resource for future extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if current_round == 0:
            return Action.D
        if current_round == n_rounds - 1:
            return Action.D
        if current_stock < capacity / 3:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_62(BaseStrategy):
    """
    Adaptive Stock-Responsive Strategy for Common Pool Resource Game.
    
    Decision logic balances immediate payoff maximization with long-term stock preservation.
    Core approach: Defect early when stock is abundant, but cooperate when stock is depleting
    or nearing critically low levels. Adapts to opponent behavior in later rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.previous_stock = game_description.capacity
        self.stock_history = [game_description.capacity]

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        self.stock_history.append(current_stock)
        rounds_remaining = n_rounds - round_number - 1
        if round_number == n_rounds - 1:
            return Action.D
        if current_stock <= 0.3 * capacity:
            return Action.C
        if rounds_remaining == 1:
            return Action.C
        if rounds_remaining > 2 and len(self.stock_history) >= 3:
            stock_two_rounds_ago = self.stock_history[-3]
            stock_previous = self.stock_history[-2]
            if stock_two_rounds_ago > 0:
                retention_ratio = stock_previous / stock_two_rounds_ago
                if retention_ratio < 0.85:
                    return Action.C
        if round_number == 0:
            return Action.D
        observed_cooperators = history.opponent_cooperators[-1]
        if observed_cooperators < n / 2:
            return Action.D
        if observed_cooperators >= n / 2 and current_stock <= 0.5 * capacity:
            return Action.C
        if current_stock >= capacity * 0.99:
            return Action.D
        if observed_cooperators >= n / 2:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_63(BaseStrategy):
    """
    Adaptive Stock-Preservation Strategy for Common Pool Resource Game.
    
    Uses a dynamic sustainability threshold to decide between cooperation and defection.
    In abundant rounds, defects to maximize extraction. In scarce rounds, cooperates to
    preserve future payoff potential. Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        rounds_remaining = r - current_round - 1
        sustainability_threshold = 0.33 + rounds_remaining / r * 0.17
        if stock_ratio > sustainability_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_64(BaseStrategy):
    """
    Adaptive Depletion-Response Strategy for Common Pool Resource Game.
    
    Dynamically adjusts cooperation based on stock health, opponent behavior,
    and endgame position. Defects when stock is depleted or when future
    rounds offer minimal payoff benefit. Cooperates strategically when
    cooperation rates exceed thresholds and stock health is sufficient.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        health = current_stock / self.capacity if self.capacity > 0 else 0.0
        if health < 0.1:
            return Action.D
        if current_round == self.n_rounds - 1:
            return Action.D
        n_opponents = self.n_players - 1
        cooperators_last_round = history.opponent_cooperators[-1]
        coop_rate = cooperators_last_round / n_opponents if n_opponents > 0 else 0.5
        if current_round == self.n_rounds - 2:
            coop_rate_threshold = 0.65
        else:
            coop_rate_threshold = 0.5
        trajectory = self._calculate_trajectory(current_stock, coop_rate)
        endgame_weight = (self.n_rounds - current_round) / self.n_rounds
        if health < 0.25:
            return Action.D
        if health < 0.5 and coop_rate < 0.4:
            return Action.D
        if health > 0.65 and trajectory > 0 and (coop_rate > coop_rate_threshold):
            return Action.C
        if coop_rate > 0.6 and health > 0.45 and (endgame_weight > 0.5):
            return Action.C
        return Action.D

    def _calculate_trajectory(self, current_stock: float, coop_rate: float) -> float:
        """
        Project stock one round ahead assuming coop_rate fraction of opponents cooperate.
        Returns the change in stock (projected_stock - current_stock).
        """
        n_opponents = self.n_players - 1
        expected_cooperators = coop_rate * n_opponents
        expected_defectors = n_opponents - expected_cooperators
        self_consumption = current_stock / (2 * self.n_players)
        coop_consumption_per_opponent = current_stock / (2 * self.n_players)
        defect_consumption_per_opponent = current_stock / self.n_players
        opponent_consumption = expected_cooperators * coop_consumption_per_opponent + expected_defectors * defect_consumption_per_opponent
        total_consumption = self_consumption + opponent_consumption
        stock_after_consumption = current_stock - total_consumption
        stock_after_consumption = max(0.0, stock_after_consumption)
        if self.capacity > 0:
            growth = 2.0 * stock_after_consumption * (1.0 - stock_after_consumption / self.capacity)
        else:
            growth = 0.0
        new_stock = min(stock_after_consumption + growth, self.capacity)
        trajectory = new_stock - current_stock
        return trajectory

class Strategy_INDIVIDUALISTIC_65(BaseStrategy):
    """
    Adaptive Stock-Threshold Strategy for Common Pool Resource Game.
    
    Maximizes personal payoff by conditionally defecting based on stock health 
    and time remaining. Defection occurs when resource can absorb consumption; 
    cooperation is enforced only when stock preservation is necessary for future payoff.
    
    Core decision rules:
    1. Last round: DEFECT unconditionally
    2. Stock critically depleted: COOPERATE
    3. Stock healthy: DEFECT (with opponent cooperation adjustment)
    4. Intermediate stock: Defect if buffer sufficient, else cooperate
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        r = self.n_rounds
        S = current_stock
        if t == r - 1:
            return Action.D
        critical_threshold = self.capacity / (3 * self.n_players)
        if S <= critical_threshold:
            return Action.C
        healthy_threshold = self.capacity * 0.65
        if t > 0:
            opponent_count = self.n_players - 1
            if opponent_count > 0:
                observed_coop_rate = history.opponent_cooperators[-1] / opponent_count
                if observed_coop_rate < 0.3:
                    healthy_threshold = self.capacity * 0.55
                elif observed_coop_rate > 0.6:
                    healthy_threshold = self.capacity * 0.75
        if S > healthy_threshold:
            return Action.D
        rounds_left = r - t - 1
        min_stock_needed = self.capacity * 0.4
        buffer_term = 0.0
        if rounds_left > 0 and S > 0:
            buffer_term = S / 4 * rounds_left
        if S > min_stock_needed + buffer_term:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_66(BaseStrategy):
    """
    Adaptive Stock-Conditional Strategy: Cooperate only when stock is critically low 
    AND a strict majority of opponents cooperated in the previous round. 
    Defect unconditionally in round 1 and final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.D
        if round_num == r - 1:
            return Action.D
        if round_num == r - 2:
            if current_stock <= capacity / 4:
                return Action.C
            return Action.D
        stock_condition = current_stock <= capacity / 2
        opponent_cooperators_prev = history.opponent_cooperators[-1]
        coop_threshold = (n - 1) / 2
        cooperation_condition = opponent_cooperators_prev >= coop_threshold
        if stock_condition and cooperation_condition:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_67(BaseStrategy):
    """
    Adaptive Stock-Responsive Defection (ASRD) Strategy
    
    Cooperates if and only if BOTH conditions hold:
    1. Current stock meets a dynamic health threshold that tightens as rounds decrease
    2. Observed defection rate doesn't exceed 50% of all players
    
    Otherwise defects. Always defects in final round regardless of conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        t = history.round_number
        if t == self.r - 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        rounds_remaining = self.r - t
        if rounds_remaining <= 0:
            return Action.D
        threshold = self.capacity * (1 - 2 / rounds_remaining)
        condition_1 = current_stock >= threshold
        if t == 0:
            observed_defectors = 0
        else:
            cooperators_last_round = history.opponent_cooperators[t - 1]
            observed_defectors = self.n - 1 - cooperators_last_round
        condition_2 = observed_defectors <= self.n / 2
        if condition_1 and condition_2:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_68(BaseStrategy):
    """
    Individualistic Stock-Adaptive Strategy for Common Pool Resource Game.
    
    Maintains defection rate history and stock trajectory to adapt between cooperation
    (to preserve commons under threat) and defection (to exploit when conditions permit).
    Uses observable aggregate defection counts and stock state only, with unconditional
    defection in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_stock <= 0:
            return Action.C
        stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0.0
        n_opponents = self.n_players - 1
        lookback_window = min(3, current_round)
        defection_counts = []
        for i in range(lookback_window):
            round_idx = current_round - 1 - i
            cooperators = history.opponent_cooperators[round_idx]
            defectors = n_opponents - cooperators
            defection_counts.append(defectors)
        if n_opponents > 0 and defection_counts:
            avg_defectors = sum(defection_counts) / len(defection_counts)
            recent_defection_rate = avg_defectors / n_opponents
        else:
            recent_defection_rate = 0.0
        if recent_defection_rate >= 0.99:
            return Action.C
        if current_round == self.n_rounds - 1:
            return Action.D if current_stock > 0 else Action.C
        if stock_ratio < 0.35:
            return Action.C
        if recent_defection_rate > 0.65:
            return Action.C
        if recent_defection_rate < 0.25 and stock_ratio > 0.65:
            return Action.D
        rounds_remaining = self.n_rounds - current_round
        if rounds_remaining >= 3:
            return Action.C
        elif rounds_remaining == 2:
            return Action.D if stock_ratio > 0.5 else Action.C
        elif rounds_remaining == 1:
            return Action.D if current_stock > 0 else Action.C
        return Action.C

class Strategy_INDIVIDUALISTIC_69(BaseStrategy):
    """
    Sustainability-Threshold Adaptive Defection strategy for Common Pool Resource Game.
    
    Cooperates when the sustainability score (opponent cooperation rate × normalized stock level)
    meets an adaptive threshold that decreases over time, inducing endgame defection.
    The threshold is calibrated to cooperate early when stock is healthy and opponent cooperation
    is high, then transitions to pure defection in the final rounds when future preservation
    has zero value.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == 0:
            opponent_coop_rate = 1.0
        else:
            m_coop = history.opponent_cooperators[-1]
            opponent_coop_rate = m_coop / (n - 1)
        sustainability_score = opponent_coop_rate * (current_stock / capacity)
        rounds_remaining = r - t
        threshold = 0.2 + 0.4 * rounds_remaining / r
        if sustainability_score >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_70(BaseStrategy):
    """
    Adaptive Stock-Threshold Strategy for Common Pool Resource Game.
    
    Uses a stock health and urgency metric to decide between cooperation and defection.
    - In the final round, always defects (no recovery period).
    - Otherwise, defects if (health × urgency) ≥ 0.45, cooperates otherwise.
    - health = current_stock / capacity
    - urgency = rounds_remaining / total_rounds
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == n_rounds - 1:
            return Action.D
        if capacity > 0:
            health = current_stock / capacity
        else:
            health = 0.0
        rounds_remaining = n_rounds - current_round
        urgency = rounds_remaining / n_rounds
        if health * urgency >= 0.45:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_71(BaseStrategy):
    """
    Threshold-based stock preservation strategy that maximizes payoffs by extracting 
    aggressively when the resource is abundant, but switches to conservation when 
    depletion becomes a constraint on future earnings.
    
    Decision rule: Maintain a stock threshold T = 0.5 × capacity
    - If stock > T: Play D (Defect) for higher immediate payoff
    - If stock ≤ T: Play C (Cooperate) to allow recovery
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = 0.5 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if current_stock > self.threshold:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_72(BaseStrategy):
    """
    Individualistic Stock-Responsive Strategy for Common Pool Resource Game.
    
    Defects in terminal rounds, when pool is depleting, when opponents defect significantly,
    or when pool recovery is unlikely. Otherwise cooperates to maintain resource sustainability
    while maximizing individual payoff opportunistically.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        rounds_remaining = r - round_num - 1
        if rounds_remaining <= 1:
            return Action.D
        observed_cooperators = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents > 0:
            opponent_defection_rate = (n_opponents - observed_cooperators) / n_opponents
        else:
            opponent_defection_rate = 0.0
        if opponent_defection_rate > 0.5:
            return Action.D
        if current_stock < capacity / 3:
            return Action.D
        if current_stock < capacity / 2 and opponent_defection_rate > 1.0 / 3.0:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_73(BaseStrategy):
    """
    Greedy Stock-Preservation Strategy for Common Pool Resource Game.
    
    Prioritizes personal consumption while respecting resource sustainability constraints.
    Uses adaptive thresholds for survival, last-round exploitation, and stock recovery.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_stock < 2 * n:
            return Action.C
        if current_round == r - 1:
            return Action.D
        if current_stock < capacity / 2:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_74(BaseStrategy):
    """
    Individualistic Common Pool Resource Strategy.
    
    Defects when stock is abundant (> capacity/3) to maximize extraction.
    Cooperates when stock is low (≤ capacity/3) to prevent collapse.
    Always defects in final two rounds (terminal exploitation).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number >= self.game_description.n_rounds - 2:
            return Action.D
        threshold = self.game_description.capacity / 3
        if current_stock > threshold:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_75(BaseStrategy):
    """
    Adaptive Threshold Cooperation with Stock-Sensitive Adjustment.
    
    Cooperates if observed opponent cooperation rate exceeds a dynamically adjusted threshold
    that depends on stock depletion and time horizon. The threshold is lowered when stock is
    depleted (encouraging cooperation for recovery) and raised near the end of the game or
    when stock is healthy (favoring defection). Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if t == 0:
            coop_rate = 0.5
        else:
            total_cooperators = np.sum(history.opponent_cooperators[:t])
            coop_rate = total_cooperators / ((n - 1) * t)
        stock_ratio = current_stock / capacity
        rounds_remaining = r - t
        if rounds_remaining == 0:
            threshold = 1.0
        else:
            threshold = 0.5 - 0.15 * stock_ratio + 0.05 * rounds_remaining / r
            threshold = max(0.0, min(1.0, threshold))
        if coop_rate >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_76(BaseStrategy):
    """
    Individualistic Adaptive Threshold Strategy
    
    Defects when stock is abundant (exceeds dynamic threshold), cooperates when depleted.
    Threshold adapts based on remaining rounds to implement selfish endgame logic:
    - Early rounds: higher threshold (accept more depletion before cooperating)
    - Late rounds: lower threshold (cooperate more readily since fewer rounds remain)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        rounds_remaining = self.n_rounds - history.round_number
        threshold = self.capacity * (0.35 + 0.15 * rounds_remaining / self.n_rounds)
        if current_stock > threshold:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_77(BaseStrategy):
    """
    Adaptive Threshold Strategy with Horizon Awareness.
    
    Cooperates only when: stock is viable (≥30% capacity), 
    opponents show reciprocal cooperation (≥50%), and sufficient rounds remain (≥25%).
    Adapts cooperation threshold based on opponent trends and adjusts stock threshold 
    if stock declines despite own cooperation. Defects in final round and at critical depletion.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.cooperation_threshold = 0.5
        self.stock_threshold = 0.3
        self.trailing_coop_rates = []
        self.prev_stock = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        t = history.round_number
        capacity = self.game_description.capacity
        if t == 0:
            self.prev_stock = current_stock
            return Action.C
        if t > 0:
            prev_coop_count = history.opponent_cooperators[-1]
            coop_rate = prev_coop_count / (n - 1) if n > 1 else 0.5
            self.trailing_coop_rates.append(coop_rate)
            if len(self.trailing_coop_rates) > 3:
                self.trailing_coop_rates.pop(0)
            if len(self.trailing_coop_rates) >= 2:
                curr_avg = self.trailing_coop_rates[-1]
                prev_avg = self.trailing_coop_rates[-2]
                if curr_avg < prev_avg:
                    self.cooperation_threshold = 0.4
                elif curr_avg > prev_avg:
                    self.cooperation_threshold = 0.6
                else:
                    self.cooperation_threshold = 0.5
            if history.my_actions[-1] and current_stock < self.prev_stock:
                self.stock_threshold = 0.25
            else:
                self.stock_threshold = 0.3
        self.prev_stock = current_stock
        if current_stock < capacity * 0.15:
            return Action.D
        if t == r - 1:
            return Action.D
        rounds_remaining_ratio = (r - t) / r if r > 0 else 0.0
        if rounds_remaining_ratio < 0.25:
            return Action.D
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        if stock_ratio < self.stock_threshold:
            return Action.D
        coop_count = history.opponent_cooperators[-1]
        coop_rate = coop_count / (n - 1) if n > 1 else 0.5
        if coop_rate < self.cooperation_threshold:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_78(BaseStrategy):
    """
    Individualistic Adaptive Resource Strategy - prioritizes self-interested extraction
    with adaptive deference to opponent behavior only when sustainable.
    Defects on final round, when stock is critically depleted, or when opponent
    cooperation doesn't justify restraint. Cooperates only to sustain future extraction.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        rounds_remaining = r - current_round
        if rounds_remaining == 1:
            return Action.D
        if current_stock < 0.3 * capacity:
            return Action.D
        stock_health = current_stock / capacity
        time_discount = (r - rounds_remaining) / r
        coop_threshold = 0.5 - 0.2 * time_discount
        if current_round == 0:
            cooperation_rate = 0.0
        else:
            opponents_cooperated = history.opponent_cooperators[-1]
            cooperation_rate = opponents_cooperated / (n - 1)
        if cooperation_rate >= coop_threshold and stock_health >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_79(BaseStrategy):
    """
    Adaptive Depletion-Response Strategy for Common Pool Resource Game.
    
    Decisions are based on the current stock-to-capacity ratio:
    - Last round: Always DEFECT (extract maximum before game ends)
    - Critical depletion (stock/capacity ≤ 0.3): COOPERATE (allow logistic recovery)
    - Healthy stock (stock/capacity > 0.6): DEFECT (exploit abundance)
    - Intermediate (0.3 < stock/capacity ≤ 0.6): Mixed based on round position
      - Rounds 0 to r-3: COOPERATE
      - Round r-2: DEFECT if stock/capacity > 0.5, else COOPERATE
      - Round r-1: DEFECT (handled by last-round rule)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number
        capacity = self.game_description.capacity
        if capacity <= 0:
            return Action.D
        stock_ratio = current_stock / capacity
        if current_round == n_rounds - 1:
            return Action.D
        if stock_ratio <= 0.3:
            return Action.C
        if stock_ratio > 0.6:
            return Action.D
        if current_round < n_rounds - 2:
            return Action.C
        if current_round == n_rounds - 2:
            if stock_ratio > 0.5:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_INDIVIDUALISTIC_80(BaseStrategy):
    """
    Adaptive Stock-Preserving Strategy that maximizes cumulative payoff by
    dynamically balancing current consumption against future stock availability.
    
    Uses stock ratio, rounds remaining, and opponent cooperation rate to decide
    between cooperation (restraint) and defection (exploitation).
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        rounds_left = self.n_rounds - current_round
        stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0.5
        if current_round == 0:
            if stock_ratio > 0.6:
                return Action.C
            else:
                return Action.D
        if rounds_left == 1:
            return Action.D
        if stock_ratio < 0.25:
            return Action.C
        n_opponents = self.n_players - 1
        opponents_coop_last_round = history.opponent_cooperators[-1]
        opponent_coop_rate = opponents_coop_last_round / n_opponents if n_opponents > 0 else 0.0
        if stock_ratio > 0.75:
            if opponent_coop_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        if rounds_left <= 2:
            return Action.D
        cooperation_threshold = 0.5 + 0.1 * math.log(rounds_left)
        if opponent_coop_rate >= cooperation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_81(BaseStrategy):
    """
    Individualistic Adaptive Resource Strategy for Common Pool Resource Game.
    
    Cooperates in round 1 unconditionally. In mid-game, cooperates only when stock
    is above critical threshold (1.5n). In endgame, additionally requires high
    opponent cooperation. Adaptively adjusts threshold based on stock depletion
    patterns. Always defects in final round and when stock is critically low.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.endgame_length = math.ceil(self.r / 4)
        self.theta_critical = 1.5 * self.n
        self.theta_critical_adjusted = self.theta_critical
        self.previous_stock = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if round_num == 0:
            self.previous_stock = current_stock
            return Action.C
        if round_num > 0 and self.previous_stock is not None:
            stock_change = current_stock - self.previous_stock
            stock_change_pct = stock_change / self.previous_stock if self.previous_stock > 0 else 0
            if stock_change_pct < -0.1 and history.my_actions[-1]:
                self.theta_critical_adjusted = self.theta_critical + 0.5 * self.n
            elif stock_change_pct > 0 and history.my_actions[-1]:
                pass
        self.previous_stock = current_stock
        if current_stock <= 0:
            return Action.D
        if round_num == self.r - 1:
            return Action.D
        rounds_remaining = self.r - round_num
        in_endgame = rounds_remaining <= self.endgame_length
        if not in_endgame:
            if current_stock > self.theta_critical_adjusted:
                return Action.C
            else:
                return Action.D
        else:
            high_cooperation = history.opponent_cooperators[-1] > self.n / 2
            if current_stock > self.theta_critical_adjusted and high_cooperation:
                return Action.C
            else:
                return Action.D

class Strategy_INDIVIDUALISTIC_82(BaseStrategy):
    """
    Adaptive Depletion-Based Strategy for Common Pool Resource Game.
    
    Cooperates when substantial stock remains relative to game progress,
    defects as stock depletes or game approaches end. Tracks depletion rate
    to detect heavy defection by opponents and responds accordingly.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.entered_death_spiral = False
        self.previous_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        d = history.round_number
        if d == 0:
            return Action.C
        if current_stock < capacity / 4:
            self.entered_death_spiral = True
        if self.entered_death_spiral:
            self.previous_stock = current_stock
            return Action.D
        if d == r - 1:
            self.previous_stock = current_stock
            return Action.D
        k = math.ceil(r / 4)
        if d >= r - k:
            self.previous_stock = current_stock
            return Action.D
        if self.previous_stock > 0:
            depletion_rate = (self.previous_stock - current_stock) / self.previous_stock
            target_sustainable_rate = (capacity - current_stock) / (2 * n * capacity)
            if depletion_rate > 1.5 * target_sustainable_rate:
                self.previous_stock = current_stock
                return Action.D
        lambda_val = 0.5
        threshold = capacity * (1 - d / r) * lambda_val
        self.previous_stock = current_stock
        if current_stock > threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_83(BaseStrategy):
    """
    Threshold Defection Strategy for Common Pool Resource Game.
    
    Defects when: (1) in terminal round, (2) majority of opponents defected last round,
    or (3) stock falls below depletion threshold. Otherwise cooperates, starting with
    cooperation in round 1 assuming adequate stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity
        if self.capacity < 2 * self.n_players:
            self.depletion_threshold = self.capacity / (4 * self.n_players)
        else:
            self.depletion_threshold = self.capacity / (3 * self.n_players)
        self.defection_majority_threshold = math.ceil((self.n_players - 1) / 2)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_stock <= 0:
            return Action.C
        if current_round == self.n_rounds - 1:
            return Action.D
        opponents_cooperating_last = history.opponent_cooperators[-1]
        opponents_defecting_last = self.n_players - 1 - opponents_cooperating_last
        if opponents_defecting_last >= self.defection_majority_threshold:
            return Action.D
        if current_stock <= self.depletion_threshold:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_84(BaseStrategy):
    """
    Individualistic Threshold-Adaptive Strategy for Common Pool Resource Game.
    
    Employs a dynamic threshold that decreases over time, combined with adaptive
    adjustments based on observed opponent cooperation. Defects when stock exceeds
    the threshold, cooperates otherwise. Always defects in the final round.
    Includes an emergency safeguard for critically low stock levels.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold_multiplier = 1.0
        self.emergency_countdown = 0

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_stock < capacity / (5 * n):
            if self.emergency_countdown > 0:
                self.emergency_countdown -= 1
                return Action.C
            else:
                self.emergency_countdown = 2
                return Action.C
        else:
            self.emergency_countdown = 0
        if current_round > 0:
            c_t = history.opponent_cooperators[-1]
            if c_t < n / 3:
                self.threshold_multiplier *= 0.9
            elif c_t > 2 * n / 3:
                self.threshold_multiplier *= 1.05
        t = current_round + 1
        time_factor = 1.0 - (t - 1) / (r - 1) if r > 1 else 0.0
        base_threshold = capacity * (0.3 + 0.2 * time_factor)
        threshold_t = base_threshold * self.threshold_multiplier
        if current_stock > threshold_t:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_85(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Cooperates when all conditions favor stock sustainability:
    - Sufficient rounds remain for stock recovery (> 2)
    - Stock above growth optimum threshold (> capacity/2)
    - Observed opponent cooperation rate ≥ 0.5, or in round 1
    
    Otherwise defects to maximize immediate extraction.
    Reflects rational calculation that defection in mostly-defecting population
    destroys future payoffs faster than cooperation.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        rounds_left = n_rounds - current_round
        if rounds_left <= 2:
            return Action.D
        if current_stock <= capacity / 2:
            return Action.D
        if current_round <= 1:
            return Action.C
        n_opponents = n_players - 1
        if n_opponents <= 0:
            return Action.D
        cooperators_last_round = history.opponent_cooperators[-1]
        coop_rate = cooperators_last_round / n_opponents
        if coop_rate >= 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_86(BaseStrategy):
    """
    Stock-Dependent Exploitation Strategy
    
    Defects when stock is healthy, threshold is exceeded, and opponent cooperation rate > 0.5.
    Otherwise cooperates. Includes recovery mode and stock collapse prevention.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_rounds = game_description.n_rounds
        self.n_players = game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if current_stock < 0.2 * self.capacity:
            return Action.C
        if current_stock <= 0.3 * self.capacity:
            return Action.C
        if round_number == 0:
            cooperation_rate = 0.5
        else:
            n_opponents = self.n_players - 1
            cooperators_last_round = history.opponent_cooperators[-1]
            cooperation_rate = cooperators_last_round / n_opponents if n_opponents > 0 else 0.5
        remaining_rounds = self.n_rounds - round_number
        dynamic_threshold = self.capacity * (0.35 + 0.15 * (1 - remaining_rounds / self.n_rounds))
        if current_stock > dynamic_threshold and cooperation_rate > 0.5:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_87(BaseStrategy):
    """
    Adaptive Stock-Threshold Strategy for Common Pool Resource Game.
    
    Dynamically adjusts defection threshold based on:
    - Time pressure (approaching end-game)
    - Observed defection rate of opponents
    - Current stock level relative to capacity
    
    Core logic: Defect when stock is abundant relative to remaining time,
    cooperate when stock is scarce. Shift toward defection as game ends.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number == n_rounds - 1:
            return Action.D
        if round_number == 0:
            safe_threshold = 0.45
            observed_defection_rate = 0.0
        else:
            time_pressure = 1.0 - (n_rounds - round_number - 1) / n_rounds
            n_opponents = n_players - 1
            if n_opponents > 0:
                cooperators_last_round = history.opponent_cooperators[-1]
                defectors_last_round = n_opponents - cooperators_last_round
                observed_defection_rate = defectors_last_round / n_opponents
            else:
                observed_defection_rate = 0.0
            safe_threshold = 0.45 + 0.35 * time_pressure
        adjusted_threshold = safe_threshold + 0.15 * observed_defection_rate
        if capacity > 0:
            stock_ratio = current_stock / capacity
        else:
            stock_ratio = 0.0
        if stock_ratio > adjusted_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_88(BaseStrategy):
    """
    Individual Extraction with Adaptive Cooperation - exploits when possible,
    cooperates only when necessary for resource recovery or when majority has
    already committed to defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if history.round_number == 0:
            return Action.D
        if history.round_number == n_rounds - 1:
            return Action.D
        cooperators_last_round = history.opponent_cooperators[-1]
        defectors_last_round = n - 1 - cooperators_last_round
        if current_stock <= n:
            return Action.C
        majority_defection_threshold = math.floor((n - 1) / 2)
        if defectors_last_round >= majority_defection_threshold:
            return Action.D
        if capacity > 0 and current_stock / capacity < 0.35:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_89(BaseStrategy):
    """
    Individualistic Adaptive Strategy for Common Pool Resource Game.
    
    Decision rule:
    - Final round (remaining_rounds == 1): Defect unconditionally (subgame perfect equilibrium).
    - All other rounds: Stock-level threshold
      - If stock ≤ capacity/3: Cooperate
      - If stock > capacity/3: Defect
    
    This strategy ignores opponent cooperation rates and fairness norms,
    adapting only to aggregate resource state.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        remaining_rounds = self.game_description.n_rounds - history.round_number
        if remaining_rounds == 1:
            return Action.D
        threshold = self.game_description.capacity / 3
        if current_stock <= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_90(BaseStrategy):
    """
    Adaptive Stock Threshold Strategy for Common Pool Resource Game.
    
    Cooperates when current stock falls below a critical threshold and the game
    has remaining rounds. Includes emergency cooperation when stock enters critical
    depletion (≤ capacity/n). Always defects in the final round.
    
    Decision logic:
    - Final round: Defect (no future payoffs)
    - Stock ≤ capacity/n: Cooperate (emergency—mutual cooperation better than mutual defection)
    - Stock < capacity×(1 - 1/(2n)): Cooperate (threshold rule)
    - Otherwise: Defect (maximize immediate payoff)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        n = game_description.n_players
        capacity = game_description.capacity
        r = game_description.n_rounds
        self.critical_threshold = capacity * (1 - 1 / (2 * n))
        self.emergency_threshold = capacity / n
        self.final_round_idx = r - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.final_round_idx:
            return Action.D
        if current_stock <= self.emergency_threshold:
            return Action.C
        if current_stock < self.critical_threshold:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_91(BaseStrategy):
    """
    Stock-Responsive Defection Strategy.
    
    Cooperates only when:
    1. Stock is critically depleted (< 35% capacity), or
    2. Stock is in medium range (35-80% capacity) AND not enough opponents cooperate
    
    Defects at capacity, in final round, or when abundance allows exploitation.
    Adjusts cooperation threshold dynamically based on declining cooperation trends.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.collapse_threshold = 0.35 * game_description.capacity
        self.cooperation_decline_count = 0
        self.previous_cooperation_rate = None

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number == r - 1:
            return Action.D
        if round_number == 0:
            return Action.D
        if current_stock < 0.2 * capacity:
            return Action.C
        if current_stock >= capacity:
            return Action.D
        if round_number > 0:
            observed_coop = history.opponent_cooperators[-1]
            cooperation_rate = observed_coop / (n - 1) if n > 1 else 0.0
            if self.previous_cooperation_rate is not None:
                if cooperation_rate < self.previous_cooperation_rate:
                    self.cooperation_decline_count += 1
                else:
                    self.cooperation_decline_count = 0
                if self.cooperation_decline_count >= 2:
                    self.collapse_threshold += 0.05 * capacity
                    self.cooperation_decline_count = 0
            if cooperation_rate > 0.6:
                self.cooperation_decline_count = 0
            self.previous_cooperation_rate = cooperation_rate
        medium_stock_range = self.collapse_threshold < current_stock < 0.8 * capacity
        required_cooperators = math.ceil((n + 1) / 2)
        observed_cooperation_count = history.opponent_cooperators[-1] if round_number > 0 else 0
        insufficient_cooperation_coverage = observed_cooperation_count < required_cooperators
        if current_stock <= self.collapse_threshold or (medium_stock_range and insufficient_cooperation_coverage):
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_92(BaseStrategy):
    """
    Individualistic Stock-Adaptive Strategy for Common Pool Resource Game.
    
    Defects by default, cooperates only when stock depletion threatens future consumption.
    Uses stock-level thresholds and sustainability projections to decide between cooperation and defection.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        capacity = self.game_description.capacity
        round_num = history.round_number
        n_rounds = self.game_description.n_rounds
        if current_stock < capacity * 0.1:
            return Action.C
        if round_num == 0:
            return Action.D
        if round_num == n_rounds - 1:
            return Action.D
        if current_stock <= capacity * 0.35:
            return Action.C
        n_opponents = n - 1
        opponents_cooperated = history.opponent_cooperators[-1]
        opponents_defected = n_opponents - opponents_cooperated
        if n_opponents > 0:
            d_prev = opponents_defected / n_opponents
        else:
            d_prev = 0.0
        projected_consumption = (1 + d_prev * (n - 1)) * current_stock / n
        projected_remaining = current_stock - projected_consumption
        if projected_remaining > 0 and capacity > 0:
            projected_growth = 2 * projected_remaining * (1 - projected_remaining / capacity)
        else:
            projected_growth = 0.0
        projected_new_stock = min(projected_remaining + projected_growth, capacity)
        if projected_new_stock < capacity * 0.25:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_93(BaseStrategy):
    """
    Adaptive Depletion-Sensitive Strategy for Common Pool Resource Game.
    
    Cooperates to sustain the resource when stock is healthy and sufficient 
    rounds remain; defects when immediate extraction exceeds the value of 
    preservation. Adapts based on observed cooperation rates and resource 
    depletion dynamics.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.n_rounds - 1:
            return Action.D
        remaining_rounds = self.n_rounds - current_round
        if current_stock < 0.08 * self.capacity:
            return Action.D
        if remaining_rounds <= 2:
            stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0
            if stock_ratio < 0.6:
                return Action.D
        if self.n_players > 1:
            cooperators_last_round = history.opponent_cooperators[-1]
            cooperation_rate = cooperators_last_round / (self.n_players - 1)
            threshold = 1.0 / (3 * self.n_players)
            if cooperation_rate < threshold:
                return Action.D
        if remaining_rounds > 0:
            stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0
            stock_per_round_ratio = stock_ratio / remaining_rounds
            if stock_per_round_ratio < 0.15:
                return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_94(BaseStrategy):
    """
    Individualistic Adaptive Extraction Strategy - maximizes personal consumption
    by exploiting stock abundance and free-riding on others' cooperation, retreating
    only under stock depletion pressure. Purely self-interested, treats high cooperation
    from others as a resource to harvest rather than reciprocate.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        stock_health = current_stock / capacity if capacity > 0 else 0
        if stock_health < 0.25:
            return Action.C
        if history.round_number == 0:
            return Action.D if n >= 4 else Action.C
        rounds_remaining = r - history.round_number
        n_opponents = n - 1
        observed_coop_rate = history.opponent_cooperators[-1] / n_opponents if n_opponents > 0 else 0
        if history.round_number == r - 1:
            return Action.D if stock_health >= 0.3 else Action.C
        if stock_health >= 0.7:
            return Action.D
        if stock_health >= 0.65 and rounds_remaining <= 2:
            return Action.D
        if stock_health >= 0.65 and observed_coop_rate <= 0.4:
            return Action.D
        if observed_coop_rate >= 0.75 and stock_health >= 0.5:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_95(BaseStrategy):
    """
    Adaptive Depletion-Responsive Strategy for Common Pool Resource Game.
    
    Cooperates initially and conditionally in middle rounds based on opponent behavior
    and stock sustainability, but always defects in final round or when severely depleted.
    
    Decision rule:
    1. Final round: Always defect
    2. Severe depletion (stock ≤ 0.3 × capacity): Always defect
    3. Initial round: Always cooperate
    4. Middle rounds: Cooperate if ≥50% of opponents cooperated AND stock > 0.3 × capacity
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == n_rounds - 1:
            return Action.D
        if current_stock <= 0.3 * capacity:
            return Action.D
        if current_round == 0:
            return Action.C
        n_opponents = n_players - 1
        cooperators_in_prev_round = history.opponent_cooperators[-1]
        cooperation_rate = cooperators_in_prev_round / n_opponents if n_opponents > 0 else 0.0
        if cooperation_rate >= 0.5 and current_stock > 0.3 * capacity:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_96(BaseStrategy):
    """
    Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Defects in the final round or when stock falls below one-third capacity.
    Otherwise cooperates to preserve the common pool for future rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.game_description.capacity / 3:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_97(BaseStrategy):
    """
    Elastic Stock-Response Strategy: Defect as default, shift toward cooperation
    when common pool faces depletion risk. Adapt based on stock health and opponent
    defection pressure. Exploit the terminal round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        health = current_stock / capacity if capacity > 0 else 0.0
        if current_round == 0:
            return Action.D
        cooperators_in_prev_round = history.opponent_cooperators[-1]
        n_opponents = n_players - 1
        if n_opponents > 0:
            defection_pressure = (n_opponents - cooperators_in_prev_round) / n_opponents
        else:
            defection_pressure = 0.5
        if health < 0.3:
            return Action.C
        if health >= 0.75:
            return Action.D
        if current_round == n_rounds - 1:
            return Action.D
        if defection_pressure > 0.6:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_98(BaseStrategy):
    """
    Threshold-Based Exploitation with Pool Monitoring
    
    Cooperates when stock is depleted (≤ 0.45×capacity) to preserve the resource
    for future personal consumption. Defects when stock is healthy to maximize
    immediate payoff. Adjusts threshold based on opponent cooperation patterns.
    Always defects in the last round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_stock < 0.1 * self.capacity:
            return Action.C
        threshold = 0.45
        if current_round > 0:
            cooperators = history.opponent_cooperators[-1]
            n_opponents = self.n_players - 1
            if cooperators < n_opponents / 2:
                threshold = 0.5
            elif cooperators > 3 * n_opponents / 4:
                threshold = 0.45
            else:
                threshold = 0.475
        if current_stock <= threshold * self.capacity:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_99(BaseStrategy):
    """
    Individualistic Adaptive Threshold Strategy for Common Pool Resource Game.
    
    Tracks opponent defection rates and stock levels to make adaptive decisions,
    abandoning a dying commons to maximize personal payoff. Defects when:
    1. Stock critically depleted (< 25% capacity)
    2. High defection contagion (> 40% opponents defect AND stock < 50% capacity)
    3. End-game with declining stock (≤ 2 rounds left AND stock < 75% capacity)
    4. Sustained high opponent defection (> 65%)
    
    Otherwise cooperates, with special attention to stock recovery and all-cooperate scenarios.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_opponents = game_description.n_players - 1

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.C
        cooperators_last_round = history.opponent_cooperators[-1]
        opponent_defection_rate = (self.n_opponents - cooperators_last_round) / self.n_opponents if self.n_opponents > 0 else 0.0
        rounds_remaining = self.game_description.n_rounds - history.round_number
        if current_stock < 0.25 * self.capacity:
            return Action.D
        if opponent_defection_rate > 0.4 and current_stock < 0.5 * self.capacity:
            return Action.D
        if rounds_remaining <= 2 and current_stock < 0.75 * self.capacity:
            return Action.D
        if opponent_defection_rate > 0.65:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_100(BaseStrategy):
    """
    Threshold-Based Adaptive Defection Strategy for Common Pool Resource Game.
    
    Uses dynamic thresholds based on remaining rounds and current stock level to decide
    between cooperation and defection. Observes opponent defection rates to adjust thresholds
    and signal pool danger. Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        if round_number == self.n_rounds - 1:
            return Action.D
        remaining_rounds = self.n_rounds - round_number
        critical_threshold = 2 * self.n_players
        caution_threshold = self.capacity * (0.5 + 0.2 * remaining_rounds / self.n_rounds)
        if round_number > 0:
            n_opponents = self.n_players - 1
            opponents_cooperated = history.opponent_cooperators[-1]
            opponents_defected = n_opponents - opponents_cooperated
            if opponents_defected > n_opponents / 2:
                caution_threshold += 0.1 * self.capacity
        S = current_stock
        if S <= critical_threshold:
            return Action.C
        elif S >= caution_threshold:
            return Action.D
        else:
            if caution_threshold <= critical_threshold:
                return Action.C
            p = (S - critical_threshold) / (caution_threshold - critical_threshold)
            if random.random() < p:
                return Action.D
            else:
                return Action.C

class Strategy_INDIVIDUALISTIC_101(BaseStrategy):
    """
    Adaptive Depletion Strategy: Defect when stock is sufficiently high to tolerate
    current depletion rates; cooperate when stock drops below preservation threshold.
    Estimates opponent defection rate from history and sets dynamic threshold accordingly.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n_opponents = self.n_players - 1
        if current_round == self.n_rounds - 1:
            return Action.D
        critical_threshold = self.capacity / (10 * self.n_players)
        if current_stock < critical_threshold:
            return Action.C
        if current_round == 0:
            return Action.C
        total_opponent_actions = current_round * n_opponents
        total_opponent_cooperations = np.sum(history.opponent_cooperators[:current_round])
        total_opponent_defections = total_opponent_actions - total_opponent_cooperations
        if total_opponent_actions > 0:
            d_rate = total_opponent_defections / total_opponent_actions
        else:
            d_rate = 0.0
        expected_consumption_per_round = current_stock * (d_rate / self.n_players + (1 - d_rate) / (2 * self.n_players))
        remaining_rounds = self.n_rounds - current_round
        threshold = expected_consumption_per_round * (remaining_rounds + 1)
        conservative_default = self.capacity / (3 * self.n_players)
        threshold = max(threshold, conservative_default)
        if current_stock > threshold:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_102(BaseStrategy):
    """
    Individualistic Adaptive Stock-Preservation Strategy.
    
    Plays Defect when stock is high (above 15% of capacity) to maximize immediate payoff.
    Plays Cooperate when stock is low (≤15% of capacity) to preserve the resource.
    In the final two rounds, always Defect regardless of stock.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.danger_threshold = game_description.capacity * 0.15

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        if current_round >= n_rounds - 2:
            return Action.D
        if current_stock == 0:
            return Action.C
        if current_stock > self.danger_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_103(BaseStrategy):
    """
    Adaptive cooperation with endgame defection.
    
    - Round 1: Cooperate unconditionally to probe opponents
    - Rounds 2 to r-1: Cooperate if both:
      * At least 50% of opponents cooperated last round (≥(n-1)/2)
      * Current stock > capacity/3 (pool is healthy)
    - Round r: Always defect (no future rounds, extract maximum)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_number = history.round_number
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        if round_number == 0:
            return Action.C
        if round_number == n_rounds - 1:
            return Action.D
        cooperation_threshold = (n_players - 1) / 2
        stock_threshold = capacity / 3
        opponents_cooperated_last_round = history.opponent_cooperators[-1]
        if opponents_cooperated_last_round >= cooperation_threshold and current_stock > stock_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_104(BaseStrategy):
    """
    Defect-on-Abundance, Cooperate-on-Scarcity Strategy.
    
    Classifies stock relative to capacity:
    - Last round: always DEFECT
    - Stock < capacity/3 (scarcity): COOPERATE to preserve future earnings
    - Stock >= capacity/3 (abundance): DEFECT to maximize immediate payoff
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        rounds_remaining = self.game_description.n_rounds - history.round_number
        if rounds_remaining == 1:
            return Action.D
        scarcity_threshold = self.game_description.capacity / 3.0
        if current_stock < scarcity_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_105(BaseStrategy):
    """
    Conditional Extraction Strategy for Common Pool Resource Game.
    Maintains dynamic thresholds based on capacity and responds to opponent 
    cooperation rates. Cooperates when stock is abundant or others cooperate,
    defects when stock is depleted or in final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.upper_threshold = 0.7 * game_description.capacity
        self.lower_threshold = 0.3 * game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        if current_stock > self.upper_threshold:
            return Action.C
        elif current_stock > self.lower_threshold:
            recent_coop_count = history.opponent_cooperators[-1]
            n_opponents = n_players - 1
            if n_opponents <= 0:
                recent_coop_rate = 0.0
            else:
                recent_coop_rate = recent_coop_count / n_opponents
            if recent_coop_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_106(BaseStrategy):
    """
    Individualistic Adaptive Strategy for Common Pool Resource Game.
    
    Uses a dynamic stock safety threshold that increases over time:
    safe_threshold = 2n × (2 + (r - current_round)) / r
    
    Cooperates when stock ≤ threshold or when stock collapses (< 2n).
    Defects opportunistically when stock > threshold, exploiting the buffer
    provided by high stock reserves.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_stock < 2 * n:
            return Action.C
        safe_threshold = 2 * n * (2 + (r - current_round)) / r
        if current_stock <= safe_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_107(BaseStrategy):
    """
    Adaptive Exploitation Strategy that monitors stock health and opponent behavior
    to decide between cooperation and defection in a common pool resource game.
    Defects when: last round, critical depletion, majority defection, or declining stock.
    Otherwise cooperates to maintain regenerative resource state.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.previous_stock = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_stock <= capacity * 0.15:
            return Action.D
        if current_round == 0:
            opponent_defection_rate = 0.5
        else:
            n_opponents = n - 1
            total_opponent_cooperations = int(np.sum(history.opponent_cooperators[:current_round]))
            total_possible_opponent_actions = n_opponents * current_round
            if total_possible_opponent_actions > 0:
                opponent_cooperation_rate = total_opponent_cooperations / total_possible_opponent_actions
                opponent_defection_rate = 1.0 - opponent_cooperation_rate
            else:
                opponent_defection_rate = 0.5
        if opponent_defection_rate > 0.5:
            return Action.D
        if current_stock <= capacity * 0.4 and current_stock < self.previous_stock:
            return Action.D
        self.previous_stock = current_stock
        return Action.C

class Strategy_INDIVIDUALISTIC_108(BaseStrategy):
    """
    Greedy Sustainability Strategy for Common Pool Resource Game.
    
    Balances short-term defection gains against long-term stock sustainability.
    Uses observed defection rates to estimate future stock dynamics and applies
    a threshold-based decision rule. Cooperates early for information gathering,
    defects in the last round, and applies edge-case logic for extreme stock levels
    and observed cooperation patterns.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity
        self.last_stock = game_description.capacity
        self.high_coop_period_remaining = 0
        self.permanent_defect = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            self.last_stock = current_stock
            return Action.C
        current_round = history.round_number
        rounds_remaining = self.r - current_round
        if current_round == self.r - 1:
            return Action.D
        if self.permanent_defect:
            return Action.D
        observed_cooperators = history.opponent_cooperators[-1]
        n_opponents = self.n - 1
        observed_defection_rate = 0.0
        if n_opponents > 0:
            observed_defection_rate = (n_opponents - observed_cooperators) / n_opponents
        if current_stock < 2:
            return Action.D
        stock_decline_rate = 0.0
        if self.last_stock > 0:
            stock_decline_rate = (self.last_stock - current_stock) / self.last_stock
        if stock_decline_rate > 0.2:
            return Action.D
        if current_stock >= 0.9 * self.capacity:
            result = Action.C if observed_defection_rate < 0.5 else Action.D
            self.last_stock = current_stock
            return result
        cooperation_rate = observed_cooperators / n_opponents if n_opponents > 0 else 0.0
        if cooperation_rate > 0.7 and self.high_coop_period_remaining == 0:
            self.high_coop_period_remaining = 2
        if self.high_coop_period_remaining > 0 and cooperation_rate < 0.4:
            self.permanent_defect = True
            return Action.D
        if self.high_coop_period_remaining > 0:
            self.high_coop_period_remaining -= 1
            self.last_stock = current_stock
            return Action.C
        immediate_gain = current_stock / self.n - current_stock / (2 * self.n)
        growth_benefit = 0.1 * self.capacity * (1 - observed_defection_rate)
        expected_future_loss = growth_benefit / max(rounds_remaining, 1)
        self.last_stock = current_stock
        if immediate_gain > expected_future_loss:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_109(BaseStrategy):
    """
    Individualistic Adaptive Stock Strategy for Common Pool Resource Game.
    
    Maximizes individual payoff by adapting defection/cooperation based on:
    - Current stock level relative to capacity
    - Remaining rounds (deadline pressure)
    - Observed cooperation rates of opponents
    
    Key behaviors:
    - Always defects in final round (no future compensation possible)
    - Defects when stock depleted or critical
    - Shifts toward defection as endgame approaches
    - Cooperates in early game with abundant stock, conditional on others cooperating
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        remaining_rounds = self.n_rounds - current_round
        if current_round == 0:
            return Action.C
        stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0.0
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_stock <= 0:
            return Action.D
        if stock_ratio < 0.4:
            return Action.D
        if stock_ratio < 0.3 and remaining_rounds <= 3:
            return Action.D
        observed_cooperators_last_round = history.opponent_cooperators[-1]
        cooperation_ratio = observed_cooperators_last_round / (self.n_players - 1) if self.n_players > 1 else 0.0
        if remaining_rounds <= 2 and cooperation_ratio < 0.15:
            return Action.D
        if current_round == self.n_rounds - 2:
            if stock_ratio > 0.65:
                return Action.C
            else:
                return Action.D
        if current_round <= 2 and stock_ratio > 0.8:
            if cooperation_ratio > 0.2:
                return Action.C
        return Action.C

class Strategy_INDIVIDUALISTIC_110(BaseStrategy):
    """
    Individualistic Adaptive Resource Strategy.
    Defects by default when resource state permits; switches to cooperation only when resource sustainability requires it to protect future payoffs.
    Purely state-responsive: reacts only to observable stock level.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        sustainability_ratio = current_stock / self.game_description.capacity
        if sustainability_ratio < 0.25:
            return Action.C
        elif sustainability_ratio > 0.7:
            return Action.D
        else:
            defection_pressure = (sustainability_ratio - 0.25) / 0.45
            if random.random() < defection_pressure:
                return Action.D
            else:
                return Action.C

class Strategy_INDIVIDUALISTIC_111(BaseStrategy):
    """
    Adaptive Stock-Threshold Strategy for Common Pool Resource Game.
    
    Uses dynamic optimization based on current stock level and time remaining.
    Defects greedily when stock is abundant, but cooperates to allow recovery
    when stock is depleted or rounds are running out.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        critical_stock = self.capacity / (4.0 * self.n)
        healthy_stock = 0.7 * self.capacity
        remaining_rounds = self.r - current_round - 1
        if current_stock <= critical_stock:
            return Action.C
        elif current_stock >= healthy_stock:
            return Action.D
        elif remaining_rounds >= 3:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_112(BaseStrategy):
    """
    Adaptive Stock-Threshold Strategy for Common Pool Resource Game.
    
    Divides stock into exploitation and preservation zones with a threshold that
    shifts based on remaining rounds. Defects when stock exceeds a dynamically
    calculated critical threshold, otherwise cooperates. Threshold starts at 2/3
    of capacity in round 1 and linearly declines toward 1/3 by the final round.
    
    Edge case: If stock ≤ 2n, always cooperate to preserve the resource.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.capacity = game_description.capacity
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        minimum_threshold = 2 * self.n_players
        if current_stock <= minimum_threshold:
            return Action.C
        round_number = history.round_number
        critical_threshold = self.capacity * (2 / 3 - round_number / (3 * self.n_rounds))
        if current_stock > critical_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_113(BaseStrategy):
    """
    Stock-responsive adaptive defection strategy for common pool resource games.
    
    Defects by default to maximize immediate payoff. Switches to cooperation only when
    stock is critically depleted (stock/capacity < 0.30) or when stock is moderately
    depleted AND most opponents are already defecting. Always defects in the final round
    since future stock provides no payoff.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_number = history.round_number
        if round_number == n_rounds - 1:
            return Action.D
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        if stock_ratio < 0.3:
            return Action.C
        if stock_ratio < 0.55 and round_number > 0:
            cooperating_opponents = history.opponent_cooperators[-1]
            n_opponents = n - 1
            if n_opponents > 0:
                defecting_opponents = n_opponents - cooperating_opponents
                defection_rate = defecting_opponents / n_opponents
                if defection_rate > 0.5:
                    return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_114(BaseStrategy):
    """
    Individualistic Threshold-Based Strategy for Common Pool Resource Game.
    
    Decision rule:
    - Maintain a critical stock threshold of capacity/3
    - COOPERATE if stock ≤ threshold
    - DEFECT if stock > threshold
    - Always DEFECT in the final round
    - If stock falls below capacity/6 (crisis level), COOPERATE for one additional round
    
    This is purely individualistic: extract maximum value when stock permits,
    cooperate only when stock depletion threatens future payoff stream.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = game_description.capacity / 3
        self.crisis_threshold = game_description.capacity / 6
        self.in_recovery = False

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        if current_round == n_rounds - 1:
            return Action.D
        if self.in_recovery:
            self.in_recovery = False
            if current_stock <= self.threshold:
                return Action.C
            else:
                return Action.D
        if current_stock < self.crisis_threshold:
            self.in_recovery = True
            return Action.C
        if current_stock <= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_115(BaseStrategy):
    """
    Stock-Adaptive Defection Strategy for Common Pool Resource Game.
    
    Makes decisions based on current stock ratio and opponent behavior,
    with special handling for endgame scenarios and collapse conditions.
    Defects when stock is plentiful, cooperates when threatened, and always
    defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.last_stock = float(game_description.capacity)

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        t = history.round_number
        if current_stock < 2 * n:
            self.last_stock = current_stock
            return Action.C
        if t == r - 1:
            self.last_stock = current_stock
            return Action.D
        rho = current_stock / capacity if capacity > 0 else 0.0
        stock_declining = current_stock < self.last_stock
        in_endgame = t > r - 3
        if t == 0:
            self.last_stock = current_stock
            if capacity >= 4 * n:
                return Action.D
            else:
                return Action.C
        c_prev = history.opponent_cooperators[-1]
        n_opponents = n - 1
        coop_rate = c_prev / n_opponents if n_opponents > 0 else 0.0
        if stock_declining and t > r - 2:
            self.last_stock = current_stock
            return Action.D
        if coop_rate > 0.75:
            if rho > 0.5:
                self.last_stock = current_stock
                return Action.D
            else:
                self.last_stock = current_stock
                return Action.C
        if coop_rate < 0.25 and rho < 0.5:
            self.last_stock = current_stock
            return Action.C
        high_threshold = 0.5 if in_endgame else 0.6
        mid_threshold = 0.2 if in_endgame else 0.3
        if rho > high_threshold:
            self.last_stock = current_stock
            return Action.D
        elif rho > mid_threshold:
            self.last_stock = current_stock
            return Action.C
        else:
            self.last_stock = current_stock
            return Action.C

class Strategy_INDIVIDUALISTIC_116(BaseStrategy):
    """
    Stock-Threshold Conditional Defection strategy.
    
    Decision rule:
    - Final round (t = r): Always DEFECT
    - Other rounds (t < r):
      - If stock >= capacity/2: DEFECT
      - If stock < capacity/2: COOPERATE
    
    This strategy ignores opponent actions and bases decisions solely on
    the observable stock level and current round number, maximizing payoff
    relative to the resource's regenerative dynamics.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        current_round = history.round_number
        is_final_round = current_round == self.game_description.n_rounds - 1
        if is_final_round:
            return Action.D
        threshold = self.game_description.capacity / 2
        if current_stock >= threshold:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_117(BaseStrategy):
    """
    Adaptive conditional defection strategy based on stock health and opponent cooperation.
    
    Decision rule (checked in order):
    1. Last round → Defect unconditionally
    2. Stock health check → Defect if stock_ratio < threshold_stock
    3. Opponent cooperation check → Defect if cooperation_rate < threshold_coop
    4. Otherwise → Cooperate
    
    Thresholds adapt to remaining time to balance sustainability with time pressure.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == r - 1:
            return Action.D
        stock_ratio = current_stock / capacity if capacity > 0 else 0
        threshold_stock = 0.15 + 0.2 * (round_num / r)
        if stock_ratio < threshold_stock:
            return Action.D
        if round_num == 0:
            cooperators_observed = 0
        else:
            cooperators_observed = history.opponent_cooperators[round_num - 1]
        cooperation_rate = cooperators_observed / (n - 1) if n > 1 else 0
        threshold_coop = 0.35 + 0.2 * (round_num / r)
        if cooperation_rate < threshold_coop:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_118(BaseStrategy):
    """
    Adaptive Stock-Aware Exploitation Strategy
    
    Defects unconditionally in round 1. In subsequent rounds, defects if:
    - Opponent cooperation rate (previous round) < 50%, OR
    - Current stock < capacity/3, OR
    - Rounds remaining <= 2
    
    Otherwise cooperates to preserve stock when conditions are favorable.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.D
        n_opponents = self.game_description.n_players - 1
        observed_cooperators = history.opponent_cooperators[-1]
        if n_opponents > 0:
            cooperation_rate = observed_cooperators / n_opponents
        else:
            cooperation_rate = 0.0
        if cooperation_rate < 0.5:
            return Action.D
        if current_stock < self.game_description.capacity / 3:
            return Action.D
        rounds_remaining = self.game_description.n_rounds - history.round_number
        if rounds_remaining <= 2:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_119(BaseStrategy):
    """
    Adaptive Greedy Depletion Strategy for Common Pool Resource Game.
    
    Maximizes consumption while maintaining stock above critical threshold.
    Exploits high cooperation, matches defection pressure, and switches to 
    defection in final rounds.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            return Action.D
        if round_num == n_rounds - 1:
            return Action.D
        stock_health = current_stock / capacity
        if stock_health <= 0.25:
            return Action.C
        rounds_remaining = n_rounds - round_num
        if rounds_remaining <= 2:
            return Action.D
        opponent_coop_count = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents > 0:
            opponent_coop_rate = opponent_coop_count / n_opponents
        else:
            opponent_coop_rate = 0.5
        if opponent_coop_rate > 0.65:
            return Action.D
        if opponent_coop_rate < 0.35 and stock_health > 0.5:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_120(BaseStrategy):
    """
    Adaptive Stock-Based Strategy that exploits abundant resources while defensively
    cooperating when stock approaches critical depletion. Adjusts cooperation thresholds
    based on observed opponent cooperation rates and always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        ratio = current_stock / self.game_description.capacity if self.game_description.capacity > 0 else 0.0
        if ratio < 0.1:
            return Action.C
        if history.round_number == 0:
            return Action.C if ratio < 0.35 else Action.D
        n_opponents = self.game_description.n_players - 1
        if n_opponents <= 0:
            return Action.C if ratio < 0.35 else Action.D
        k = history.opponent_cooperators[-1]
        coop_rate = k / n_opponents
        if coop_rate < 0.3:
            return Action.C if ratio < 0.45 else Action.D
        elif coop_rate >= 0.7:
            return Action.C if ratio < 0.25 else Action.D
        else:
            return Action.C if ratio < 0.35 else Action.D

class Strategy_INDIVIDUALISTIC_121(BaseStrategy):
    """
    Cooperative Defection with Stock-Aware Adaptation.
    
    Starts with cooperation to establish baseline. In middle rounds, adapts between
    cooperation and defection based on stock health and opponent cooperation rates.
    Always defects in the final round. Prioritizes stock recovery when depleted.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        if current_stock == 0:
            return Action.D
        opponent_coop_count = history.opponent_cooperators[-1]
        n_opponents = n - 1
        opponent_coop_rate = opponent_coop_count / n_opponents if n_opponents > 0 else 0.0
        stock_collapse_threshold = n
        stock_health_threshold = 1.5 * n
        if current_stock < stock_collapse_threshold:
            return Action.C
        elif current_stock >= stock_health_threshold:
            return Action.D
        elif opponent_coop_rate >= 0.6:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_122(BaseStrategy):
    """
    Adaptive defection strategy with stock-based thresholds.
    
    Exploits maximum consumption (defection) while using stock levels as
    self-interested constraints. Defects aggressively early, cooperates only
    when stock depletion threatens future earnings, and always defects in
    final round. Tracks opponent cooperation rates to adjust sustainability
    thresholds dynamically.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.n_rounds - 1:
            return Action.D
        current_round = history.round_number
        remaining_rounds = self.n_rounds - current_round
        stock_ratio = current_stock / self.capacity if self.capacity > 0 else 0.0
        if stock_ratio <= 0.0:
            return Action.D
        n_opponents = self.n_players - 1
        cooperators_previous_round = history.opponent_cooperators[-1]
        if n_opponents > 0:
            observed_coop_rate = cooperators_previous_round / n_opponents
        else:
            observed_coop_rate = 0.0
        if observed_coop_rate == 0.0:
            return Action.D
        base_threshold = 0.55
        adjustment = observed_coop_rate * 0.15
        effective_threshold = min(base_threshold + adjustment, 0.75)
        if self.capacity < 2 * self.n_players:
            effective_threshold -= 0.1
            effective_threshold = max(effective_threshold, 0.0)
        if stock_ratio > effective_threshold:
            return Action.D
        elif stock_ratio > 0.35 and remaining_rounds > self.n_rounds / 2:
            return Action.C
        elif stock_ratio > 0.25:
            return Action.D
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_123(BaseStrategy):
    """
    Adaptive Depletion-Response Strategy for Common Pool Resource Game.
    Cooperates when stock is sustainable based on opponent behavior; defects when
    opponents exploit or future stock value is negligible. Incorporates endgame
    adjustments and stock depletion safeguards.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.capacity = game_description.capacity

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        round_num = history.round_number
        if current_stock < 0.1 * self.capacity:
            return Action.C
        if round_num == 0:
            return Action.C
        if round_num == self.n_rounds - 1:
            return Action.D
        if self.n_rounds <= 4 and round_num == self.n_rounds - 2:
            return Action.D
        k = history.opponent_cooperators[-1]
        coop_rate = k / (self.n_players - 1) if self.n_players > 1 else 0.0
        if coop_rate >= 0.6:
            return Action.C
        elif coop_rate < 0.4 and current_stock > 0.5 * self.capacity:
            return Action.D
        elif current_stock <= 0.3 * self.capacity:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_124(BaseStrategy):
    """
    Adaptive Threshold Defection with Sustainability Safeguard.
    
    Maximizes individual payoff while monitoring pool health. Defects when stock
    is stable, but cooperates to help recovery if: (1) stock is low, (2) enough
    opponents are already cooperating, and (3) there's time for recovery. Always
    defects in the final two rounds regardless of conditions.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        t = history.round_number
        remaining_rounds = r - t
        if remaining_rounds <= 2:
            threshold = 0
        else:
            threshold = 4 * n
        if t == 0:
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        if current_stock >= threshold:
            return Action.D
        elif current_stock < threshold and c_prev >= n / 3 and (remaining_rounds >= 3):
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_125(BaseStrategy):
    """
    Adaptive Defection with Conditional Cooperation.
    
    Monitors opponent cooperation in the previous round and conditionally cooperates
    based on whether majority of opponents cooperate. Always defects in first and
    final rounds. Switches to pure defection if stock drops below critical level.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description
        self.threshold = game_description.n_players / 2
        self.stock_depletion_threshold = 2 * game_description.n_players

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if current_stock < self.stock_depletion_threshold:
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        if c_prev >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_126(BaseStrategy):
    """
    Individualistic Adaptive Strategy for Common Pool Resource Game.
    
    Prioritizes personal payoff maximization by defaulting to defection except when:
    - Stock level is robust (≥65% of capacity)
    - Majority of opponents are visibly cooperating
    
    Features endgame ruthlessness (always defect in final round) and heightened
    defection bias in penultimate round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        round_num = history.round_number
        if round_num == 0:
            if current_stock >= 0.65 * capacity:
                return Action.C
            else:
                return Action.D
        if round_num == r - 1:
            return Action.D
        stock_ratio = current_stock / capacity if capacity > 0 else 0.0
        cooperators_last_round = history.opponent_cooperators[-1]
        if stock_ratio < 0.35:
            return Action.D
        if round_num == r - 2:
            threshold = n - 2
        else:
            threshold = math.ceil((n - 1) / 2)
        if cooperators_last_round >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_127(BaseStrategy):
    """
    Individualistic Adaptive Stock-Threshold Strategy
    
    Defects when current stock exceeds a dynamic threshold that rises as rounds expire.
    Early in the game, the threshold is conservative (near capacity/2), encouraging exploitation
    of abundance. As the game nears completion, the threshold increases toward capacity,
    reflecting the reduced future value of stock preservation.
    
    Decision rule: Defect ⟺ stock > threshold(rounds_remaining)
    where threshold(r_rem) = capacity/2 + (capacity/4) × (r_rem - 1) / (r - 1)
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n_rounds = self.game_description.n_rounds
        capacity = self.game_description.capacity
        rounds_remaining = n_rounds - history.round_number
        threshold = capacity / 2 + capacity / 4 * (rounds_remaining - 1) / (n_rounds - 1)
        return Action.D if current_stock > threshold else Action.C

class Strategy_INDIVIDUALISTIC_128(BaseStrategy):
    """
    Adaptive stock-preservation strategy that exploits resource abundance when safe
    and defends against depletion when threatened. Always defects in the final round.
    """

    def __init__(self, game_description: CommonPoolDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory, current_stock: float) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        capacity = self.game_description.capacity
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        stock_ratio = current_stock / capacity if capacity > 0 else 0
        if stock_ratio <= 0.35:
            return Action.C
        if stock_ratio >= 0.75:
            return Action.D
        if current_round == 0:
            return Action.D
        n_opponents = n - 1
        if n_opponents <= 0:
            return Action.C
        total_cooperators = int(np.sum(history.opponent_cooperators[:current_round]))
        total_rounds_observed = current_round * n_opponents
        observed_defection_rate = 1.0 - total_cooperators / total_rounds_observed
        if observed_defection_rate >= 0.6:
            return Action.D
        if stock_ratio >= 0.6 and observed_defection_rate <= 0.4:
            return Action.D
        return Action.C